-- Poems batch 403
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-772','水龙吟','周密','宋','宋词','song-ci','水龙吟','[]','素鸾飞下青冥，舞衣半惹凉云碎。',126,'宋词/ci.song.17000.json','["素鸾飞下青冥，舞衣半惹凉云碎。", "蓝田种玉，绿房迎晓，一奁秋意。", "擎露盘深，忆君凉夜，暗倾铅水。", "想鸳鸯、正结梨云好梦，西风冷、还惊起。", "应是飞琼仙会。", "倚凉飙、碧簪斜坠。", "轻妆斗白，明珰照影，红衣羞避。", "霁月三更，粉云千点，静香十里。", "听湘弦奏彻，冰绡偷翦，聚相思泪。"]'),
('song-ci-773','天香','周密','宋','宋词','song-ci','天香','[]','碧脑浮冰，红薇染露，骊宫玉唾谁捣。',118,'宋词/ci.song.17000.json','["碧脑浮冰，红薇染露，骊宫玉唾谁捣。", "麝月双心，凤云百和，宝钏佩环争巧。", "浓熏浅注，疑醉度、千花春晓。", "金饼著衣馀润，银叶透帘微袅。", "素被琼篝夜悄。", "酒初醒、翠屏深窈。", "一缕旧情，空趁断烟飞绕。", "罗袖馀香馨渐少。", "怅东阁、凄凉梦难到。", "谁念韩郎，清愁渐老。"]'),
('song-ci-774','珍珠帘・真珠帘','周密','宋','宋词','song-ci','珍珠帘・真珠帘','[]','宝阶斜转春宵永，云屏敞、雾卷东风新霁。',122,'宋词/ci.song.17000.json','["宝阶斜转春宵永，云屏敞、雾卷东风新霁。", "光动万星寒，曳冷云垂地。", "暗省连昌游冶事，照炫转、荧煌珠翠。", "难比。", "是鲛人织就，冰绡渍泪。", "独记梦入瑶台，正玲珑透月，琼钩十二。", "金缕逗浓香，接翠蓬云气。", "缟夜梨花生暖白，浸潋滟、一池春水。", "沈醉。", "归时人在，明河影里。"]'),
('song-ci-775','疏影','周密','宋','宋词','song-ci','疏影','[]','冰条木叶。',134,'宋词/ci.song.17000.json','["冰条木叶。", "又横斜照水，一花初发。", "素壁秋屏，招得芳魂，彷佛玉容明灭。", "疏疏满地珊湖冷，全误却、扑花幽蝶。", "甚美人、忽到窗前，镜里好春难折。", "闲想孤山旧事，浸清漪、倒映千树残雪。", "暗里东风，可惯无情，搅碎一帘香月。", "轻妆谁写崔徽面，认隐约、烟绡重叠。", "记梦回，纸帐残灯，瘦倚数枝清绝。"]'),
('song-ci-776','齐天乐','周密','宋','宋词','song-ci','齐天乐','[]','槐薰忽送清商怨，依稀正闻还歇。',123,'宋词/ci.song.17000.json','["槐薰忽送清商怨，依稀正闻还歇。", "故苑愁深，危弦调苦，前梦蜕痕枯叶。", "伤情念别。", "是几度斜阳，几回残月。", "转眼西风，一襟幽恨向谁说。", "轻鬟犹记动影，翠娥应妒我，双鬓如雪。", "枝冷频移，叶疏犹抱，孤负好秋时节。", "凄凄切切。", "渐迤逦黄昏，砌蛩相接。", "露洗馀悲，暮烟声更咽。"]'),
('song-ci-777','满江红','周密','宋','宋词','song-ci','满江红','[]','秋水涓涓，情渺渺、美人何许。',115,'宋词/ci.song.17000.json','["秋水涓涓，情渺渺、美人何许。", "还记得、东堂松桂，对床风雨。", "流水桃花西塞隐，茂林修竹山阴路。", "二十年、历历旧经行，空怀古。", "评砚品，临书谱。", "笺画史，修茶具。", "喜一愚天禀，一闲天赋。", "百战徵求千里马，十年饾饤三都赋。", "问何如、石鼎约弥明，同联句。"]'),
('song-ci-778','玉漏迟','周密','宋','宋词','song-ci','玉漏迟','[]','老来欢意少。',115,'宋词/ci.song.17000.json','["老来欢意少。", "锦鲸仙去，紫霞声杳。", "怕展金奁，依旧故人怀抱。", "犹想乌丝醉墨，惊俊语、香红围绕。", "闲自笑。", "与君共是，承平年少。", "雨窗短梦难凭，是几番宫商，几番吟啸。", "泪眼东风，回首四桥烟草。", "载酒倦游甚处，已换却、花间啼鸟。", "春恨悄。", "天涯暮云残照。"]'),
('song-ci-779','西江月','周密','宋','宋词','song-ci','西江月','[]','万壑千岩剡曲，朝南暮北樵中。',58,'宋词/ci.song.17000.json','["万壑千岩剡曲，朝南暮北樵中。", "江潭杨柳几东风。", "犹忆当年手种。", "鬓雪愁侵秋绿，容华酒借春红。", "非非是是总成空。", "金谷兰亭同梦。"]'),
('song-ci-780','杏花天','周密','宋','宋词','song-ci','杏花天','[]','金池琼苑曾经醉。',65,'宋词/ci.song.17000.json','["金池琼苑曾经醉。", "是多少、红情绿意。", "东风一枕游仙睡。", "换却莺花人世。", "渐暮色、鹃声四起。", "正愁满、香沟御水。", "一色柳烟三十里。", "为问春归那里。"]'),
('song-ci-781','四字令・醉太平','周密','宋','宋词','song-ci','四字令・醉太平','[]','残月半篱。',46,'宋词/ci.song.17000.json','["残月半篱。", "残雪半枝。", "孤吟自款柴扉。", "听猿啼鸟啼。", "人归未归。", "无诗有诗。", "水边伫立多时。", "问梅花便知。"]'),
('song-ci-782','醉落魄・一斛珠','周密','宋','宋词','song-ci','醉落魄・一斛珠','[]','寒侵径叶。',67,'宋词/ci.song.17000.json','["寒侵径叶。", "雁风击碎珊瑚屑。", "砚凉闲试霜晴帖。", "颂菊骚兰，秋事正奇绝。", "故人又作江西别。", "书楼虚度中秋节。", "碧阑倚遍愁谁说。", "愁是新愁，月是旧时月。"]'),
('song-ci-783','祝英台近','周密','宋','宋词','song-ci','祝英台近','[]','殢馀酲，寻旧雨，愁与病相半。',95,'宋词/ci.song.17000.json','["殢馀酲，寻旧雨，愁与病相半。", "绿意阴阴，丝竹静深院。", "绝怜事逐春移，泪随花落，似翦断、鲛房珠串。", "喜重见。", "为谁倦酒慵诗，筠屏掩双扇。", "白发潘郎，羞见看花伴。", "可堪好梦残时，新愁生处，烟月冷、子规声断。"]'),
('song-ci-784','甘州・八声甘州','周密','宋','宋词','song-ci','甘州・八声甘州','[]','渐萋萋、芳草绿江南，轻晖弄春容。',119,'宋词/ci.song.17000.json','["渐萋萋、芳草绿江南，轻晖弄春容。", "记少年游处，箫声巷陌，灯影帘栊。", "月暖烘炉戏鼓，十里步香红。", "敧枕听新雨，往事朦胧。", "还是江春梦晓，怕等闲愁见，雁影西东。", "喜故人好在，水驿寄诗筒。", "数芳程、渐催花信，送归帆、知第几番风。", "空吟想、梅花千树，人在其中。"]'),
('song-ci-785','甘州・八声甘州','周密','宋','宋词','song-ci','甘州・八声甘州','[]','信山阴、道上景多奇，仙翁幻吟壶。',119,'宋词/ci.song.17000.json','["信山阴、道上景多奇，仙翁幻吟壶。", "爱一邱一壑，一花一草，窈窕扶疏。", "染就春云五色，更种玉千株。", "咳唾骚香在，四壁骊珠。", "曲折冷红幽翠，涉流花涧净，步月堂虚。", "羡风流鱼鸟，来往贺家湖。", "认秦鬟、越妆窥镜，倚斜阳、人在会稽图。", "图多赏，池香洗砚，山秀藏书。"]'),
('song-ci-786','齐天乐','周密','宋','宋词','song-ci','齐天乐','[]','护春帘幕东风里，当年问花曾到。',123,'宋词/ci.song.17000.json','["护春帘幕东风里，当年问花曾到。", "玉影孤搴，冰痕半拆，漠漠冻云迷道。", "临流更好。", "正雪意逢迎，阴光相照。", "梦入罗浮，古苔啁哳翠禽小。", "一枝空念赠远，溯波流不到，心事谁表。", "倚竹天寒，吟香夜冷，几度月昏霜晓。", "寻芳欠早。", "怕鹤怨山空，雁归书少。", "不恨春迟，恨春容易老。"]'),
('song-ci-787','忆旧游','周密','宋','宋词','song-ci','忆旧游','[]','记移灯翦雨，换火篝香，去岁今朝。',125,'宋词/ci.song.17000.json','["记移灯翦雨，换火篝香，去岁今朝。", "乍见翻疑梦，向梅边携手，笑挽吟桡。", "依依故人情味，歌舞试春娇。", "对婉娩年芳，漂零身世，酒趁愁消。", "天涯未归客，望锦羽沈沈，翠水迢迢。", "叹菊荒薇老，负故人猿鹤，旧隐谁招。", "疏花漫撩愁思，无句到寒梢。", "但梦绕西泠，空江冷月，魂断随潮。"]'),
('song-ci-788','声声慢','周密','宋','宋词','song-ci','声声慢','[]','琼壶歌月，白发簪花，十年一梦扬州。',121,'宋词/ci.song.17000.json','["琼壶歌月，白发簪花，十年一梦扬州。", "恨入琵琶，小怜重见湾头。", "尊前漫题金缕，奈芳情、已逐东流。", "还送远，甚长安乱叶，都是闲愁。", "次第重阳近也，看黄花绿酒，也合迟留。", "脆柳无情，不堪重系行舟。", "百年正消几别，对西风、休赋登楼。", "怎去得，怕凄凉时节，团扇悲秋。"]'),
('song-ci-789','踏莎行','周密','宋','宋词','song-ci','踏莎行','[]','结客千金，醉春双玉。',68,'宋词/ci.song.17000.json','["结客千金，醉春双玉。", "旧游宫柳藏仙屋。", "白头吟老茂陵西，清平梦远沈香北。", "玉笛天津，锦囊昌谷。", "春红转眼成秋绿。", "重翻花外侍儿歌，休听酒边供奉曲。"]'),
('song-ci-790','国香慢・国香','周密','宋','宋词','song-ci','国香慢・国香','[]','玉润金明。',121,'宋词/ci.song.17000.json','["玉润金明。", "记曲屏小几，翦叶移根。", "经年汜人重见，瘦影娉婷。", "雨带风襟零乱，步云冷、鹅管吹春。", "相逢旧京洛，素靥尘缁，仙掌霜凝。", "国香流落恨，正冰铺翠薄，谁念遗簪。", "水天空远，应念矾弟梅兄。", "渺渺鱼波望极，五十弦、愁满湘云。", "凄凉耿无语，梦入东风，雪尽江清。"]'),
('song-ci-791','一萼红','周密','宋','宋词','song-ci','一萼红','[]','步深幽。',133,'宋词/ci.song.17000.json','["步深幽。", "正云黄天淡，雪意未全休。", "鉴曲寒沙，茂林烟草，俯仰千古悠悠。", "岁华晚、漂零渐远，谁念我、同载五湖舟。", "磴古松斜，崖阴苔老，一片清愁。", "回首天涯归梦，几魂飞西浦，泪洒东州。", "故国山川，故园心眼，还似王粲登楼。", "最怜他、秦鬟妆镜，好江山、何事此时游。", "为唤狂吟老监，共赋销忧。"]'),
('song-ci-792','扫花游・扫地游','周密','宋','宋词','song-ci','扫花游・扫地游','[]','江蓠怨碧，早过了霜花，锦空洲渚。',117,'宋词/ci.song.17000.json','["江蓠怨碧，早过了霜花，锦空洲渚。", "孤蛩自语。", "正长安乱叶，万家砧杵。", "尘染秋衣，谁念西风倦旅。", "恨无据。", "怅望极归舟，天际烟树。", "心事曾细数。", "怕水叶沈红，梦云离去。", "情丝恨缕。", "倩回纹为织，那时愁句。", "雁字无多，写得相思几许。", "暗凝伫。", "近重阳、满城风雨。"]'),
('song-ci-793','三姝媚','周密','宋','宋词','song-ci','三姝媚','[]','浅寒梅未绽。',122,'宋词/ci.song.17000.json','["浅寒梅未绽。", "正潮过西陵，短亭逢雁。", "秉烛相看，叹俊游零落，满襟依黯。", "露草霜花，愁正在、废宫芜苑。", "明月河桥，笛外尊前，旧情消减。", "莫诉离肠深浅。", "恨聚散匆匆，梦随帆远。", "玉镜尘昏，怕赋情人老，后逢凄惋。", "一样归心，又唤起、故园愁眼。", "立尽斜阳无语，空江岁晚。"]'),
('song-ci-794','献仙音・法曲献仙音','周密','宋','宋词','song-ci','献仙音・法曲献仙音','[]','松雪飘寒，岭云吹冻，红破数椒春浅。',113,'宋词/ci.song.17000.json','["松雪飘寒，岭云吹冻，红破数椒春浅。", "衬舞台荒，浣妆池冷，凄凉市朝轻换。", "叹花与人凋谢，依依岁华晚。", "共凄黯。", "问东风、几番吹梦，应惯识当年，翠屏金辇。", "一片古今愁，但废绿、平烟空远。", "无语消魂，对斜阳、衰草泪满。", "又西泠残笛，低送数声春怨。"]'),
('song-ci-795','高阳台','周密','宋','宋词','song-ci','高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','照野旌旗，朝天车马，平沙万里天低。',122,'宋词/ci.song.17000.json','["照野旌旗，朝天车马，平沙万里天低。", "宝带金章，尊前茸帽风敧。", "秦关汴水经行地，想登临、都付新诗。", "纵英游，叠鼓清笳，骏马名姬。", "酒酣应对燕山雪，正冰河月冻，晓陇云飞。", "投老残年，江南谁念方回。", "东风渐绿西湖柳，雁已还、人未南归。", "最关情，折尽梅花，难寄相思。"]'),
('song-ci-796','庆宫春・高阳台','周密','宋','宋词','song-ci','庆宫春・高阳台','[]','重叠云衣，微茫雁影，短篷稳载吴雪。',126,'宋词/ci.song.17000.json','["重叠云衣，微茫雁影，短篷稳载吴雪。", "霜叶敲寒，风灯摇晕，棹歌人语呜咽。", "拥衾呼酒，正百里、冰河乍合。", "千山换色，一镜无尘，玉龙吹裂。", "夜深醉踏长虹，表里空明，古今清绝。", "高台在否，登临休赋，忍见旧时明月。", "翠消香冷，怕空负、年芳轻别。", "孤山春早，一树梅花，待君同折。"]'),
('song-ci-797','高阳台','周密','宋','宋词','song-ci','高阳台','[]','小雨分江，残寒迷浦，春容浅入蒹葭。',122,'宋词/ci.song.17000.json','["小雨分江，残寒迷浦，春容浅入蒹葭。", "雪霁空城，燕归何处人家。", "梦魂欲渡苍茫去，怕梦轻、还被愁遮。", "感流年，夜汐东还，冷照西斜。", "萋萋望极王孙草，认云中烟树，鸥外春沙。", "白发青山，可怜相对苍华。", "归鸿自趁潮回去，笑倦游、犹是天涯。", "问东风，先到垂杨，后到梅花。"]'),
('song-ci-798','探芳讯','周密','宋','宋词','song-ci','探芳讯','[]','步晴昼。',108,'宋词/ci.song.17000.json','["步晴昼。", "向水院维舟，津亭唤酒。", "叹刘郎重到，依依谩怀旧。", "东风空结丁香怨，花与人俱瘦。", "甚凄凉，暗草沿池，冷苔侵甃。", "桥外晚风骤。", "正香雪随波，浅烟迷岫。", "废苑尘梁，如今燕来否。", "翠云零落空堤冷，往事休回首。", "最消魂，一片斜阳恋柳。"]'),
('song-ci-799','四字令・醉太平','周密','宋','宋词','song-ci','四字令・醉太平','[]','眉消睡黄。',46,'宋词/ci.song.17000.json','["眉消睡黄。", "春凝泪妆。", "玉屏水暖微香。", "听蜂儿打窗。", "筝尘半妆。", "绡痕半方。", "愁心欲诉垂杨。", "奈飞红正忙。"]'),
('song-ci-800','西江月','周密','宋','宋词','song-ci','西江月','[]','绿绮紫丝步障，红鸾彩凤仙城。',58,'宋词/ci.song.17000.json','["绿绮紫丝步障，红鸾彩凤仙城。", "谁将三十六陂春。", "换得两堤秋锦。", "眼缬醉迷朱碧，笔花俊赏丹青。", "斜阳展尽赵昌屏。", "羞死舞鸾妆镜。"]'),
('song-ci-801','江城子','周密','宋','宋词','song-ci','江城子','[]','罗窗晓色透花明。',86,'宋词/ci.song.17000.json','["罗窗晓色透花明。", "靘瑶笙。", "按瑶筝。", "试讯东风，能有几分春。", "二十四阑凭玉暖，杨柳月，海棠阴。", "依依愁翠沁双颦。", "爱莺声。", "怕鹃声。", "人自多情，春去自无情。", "把酒问花花不语，花外梦，梦中云。"]'),
('song-ci-802','少年游','周密','宋','宋词','song-ci','少年游','[]','帘消宝篆卷宫罗。',58,'宋词/ci.song.17000.json','["帘消宝篆卷宫罗。", "蜂蝶扑飞梭。", "一样东风，燕梁莺院，那处春多。", "晓妆日日随香辇，多在牡丹坡。", "花深深处，柳阴阴处，一片笙歌。"]'),
('song-ci-803','好事近','周密','宋','宋词','song-ci','好事近','[]','新雨洗花尘，扑扑小庭香湿。',53,'宋词/ci.song.17000.json','["新雨洗花尘，扑扑小庭香湿。", "早是垂杨烟老，渐嫩黄城碧。", "晚帘都卷看青山，山外更山色。", "一色梨花新月，伴夜窗吹笛。"]'),
('song-ci-804','西江月','周密','宋','宋词','song-ci','西江月','[]','情缕红丝冉冉，啼花碧袖荧荧。',58,'宋词/ci.song.17000.json','["情缕红丝冉冉，啼花碧袖荧荧。", "迷香双蝶下庭心。", "一行愔愔帘影。", "北里红红短梦，东风雁雁前尘。", "称消不过牡丹情。", "中半伤春酒病。"]'),
('song-ci-805','醉落魄・一斛珠','周密','宋','宋词','song-ci','醉落魄・一斛珠','[]','忆忆忆忆。',67,'宋词/ci.song.17000.json','["忆忆忆忆。", "宫罗褶褶消金色。", "吹花有尽情无极。", "泪滴空帘，香润柳枝湿。", "春愁浩荡湘波窄。", "红兰梦绕江南北。", "燕莺都是东风客。", "移尽庭阴，风老杏花白。"]'),
('song-ci-806','朝中措','周密','宋','宋词','song-ci','朝中措','[]','彩绳朱乘驾涛云。',57,'宋词/ci.song.17000.json','["彩绳朱乘驾涛云。", "亲见许飞琼。", "多定梅魂才返，香瘢半掐秋痕。", "枕函钗缕，熏篝芳焙，儿女心情。", "尚有第三花在，不妨留待凉生。"]'),
('song-ci-807','醉落魄・一斛珠','周密','宋','宋词','song-ci','醉落魄・一斛珠','[]','馀寒正怯。',67,'宋词/ci.song.17000.json','["馀寒正怯。", "金钗影卸东风揭。", "舞衣丝损愁千褶。", "一缕杨丝，犹是去年折。", "临窗拥髻愁难说。", "花庭一寸燕支雪。", "春花似旧心情别。", "待摘玫瑰，飞下粉黄蝶。"]'),
('song-ci-808','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','蚕已三眠柳二眠。',48,'宋词/ci.song.17000.json','["蚕已三眠柳二眠。", "双竿初起画秋千。", "莺栊风响十三弦。", "鱼素不传新信息，鸾胶难续旧因缘。", "薄情明月几番圆。"]'),
('song-ci-809','踏莎行','周密','宋','宋词','song-ci','踏莎行','[]','远草情锺，孤花韵胜。',68,'宋词/ci.song.17000.json','["远草情锺，孤花韵胜。", "一楼耸翠生秋暝。", "十年二十四桥春，转头明月箫声冷。", "赋药才高，题琼语俊。", "蒸香压酒芙蓉顶。", "景留人去怕思量，桂窗风露秋眠醒。"]'),
('song-ci-810','酹江月・念奴娇','林式之','宋','宋词','song-ci','酹江月・念奴娇','[]','桐皋东去，又依然、烟际云边柔橹。',120,'宋词/ci.song.17000.json','["桐皋东去，又依然、烟际云边柔橹。", "赖有双台知己耳，牢落孤怀欲吐。", "小倚云根，细商心事，提起千年语。", "九天飞梦，别来长记幽渚。", "试说北海归文，西山何事，犹不甘臣武。", "广大尧天箕颍小，绵上可能如许。", "举世真痴，先生长啸，尘海谁堪与。", "啸声吹送，刺天鸾鹤冲举。"]'),
('song-ci-811','摸鱼儿','王奕','宋','宋词','song-ci','摸鱼儿','[]','问梅花、几人邀咏，平生见外骚楚。',140,'宋词/ci.song.17000.json','["问梅花、几人邀咏，平生见外骚楚。", "相思一夜罗浮远，姑射仙姿何处。", "情未吐。", "□□□、雄蜂雌蝶空相遇。", "岁年孰与。", "叹皓首相看，冰心独抱，谩作广平赋。", "黄昏暮。", "半点酸辛谁诉。", "寿阳眉恨妖妩。", "南来北使无明眼，细认杏花真谱。", "私自语。", "道消息、孤根还有春风主。", "启明未举。", "听画角吹残，马头摇梦，人已山阳路。"]'),
('song-ci-812','水调歌头','王奕','宋','宋词','song-ci','水调歌头','[]','吾玄终不白，拗出老扬雄。',114,'宋词/ci.song.17000.json','["吾玄终不白，拗出老扬雄。", "近日青衿绿发，转盼忽成翁。", "缩首□天坠地，极力虞渊取日，直欲入冯宫。", "迂阔有如此，谁不笑王公。", "十年后，数椽屋，隐琊峰。", "人叹乾坤许大，醯瓮老山中。", "於是泛淮航泗，於是沿邹过鲁，千古慕雩风。", "造物既生我，斯道岂终穷。"]'),
('song-ci-813','沁园春','王奕','宋','宋词','song-ci','沁园春','[]','耳目肺肠，不由我乎，更由乎谁。',138,'宋词/ci.song.17000.json','["耳目肺肠，不由我乎，更由乎谁。", "也不必君平，不消詹尹，不疑何卜，不卜何疑。", "三径归来，一时有见，岂为黄初与义熙。", "天下事，但行其可，自合乎宜。", "大哉用易乘时。", "纵乌喙那能食子皮。", "叹失若塞翁，失为得本，赢如刘毅，赢乃输基。", "大黠小痴，有馀不足，谁必彭殇早与迟。", "眼前物，纵铜山金屋，一瞑全非。"]'),
('song-ci-814','南乡子','王奕','宋','宋词','song-ci','南乡子','[]','搔首倚薰风。',66,'宋词/ci.song.17000.json','["搔首倚薰风。", "一幅画图尘土中。", "鹤怨猿惊人去也，潜龙。", "谁绞香车起蛰松。", "岁月去熙丰。", "世味人情自淡浓。", "春去春来墩不竞，匆匆。", "蜀水吴山血又红。"]'),
('song-ci-815','霜天晓角','王奕','宋','宋词','song-ci','霜天晓角','[]','天无四壁。',53,'宋词/ci.song.17000.json','["天无四壁。", "底用量江尺。", "徒把乾坤分裂，谁与帝、扶民厄。", "几年樊圃缺。", "耳风腔转笛。", "此日双蛾空蹙，依然也，暮山碧。"]'),
('song-ci-816','贺新郎','王奕','宋','宋词','song-ci','贺新郎','[]','有客过东鲁。',146,'宋词/ci.song.17000.json','["有客过东鲁。", "自葛水、泛舟西下，帆开三楚。", "万里湖光磨水镜，际五老、落星烟渚。", "又飞过、二姑门户。", "彭泽柳青新旧色，望九华、依约池阳路。", "风雨庙，乌江羽。", "蛾眉牛渚皆如故。", "问缘何、鲁港汀洲，江声无语。", "采石书生勋业在，吊锦袍、公子魂何处。", "流恨下、秦淮商女。", "多景楼头吟北固，笑平山堂里谁为主。", "且烂饮，琼花露。"]'),
('song-ci-817','贺新郎','王奕','宋','宋词','song-ci','贺新郎','[]','醉醒琼花露。',148,'宋词/ci.song.17000.json','["醉醒琼花露。", "买扁舟、邵伯津头，向秦邮去。", "流水孤村鸦万点，忆少游、回首斜阳树。", "又访著、山阳酒侣。", "细剔留城碑藓看，上歌舞、一啸江东主。", "望凫峄，过邹鲁。", "孔林百拜瞻茔墓。", "历四阜、少皞之墟，大庭之库。", "竟涉汶河登泰岱，候清光，夜半开玄圃。", "迤逦问、东平归路。", "蚩冢黄花吟笑罢，下新州，醉白楼头赋。", "复淮楚，寻故步。"]'),
('song-ci-818','贺新郎','王奕','宋','宋词','song-ci','贺新郎','[]','帆卸西湾侧。',143,'宋词/ci.song.17000.json','["帆卸西湾侧。", "望康庐、老峰面目，旧曾相识。", "岁岁滔滔江浪远，回首暮云空碧。", "今想见、发痕全白。", "眠鹿矶头茅屋烂，问草堂、谁管真泉石。", "还更有，青牛迹。", "老峰点首如招客。", "道十年、玉斗窗间，两成疏觌。", "赢得老夫谙阅世，不作少年太息。", "看雨馀、依旧青山色。", "汶上归来重过我，最峰头、新长芝堪摘。", "分半席、共横笛。"]'),
('song-ci-819','沁园春','王奕','宋','宋词','song-ci','沁园春','[]','八十日官，浩然归去，知心者希。',138,'宋词/ci.song.17000.json','["八十日官，浩然归去，知心者希。", "谓诗有招魂，姑言其概，注其述酒，亦特其微。", "不事小儿，惟书甲子，皆是先生杜得机。", "看时运，与天荣木，始识真归。", "黄唐邈不可追。", "慨四十无闻昨已非。", "故怀彼仙师，策夫名骥，志夫童冠，寤寐交挥。", "人表何时，谁生过鲁，愿企高风慕浴沂。", "兹行也，尚庶几短葛，不负公衣。"]'),
('song-ci-820','八声甘州','王奕','宋','宋词','song-ci','八声甘州','[]','诵公诗、大雅久不闻，吾衰竟谁陈。',117,'宋词/ci.song.17000.json','["诵公诗、大雅久不闻，吾衰竟谁陈。", "自晋宋以来，隋唐而下，旁若无人。", "光焰文章万丈，肯媚永王璘。", "卓有汾阳老，抱丈人贞。", "不是沈香亭上，谩题飞燕，蹴起靴尘。", "安得锦袍西下，明月堕江滨。", "青山冢、知几番风雨，雷霆走精神。", "因过鲁，携一尊吊古，疑是前身。"]'),
('song-ci-821','水调歌头','王奕','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','长江衣带水，历代鼎彝功。',114,'宋词/ci.song.17000.json','["长江衣带水，历代鼎彝功。", "服定衣冠礼乐，聊尔就江东。", "追忆金戈铁马，保以油幢玉垒，熢燧几秋风。", "更有当头著，全局倚元戎。", "攒万舸，开一棹，散无踪。", "到了书生死节，蜂蚁愧诸公。", "上有皇天白日，下有人心青史，未必竟朦胧。", "停棹抚遗迹，往恨逐冥鸿。"]'),
('song-ci-822','贺新郎','王奕','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','决眦斜阳里。',142,'宋词/ci.song.17000.json','["决眦斜阳里。", "品江山、洛阳第一，金陵第二。", "休论六朝兴废梦，且说南浮之始。", "合就此、衣冠故址。", "底事轻抛形胜地，把笙歌、恋定西湖水。", "百年内，苟而已。", "纵然成败由天理。", "叹石城、潮落潮生，朝昏知几。", "可笑诸公俱铸错，回首金瓯瞥徙。", "漫涴了、紫云青史。", "老媚幽花栖断础，睇故宫、空拊英雄髀。", "身世蝶，侯王蚁。"]'),
('song-ci-823','酹江月・念奴娇','王奕','宋','宋词','song-ci','酹江月・念奴娇','[]','英雄老矣，对江山、莫遣泪珠成斛。',120,'宋词/ci.song.17000.json','["英雄老矣，对江山、莫遣泪珠成斛。", "一箑西风休掩面，白浪黄尘迷目。", "凤去台空，鹭飞洲冷，几度斜阳木。", "欲书往事，南山应恨无竹。", "宁是商女当年，后来腔调，拍手铜鞮曲。", "偃蹇老松虽拗□，犹□一枰残局。", "乌巷垂杨，雀桥野草，今为谁家绿。", "赏心何处，浩歌归卧梅屋。"]'),
('song-ci-824','法曲献仙音','王奕','宋','宋词','song-ci','法曲献仙音','[]','九曲青溪，千年陈迹，往事不堪依据。',113,'宋词/ci.song.17000.json','["九曲青溪，千年陈迹，往事不堪依据。", "老我重来，海乾石烂，那复断碑残础。", "应讶野王当日，三弄罢、乍无语。", "□□□。", "高牙大纛船如屋，又少甚笙歌，翠云箫鼓。", "流恨入寒筝，离合君臣良苦。", "花落几春□，无此一番风雨。", "是何人、尚秦淮门馆，柳桥荷浦。"]'),
('song-ci-825','贺新郎','王奕','宋','宋词','song-ci','贺新郎','["\u957f\u6c5f"]','惆怅秦淮路。',142,'宋词/ci.song.17000.json','["惆怅秦淮路。", "慨当年、商女谁家，几多年数。", "死去方知亡国恨，尚激起、浪花如语，应不为、黍峰蒲缕。", "花隔青溪胭井湿，又谁省、此时情绪。", "云盖拥，翠阴午。", "汨罗无复灵均楚。", "到如今、荃蕙椒兰，尽成禾黍。", "疑是□龙穿王气，遗恨六朝作古。", "□留与、浮歌载醑。", "天外长江浑不管，也无春无夏无晴雨。", "流岁月、滔滔去。"]'),
('song-ci-826','木兰花慢','王奕','宋','宋词','song-ci','木兰花慢','[]','翠微亭上醉，搔短发、舞缤纷。',121,'宋词/ci.song.17000.json','["翠微亭上醉，搔短发、舞缤纷。", "问六朝五姓，王姬帝胄，今有谁存。", "何似乌衣故垒，尚年年、生长儿孙。", "今古兴亡无据，好将往史俱焚。", "招魂。", "何处觅东山，筝泪落清樽。", "怅石城暗浪，秦淮旧月，东去西奔。", "休说清谈误国，有清谈，还有斯文。", "遥睇新亭一笑，漫漫天际江痕。"]'),
('song-ci-827','南乡子','王奕','宋','宋词','song-ci','南乡子','[]','豪杰说中州。',66,'宋词/ci.song.17000.json','["豪杰说中州。", "及此见题多景楼。", "曹石当年徒浪耳，悠悠。", "岁月滔滔江自流。", "风雪老兜鍪。", "不混关河事不休。", "浪舞桃花颠又蹶，嬴刘。", "莫与武陵仙客谋。"]'),
('song-ci-828','水调歌头','王奕','宋','宋词','song-ci','水调歌头','[]','迢迢嶓冢水，直泻到东州。',114,'宋词/ci.song.17000.json','["迢迢嶓冢水，直泻到东州。", "不拣秦淮吴楚，明月一家楼，何代非卿非相，底事柴桑老子，偏恁不推刘。", "半体鹿皮服，千古晋貔貅。", "过东鲁，登北固，感春秋。", "抵掌嫣然一笑，莫枉少陵愁。", "说甚萧锅曹石，古矣苏吟米画，黑白满盘收。", "对水注杯酒，为我向东流。"]'),
('song-ci-829','八声甘州','王奕','宋','宋词','song-ci','八声甘州','[]','问苍天、苍天阒无言，浩歌摘星楼。',116,'宋词/ci.song.17000.json','["问苍天、苍天阒无言，浩歌摘星楼。", "这茫茫禹迹，南来第一，是古扬州。", "当日双龙未渡，风月一家秋。", "中分胡越后，横断江流。", "□百年间春梦，笑槐柯蚁穴，多少王侯。", "谩平山堂里，棋局几边筹。", "是谁教、海乾仙去，天地付浮沤。", "书生老，对琼花一笑，白发苍洲。"]'),
('song-ci-830','临江仙','王奕','宋','宋词','song-ci','临江仙','[]','二十四桥明月好，暮年方到扬州。',70,'宋词/ci.song.17000.json','["二十四桥明月好，暮年方到扬州。", "鹤飞仙去总成休。", "襄阳风笛急，何事付悠悠。", "几阕平山堂上酒，夕阳还照边楼。", "不堪风景事回头。", "淮南新枣熟，应不说防秋。"]'),
('song-ci-831','沁园春','王奕','宋','宋词','song-ci','沁园春','[]','唐李太白，访贺知章，浩歌此楼。',140,'宋词/ci.song.17000.json','["唐李太白，访贺知章，浩歌此楼。", "想斗酒百篇，眼花落井，一时豪杰，千古风流。", "白骨青山，美人黄土，醉魄吟魂安在否。", "江南客，因来游胜践，稽首前修。", "悠悠。", "往事俱休，更莫遣兴亡狂白头。", "也莫论高皇、莫论项羽，谁为黄帝，谁为蚩尤。", "拶破愁城，吸乾酒海，袖拂安梁舞暮秋。", "题未了，又笑骑白鹤，飞下扬州。"]'),
('song-ci-832','婆罗门引','王奕','宋','宋词','song-ci','婆罗门引','[]','佳人鬓发，几回涂抹共蝉娟。',90,'宋词/ci.song.17000.json','["佳人鬓发，几回涂抹共蝉娟。", "又何止三千。", "拟待盈盈宝鉴，多少绮罗筵。", "恨妖蟆怪事，长夜中天。", "中河影圆。", "清泪落尊前。", "舞罢霓裳初服，肯为人妍。", "□□□□，算惟有、蕊宫天上仙。", "缑山鹤，亦欲蹁跹。"]'),
('song-ci-833','贺新郎','王奕','宋','宋词','song-ci','贺新郎','[]','试问司花女。',142,'宋词/ci.song.17000.json','["试问司花女。", "是何年、培植琼葩，分来何谱。", "禁苑岂无新雨露，底事刚移不去，偏恋定、鹤城抷土。", "却怕杏花生眼觑。", "先廿年、和影无寻处。", "遗草木，悴风雨。", "看花老我成迟暮。", "绕阑干、追忆沈吟，欲言难赋。", "根本已非枝叶异，谁把赝苗裨补。", "但认得、唐人旧句。", "明月楼前无水部。", "扣之梅、梅又全无语。", "询古柏，过东鲁。"]'),
('song-ci-834','沁园春','王奕','宋','宋词','song-ci','沁园春','[]','醉面挟风，携杜康酒，酹刘伶台。',140,'宋词/ci.song.17000.json','["醉面挟风，携杜康酒，酹刘伶台。", "问漂母矶头，韩侯安在，钵山池下，乔鹊曾回。", "孝说仲车，忠传祖逖，忠孝如今亦可哀。", "清河口，但潮生潮落，帆去帆来。", "休呆。", "且饮三杯。", "莫枉教、东乌西兔催。", "更谁可百年，脱身不化，谁能五日，笑口长开。", "痛饮高歌，胡涂乱抹，快活斗山王秀才。", "今天下，曰利而已，何以平哉。"]'),
('song-ci-835','唐多令','王奕','宋','宋词','song-ci','唐多令','["\u9ec4\u6cb3"]','直上倚天楼。',74,'宋词/ci.song.17000.json','["直上倚天楼。", "怀哉古楚州。", "黄河水、依旧东流。", "千古兴亡多少事，分付与、白头鸥。", "祖逖与留侯。", "二公今在不。", "眉尖上、莫带星愁。", "笑拍危阑歌短阕，翁醉矣，且归休。"]'),
('song-ci-836','沁园春','王奕','宋','宋词','song-ci','沁园春','["\u6cf0\u5c71", "\u9ec4\u6cb3"]','吾祖文中，曾於夫子，受罔极恩。',140,'宋词/ci.song.17000.json','["吾祖文中，曾於夫子，受罔极恩。", "有宇宙以来，春秋而后，三纲所系，万古常存。", "列国何时，东吴何地，十哲之中尚有言。", "况今也、与圣闲邦域，同一乾坤。", "卑飞难傍天阍。", "但勃窣衔香拜圣门。", "要水看黄河，山登岱岳，鲁求君子，学究中原。", "虽有他人，不如同姓，仰止文星出禁垣。", "又安得，借蒙庄大瓢，酌泗水之源。"]'),
('song-ci-837','西河','王奕','宋','宋词','song-ci','西河','[]','江左地。',127,'宋词/ci.song.17000.json','["江左地。", "兴亡旧恨谁记。", "腥风不搅洛山云，怒涛怎起。", "泪眶历落泫新亭，碑趺犹卧江际。", "古今事，天莫倚。", "废兴元有时系。", "女墙月色自荒荒，尽平寸垒。", "舞台歌谢草痕深，青溪弥望烟水。", "马蹄杂遝锦绣市。", "认乌衣六朝，东巷西里。", "景物已非人世。", "但长干铁塔，岿然相对。", "檐铃嘈囋薰风里。"]'),
('song-ci-838','满江红','蒲寿宬','宋','宋词','song-ci','满江红','[]','楼倚虚空。',115,'宋词/ci.song.17000.json','["楼倚虚空。", "觉人世、不知何处。", "人缥缈、半檐星斗，一窗风露。", "潮退沙平凫雁静，夜深月黑鱼龙怒。", "把清樽、独自笑馀生，成何事。", "尘埃外，谈高趣。", "烟波上，题诗句。", "这美景良宵，且休虚度。", "梦觉宦情甜似蜡，老来况味酸如醋。", "念儿曹、南北几时归，情朝暮。"]'),
('song-ci-839','贺新郎','蒲寿宬','宋','宋词','song-ci','贺新郎','[]','铁笛穿花去。',141,'宋词/ci.song.17000.json','["铁笛穿花去。", "问长安、市上生涯，而今何似。", "破帽青衫尘满面。", "不识何人共语。", "且面壁、听风雨。", "惟我虚中元识破，笑人间、日月无停杼。", "名与利，莫轻许。", "人生穷达皆天铸。", "试灯前、为问灵龟，劝君休怒。", "心肯命通元有数，何幸知音记取。", "季主也、应留得住。", "百岁光阴弹指过，算伯夷、盗跖俱尘土。", "心一寸，人千古。"]'),
('song-ci-840','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','["\u957f\u6c5f"]','万里长江一钓丝。',32,'宋词/ci.song.17000.json','["万里长江一钓丝。", "萧萧蓬鬓任风吹。", "微雨过，片帆敧。", "青山浓淡更多奇。"]'),
('song-ci-841','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','江渚春风澹荡时。',32,'宋词/ci.song.17000.json','["江渚春风澹荡时。", "斜阳芳草鹧鸪飞。", "莼菜滑，白鱼肥。", "浮家泛宅不曾归。"]'),
('song-ci-842','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','烟浦回环几百湾。',32,'宋词/ci.song.17000.json','["烟浦回环几百湾。", "无人知此橛头船。", "风露冷，月娟娟。", "云间一过看飞仙。"]'),
('song-ci-843','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','野缆闲移石笋江。',32,'宋词/ci.song.17000.json','["野缆闲移石笋江。", "旁人争看老眉庞。", "铺月席，展风窗。", "飞来何处白鸥双。"]'),
('song-ci-844','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','葭荻横披众木东。',32,'宋词/ci.song.17000.json','["葭荻横披众木东。", "浪花如雪晚来风。", "云母幌，水晶宫。", "莲花一叶白头翁。"]'),
('song-ci-845','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','飘忽狂风一霎间。',32,'宋词/ci.song.17000.json','["飘忽狂风一霎间。", "长鱼吹浪势如山。", "牢系缆，蓼花湾。", "白鸥沙上伴人闲。"]'),
('song-ci-846','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','清晓朦胧古渡头。',32,'宋词/ci.song.17000.json','["清晓朦胧古渡头。", "烟中人语橹声柔。", "云五色，蜃成楼。", "鸡鸣日出似罗浮。"]'),
('song-ci-847','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','搔首推篷晓色新。',32,'宋词/ci.song.17000.json','["搔首推篷晓色新。", "雪花飘瞥大江滨。", "渔父醉，不收缗。", "白髭红颊玉为人。"]'),
('song-ci-848','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','明月愁人夜未央。',32,'宋词/ci.song.17000.json','["明月愁人夜未央。", "篷窗如画水浪浪。", "何处笛，起凄凉。", "梅花喷作一天霜。"]'),
('song-ci-849','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','白首渔郎不解愁。',32,'宋词/ci.song.17000.json','["白首渔郎不解愁。", "长歌箕踞亦风流。", "江上事，寄蜉蝣。", "灵均那更恨悠悠。"]'),
('song-ci-850','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','琉璃为地水精天。',32,'宋词/ci.song.17000.json','["琉璃为地水精天。", "一叶渔舟浪满颠。", "风肃肃，露娟娟。", "家在芦花何处边。"]'),
('song-ci-851','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','江上浪花飞洒天。',32,'宋词/ci.song.17000.json','["江上浪花飞洒天。", "拍阶鞺鞳屋如船。", "月不夜，水无边。", "何处笛声人未眠。"]'),
('song-ci-852','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','远入茫茫无尽边。',32,'宋词/ci.song.17000.json','["远入茫茫无尽边。", "渔舟来往似行天。", "敧枕看，不成眠。", "谁识人间太乙仙。"]'),
('song-ci-853','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','白水塘边白鹭飞。',32,'宋词/ci.song.17000.json','["白水塘边白鹭飞。", "龙湫山下鲫鱼肥。", "敧雨笠，著云衣。", "玄真不见又空归。"]'),
('song-ci-854','渔父词・渔父','蒲寿宬','宋','宋词','song-ci','渔父词・渔父','[]','岩下无心云自飞。',32,'宋词/ci.song.17000.json','["岩下无心云自飞。", "塘边足雨水初肥。", "龟曳尾，绿毛衣。", "荷盘无数尔安归。"]'),
('song-ci-855','乃词','蒲寿宬','宋','宋词','song-ci','乃词','[]','白头翁。',32,'宋词/ci.song.17000.json','["白头翁。", "白头翁。", "江海为田鱼作粮。", "相逢只可唤刘四，不受人呼刘四郎。"]'),
('song-ci-856','喜迁莺','吴龙翰','宋','宋词','song-ci','喜迁莺','[]','微雨后，落花天。',57,'宋词/ci.song.17000.json','["微雨后，落花天。", "娇态病恹恹。", "怕人猜著是相思，成日不开帘。", "宝钗横，蝉鬓乱。", "院宇待人归尽。", "缓移莲步玉阑前。", "纤手掐花钿。"]'),
('song-ci-857','摸鱼儿','朱嗣发','宋','宋词','song-ci','摸鱼儿','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','对西风、鬓摇烟碧，参差前事流水。',140,'宋词/ci.song.17000.json','["对西风、鬓摇烟碧，参差前事流水。", "紫丝罗带鸳鸯结，的的镜盟钗誓。", "浑不记、漫手织回文，几度欲心碎。", "安花著蒂。", "奈雨覆云翻，情宽分窄，石上玉簪脆。", "朱楼外。", "愁压空云欲坠。", "月痕犹照无寐。", "阴晴也只随天意。", "枉了玉消香碎。", "君且醉。", "君不见、长门青草春风泪。", "一时左计。", "悔不早荆钗，暮天修竹，头白倚寒翠。"]'),
('song-ci-858','更漏子','陈达叟','宋','宋词','song-ci','更漏子','[]','妾倚门，君上马。',58,'宋词/ci.song.17000.json','["妾倚门，君上马。", "残月晓星犹挂。", "眉黛敛，泪珠凝。", "别离多少情。", "翠翘横，云鬓乱。", "复入绮衾犹暖。", "人独自，枕成双。", "争教不断肠。"]'),
('song-ci-859','菩萨蛮','陈达叟','宋','宋词','song-ci','菩萨蛮','[]','举头忽见衡阳雁。',52,'宋词/ci.song.17000.json','["举头忽见衡阳雁。", "千声万字情何限。", "叵耐薄情夫。", "一行书也无。", "泣归香阁恨。", "和泪掩红粉。", "待雁却回时。", "也无书寄伊。"]'),
('song-ci-860','齐天乐','文天祥','宋','宋词','song-ci','齐天乐','[]','南楼月转银河曙，玉箫又吹梅早。',123,'宋词/ci.song.17000.json','["南楼月转银河曙，玉箫又吹梅早。", "鹦鹉沙晴，葡萄水暖，一缕燕香清袅。", "瑶池春透。", "想桃露霏霞，菊波沁晓。", "袍锦风流，御仙花带瑞虹绕。", "玉关人正未老。", "唤矶头黄鹤，岸巾谈笑。", "剑拂淮清，槊横楚黛，雨洗一川烟草。", "印黄似斗。", "看半砚蔷薇，满鞍杨柳。", "沙路归来，金貂蝉翼小。"]'),
('song-ci-861','齐天乐','文天祥','宋','宋词','song-ci','齐天乐','[]','夜来早得东风信，潇湘一川新绿，柳色含晴，梅心沁暖，春浅千花如束。',123,'宋词/ci.song.17000.json','["夜来早得东风信，潇湘一川新绿，柳色含晴，梅心沁暖，春浅千花如束。", "银蝉乍浴。", "正沙雁将还，海鳌初矗。", "云拥旌旗，笑声人在画阑曲。", "星虹瑶树缥缈，佩环鸣碧落，瑞笼华屋。", "露耿铜虬，冰翻铁马，帘幕光摇金粟。", "迟迟倚竹。", "更为把瑶尊，满斟醽醁。", "回首宫莲，夜深归院烛。"]'),
('song-ci-862','酹江月・念奴娇','文天祥','宋','宋词','song-ci','酹江月・念奴娇','["\u5e90\u5c71"]','庐山依旧，凄凉处、无限江南风物。',120,'宋词/ci.song.17000.json','["庐山依旧，凄凉处、无限江南风物。", "空翠晴岚浮汗漫，还障天东半壁。", "雁过孤峰，猿归危嶂，风急波翻雪。", "乾坤未老，地灵尚有人杰。", "堪嗟漂泊孤舟，河倾斗落，客梦催明发。", "南浦闲云连草树，回首旌旗明灭。", "三十年来，十年一过，空有星星发。", "夜深愁听，胡笳吹彻寒月。"]'),
('song-ci-863','酹江月・念奴娇','文天祥','宋','宋词','song-ci','酹江月・念奴娇','[]','水天空阔，恨东风不借、世间英物。',120,'宋词/ci.song.17000.json','["水天空阔，恨东风不借、世间英物。", "蜀鸟吴花残照里，忍见荒城颓壁。", "铜雀春情，金人秋泪，此恨凭谁雪。", "堂堂剑气，斗牛空认奇杰。", "那信江海馀生，南行万里，属扁舟齐发。", "正为鸥盟留醉眼，细看涛声云灭。", "睨柱吞嬴，回旗走懿，千古冲冠发。", "伴人无寐。", "秦淮应是孤月。"]'),
('song-ci-864','酹江月・念奴娇','文天祥','宋','宋词','song-ci','酹江月・念奴娇','[]','乾坤能大，算蛟龙、元不是池中物。',120,'宋词/ci.song.17000.json','["乾坤能大，算蛟龙、元不是池中物。", "风雨牢愁无著处，那更寒虫四壁。", "横槊题诗，登楼作赋，万事空中雪。", "江流如此，方来还有英杰。", "堪笑一叶漂零，重来淮水，正凉风新发。", "镜里朱颜都变尽，只有丹心难灭。", "去去龙沙，江山回首，一线青如发。", "故人应念，杜鹃枝上残月。"]'),
('song-ci-865','满江红','文天祥','宋','宋词','song-ci','满江红','[]','燕子楼中，又捱过、几番秋色。',115,'宋词/ci.song.17000.json','["燕子楼中，又捱过、几番秋色。", "相思处、青年如梦，乘鸾仙阙。", "肌玉暗消衣带缓，泪珠斜透花钿侧。", "最无端、蕉影上窗纱，青灯歇。", "曲池合，高台灭。", "人间事，何堪说。", "向南阳阡上，满襟清血。", "世态便如翻覆雨，妾身元是分明月。", "笑乐昌、一段好风流，菱花缺。"]'),
('song-ci-866','满江红','文天祥','宋','宋词','song-ci','满江红','[]','试问琵琶，胡沙外、怎生风色。',115,'宋词/ci.song.17000.json','["试问琵琶，胡沙外、怎生风色。", "最苦是、姚黄一朵，移根仙阙。", "王母欢阑琼宴罢，仙人泪满金盘侧。", "听行宫、半夜雨淋铃，声声歇。", "彩云散，香尘灭。", "铜驼恨，那堪说。", "想男儿慷慨，嚼穿龈血。", "回首昭阳离落日，伤心铜雀迎秋月。", "算妾身、不愿似天家，金瓯缺。"]'),
('song-ci-867','沁园春','文天祥','宋','宋词','song-ci','沁园春','[]','为子死孝，为臣死忠，死又何妨。',139,'宋词/ci.song.17000.json','["为子死孝，为臣死忠，死又何妨。", "自光岳气分，士无全节，君臣义缺，谁负刚肠。", "骂贼睢阳，爱君许远，留得声名万古香。", "后来者，无二公之操，百炼之钢。", "人生翕欻云亡。", "好烈烈轰轰做一场。", "使当时卖国，甘心降虏，受人唾骂，安得留芳。", "古庙幽沈，仪容俨雅，枯木寒鸦几夕阳。", "邮亭下，有奸雄过此，仔细思量。"]'),
('song-ci-868','念奴娇','邓剡','宋','宋词','song-ci','念奴娇','[]','水天空阔，恨东风不惜、世间英物。',120,'宋词/ci.song.17000.json','["水天空阔，恨东风不惜、世间英物。", "蜀鸟吴花残照里，忍见荒城颓壁。", "铜雀春情，金人秋泪，此恨凭谁雪。", "堂堂剑气，斗牛空认奇杰。", "那信江海馀生，南行万里，不放扁舟发。", "正为鸥盟留醉眼，细看涛声云灭。", "睨柱吞嬴，回旗走懿，千古冲冠发。", "伴人无寐，秦淮应是孤月。"]'),
('song-ci-869','满江红','邓剡','宋','宋词','song-ci','满江红','[]','王母仙桃，亲曾醉、九重春色。',115,'宋词/ci.song.17000.json','["王母仙桃，亲曾醉、九重春色。", "谁信道、鹿衔花去，浪翻鳌阙。", "眉锁娇娥山宛转，髻梳堕马云敧侧。", "恨风沙、吹透汉宫衣，馀香歇。", "霓裳散，庭花灭。", "昭阳燕，应难说。", "想春深铜雀，梦残啼血。", "空有琵琶传出塞，更无环佩鸣归月。", "又争知、有客夜悲歌，壶敲缺。"]'),
('song-ci-870','浪淘沙','邓剡','宋','宋词','song-ci','浪淘沙','[]','疏雨洗天晴。',63,'宋词/ci.song.17000.json','["疏雨洗天晴。", "枕簟凉生。", "井梧一叶做秋声。", "谁念客身轻似叶，千里飘零。", "梦断古台城。", "月淡潮平。", "便携酒访新亭。", "不见当时王谢宅，烟草青青。"]'),
('song-ci-871','唐多令','邓剡','宋','宋词','song-ci','唐多令','[]','雨过水明霞。',74,'宋词/ci.song.17000.json','["雨过水明霞。", "潮回岸带沙。", "叶声寒、飞透窗纱。", "堪恨西风吹世换，更吹我、落天涯。", "寂寞古豪华。", "乌衣日又斜。", "说兴亡、燕入谁家。", "惟有南来无数雁，和明月、宿芦花。"]'),
('song-ci-872','烛影摇红','邓剡','宋','宋词','song-ci','烛影摇红','[]','郢雪歌高，天教鹤子参鸣和。',116,'宋词/ci.song.17000.json','["郢雪歌高，天教鹤子参鸣和。", "薰风旌节瑞华□，光动垂弧左。", "早是烟楼撞破。", "更明珠、重添一颗。", "镜容中夜，摩顶欣然，石麟天堕。", "未羡眉山，两峰儿子中峰我。", "推贤世世珥金貂，何况阴功大。", "欲写弄獐书贺。", "愧无功、难消玉果。", "摩挲老眼，曾识英雄，试啼则个。"]'),
('song-ci-873','霜天晓角','邓剡','宋','宋词','song-ci','霜天晓角','[]','蛮烟塞雪。',53,'宋词/ci.song.17000.json','["蛮烟塞雪。", "天老梅花骨。", "还著锦衣游戏，清江上、管风月。", "木兰归海北。", "竹梧侵户碧。", "三十六峰苍玉，驾白鹿、友仙客。"]'),
('song-ci-874','木兰花慢','邓剡','宋','宋词','song-ci','木兰花慢','[]','步凉飔绿野，□锺鼓、□园林。',122,'宋词/ci.song.17000.json','["步凉飔绿野，□锺鼓、□园林。", "有骑竹更生，扶藜未老，歌舞堂阴。", "金鞭半横玉带，烨神人、风度五云深。", "大耐自应鹤骨，活人总是天心。", "寿蒲香晚尚堪斟。", "梧竹对潇森。", "早问道燕城，衣裁绣衮，台筑黄金。", "天瓢正消几滴，化中原、焦土作甘霖。", "却伴赤松未晚，碧桃花下横琴。"]'),
('song-ci-875','摸鱼儿','邓剡','宋','宋词','song-ci','摸鱼儿','[]','问庐陵、米作何价。',140,'宋词/ci.song.17000.json','["问庐陵、米作何价。", "棠阴又绿今夏。", "活人手段依然在，独乐园中司马。", "初度也。", "算几处篝香，手额你多谢。", "风亭月榭。", "尽隐橘观棋，折荷筒酒，花竹秀而野。", "阶庭树，满目鱼鱼雅雅。", "千金难买清暇。", "纷纷征榷尘如梦，谁有似公闲者。", "天怎舍。", "趁绿鬓朱颜，须入凌烟画。", "海天不夜。", "管岁岁安期，采蒲为寿，高宴碧桃下。"]'),
('song-ci-876','促拍丑奴儿','邓剡','宋','宋词','song-ci','促拍丑奴儿','[]','睡起怯春寒。',76,'宋词/ci.song.17000.json','["睡起怯春寒。", "海棠花、开未开间。", "莫言春色三分二，朱颜绿鬓，栽花种竹，谁似君闲。", "侯印旧家毡。", "早天边、飞诏催还。", "从今岁岁称觞处，人如玉雪，花如锦绣，福寿如山。"]'),
('song-ci-877','八声甘州','邓剡','宋','宋词','song-ci','八声甘州','[]','笑钗符、恰正带宜男。',119,'宋词/ci.song.17000.json','["笑钗符、恰正带宜男。", "还将寿花簪。", "早风薰竹醉，松凉鹤健，午坐存庵。", "三十六峰玉立，隔尘听玄谈。", "何似人难老，三十才三。", "闻得天边好语，第一流人物，偏重江南。", "满玻璃春绿，十载爱棠甘。", "青青鬓、尽堪图画，趁紫岩、年纪作枢参。", "却归宴、瑶池未晚，荷日红酣。"]'),
('song-ci-878','好事近','邓剡','宋','宋词','song-ci','好事近','[]','桃脸破初寒，笑问刘郎前度。',53,'宋词/ci.song.17000.json','["桃脸破初寒，笑问刘郎前度。", "为说正元朝上，缥缈午桥午。", "百年方半日来多，且醉且吟去。", "须信剑南万首，胜侯封千户。"]'),
('song-ci-879','摸鱼儿','邓剡','宋','宋词','song-ci','摸鱼儿','[]','笑平生、布帆无恙，堂堂稳送君去。',140,'宋词/ci.song.17000.json','["笑平生、布帆无恙，堂堂稳送君去。", "江声悲壮崖殷血，曾是英雄行处。", "今亦古。", "甚一点东风，天不周郎与。", "城幡夜竖。", "几铜爵春残，战沙秋冷，华发遽如许。", "东坡老，千载风流两赋。", "馀音不绝如缕。", "临皋一笑三生梦，还认岷峨乡语。", "挥玉麈。", "尽不碍灯前，痛饮檐花雨。", "雪堂在否。", "管驾鹤归来，为君细赏，蝴蝶上阶句。"]'),
('song-ci-880','疏影','邓剡','宋','宋词','song-ci','疏影','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','瑶尊蘸翠。',134,'宋词/ci.song.17000.json','["瑶尊蘸翠。", "短长亭送别，风恋晴袂。", "腊树迎春，一路清寒，能消几日羁思。", "霜华不惜阳关柳，悄莫系、行人嘶骑。", "对梅花、一笑分携，胜约别来相寄。", "人物仙蓬妙韵，瑞鸾敛迅翼，聊憩香枳。", "见说使君，好语先传，付与芙蓉清致。", "客来欲问荆州事，但细语、岳阳楼记。", "梦故人、剪烛西窗，已隔洞庭烟水。"]'),
('song-ci-881','贺新郎','刘鉴','宋','宋词','song-ci','贺新郎','[]','曾作莺迁贺。',142,'宋词/ci.song.17000.json','["曾作莺迁贺。", "道玉皇、久敕薇垣，分君星颗。", "只待好年好时日，约束东风吹堕。", "到今日、看来真个。", "恰好丁年翁七十，五云间、太乙吹藜火。", "青一点，杉溪左。", "太翁阴隲天来大。", "后隆山、层一层高，层层突过。", "簪绂蝉联孙又子，眼里人家谁那。", "算只有、臞翁恁麽。", "孙陆机云翁卫武，便履声、毡复尚书坐。", "拚几许，犀钱果。"]'),
('song-ci-882','满江红','刘鉴','宋','宋词','song-ci','满江红','[]','袅袅春幡，恰十日、又逢元夕。',115,'宋词/ci.song.17000.json','["袅袅春幡，恰十日、又逢元夕。", "人正在、景清堂上，金樽娱客。", "蜡炬红摇花外竹，宝香情透梅边石。", "听儿童、父老说青原，东风国。", "平易政，人皆悦。", "真实念，天知得。", "想旌旗一路，又添春色。", "满眼变成金色界，举头身近琼楼月。", "问明年、何处著鳌山，蓬莱北。"]'),
('song-ci-883','满江红','翁','宋','宋词','song-ci','满江红','[]','祷雨文昌，只全靠、心香一瓣。',115,'宋词/ci.song.17000.json','["祷雨文昌，只全靠、心香一瓣。", "才信宿，沛然膏泽，来从方寸。", "早稻含风香旖旎，晚秧饱水青葱茜。", "问螺江、恰见线来流，今平岸。", "君作事，看天面。", "天有眼，从君愿。", "信瑞莲芝草，几曾虚献。", "此雨千金无买处，丰年饱吃君侯饭。", "管酿成、春酒上公堂，人人献。"]'),
('song-ci-884','糖多令・唐多令','王洧','宋','宋词','song-ci','糖多令・唐多令','[]','雁荡接台山。',74,'宋词/ci.song.17000.json','["雁荡接台山。", "秋来最好看。", "寿星明、高现云端。", "八月初弦三日里，□二老、福人间。", "玉节近天颜。", "东西两路安。", "祝苍松、节劲根蟠。", "相汉元勋萧第一，留次位、著曹参。"]'),
('song-ci-885','南乡子','汪梦斗','宋','宋词','song-ci','南乡子','[]','西北有神州。',66,'宋词/ci.song.17000.json','["西北有神州。", "曾倚斜阳江上楼。", "目断淮南山一抹，何由。", "载泪东风洒汴流。", "何事却狂游。", "直驾驴车度白沟。", "自古幽燕为绝塞，休愁。", "未是穷荒天尽头。"]'),
('song-ci-886','朝中措','汪梦斗','宋','宋词','song-ci','朝中措','[]','人言楼观似寥阳。',57,'宋词/ci.song.17000.json','["人言楼观似寥阳。", "巍倚太清傍。", "便有二京赋手，也须费力铺张。", "客窗梦断，星稀月澹，一枕凄凉。", "旧日春风汴水，□□多少垂杨。"]'),
('song-ci-887','人月圆','汪梦斗','宋','宋词','song-ci','人月圆','[]','寻常一样窗前月，人只看中秋。',59,'宋词/ci.song.17000.json','["寻常一样窗前月，人只看中秋。", "年年今夜，争寻诗酒，共上高楼。", "一奁明镜，能圆几度，白了人头。", "良辰美景，赏心乐事，输少年游。"]'),
('song-ci-888','金缕曲・贺新郎','汪梦斗','宋','宋词','song-ci','金缕曲・贺新郎','[]','满目飞明镜。',142,'宋词/ci.song.17000.json','["满目飞明镜。", "忆年时、呼朋楼上，畅怀觞咏。", "圆到今宵依前好，诗酒不成佳兴。", "身恰在、燕台天近。", "一段凄凉心中事，被秋光、照破无馀蕴。", "却不是，诉贫病。", "宫庭花草埋幽径。", "想夜深，女墙还有，过来蟾影。", "千古词人伤情处，旧说石城形胜。", "又今说、断桥风韵。", "客里蝉娟都相似，只后朝、不见潮来信。", "且喜得，四边静。"]'),
('song-ci-889','摸鱼儿','汪梦斗','宋','宋词','song-ci','摸鱼儿','["\u897f\u6e56"]','忆旧时、东方□郡，东原尽是佳处。',140,'宋词/ci.song.17000.json','["忆旧时、东方□郡，东原尽是佳处。", "梁都破了寻南渡，几遍狐号鳝舞。", "君试觑。", "环一抹荒城，草色今如许。", "芳华旧地。", "曾一上飞云，歌台酒馆，落日乱鸦度。", "吟情苦。", "滴尽应雄老泪。", "凄酸非是儿女。", "西湖似我西湖否。", "只怕不如西子。", "秋欲暮。", "要一看秋波，又自催归计。", "休□浪语。", "待过江说与，高车驷马，今是朝天路。"]'),
('song-ci-890','踏莎行','汪梦斗','宋','宋词','song-ci','踏莎行','[]','选得官归，黄埃满面。',68,'宋词/ci.song.17000.json','["选得官归，黄埃满面。", "难於奏赋明光殿。", "秋帆落日渡淮来，三杯酒浊凭谁劝。", "旧日佳词，自吟一遍。", "绿袍不是嫦娥翦。", "红楼十里古扬州，无人为把珠帘卷。"]'),
('song-ci-891','汉宫春','彭元逊','宋','宋词','song-ci','汉宫春','[]','十日春风，又一番调弄，怕暖愁阴。',115,'宋词/ci.song.17000.json','["十日春风，又一番调弄，怕暖愁阴。", "夜来风雨，摇得杨柳黄深。", "熏篝未断，梦旧寒、浅醉同衾。", "便是闻灯见月，看花对酒惊心。", "携手满身花影，香物霏霏，露湿罗襟。", "笙歌行人归去，回首沈沈。", "人间此夜，误春光、一刻千金。", "明日问、红巾青鸟，苍苔自拾遗簪。"]'),
('song-ci-892','满江红','彭元逊','宋','宋词','song-ci','满江红','[]','翠袖馀寒，早添得、铢衣几重。',115,'宋词/ci.song.17000.json','["翠袖馀寒，早添得、铢衣几重。", "何须怪、妍华都谢，更为谁容。", "衔尽吴花成鹿苑，人间不恨雨和风。", "便一枝、流落到人家，清泪红。", "山雾湿，倚熏笼。", "垂ぢ叶，鬓酥融。", "恨宫云一朵，飞过空同。", "白日长闲青鸟在，杨家花落白苹中。", "问故人、忍更负东风，尊酒空。"]'),
('song-ci-893','解佩环・疏影','彭元逊','宋','宋词','song-ci','解佩环・疏影','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','江空不渡，恨蘼芜杜若，零落无数。',132,'宋词/ci.song.17000.json','["江空不渡，恨蘼芜杜若，零落无数。", "远道荒寒，婉娩流年，望望美人迟暮。", "风烟雨雪阴晴晚，更何须，春风千树。", "尽孤城、落木萧萧，日夜江声流去。", "日晏山深闻笛，恐他年流落，与子同赋。", "事阔心违，交淡媒劳，蔓草沾衣多露。", "汀洲窈窕馀醒寐，遗珮浮沈沣浦。", "有白鸥淡月，微波寄语，逍遥容与。"]'),
('song-ci-894','徵招','彭元逊','宋','宋词','song-ci','徵招','[]','人间无欠秋风处，偏到霜痕月杪。',113,'宋词/ci.song.17000.json','["人间无欠秋风处，偏到霜痕月杪。", "风雨船篷，日夜风波未了。", "忽潮生海立，又天阔、江清欲晓。", "孤迥幽深，激扬悲壮，浮沈浩渺。", "行路古来难，貂裘敞、匹马关山人老。", "锦字未成，寒到君边书到否。", "倚门回首，儿女灯前娭笑。", "早斟酌、万里封侯，镜迟霜照。"]'),
('song-ci-895','子夜歌','彭元逊','宋','宋词','song-ci','子夜歌','[]','视春衫、箧中半在，浥浥酒痕花露。',144,'宋词/ci.song.17000.json','["视春衫、箧中半在，浥浥酒痕花露。", "恨桃李、如风过尽，梦里故人成雾。", "临颍美人，秦川公子，晚共何人语。", "对人家、花草池台，回首故园咫尺，未成归去。", "昨宵听、危弦急管，酒醒不知何处。", "飘泊情多，衰迟感易，无限堪怜许。", "似尊前眼底，红颜消几寒暑。", "年少风流，未谙春事，追与东风赋。", "待他年、君老巴山，共君听雨。"]'),
('song-ci-896','临江仙','彭元逊','宋','宋词','song-ci','临江仙','[]','红袖乌丝失酒，金钗银烛销春。',68,'宋词/ci.song.17000.json','["红袖乌丝失酒，金钗银烛销春。", "柳边桃下复清晨。", "帽风回马旋，扇雨拂花情。", "白帝空惊旧曲，阳关只梦行人。", "碧云何处认芳尘。", "紫荆花作荚，青杏核生仁。"]'),
('song-ci-897','临江仙','彭元逊','宋','宋词','song-ci','临江仙','[]','自结床头麈尾，角巾坐枕孤松。',68,'宋词/ci.song.17000.json','["自结床头麈尾，角巾坐枕孤松。", "片云承日过山东。", "起听荷叶雨，行受芷花风。", "无客同羹莼菜，有人为剥莲蓬。", "东墙年少未从容。", "何因知我意，吹笛月明中。"]'),
('song-ci-898','瑞鹧鸪','彭元逊','宋','宋词','song-ci','瑞鹧鸪','[]','背人西去一莺啼。',64,'宋词/ci.song.17000.json','["背人西去一莺啼。", "拍手还惊百舌飞。", "浅雨微寒春有思，宿妆残酒欲忺时。", "鵁鶄浪起蒲茸暖，翡翠风来柳絮低。", "故遣苍头寻杏子，凭肩小语只心知。"]'),
('song-ci-899','瑞鹧鸪','彭元逊','宋','宋词','song-ci','瑞鹧鸪','[]','东洲游伴寄兰苕。',64,'宋词/ci.song.17000.json','["东洲游伴寄兰苕。", "人日晴时不用招。", "微雨来看杨柳色，故人相遇浴龙桥。", "愁如春水年年长，老共东风日日消。", "几欲作笺无可寄，双鱼犹自等归潮。"]'),
('song-ci-900','蝶恋花','彭元逊','宋','宋词','song-ci','蝶恋花','[]','微雨烧香馀润气，新绿愔愔，乳燕相依睡。',70,'宋词/ci.song.17000.json','["微雨烧香馀润气，新绿愔愔，乳燕相依睡。", "无复卷帘知客意，杨柳更欲因风起。", "旧梦苍茫云海际。", "强作欢娱，不觉当年似。", "曾笑浮花并浪蕊。", "如今更惜棠梨子。"]'),
('song-ci-901','蝶恋花','彭元逊','宋','宋词','song-ci','蝶恋花','[]','日晚游人酥粉涴。',70,'宋词/ci.song.17000.json','["日晚游人酥粉涴。", "四雨亭前，面面看花坐。", "扇拂游蜂青杏堕。", "新红一路秋千过。", "帘外清歌帘底和。", "自理琵琶，不用笙簧佐。", "八摺香罗馀碧唾。", "路花点笔轻题破。"]'),
('song-ci-902','如梦令','彭元逊','宋','宋词','song-ci','如梦令','[]','今夜故人独宿。',40,'宋词/ci.song.17000.json','["今夜故人独宿。", "小雨梨花当屋。", "犹有未残枝，轻脆不堪人触。", "休触。", "休触。", "憔悴怕惊郎目。"]'),
('song-ci-903','菩萨蛮','彭元逊','宋','宋词','song-ci','菩萨蛮','[]','玉蛇踯躅流光卷。',52,'宋词/ci.song.17000.json','["玉蛇踯躅流光卷。", "连珠合沓帘波远。", "花动见鱼行。", "红裳眩欲倾。", "人来惊翡翠。", "小鸭惊还睡。", "两岸绿阴生。", "修廊时听莺。"]'),
('song-ci-904','谒金门','彭元逊','宋','宋词','song-ci','谒金门','[]','春一点。',53,'宋词/ci.song.17000.json','["春一点。", "透得酥温玉软。", "唇晕睡花连袖染。", "嫣红惊绝艳。", "日暮飞红扑脸。", "翠被夜寒波飐。", "梦断锦茵成堕靥。", "宫廊微月转。"]'),
('song-ci-905','月下笛','彭元逊','宋','宋词','song-ci','月下笛','[]','江上行人，竹间茅屋，下临深窈。',119,'宋词/ci.song.17000.json','["江上行人，竹间茅屋，下临深窈。", "春风袅袅，翠鬟窥树犹小。", "遥迎近倚，归还愿、分付横枝未了。", "扁舟却去，中流回首，惊散飞鸟。", "重踏新亭屐齿，耿山抱孤城，月来华表。", "鸡听人语，隔江相伴歌笑。", "壮游历历，同高李、未拟诗成草草。", "长桥外，有醒人吹笛，并在霜晓。"]'),
('song-ci-906','六丑','彭元逊','宋','宋词','song-ci','六丑','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','似东风老大，那复有、当时风气。',170,'宋词/ci.song.17000.json','["似东风老大，那复有、当时风气。", "有情不收，江山身是寄。", "浩荡何世。", "但忆临官道，暂来不住，便出门千里。", "痴心指望回风坠。", "扇底相逢，钗头微缀。", "他家万条千缕，解遮亭障驿，不隔江水。", "瓜洲曾舣，等行人岁岁。", "日下长秋，城乌夜起。", "帐庐好在春睡。", "共飞归湖上，草青无地。", "愔愔雨、春心如腻。", "欲待化、丰乐楼前，青门都废。", "何人念、流落无几。", "点点抟作，雪绵松润，为君裛泪。"]'),
('song-ci-907','隔浦莲近・隔浦莲近拍','彭元逊','宋','宋词','song-ci','隔浦莲近・隔浦莲近拍','[]','夜寒晴早人起。',88,'宋词/ci.song.17000.json','["夜寒晴早人起。", "见柳知新翠。", "撼树试花意。", "两蜂狂救堕蕊。", "见著羞懒避。", "春都在，时节到愁地。", "屏间字。", "香痕半掏，误期一一曾记。", "朱弦谩锁，不会近番慵脆。", "强踏秋千似醉里。", "扶下，眼花跕跕飞坠。"]'),
('song-ci-908','忆旧游','彭元逊','宋','宋词','song-ci','忆旧游','[]','记新楼试酒，上客回车，初识能歌。',122,'宋词/ci.song.17000.json','["记新楼试酒，上客回车，初识能歌。", "几许怜才意，觉援琴意动，授简情多。", "青鸾昼下缥缈，烟雾隔轻罗。", "还自有人猜，素巾承汗，微影双蛾。", "西陂千树雪，欲绝世乘风，下照沧波。", "怪倚春憔悴，扁舟月上，草草相过。", "少年翰墨相误，幽恨愧星河。", "谁为语伶玄，秋风并冷双燕窠。"]'),
('song-ci-909','生查子','彭元逊','宋','宋词','song-ci','生查子','[]','痴多故恼人，妆晚翻嫌趣。',48,'宋词/ci.song.17000.json','["痴多故恼人，妆晚翻嫌趣。", "只为眼波长，嗔笑娇难触。", "春心不肯深，春睡何曾足。", "莫待柳花飞，飞去无拘束。"]'),
('song-ci-910','玉女迎春慢・玉女迎春','彭元逊','宋','宋词','song-ci','玉女迎春慢・玉女迎春','[]','浅入新年，逢人日、拂拂淡烟无雨。',116,'宋词/ci.song.17000.json','["浅入新年，逢人日、拂拂淡烟无雨。", "叶底妖禽自语。", "小啄幽香还吐。", "东风辛苦，便怕有、踏青人误。", "清明寒食，消得渡江，黄翠千缕。", "看临小帖宜春，填轻晕湿，碧花生雾。", "为说钗头袅袅，系著轻盈不住。", "问郎留否。", "似昨夜、教成鹦鹉。", "走马章台，忆得画眉归去。"]'),
('song-ci-911','齐天乐','方衡','宋','宋词','song-ci','齐天乐','[]','皇天眷佑中兴烈。',123,'宋词/ci.song.17000.json','["皇天眷佑中兴烈。", "维岳共生鸿硕。", "镇抚精神，规恢调度，未数至言长策。", "中原徯望，总万里山河，尽归经画。", "更看旋乾转坤，烦一指麾力。", "胡尘顿消海岱，倚天长啸处，兼惠南北。", "宝镇还朝，圣恩如海，趁得崧高华席。", "星晨步峻，看丹凤飞来，趣登枢极。", "□寿齐天，愿齐开寿域。"]'),
('song-ci-912','声声慢','郭居安','宋','宋词','song-ci','声声慢','[]','捷书连昼，甘洒通宵，新来喜沁尧眉。',119,'宋词/ci.song.17000.json','["捷书连昼，甘洒通宵，新来喜沁尧眉。", "许大担当，人间佛力须弥。", "年年八月八日，长记他、三月三时。", "平生事，想祗和天语，不遣人知。", "一片闲心鹤外，被乾坤系定，虹玉腰围。", "阊阖云边，西风万籁吹齐。", "归舟更归何处，是天教、家在苏堤。", "千千岁，比周公、多个彩衣。"]'),
('song-ci-913','木兰花慢','郭居安','宋','宋词','song-ci','木兰花慢','[]','听都人共语，又还是、岁逢庚。',123,'宋词/ci.song.17000.json','["听都人共语，又还是、岁逢庚。", "记今帖频催，衮衣将至，绣幰先迎。", "笙歌六宫齐奏，到而今、犹唱贺升平。", "千岁人间福本，天公著意看承。", "秋深。", "帘卷空明。", "问西子，最宜晴。", "喜新来多暇，玉醪龙炙，菊院花城。", "明年耳孙头上，更君王、亲点泥金。", "兜率摩耶住世，长看佛度众生。"]'),
('song-ci-914','摸鱼儿','赵从橐','宋','宋词','song-ci','摸鱼儿','["\u897f\u6e56"]','指庭前、翠云金雨。',138,'宋词/ci.song.17000.json','["指庭前、翠云金雨。", "霏霏香满仙宇。", "一清透彻浑无底，秋水也无流处。", "君试数。", "此样襟怀，顿得乾坤住。", "闲情半许。", "听万物氤氲，从来形色，每向静中觑。", "琪花落，相接西池寿母。", "年年弦月时序。", "荷衣菊佩寻常事，分付两山容与。", "天证取。", "此老平生，可向青天语。", "瑶卮缓举。", "要见我何心，西湖万顷，来去自鸥鹭。"]'),
('song-ci-915','木兰花慢','廖莹中','宋','宋词','song-ci','木兰花慢','[]','请诸君著眼，来看我、福华编。',122,'宋词/ci.song.17000.json','["请诸君著眼，来看我、福华编。", "记江上秋风，鲸漦涨雪，雁徼迷烟。", "一时几多人物，只我公、只手护山川。", "争睹阶符瑞象，又扶红日中天。", "因怀下走奉櫜鞬。", "磨盾夜无眠。", "知重开宇宙，活人万万，合寿千千。", "凫鷖太平世也，要东还、赴上是何年。", "消得清时钟鼓，不妨平地神仙。"]'),
('song-ci-916','个侬','廖莹中','宋','宋词','song-ci','个侬','[]','恨个侬无赖，卖娇眼、春心偷掷。',190,'宋词/ci.song.17000.json','["恨个侬无赖，卖娇眼、春心偷掷。", "苍苔花落，先印下一双春迹。", "花不知名，香才闻气，似月下箜篌，蒋山倾国。", "半解罗襟，蕙薰微度，镇宿粉、栖香双蝶。", "语态眠情，感多情、轻怜细阅。", "休问望宋墙高，窥韩路隔。", "寻寻觅觅。", "又暮雨凝碧。", "花径横烟，红扉映月，尽一刻、千金堪值。", "卸袜熏笼，藏灯衣桁，任裹臂金斜，搔头玉滑。", "更恨檀郎，恶怜深惜。", "尽颤袅、周旋倾侧。", "软玉香钩，怪无端、凤珠微脱。", "多少怕晓听钟，琼钗暗擘。"]'),
('song-ci-917','万年欢','丁察院','宋','宋词','song-ci','万年欢','[]','葛井丹明，西来金母，霓旌云旆。',121,'宋词/ci.song.17000.json','["葛井丹明，西来金母，霓旌云旆。", "移下瑶池，竹外一壶秋水。", "菊□香留宿醉。", "看后夜、冰轮满桂。", "貂蝉映、虹玉称觞，遂初堂上佳会。", "娇孙彩衣聚戏。", "指明年八十，儿额先记。", "要比庄椿，八数更加千倍。", "好是皇恩锡类。", "许东殿、首舆扶至。", "君臣庆、齐侍慈颜，万年欢对尧世。"]'),
('song-ci-918','卜算子','黄右曹','宋','宋词','song-ci','卜算子','[]','清晓听麻姑，来约西王母。',52,'宋词/ci.song.17000.json','["清晓听麻姑，来约西王母。", "共取蟠桃簇玉盘，来劝摩耶酒。", "王母问摩耶，此意还知否。", "只为曾生我佛来，更与千千寿。"]'),
('song-ci-919','水龙吟','翁溪园','宋','宋词','song-ci','水龙吟','[]','镇淮楼下旌旗，晶明辉映云山阁。',126,'宋词/ci.song.17000.json','["镇淮楼下旌旗，晶明辉映云山阁。", "宸旒倚重，折冲千里，无逾秋壑。", "缓带清裘，纶巾羽扇，从容筹略。", "使毡裘胆破，丁宁边吏，无生事，空沙漠。", "二十四桥风月，称迷楼、卷尽帘箔。", "绂麟华旦，饱吟玉蕊，款簪金药。", "驿骑朝驰，宝鞍赍赐，御筵宣押。", "更赐环促召，中书入令，作汾阳郭。"]'),
('song-ci-920','水调歌头','翁溪园','宋','宋词','song-ci','水调歌头','[]','丹鹤结青士，玄鹿侍苍官。',114,'宋词/ci.song.17000.json','["丹鹤结青士，玄鹿侍苍官。", "寿仙堂下，应伴凫舄戏莱斑。", "麟记当年绣绂，燕剪今朝彩胜，淑气逐椒盘。", "孕毓阳和粹，独占一春先。", "平淮了，勋业盛，傲东山。", "中原犹待经略，趣诏凤池还。", "更数尧阶五荚，又上华封三祝，千载圣须贤。", "即拜玉枝赐，长冠紫宸班。"]'),
('song-ci-921','沁园春','翁溪园','宋','宋词','song-ci','沁园春','[]','记得花筵，巧夕星河，初度女牛。',139,'宋词/ci.song.17000.json','["记得花筵，巧夕星河，初度女牛。", "更四双蓂荚，十分桂魄，中元佳致，妆点初秋。", "蔼蔼非烟，濛濛如雾，锦水郁葱佳气浮。", "人人道，是王孙帝胄，今日生朝。", "银潢万叶源流。", "见一点长庚辉绛霄。", "似东平为善，河间献雅，风流酝藉，西汉诸刘。", "恰遇称觞，蓬壶歌缓，满酌蒲萄双玉舟。", "椿松等算，年年醉傲，花马金裘。"]'),
('song-ci-922','洞仙歌','翁溪园','宋','宋词','song-ci','洞仙歌','[]','几番梅雨，蒲风过、端阳后。',111,'宋词/ci.song.17000.json','["几番梅雨，蒲风过、端阳后。", "细数月轮，犹待双蓂秀。", "戏彩华堂宴，设帨朱门右。", "酌金荷，争献寿。", "蟠桃新熟，阿母齐长久。", "一门奋建，攀桂客、无双手。", "好事来春在，杏苑联蓝绶。", "应继琼林董，却胜燕山窦。", "夸盛事、真罕有。", "金花封诰，管取重重受。"]'),
('song-ci-923','踏莎行','翁溪园','宋','宋词','song-ci','踏莎行','[]','蓂荚飞双，桂分缺二。',68,'宋词/ci.song.17000.json','["蓂荚飞双，桂分缺二。", "金风已肃深秋意。", "萱庭戏彩恰称觞，蕊宫仙子天台裔。", "鹤发童颜，龟龄福备。", "孩儿书额添三字。", "常将机训付儿孙，取青行拥潘舆侍。"]'),
('song-ci-924','夜行船','倪君','宋','宋词','song-ci','夜行船','[]','年少疏狂今已老。',73,'宋词/ci.song.17000.json','["年少疏狂今已老。", "筵席散、杂剧打了。", "生向空来，死从空去，有何喜、有何烦恼。", "说与无常二鬼道。", "福亦不作，祸亦不造。", "地狱阎王，天堂玉帝，看你去、那里押到。"]'),
('song-ci-925','一翦梅','杨佥判','宋','宋词','song-ci','一翦梅','[]','襄樊四载弄干戈。',72,'宋词/ci.song.17000.json','["襄樊四载弄干戈。", "不见渔歌。", "不见樵歌。", "试问如今事若何。", "金也消磨。", "谷也消磨。", "拓枝不用舞婆娑。", "丑也能多。", "恶也能多。", "朱门日日买朱娥。", "军事如何。", "民事如何。"]'),
('song-ci-926','沁园春','萧某','宋','宋词','song-ci','沁园春','[]','士籍令行，伯仲分明，逐一排连。',137,'宋词/ci.song.17000.json','["士籍令行，伯仲分明，逐一排连。", "问子孙何习，父兄何业，明经词赋，右具如前。", "最是中间，娶妻某氏，试问于妻何与焉。", "乡保举，那当著押，开口论钱。", "祖宗立法于前。", "又何必更张万万千。", "算行关改会，限田放籴，生民凋瘵，膏血既朘。", "只有士心，仅存一脉，今又艰难最可怜。", "谁作俑，陈坚伯大，附势专权。"]'),
('song-ci-927','乌夜啼','赵文','宋','宋词','song-ci','乌夜啼','[]','院静槐阴似水，雨馀蝉语先秋。',56,'宋词/ci.song.17000.json','["院静槐阴似水，雨馀蝉语先秋。", "熟残梅子无人打，金弹满红沟。", "又送行人归去，谁怜倦客淹留。", "画船旗鼓江南岸，人倚夕阳楼。"]'),
('song-ci-928','阮郎归','赵文','宋','宋词','song-ci','阮郎归','[]','冰肌玉骨淡裳衣。',56,'宋词/ci.song.17000.json','["冰肌玉骨淡裳衣。", "素云生翠枝。", "一生不晓谪仙诗。", "雪香应自知。", "微雨后，禁烟时。", "洗妆君莫迟。", "东风不解惜妍姿。", "吹成蝴蝶飞。"]'),
('song-ci-929','阮郎归','赵文','宋','宋词','song-ci','阮郎归','[]','舞红一架欲生衣。',56,'宋词/ci.song.17000.json','["舞红一架欲生衣。", "残英辞旧枝。", "雨生自唱惜春词。", "行人应未知。", "新火后，薄罗时。", "君归何太迟。", "镜中失却少年姿。", "年随花共飞。"]'),
('song-ci-930','苏幕遮','赵文','宋','宋词','song-ci','苏幕遮','[]','绿秧平，烟树远，村落声喧，凫雁归来晚。',76,'宋词/ci.song.17000.json','["绿秧平，烟树远，村落声喧，凫雁归来晚。", "自倚阑干舒困眼。", "一架葡萄，青得池塘满。", "饮先愁，吟又懒。", "几许闲情，百计难消遣。", "客落不如归梦短。", "何况啼鹃，怎不教肠断。"]'),
('song-ci-931','侧犯','赵文','宋','宋词','song-ci','侧犯','[]','恨花开尽，夜深自敛胭脂颗。',94,'宋词/ci.song.17000.json','["恨花开尽，夜深自敛胭脂颗。", "雨过。", "绕曲曲花篷锦围裹。", "浮空烧蜜矩，香雾霏霏堕。", "无那。", "倚滴滴娇红笑相亸。", "歌俦饮伴，花底围春坐。", "念满眼、少年人，谁更老於我。", "岁岁花时，洞门无锁。", "莫负东君，酒盟诗课。"]'),
('song-ci-932','石州慢','赵文','宋','宋词','song-ci','石州慢','[]','京浙尘埃，闽峤风霜，不觉催老。',122,'宋词/ci.song.17000.json','["京浙尘埃，闽峤风霜，不觉催老。", "封侯事付儿曹，懒把菱花频照。", "明光赋笔，那知白首山中，年年管领闲花草。", "叩角夜漫漫，问何时能晓。", "堪笑。", "空有传世千篇，正似病呻饥啸。", "欲傲王侯，早被王侯相傲。", "盖棺事定，即今老子犹龙，荣枯得丧浑难料。", "无酒不须愁，问黄花知道。"]'),
('song-ci-933','望海潮','赵文','宋','宋词','song-ci','望海潮','[]','云外梅阴，雨馀苔晕，嫩寒初沁罗裳。',131,'宋词/ci.song.17000.json','["云外梅阴，雨馀苔晕，嫩寒初沁罗裳。", "书几凝尘，琴丝带润，小窗幽梦生凉。", "新水涨银塘。", "恨王孙去后，烟草茫茫。", "记得湖山胜处，相对拆封黄。", "情笺思墨犹香。", "奈当时两鬓，都是吴霜。", "兔颖吟苦，鸘裘解尽，何意此□游梁。", "旧话不堪长。", "便倩薰风吹去，本地看风光。", "惟有青山，伴我耕钓老村庄。"]'),
('song-ci-934','大','赵文','宋','宋词','song-ci','大','[]','正宝香残，重帘静，飞鸟时惊花铎。',164,'宋词/ci.song.17000.json','["正宝香残，重帘静，飞鸟时惊花铎。", "沈思前梦去，有当时老泪，欲弹还阁。", "太一宫墙，菩提寺路，谁管纷纷开落。", "心情浑何似，似琵琶马上，晓寒沙漠。", "想筝雁频移，钏金度瘦，素肌清削。", "相思无奈著。", "重访旧、谁遣车生角。", "暗记省、刘郎前度，杜枚三生，为何人、顿乖芳约。", "试把菱花拭，愁来处、鬓丝先觉。", "念幽独、成荒索。", "何日重见，错拟扬州骑鹤，绿阴不妨细酌。"]'),
('song-ci-935','莺啼序','赵文','宋','宋词','song-ci','莺啼序','[]','东风何许红紫，又匆匆吹去。',293,'宋词/ci.song.17000.json','["东风何许红紫，又匆匆吹去。", "最堪惜、九十春光，一半情绪听雨。", "到昨日、看花去处，如今尽是相思树。", "倚斜阳脉脉，多情燕子能语。", "自怪情怀，近日顿懒，忆刘郎前度。", "断桥外、小院重帘，那人正柳边住。", "问章台、青青在否。", "芳信隔、□魂无据。", "想行人，折尽柔条，滚愁成絮。", "闲将杯酒，苦劝羲和，揽辔更少驻。", "怎忍把、芳菲容易委路。", "春还倒转归来，为君起舞。", "寸肠万恨，何人共说，十年暗洒铜仙泪，是当时、滴滴金盘露。", "思量万事成空，只有初心，英英未化为土。", "浮生似客，春不怜人，人更怜春暮。", "君不见、青楼朱阁，舞女歌童，零落山丘，便房幽户。", "长门词赋，沈香乐府，悠悠谁是知音者，且绿阴多处修花谱。", "殷勤更倩啼莺，传语风光，后期莫误。"]'),
('song-ci-936','莺啼序','赵文','宋','宋词','song-ci','莺啼序','[]','秋风又吹华发，怪流光暗度。',292,'宋词/ci.song.17000.json','["秋风又吹华发，怪流光暗度。", "最可恨、木落山空，故国芳草何处。", "看前古、兴亡堕泪，谁知历历今如古。", "听吴儿唱彻，庭花又翻新谱。", "肠断江南，庾信最苦，有何人共赋。", "天又远，云海茫茫，鳞鸿似梦无据。", "怨东风、不如人意，珠履散、宝钗何许。", "想故人、月下沈吟，此时难诉。", "吾生已矣，如此江山，又何怀故宇。", "不恨赋归迟，归计大误。", "当时只合云龙，飘飘平楚。", "男儿死耳，嘤嘤昵昵，丁宁卖履分香事，又何如、化作胥潮去。", "东君岂是无能，成败归来，手种瓜圃。", "膏残夜久，月落山寒，相对耿无语。", "恨前此、燕丹计早，荆庆才疏，易水衣冠，总成尘土。", "斗鸡走狗，呼卢蹴鞠，平生把臂江湖旧，约何时、共话连床雨。", "王孙招不归来，自采黄花，醉扶山路。"]'),
('song-ci-937','绮寮怨','赵文','宋','宋词','song-ci','绮寮怨','[]','绛阙珠宫何处，碧梧双凤吟。',129,'宋词/ci.song.17000.json','["绛阙珠宫何处，碧梧双凤吟。", "为底事、一落人间，轻题破、隐韵天音。", "当时点云滴雨，匆匆处、误墨沾素襟。", "算人间、最苦多情，争知道、天上情更深。", "世事似晴又阴。", "罗褥甲帐，回头一梦难寻。", "虎啸ㄛ嶔，护遗迹、尚如今。", "斜阳落花流水，吹紫宇、澹成林。", "霜空月明，天风响、环佩飞翠禽。"]'),
('song-ci-938','疏影','赵文','宋','宋词','song-ci','疏影','[]','寒泉溅雪，有环佩隐隐，飞度霜月。',134,'宋词/ci.song.17000.json','["寒泉溅雪，有环佩隐隐，飞度霜月。", "易水风寒，壮士悲歌，关山万里离别。", "杨花浩荡晴空转，又化作、云鸿霜鹘。", "耿石壕，夜久无言寂历，如闻幽咽。", "云谷山人老矣，江空又岁晚，相对愁绝。", "玉立长身，自是胎仙，舞我黄庭三叠。", "人间只惯丁当字，妙处在、一声清拙。", "待明朝、试拂菱花，老我一簪华发。"]'),
('song-ci-939','瑞鹤仙','赵文','宋','宋词','song-ci','瑞鹤仙','["\u897f\u6e56"]','绿杨深似雨。',125,'宋词/ci.song.17000.json','["绿杨深似雨。", "西湖上、旧日情丝恨缕。", "风流似张绪。", "羡春风依旧，年年眉妩。", "宫腰楚楚。", "倚画阑、曾斗妙舞。", "想而今似我，零落天涯，却悔相妒。", "痛绝长秋去后，杨白花飞，旧腔难谱。", "年年暗度。", "凄凉事，不堪诉。", "记菩提寺路，段家桥水，何时重到梦处。", "况柔条老去，争奈系春不住。"]'),
('song-ci-940','法驾导引','赵文','宋','宋词','song-ci','法驾导引','[]','云漠漠，云漠漠，云拥紫皇家。',36,'宋词/ci.song.17000.json','["云漠漠，云漠漠，云拥紫皇家。", "岩上神仙无一事，幅巾临水看桃花。", "点点是丹砂。"]'),
('song-ci-941','法驾导引','赵文','宋','宋词','song-ci','法驾导引','[]','山中好，山中好，长日养婴儿。',36,'宋词/ci.song.17000.json','["山中好，山中好，长日养婴儿。", "午夜独行金阙路，晴窗自写绿章词。", "闲有鹤相随。"]'),
('song-ci-942','法驾导引','赵文','宋','宋词','song-ci','法驾导引','[]','公度我，公度我，我是汉铜仙。',36,'宋词/ci.song.17000.json','["公度我，公度我，我是汉铜仙。", "惜我玉龙为觳觫，为公锄雨种芝田。", "留眼看千年。"]'),
('song-ci-943','八声甘州','赵文','宋','宋词','song-ci','八声甘州','[]','是去年、春草又凄凄，尘生缕金衣。',119,'宋词/ci.song.17000.json','["是去年、春草又凄凄，尘生缕金衣。", "怅朱颜为土，白杨堪柱，燕子谁依。", "谩说漫漫六合，无地著相思。", "辽鹤归来后，城亦全非。", "更有延平一剑，向风雷半夜，何处寻伊。", "怪天天何物，堪作玉弹棋。", "到年年、无肠堪断，向清明、独自掩荆扉。", "何况又、禽声杜宇，花事酴醿。"]'),
('song-ci-944','塞翁吟','赵文','宋','宋词','song-ci','塞翁吟','["\u897f\u6e56"]','又海棠开后，楼上倍觉春寒。',115,'宋词/ci.song.17000.json','["又海棠开后，楼上倍觉春寒。", "绿叶润，雨初乾。", "爱远树团团。", "当时剩买名花种，那信付与谁看。", "十载事，土花漫。", "但青得阑干。", "悲欢。", "思人世、真如一梦，留不住、城头日残。", "看眼底、西湖过了，又还见、赵舞燕歌，抹粉涂丹。", "凭君更酌，后日重来，直是晴难。"]'),
('song-ci-945','凤凰台上忆吹箫','赵文','宋','宋词','song-ci','凤凰台上忆吹箫','[]','白玉磋成，香罗捻就，为谁特地团团。',118,'宋词/ci.song.17000.json','["白玉磋成，香罗捻就，为谁特地团团。", "羡司花神女，有此清闲。", "疑是弓靴蹴鞠，刚一踢、误挂花间。", "方信道，酴醿失色，玉蕊无言。", "凭阑。", "几回淡月，怪天上冰轮，移下尘寰。", "奈堪同玉手，难插云鬟。", "人道转官球也，春去也，欲转何官。", "聊寄与、诗人案头，冰雪相看。"]'),
('song-ci-946','玉烛新','赵文','宋','宋词','song-ci','玉烛新','[]','梅花新霁后。',124,'宋词/ci.song.17000.json','["梅花新霁后。", "正锦样华堂，一时装就。", "洞房花烛深深处，慢转铜壶银漏。", "新妆未了。", "奈浩荡、春心相侯。", "香篆里、簇簇笙歌，微寒半侵罗袖。", "侵晨浅捧兰汤，问堂上萱花，夜来安否。", "功名漫斗。", "漫赢得、万里相思清瘦。", "蓝袍俊秀。", "便胜却、登科龙首。", "春昼永、帘幕重重，箫声缓奏。"]'),
('song-ci-947','花犯','赵文','宋','宋词','song-ci','花犯','["\u9ec4\u6cb3"]','绣帘深，刘郎一笑，风流胜前度。',126,'宋词/ci.song.17000.json','["绣帘深，刘郎一笑，风流胜前度。", "戟香门户。", "还别有祥云，檐外飞舞。", "洞底烛下应低语。", "晨妆须带曙。", "待献了、堂前罗袜，双双交祝付。", "从前茜桃与杨枝，如今便、合逊梅花为主。", "行乐处。", "西溪上、柳汀花屿。", "封侯事、看人漫苦。", "谁能向、黄河风雪路。", "且对取、锦屏金幕，双蛾新样妩。"]'),
('song-ci-948','氐州第一','赵文','宋','宋词','song-ci','氐州第一','[]','风雨山城，天意欲雪，梅花照影清峭。',126,'宋词/ci.song.17000.json','["风雨山城，天意欲雪，梅花照影清峭。", "彩燕飞春，祥麟祓旦，当日文星高照。", "天地无情，向十载、风埃吹老。", "盖世科名，经邦事业，白衣苍狗。", "不是贪名求分表。", "漫猎较、逢场一笑。", "野外朝仪，城中马队，且暂淹才调。", "为斯文争一脉，斯文在、乾坤未了。", "烂醉金尊，夜何其，东方渐晓。"]'),
('song-ci-949','莺啼序','赵文','宋','宋词','song-ci','莺啼序','[]','初荷一番濯雨，锦云红尚卷。',293,'宋词/ci.song.17000.json','["初荷一番濯雨，锦云红尚卷。", "隘华屋、赋客吟仙，候望南极天远。", "还报道、飘然紫气，山奇水胜都行遍。", "却归来领客，水晶庭院开宴。", "窗户青红，正似京洛，按笙歌一片。", "似别有、金屋佳人，桃根桃叶清婉。", "倚薰风、虬须正绿，人似玉手挼纨扇。", "算风流，只有蓬瀛，画图曾见。", "谁知老子，正自萧然，於此兴颇浅。", "只拟问、金砂玉蕊，兔髓乌肝，偃月炉中，七还九转。", "今来古往，悠悠史传，神仙本是英雄做，笑英雄、到此多留恋。", "看看破晓耕龙，跨海骑鲸，千年依旧丹脸。", "便教乞与，万里封侯，奈朔风如箭。", "又何似、广山一任，种竹栽花，棋局思量，墨池挥染。", "天还记得，生贤初意，乾坤正要人撑拄，便公能安稳天宁肯。", "待看佐汉功成，伴赤松游，恁时未晚。"]'),
('song-ci-950','最高楼','赵文','宋','宋词','song-ci','最高楼','[]','春小小，和气满仙家。',98,'宋词/ci.song.17000.json','["春小小，和气满仙家。", "喜渐近春华。", "彩衣明媚人如玉，金杯潋滟酒成霞。", "寿诗翁，翁饮少，更添些。", "便万里传宣谁不羡。", "便万里封侯谁不愿。", "适意处，退为佳。", "田园尽可渊明栗，弓刀何似邵平瓜。", "但年年，清浅水，看梅花。"]'),
('song-ci-951','临江仙','赵文','宋','宋词','song-ci','临江仙','[]','如此中山如此酒，何须更觅蓬瀛。',69,'宋词/ci.song.17000.json','["如此中山如此酒，何须更觅蓬瀛。", "江湖历□记平生。", "诗囊都束起，只好说丹经。", "家事付他儿辈，功名留待诸孙。", "维摩法喜鬓青青。", "日长深院里，时听读书声。"]'),
('song-ci-952','临江仙','赵文','宋','宋词','song-ci','临江仙','[]','恰好菊花前二日，寿星高照秋天。',70,'宋词/ci.song.17000.json','["恰好菊花前二日，寿星高照秋天。", "堂前王母鬓方玄。", "怀中娇凤小，已解祝公年。", "如此生涯如此屋，看看海亦成田。", "闲中多把酒杯传。", "长生无别诀，放下有神仙。"]'),
('song-ci-953','洞仙歌','赵文','宋','宋词','song-ci','洞仙歌','[]','千年鹭渚，持作须翁酒。',101,'宋词/ci.song.17000.json','["千年鹭渚，持作须翁酒。", "剩有儿孙上翁寿。", "向玉和堂前，樽俎从容，笑此处，惯著丝纶大手。", "金丹曾熟未，熟得金丹，头上安头甚时了。", "便踢翻炉鼎，抛却蒲团，直恁俊鹘梢空时候。", "但唤取、心斋老门生，向城北城南，傍花随柳。"]'),
('song-ci-954','塞翁吟','赵文','宋','宋词','song-ci','塞翁吟','[]','坐对梅花笑，还记初度年时。',114,'宋词/ci.song.17000.json','["坐对梅花笑，还记初度年时。", "名利事，总成非。", "漫老矣何为。", "吴山夜月闽山雾，回首鬓影如丝。", "懒更问，斗牛箕。", "强凭醉成诗。", "闲思。", "嗟飘泊，浮云飞絮，曾跌荡、春风柘枝。", "便万里、金台筑就，已长分采药庞公，誓墓羲之。", "百年正尔，一笑尊前，儿女牵衣。"]'),
('song-ci-955','八声甘州','赵文','宋','宋词','song-ci','八声甘州','[]','记年时、快马上青云，而今衮衣还。',119,'宋词/ci.song.17000.json','["记年时、快马上青云，而今衮衣还。", "问公归何有，春风万斛，散满人间。", "闻道金銮召对，风采动朝班。", "宰相从来有，几个朱颜。", "梅雨槐风清润，正台星一点，光照龙湾。", "赴经纶馀暇，按行紫芝山。", "念江南、民生何似，把囊封、奏上九重关。", "须信道，济时功行，便是仙丹。"]'),
('song-ci-956','木兰花慢','赵文','宋','宋词','song-ci','木兰花慢','[]','鹭州江上水，望南浦、送将归。',122,'宋词/ci.song.17000.json','["鹭州江上水，望南浦、送将归。", "想陌上儿童，尊前父老，口口能碑。", "家声一琴一鹤，甚和他、琴鹤也无之。", "城市貔貅昼静，泮宫芹藻春迟。", "与公南北两天涯，渺再见何时。", "记楼月歌残，碧云句好，尽是相思。", "江南烧痕未补，倩春归、说与上天知。", "早晚洪钧一转，东风先到寒枝。"]'),
('song-ci-957','扫花游・扫地游','赵文','宋','宋词','song-ci','扫花游・扫地游','[]','结庐胜境，似旧日曾游，玉莲佳处。',117,'宋词/ci.song.17000.json','["结庐胜境，似旧日曾游，玉莲佳处。", "万花织组。", "爱回廊宛转，楚腰束素。", "度密穿青，上有燕支万树。", "探梅去。", "正竹外一枝，春意如许。", "奇绝盘谷序。", "更碧皱沿堤，绮霏承宇。", "柳桥花坞。", "问何人解有，玉兰能赋。", "老子婆娑，长与春风作主。", "彩衣舞。", "看人间、落花飞絮。"]'),
('song-ci-958','八声甘州','赵功可','宋','宋词','song-ci','八声甘州','[]','渺平沙、莽莽海风吹，一寒气崔嵬。',117,'宋词/ci.song.17000.json','["渺平沙、莽莽海风吹，一寒气崔嵬。", "耿长天欲压，河流不动，云湿如灰。", "帝敕冰花剪刻，飞瑞上燕台。", "马上行人笑，万玉堆豗。", "滉漾天衔晴昼，料酒楼歌馆，都是春回。", "喜丰年有象，贺表四方来。", "仗下貂裘茸帽，拥千宫、齐上紫金杯。", "明朝起，江南驿史，来进宫梅。"]'),
('song-ci-959','氐州第一','赵功可','宋','宋词','song-ci','氐州第一','[]','杨柳楼深，推梦乍起，前山一片愁雨。',127,'宋词/ci.song.17000.json','["杨柳楼深，推梦乍起，前山一片愁雨。", "嫩绿成云，飞红欲雪，天亦留春不住。", "借问东风，甚飘泊、天涯何许。", "可惜风流，三生杜枚，少年张绪。", "陌上差差携手去。", "怕行到、歌台旧处。", "落日啼鹃，断烟荒草，吟不成谁语。", "听西河、人唱罢，何堪把、江南重赋。", "敲碎琼壶，又前村、数声钟鼓。"]'),
('song-ci-960','曲游春','赵功可','宋','宋词','song-ci','曲游春','[]','千树玲珑罩，正蒲风微过，梅雨新霁。',123,'宋词/ci.song.17000.json','["千树玲珑罩，正蒲风微过，梅雨新霁。", "客里幽窗，算无春可到，和愁都闭。", "万种人生计。", "应不似、午天闲睡。", "起来踏碎松阴，萧萧欲动疑水。", "借问归舟归未。", "望柳色烟光，何处明媚。", "抖擞人间，除离情别恨，乾坤馀几。", "一笑晴凫起。", "酒醒后、阑干独倚。", "时见双燕飞来，斜阳满地。"]'),
('song-ci-961','声声慢','赵功可','宋','宋词','song-ci','声声慢','[]','情痴倦极，天阔归迟，吟魂无力随风。',119,'宋词/ci.song.17000.json','["情痴倦极，天阔归迟，吟魂无力随风。", "月落墙阴，一屏睡睫濛濛。", "邯郸平生难记，记花前、犹醉金锺。", "留连处，忽一声山外，吹度晴钟。", "觉来重重追忆，似游尘飞去，那拾遗踪。", "寄谢芳卿，向来曾主芙蓉。", "人间兴亡万感，看千年、与梦皆空。", "披衣起，倚阑干、人在笑中。"]'),
('song-ci-962','桂枝香','赵功可','宋','宋词','song-ci','桂枝香','[]','晓天凉露。',124,'宋词/ci.song.17000.json','["晓天凉露。", "天上玉箫吹，飞声如雨。", "金阙高寒，闲却一庭梅雨。", "漫漫八表尘埃梦，把文章、洗空千古。", "精神一似，风裳水佩，兰皋蘅浦。", "看万里、跳龙跃虎。", "甚花娇英气，剑清尘妩。", "憔悴江南，应念小窗贫女。", "朱楼十二春无际，倚苍寒、青袖如故。", "茶香酒熟，月明风细，试教歌舞。"]'),
('song-ci-963','绮寮怨','赵功可','宋','宋词','song-ci','绮寮怨','[]','忽忽东风又老，冷云吹晚阴。',129,'宋词/ci.song.17000.json','["忽忽东风又老，冷云吹晚阴。", "疏帘下、茶鼎孤烟，断桥外、梅豆千林。", "江南庾郎憔悴，睡未醒、病酒愁怎禁。", "倚阑干、一扇凉风，看平地、落花如雪深。", "千曲囊中古琴。", "平泉金谷，不堪旧事重寻。", "当日登临。", "都化作、梦销沈。", "元龙丘坟无恙，谁唤起，共论心。", "哀歌怨吟。", "问何似、啼鸟枝上音。"]'),
('song-ci-964','柳梢青','赵功可','宋','宋词','song-ci','柳梢青','[]','一健如仙，东湖烟柳，坐拥吟翁。',61,'宋词/ci.song.17000.json','["一健如仙，东湖烟柳，坐拥吟翁。", "几许功名，百年身世，相见匆匆。", "别来三度秋风。", "怕看见、云间过鸿。", "酒醒灯寒，更残月落，吾美楼中。"]'),
('song-ci-965','柳梢青','赵功可','宋','宋词','song-ci','柳梢青','[]','客里凄凉，桐花满地，杜宇深山。',61,'宋词/ci.song.17000.json','["客里凄凉，桐花满地，杜宇深山。", "幸自君来，谁教春去，剪剪轻寒。", "愁怀无语相看。", "谩写入、徽弦自弹。", "小院黄昏，前村风雨，莫倚阑干。"]'),
('song-ci-966','满江红','汪宗臣','宋','宋词','song-ci','满江红','[]','检点春光，阴雨过、三分之一。',115,'宋词/ci.song.17000.json','["检点春光，阴雨过、三分之一。", "从头数、元宵灯夕，都无晴日。", "不碍郊原肥草绿，但漫丘壑沈云黑。", "那东君、忒煞没纲维，春无力。", "燕忙甚，泥浑湿。", "蜂愁甚，脾无蜜。", "更两旬又是，梨花寒食。", "蔫红殷桃吾不较，岂堪浸烂东畴麦。", "望前村、白鹭衬霞红，探晴色。"]'),
('song-ci-967','蝶恋花','汪宗臣','宋','宋词','song-ci','蝶恋花','[]','年去年来来去早。',70,'宋词/ci.song.17000.json','["年去年来来去早。", "怪底不来，庭院春光老。", "知过谁家翻别调。", "家家望断飞踪窅。", "千里潇湘烟渺渺。", "不记雕梁，旧日恩多少。", "匝近清明檐外叫。", "故巢犹在朱檐晓。"]'),
('song-ci-968','酹江月・念奴娇','汪宗臣','宋','宋词','song-ci','酹江月・念奴娇','[]','白蛇宵断，逐鹿人、交趁罾鱼群起。',120,'宋词/ci.song.17000.json','["白蛇宵断，逐鹿人、交趁罾鱼群起。", "赤帜雄张军缟素，龙种天生大器。", "堪鄙猴冠，自为狼藉，楚帐多尘垒。", "胆寒垓下，一鞭东窜休矣。", "亭长空舣扁舟，范增群辈，尽涂脂流髓。", "望断秦关无限恨，羞面江东山水。", "购首千金，若为名利，黯黯斜阳里。", "石炉灰冷，美人魂落烟翠。"]'),
('song-ci-969','水调歌头','汪宗臣','宋','宋词','song-ci','水调歌头','[]','候应黄锺动，吹出百葭灰。',114,'宋词/ci.song.17000.json','["候应黄锺动，吹出百葭灰。", "五云重压头上，潜蛰地中雷。", "莫道希声妙寂，嶰竹雄鸣合凤，九寸律初裁。", "欲识天心处，请问学颜回。", "冷中温，穷时达，信然哉。", "彩云山外如画，送上笔尖来。", "一气先通关窍，万物旋生头角，谁合又谁开。", "官路春光早，箫落数枝梅。"]'),
('song-ci-970','湘灵瑟','刘埙','宋','宋词','song-ci','湘灵瑟','[]','酸风泠泠。',41,'宋词/ci.song.17000.json','["酸风泠泠。", "哀笳吹数声。", "碎雨冥冥。", "泣瑶英。", "花心路，芙蓉城。", "相思几回魂惊。", "肠断坟草青。"]'),
('song-ci-971','醉思仙','刘埙','宋','宋词','song-ci','醉思仙','[]','琼楼几间。',46,'宋词/ci.song.17000.json','["琼楼几间。", "瑶徽几弹。", "觅花声绕回阑。", "悄微闻佩环。", "帘栊昼闲。", "炉薰昼残。", "午风摇曳屏山。", "露裙红一班。"]'),
('song-ci-972','点绛唇','刘埙','宋','宋词','song-ci','点绛唇','[]','风卷游云，梨云梦冷人何处。',50,'宋词/ci.song.17000.json','["风卷游云，梨云梦冷人何处。", "一溪烟雨。", "遮断垂杨路。", "恨入琴心，能写当时语。", "愁无绪。", "泪痕红蠹。", "犹带香如故。"]'),
('song-ci-973','浣溪沙','刘埙','宋','宋词','song-ci','浣溪沙','[]','已断因缘莫更寻。',48,'宋词/ci.song.17000.json','["已断因缘莫更寻。", "寻时烦恼不如心。", "从今休听世间音。", "鸾梦渐随秋水远，鹤情甘伴野云深。", "隔楼花月自阴阴。"]'),
('song-ci-974','菩萨蛮','刘埙','宋','宋词','song-ci','菩萨蛮','[]','长亭望断来时路。',52,'宋词/ci.song.17000.json','["长亭望断来时路。", "楼台杳霭迷花雾。", "山雨隔窗声。", "思君魂梦惊。", "泪痕侵褥锦。", "闲却鸳鸯枕。", "有泪不须垂。", "金鞍明月归。"]'),
('song-ci-975','菩萨蛮','刘埙','宋','宋词','song-ci','菩萨蛮','[]','故园青草依然绿。',52,'宋词/ci.song.17000.json','["故园青草依然绿。", "故宫废址空乔木。", "狐兔穴岩城。", "悠悠万感生。", "胡笳吹汉月。", "北语南人说。", "红紫闹东风。", "湖山一梦中。"]'),
('song-ci-976','谒金门','刘埙','宋','宋词','song-ci','谒金门','[]','云薄薄。',53,'宋词/ci.song.17000.json','["云薄薄。", "人静黄梅院落。", "细数花期并柳约。", "新愁沾一握。", "梦醒从前多错。", "寄恨画檐灵鹊。", "明月欲西天寂寞。", "魂销连晓角。"]'),
('song-ci-977','谒金门','刘埙','宋','宋词','song-ci','谒金门','[]','花雾暖。',53,'宋词/ci.song.17000.json','["花雾暖。", "红逗海棠开半。", "毡坐谈经春四换。", "今朝官正满。", "好上鳌坡虎观。", "好近御屏香案。", "休笑吾侬行色缓。", "待君来作伴。"]'),
('song-ci-978','谒金门','刘埙','宋','宋词','song-ci','谒金门','[]','眉月小。',53,'宋词/ci.song.17000.json','["眉月小。", "红烛画楼歌绕。", "唱到刘郎频笑道。", "古词今恰好。", "深夜银屏香袅。", "明日雕鞍尘杳。", "一饷春风容易晓。", "三生思不了。"]'),
('song-ci-979','谒金门','刘埙','宋','宋词','song-ci','谒金门','["\u6d1e\u5ead\u6e56"]','春正媚。',53,'宋词/ci.song.17000.json','["春正媚。", "闲步武陵源里。", "千树霞蒸红散绮。", "一枝高插髻。", "飞过洞庭烟水。", "酩酊莫教花坠。", "铅鼎温温神谒帝。", "何曾真是醉。"]'),
('song-ci-980','清平乐','刘埙','宋','宋词','song-ci','清平乐','[]','铿金戛玉。',53,'宋词/ci.song.17000.json','["铿金戛玉。", "弹就神仙曲。", "铁拨鵾弦清更熟。", "新腔浑胜俗。", "教坊尽道名师。", "声华都处俱知。", "指日内前宣唤，云韶独步丹墀。"]'),
('song-ci-981','太常引','刘埙','宋','宋词','song-ci','太常引','[]','甘棠春色满南丰。',62,'宋词/ci.song.17000.json','["甘棠春色满南丰。", "春好处、在黉宫。", "宫柳映墙红。", "对墙柳、常思耐翁。", "文章太守，词华哲匠，人与易居东。", "攀恋计无从。", "判行省、重临旧封。"]'),
('song-ci-982','柳梢青','刘埙','宋','宋词','song-ci','柳梢青','[]','青鸟西沈，彩鸾北去，月冷河桥。',61,'宋词/ci.song.17000.json','["青鸟西沈，彩鸾北去，月冷河桥。", "梦事荒凉，垂杨暗老，几度魂销。", "云边音信迢迢。", "把楚些、凭谁为招。", "万叠清愁，西风横笛，吹落寒潮。"]'),
('song-ci-983','恋绣衾','刘埙','宋','宋词','song-ci','恋绣衾','[]','轻风吹雾月满廊。',68,'宋词/ci.song.17000.json','["轻风吹雾月满廊。", "芙蕖香、飘入隔窗。", "记旧月、闲庭院，擘碎红、蒙幂晓妆。", "如今两鬓秋凄恻，负凌波、万顷凄凉。", "花若惜、刘郎老，倩藕丝、牵住夕阳。"]'),
('song-ci-984','临江仙','刘埙','宋','宋词','song-ci','临江仙','[]','朔雪驱将残腊去，东风放出新晴。',70,'宋词/ci.song.17000.json','["朔雪驱将残腊去，东风放出新晴。", "绣衣瑞彩照岩城。", "江天收宿霭，湖水动春声。", "要净狐嗥并鳝舞，未烦鹤怨猿惊。", "元龙老气正峥嵘。", "毫端肤寸润，野烧绿痕生。"]'),
('song-ci-985','洞仙歌','刘埙','宋','宋词','song-ci','洞仙歌','[]','津亭折柳，正秋光如画。',103,'宋词/ci.song.17000.json','["津亭折柳，正秋光如画。", "绕路黄花拥朝马。", "叹市槐景淡，池藻波寒，分明是、三载春风难舍。", "军峰天际碧，云隔空同，无奈相思月明夜。", "薇药早催人，应占先春，休如我、醉卧水边林下。", "待来岁、今时庆除书，绣锦映宫花，玉京随驾。"]'),
('song-ci-986','西湖明月引・江城梅花引','刘埙','宋','宋词','song-ci','西湖明月引・江城梅花引','[]','江村烟雨暗萧萧。',108,'宋词/ci.song.17000.json','["江村烟雨暗萧萧。", "涨寒潮。", "送春桡。", "目断京尘，何日听鸾箫。", "金雀觚棱千里外，指天际，碧云深，魂欲飘。", "薰炉炷愁烟尽销。", "酒孤斟、谁与招。", "满怀情思，任吟笺、赋笔难描。", "惆怅山风、吹梦老秋宵。", "绿漾湖心波影阔，终待到，借垂杨、月半桥。"]'),
('song-ci-987','意难忘','刘埙','宋','宋词','song-ci','意难忘','[]','汀柳初黄。',114,'宋词/ci.song.17000.json','["汀柳初黄。", "送流车出陌，别酒浮觞。", "乱山迷去路，空阁带馀香。", "人渐远，意凄凉。", "更暮雨淋浪。", "悔不办，窄衫细马，两两交相。", "春梁语燕犹双。", "叹晓窗新月，独照刘郎。", "寄笺频误约，临镜想慵妆。", "知几梦，恼愁肠。", "任更驻何妨。", "但只怜，绿阴匝匝，过了韶光。"]'),
('song-ci-988','六么令','刘埙','宋','宋词','song-ci','六么令','[]','晓来寒角，吹起愁相触。',112,'宋词/ci.song.17000.json','["晓来寒角，吹起愁相触。", "乱云黯淡江渚，疏柳双鸦宿。", "锦瑟银屏何处，花雾翻香曲。", "柔红娇绿。", "魂消往梦，羞向孤梅说幽独。", "燕支曾印素袂，绛艳收残馥。", "频问讯，道新来闷损纤腰束。", "多谢芳心惓恋，罗结文鸳蹴。", "前欢谁卜。", "云笺封蜡，就寄相思恨盈匊。"]'),
('song-ci-989','满庭芳','刘埙','宋','宋词','song-ci','满庭芳','[]','帘卷疏櫺，楼平危堞，几回笋玉凭阑。',118,'宋词/ci.song.17000.json','["帘卷疏櫺，楼平危堞，几回笋玉凭阑。", "觅花呼酒，更共理哀弹。", "暖日柔风好景，行云绕、莺燕翩翻。", "谁知道，冶游重到，已付解连环。", "乘云，行处去，花深隔院，应恨春闲。", "但紫骝嘶度，时望重关。", "长恨江楼柳老，女郎腰、又负眠三。", "东城路，一回一感，愁见月儿弯。"]'),
('song-ci-990','天香','刘埙','宋','宋词','song-ci','天香','[]','雨秀风明，烟柔雾滑，魏家初试娇紫。',117,'宋词/ci.song.17000.json','["雨秀风明，烟柔雾滑，魏家初试娇紫。", "翠羽低云，檀心晕粉，独冠洛京新谱。", "沈香醉墨，曾赋与、昭阳仙侣。", "尘世几经朝暮，花神岂知今古。", "愁听流莺自语，叹唐宫、草青如许。", "空有天边浩月，见霓裳舞。", "更后百年人换，又谁记、今番看花处。", "流水夕阳，断魂钟鼓。"]'),
('song-ci-991','烛影摇红','刘埙','宋','宋词','song-ci','烛影摇红','[]','院落黄昏，残霞收尽廉纤雨。',116,'宋词/ci.song.17000.json','["院落黄昏，残霞收尽廉纤雨。", "天香富贵洛阳城，巧费春工作。", "自笑平生吟苦。", "写不尽、此花风度。", "玉堂银烛，翠幄画阑，万红争妒。", "那更深宵，寒光幻出清都府。", "嫦娥跨影下人间，来按红鸾舞。", "连夜杯行休驻。", "生怕化、彩云飞去。", "酒阑人静，月淡尘清，晓风轻露。"]'),
('song-ci-992','长相思','刘埙','宋','宋词','song-ci','长相思','[]','雾隔平林，风欺败褐，十分秋满黄华。',128,'宋词/ci.song.17000.json','["雾隔平林，风欺败褐，十分秋满黄华。", "荒庭人静，声惨寒蛩，惊回羁思如麻。", "庾信多愁，有中宵清梦，迢递还家。", "楚水绕天涯。", "黯消魂、几度栖鸦。", "对绿橘黄橙，故园在念，怅望归路犹赊。", "此情吟不尽，被西风、吹入胡笳。", "目极黄云，飞渡处、临流自嗟。", "又斜阳，征鸿影断，夜来空信灯花。"]'),
('song-ci-993','选冠子','刘埙','宋','宋词','song-ci','选冠子','[]','暝霭迷红，水天笼晓，帆去野潮声急。',135,'宋词/ci.song.17000.json','["暝霭迷红，水天笼晓，帆去野潮声急。", "离鸾独倚，巧燕双飞，忍向东风飘拆。", "尘销紫曲阑干，筝雁成声，顿成孤臆。", "叹舟回人远，钿花芗泽，悄无痕迹。", "憔悴损，俊赏杜郎，多情荀令，欲写别愁无力。", "闽星南转，江月西沈，空拟梦来今夕。", "古驿荒村，谁怜腻粉风侵，松蝉云湿。", "但断魂烟浪，痴看桥西落日。"]'),
('song-ci-994','惜馀春慢・选冠子','刘埙','宋','宋词','song-ci','惜馀春慢・选冠子','[]','玉勒丝鞭，彩旗红索，总向愁中休了。',138,'宋词/ci.song.17000.json','["玉勒丝鞭，彩旗红索，总向愁中休了。", "偏怜景媚，为甚愁浓，都为雨多晴少。", "桃杏开到梨花，红印香印，绿平幽沼。", "也无饶、红药殿春，更作薄寒清峭。", "尘梦里、暗换年华，东风能几，又把一番春老。", "莺花过眼，蚕麦当头，朝日浓阴笼晓。", "休恨烟林杜鹃，只恨啼鸠，呼云声杳。", "到如今，暖霭烘晴，满地绿阴芳草。"]'),
('song-ci-995','买陂塘・摸鱼儿','刘埙','宋','宋词','song-ci','买陂塘・摸鱼儿','[]','暮云沈、凄凄花陌，荒苔青润鸳甃。',140,'宋词/ci.song.17000.json','["暮云沈、凄凄花陌，荒苔青润鸳甃。", "娇红一捻不胜春，苦雨酸雨僝僽。", "从别后。", "但暗忆娉婷，几把垂杨蹂。", "香销韩袖。", "念莺燕悲吟，凤鸾仙去，空负摘花手。", "铜铺掩，窥见文窗依旧。", "筝琶尘暗弦绉。", "欲圆春梦今犹未，怪得西飞太骤。", "凝伫久。", "拟待倩、鸿都羽客寻仙偶。", "青衫湿透。", "叹玉骨沈埋，芳魂缥缈，何处酹尊酒。"]'),
('song-ci-996','买陂塘・摸鱼儿','刘埙','宋','宋词','song-ci','买陂塘・摸鱼儿','[]','倚楼西、西风惊鬓，吹回尘思萧瑟。',140,'宋词/ci.song.17000.json','["倚楼西、西风惊鬓，吹回尘思萧瑟。", "碧桃花下骖鸾梦，十载雨沈云隔。", "空自忆。", "漫红蜡香笺，难写旧凄恻。", "烟村水国。", "欲闲却琴心，蠹残箧面，老尽看花客。", "河桥侧。", "曾试雕鞍玉勒。", "如今已忘南北。", "人间纵有垂杨在，欲挽一丝无力。", "君莫拍。", "浑不似、年时爱听酒边笛。", "湘帘巷陌。", "但斜照断烟，淡萤衰草，零落旧春色。"]'),
('song-ci-997','贺新郎','刘埙','宋','宋词','song-ci','贺新郎','[]','办著春游费。',140,'宋词/ci.song.17000.json','["办著春游费。", "奈狂风吹寒，禁定满城花事。", "天暝云深时度雨。", "院落秦筝未试。", "倩谁趱、杏娇桃媚。", "韶色三停今过一，只淡黄杨柳装愁思。", "芳径滑，绣窗闭。", "玉炉闷炷香温被。", "忆去年、匆匆胜赏，梦沈烟水。", "遥望秋千新彩索，难把旧痕重系。", "待暖入、香红十里。", "别拥双鸾迎素月，教明年、不恨今憔悴。", "莺共燕，汝知未。"]'),
('song-ci-998','贺新郎','刘埙','宋','宋词','song-ci','贺新郎','[]','莫笑刘郎老。',141,'宋词/ci.song.17000.json','["莫笑刘郎老。", "老刘郎平生，不是山林怀抱。", "梦里风云翻海岳，觉后狂歌坠帽。", "叹几度、荒鸡误晓。", "天际晴云开五色，纵今年、意气犹年少。", "机事远，有时到。", "凯歌檄笔凭谁道。", "对村中、一溪流水，半林斜照。", "赖有可人堪话旧，时共掀髯绝倒。", "也来问、衮衣茸帽。", "聊且问天占百岁，看乾坤、此事如何了。", "肠断处，春城早。"]'),
('song-ci-999','贺新郎','刘埙','宋','宋词','song-ci','贺新郎','[]','醉里江南路。',141,'宋词/ci.song.17000.json','["醉里江南路。", "问梅花、经年冷落，几番烟雨。", "玉骨冰肌终是别，犹带孤山瑞露。", "想蕴藉、和羹风度。", "万紫千红羡妒早，羡仙标、岂比人间侣。", "聊玩弄，六花舞。", "云寒木落山城暮。", "忽飘来、暗香万斛，春浮江浦。", "茅舍竹篱词客老，拟傍东风千树。", "看好月、亭亭当午。", "流水村中清浅处，称横斜疏影相容与。", "时索笑，想应许。"]'),
('song-ci-0','太常引','王清观','宋','宋词','song-ci','太常引','[]','邯郸梦里武陵溪。',60,'宋词/ci.song.18000.json','["邯郸梦里武陵溪。", "春色醉冥迷。", "花压帽檐欹，谩赢得、红尘满衣。", "青蛇飞起，黄龙喝住，才是酒醒时。", "和露饮刀圭。", "待月满、长空鹤归。"]'),
('song-ci-1','满庭芳','熊则轩','宋','宋词','song-ci','满庭芳','[]','波有颓澜，渴无冷镬，谁言制邑为难。',117,'宋词/ci.song.18000.json','["波有颓澜，渴无冷镬，谁言制邑为难。", "汾阳善政，只在笑谈间。", "三载刑清讼简，官事辨、俗阜民安。", "帘垂昼，焚香宴坐，犹得半清闲。", "西风，催入觐，声驰当道，名达朝端。", "任锦溪溪上，卧辙攀辕。", "从此燕辕北去，好官样、留与人看。", "扁舟稳，图书外，惟有月俱还。"]'),
('song-ci-2','大江乘・念奴娇','阮溪','宋','宋词','song-ci','大江乘・念奴娇','[]','东阳四载，但好事、一一为民做了。',121,'宋词/ci.song.18000.json','["东阳四载，但好事、一一为民做了。", "谈笑半闲风月里，管甚讼庭生草。", "瓯茗炉香，菜羹淡饭，此外无烦恼。", "问侯何苦，自饥只要民饱。", "犹念甘旨相违，白云万里，不得随昏晓。", "暂舍苍生归定省，回首又看父老。", "听得乖崖，交章力荐，道此官员好。", "且来典宪，中书还二十四考。"]'),
('song-ci-3','风流子','危西麓','宋','宋词','song-ci','风流子','[]','西风吹锦水，朝天路、冉冉两凫飞。',133,'宋词/ci.song.18000.json','["西风吹锦水，朝天路、冉冉两凫飞。", "看父老袅花，苦遮去辙，儿童骑竹，争问归期。", "帐簇马前纷蔽日，实绩纪行碑。", "冰饮三年，从容官事，棠阴百里，悠久民思。", "圣明衿遐远，关山道，应是来骤华丝。", "画绣过家，莱庭彩舞斑衣。", "便稳奉安舆，江南向暖，早传言语，樵曲先知。", "重约旧临，倪耄迎候杭西。"]'),
('song-ci-4','满江红','汪元量','宋','宋词','song-ci','满江红','[]','一个兰舟，双桂桨、顺流东去。',115,'宋词/ci.song.18000.json','["一个兰舟，双桂桨、顺流东去。", "但满目、银光万顷，凄其风露。", "渔火已归鸿雁汊，棹歌更在鸳鸯浦。", "渐夜深、芦叶冷飕飕，临平路。", "吹铁笛，鸣金谷。", "丝玉脍，倾香醑。", "且浩歌痛饮，藕花深处。", "秋水长天迷远望，晓风残月空凝伫。", "问人间、今夕是何年，清如许。"]'),
('song-ci-5','金人捧露盘','汪元量','宋','宋词','song-ci','金人捧露盘','[]','越山云，越江水，越王台。',98,'宋词/ci.song.18000.json','["越山云，越江水，越王台。", "个中景、尽可徘徊。", "凌高放目，使人胸次共崔嵬。", "黄鹂紫燕报春晚，劝我衔杯。", "古时事，今时泪，前人喜，后人哀。", "正醉里、歌管成灰。", "新愁旧恨，一时分付与潮回。", "鹧鸪啼歇夕阳去，满地风埃。"]'),
('song-ci-6','相思引','汪元量','宋','宋词','song-ci','相思引','[]','晓拂菱花巧画眉。',54,'宋词/ci.song.18000.json','["晓拂菱花巧画眉。", "猩罗新翦作春衣。", "恐春归去，无处看花枝。", "已恨东风成去客，更教飞燕舞些时。", "惜花人醉，头上插花归。"]'),
('song-ci-7','长相思','汪元量','宋','宋词','song-ci','长相思','[]','吴山深。',44,'宋词/ci.song.18000.json','["吴山深。", "越山深。", "空谷佳人金玉音。", "有谁知此心。", "夜沈沈。", "漏沈沈。", "闲却梅花一曲琴。", "月高松竹林。"]'),
('song-ci-8','传言玉女','汪元量','宋','宋词','song-ci','传言玉女','[]','一片风流，今夕与谁同乐。',90,'宋词/ci.song.18000.json','["一片风流，今夕与谁同乐。", "月台花馆，慨尘埃漠漠。", "豪华荡尽，只有青山如洛。", "钱塘依旧，潮生潮落。", "万点灯光，羞照舞钿歌箔。", "玉梅消瘦，恨东皇命薄。", "昭君流泪，手拈琵琶弦索。", "离愁聊寄，画楼哀角。"]'),
('song-ci-9','好事近','汪元量','宋','宋词','song-ci','好事近','[]','独倚浙江楼，满耳怨笳哀笛。',53,'宋词/ci.song.18000.json','["独倚浙江楼，满耳怨笳哀笛。", "犹有梨园声在，念那人天北。", "海棠憔悴怯春寒，风雨怎禁得。", "回首华清池畔，渺露芜烟荻。"]'),
('song-ci-10','洞仙歌','汪元量','宋','宋词','song-ci','洞仙歌','[]','西园春暮。',101,'宋词/ci.song.18000.json','["西园春暮。", "乱山迷行路。", "风卷残花堕红雨。", "念旧巢燕子，飞傍谁家，斜阳外、长笛一声今古。", "繁华流水去。", "舞歇歌沈，忍见遗钿种香土。", "渐橘树方生，桑枝才长，都付与、沙门为主。", "便关防、不放贵游来，又突兀梯空，楚王宫宇。"]'),
('song-ci-11','莺啼序','汪元量','宋','宋词','song-ci','莺啼序','[]','金陵故都最好，有朱楼迢递。',288,'宋词/ci.song.18000.json','["金陵故都最好，有朱楼迢递。", "嗟倦客、又此凭高，槛外已少佳致。", "更落尽梨花，飞尽杨花，春也成憔悴。", "问青山、三国英雄，六朝奇伟。", "麦甸葵丘，荒台败垒。", "鹿豕衔枯荠。", "正朝打孤城，寂寞斜阳影里。", "听楼头、哀笳怨角，未把酒、愁心先醉。", "渐夜深，月满秦淮，烟笼寒水。", "凄凄惨惨，冷冷清清，灯火渡头市。", "慨商女不知兴废。", "隔江犹唱庭花，馀音亹亹。", "伤心千古，泪痕如洗。", "乌衣巷口青芜路，认依稀、王谢旧邻里。", "临春结绮。", "可怜红粉成灰，萧索白杨风起。", "因思畴昔，铁索千寻，谩沈江底。", "挥羽扇、障西尘，便好角巾私第。", "清谈到底成何事。", "回首新亭，风景今如此。", "楚囚对泣何时已。", "叹人间、今古真儿戏。", "东风岁岁还来，吹入锺山，几重苍翠。"]'),
('song-ci-12','六州歌头','汪元量','宋','宋词','song-ci','六州歌头','[]','绿芜城上，怀古恨依依。',117,'宋词/ci.song.18000.json','["绿芜城上，怀古恨依依。", "淮山碎。", "江波逝。", "昔人非。", "今人悲。", "惆怅隋天子。", "锦帆里。", "环朱履。", "丛香绮。", "展旌旗。", "荡涟猗。", "击鼓挝金，拥琼璈玉吹。", "姿意游嬉。", "斜日晖晖。", "乱莺啼。", "销魂此际。", "君臣醉。", "貔貅弊。", "事如飞。", "山河坠。", "烟尘起。", "风凄凄。", "雨霏霏。", "草木皆垂泪。"]'),
('song-ci-13','水龙吟','汪元量','宋','宋词','song-ci','水龙吟','[]','鼓鞞惊破霓裳，海棠亭北多风雨。',126,'宋词/ci.song.18000.json','["鼓鞞惊破霓裳，海棠亭北多风雨。", "歌阑酒罢，玉啼金泣，此行良苦。", "驼背模糊，马头匼匝，朝朝暮暮。", "自都门燕别，龙艘锦缆，空载得、春归去。", "目断东南半壁，怅长淮、已非吾土。", "受降城下，草如霜白，凄凉酸楚。", "粉阵红围，夜深人静，谁宾谁主。", "对渔灯一点，羁愁一搦，谱琴中语。"]'),
('song-ci-14','望江南・忆江南','汪元量','宋','宋词','song-ci','望江南・忆江南','[]','官舍悄，坐到月西斜。',64,'宋词/ci.song.18000.json','["官舍悄，坐到月西斜。", "永夜角声悲自语，客心愁破正思家。", "南北各天涯。", "肠断裂，搔首一长嗟。", "绮席象床寒玉枕，美人何处醉黄花。", "和泪拈琵琶。"]'),
('song-ci-15','卜算子','汪元量','宋','宋词','song-ci','卜算子','[]','我向河南来，伊向河西去。',52,'宋词/ci.song.18000.json','["我向河南来，伊向河西去。", "客里相逢只片时，无计留伊住。", "去住总由伊，莫把眉头聚。", "安得并州快剪刀，割断相思路。"]'),
('song-ci-16','满江红','汪元量','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','天上人家，醉王母、蟠桃春色。',115,'宋词/ci.song.18000.json','["天上人家，醉王母、蟠桃春色。", "被午夜、漏声催箭，晓光侵阙。", "花覆千官鸾阁外，香浮九鼎龙楼侧。", "恨黑风、吹雨湿霓裳，歌声歇。", "人去后，书应绝。", "肠断处，心难说。", "更那堪杜宇，满山啼血。", "事去空流东汴水，愁来不见西湖月。", "有谁知、海上泣蝉娟，菱花缺。"]'),
('song-ci-17','满江红','汪元量','宋','宋词','song-ci','满江红','[]','一霎浮云，都掩尽、日无光色。',115,'宋词/ci.song.18000.json','["一霎浮云，都掩尽、日无光色。", "遥望处、浮图对峙，梵王新阙。", "燕子自飞关北外，杨花闲度楼西侧。", "慨金鞍、玉勒早朝人，经年歇。", "昭君去，空愁绝。", "文姬去，难言说。", "想琵琶哀怨，流泪成血。", "蝴蝶梦中千种恨，杜鹃声里三更月。", "最无情、鸿雁自南飞，音书缺。"]'),
('song-ci-18','一翦梅','汪元量','宋','宋词','song-ci','一翦梅','[]','十年愁眼泪巴巴。',72,'宋词/ci.song.18000.json','["十年愁眼泪巴巴。", "今日思家。", "明日思家。", "一团燕月照窗纱。", "楼上胡笳。", "塞上胡笳。", "玉人劝我酌流霞。", "急拈琵琶。", "缓拈琵琶。", "一从别后各天涯。", "欲寄梅花。", "莫寄梅花。"]'),
('song-ci-19','惜分飞','汪元量','宋','宋词','song-ci','惜分飞','[]','燕子留君君欲去。',60,'宋词/ci.song.18000.json','["燕子留君君欲去。", "征马频嘶不住。", "握手空相觑。", "泪珠成缕。", "眉峰聚。", "恨入金徽孤凤语。", "愁得文君更苦。", "今夜西窗雨。", "断肠能赋。", "江南句。"]'),
('song-ci-20','唐多令','汪元量','宋','宋词','song-ci','唐多令','[]','莎草被长洲。',74,'宋词/ci.song.18000.json','["莎草被长洲。", "吴江拍岸流。", "忆故家、西北高楼。", "十载客窗憔悴损，搔短鬓、独悲秋。", "人在塞边头。", "断鸿书寄不。", "记当年、一片闲愁。", "舞罢羽衣尘满面，谁伴我、广寒游。"]'),
('song-ci-21','鹧鸪天','汪元量','宋','宋词','song-ci','鹧鸪天','[]','潋滟湖光绿正肥。',64,'宋词/ci.song.18000.json','["潋滟湖光绿正肥。", "苏堤十里柳丝垂。", "轻便燕子低低舞，小巧莺儿恰恰啼。", "花似锦，酒成池。", "对花对酒两相宜。", "水边莫话长安事，且请卿卿吃蛤蜊。"]'),
('song-ci-22','眼儿媚','汪元量','宋','宋词','song-ci','眼儿媚','[]','记得年时想荼䕷。',58,'宋词/ci.song.18000.json','["记得年时想荼䕷。", "蝴蝶满园飞。", "一双宝马，两行箫管，月下扶归。", "而今寂寞人何处，脉脉泪沾衣。", "空房独守，风穿帘子，雨隔窗儿。"]'),
('song-ci-23','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','汉家宫阙动高秋。',36,'宋词/ci.song.18000.json','["汉家宫阙动高秋。", "人自伤心水自流。", "今日晴明独上楼。", "恨悠悠。", "白尽梨园子弟头。"]'),
('song-ci-24','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','吴王此地有楼台。',36,'宋词/ci.song.18000.json','["吴王此地有楼台。", "风雨谁知长绿苔。", "半醉闲吟独自来。", "小徘徊。", "惟见江流去不回。"]'),
('song-ci-25','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','长安不见使人愁。',36,'宋词/ci.song.18000.json','["长安不见使人愁。", "物换星移几度秋。", "一自佳人坠玉楼。", "莫淹留。", "远别秦城万里游。"]'),
('song-ci-26','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','阵前金甲受降时。',36,'宋词/ci.song.18000.json','["阵前金甲受降时。", "园客争偷御果枝。", "白发宫娃不解悲。", "理征衣。", "一片春帆带雨飞。"]'),
('song-ci-27','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','鹧鸪飞上越王台。',36,'宋词/ci.song.18000.json','["鹧鸪飞上越王台。", "烧接黄云惨不开。", "有客新从赵地回。", "转堪哀。", "岩畔古碑空绿苔。"]'),
('song-ci-28','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','离宫别苑草萋萋。',36,'宋词/ci.song.18000.json','["离宫别苑草萋萋。", "对此如何不泪垂。", "满槛山川漾落晖。", "昔人非。", "惟有年年秋雁飞。"]'),
('song-ci-29','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','上阳宫里断肠时。',36,'宋词/ci.song.18000.json','["上阳宫里断肠时。", "春半如秋意转迷。", "独坐纱窗刺绣迟。", "泪沾衣。", "不见人归见燕归。"]'),
('song-ci-30','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','华清宫树不胜秋。',36,'宋词/ci.song.18000.json','["华清宫树不胜秋。", "云物凄凉拂曙流。", "七夕何人望斗牛。", "一登楼。", "水远山长步步愁。"]'),
('song-ci-31','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','五陵无树起秋风。',36,'宋词/ci.song.18000.json','["五陵无树起秋风。", "千里黄云与断蓬。", "人物萧条市井空。", "思无穷。", "惟有青山似洛中。"]'),
('song-ci-32','凤鸾双舞','汪元量','宋','宋词','song-ci','凤鸾双舞','[]','慈元殿、薰风宝鼎，喷香云飘坠。',119,'宋词/ci.song.18000.json','["慈元殿、薰风宝鼎，喷香云飘坠。", "环立翠羽，双歌丽调，舞腰新束，舞缨新缀。", "金莲步、轻摇彩凤儿，翩翻作戏。", "便似月里仙娥谪来，人间天上，一番游戏。", "圣人乐意。", "任乐部、箾韶声沸。", "众妃欢也，渐调笑微醉。", "竞奉霞觞，深深愿、圣母寿如松桂。", "迢递。", "更万年千岁。"]'),
('song-ci-33','柳梢青','汪元量','宋','宋词','song-ci','柳梢青','[]','滟滟平湖，双双画桨，小小船儿。',61,'宋词/ci.song.18000.json','["滟滟平湖，双双画桨，小小船儿。", "袅袅珠歌，翩翩翠舞，续续弹丝。", "山南山北游□，看十里、荷花未归。", "缓引壶觞，个人未醉，要我吟诗。"]'),
('song-ci-34','暗香','汪元量','宋','宋词','song-ci','暗香','[]','馆娃艳骨。',120,'宋词/ci.song.18000.json','["馆娃艳骨。", "见数枝雪里，争开时节。", "底事化工，著衣阳和暗偷泄。", "偏把红膏染质，都点缀、枝头如血。", "最好是、院落黄昏，压栏照水清绝。", "风韵自迥别。", "谩记省故家，玉手曾折。", "翠条袅娜，犹学宫妆舞残月。", "肠断江南倦客，歌未了、琼壶敲缺。", "更忍见，吹万点、满庭绛雪。"]'),
('song-ci-35','疏影','汪元量','宋','宋词','song-ci','疏影','[]','虬枝茜萼。',135,'宋词/ci.song.18000.json','["虬枝茜萼。", "使轻盈态度，香透帘幕。", "净洗铅华，浓抹胭脂，风前伴我孤酌。", "诗翁瘦硬□□□，断不被、春风熔铄。", "有陇头、折赠殷勤，又恐暮笳吹落。", "寂寞。", "孤山月夜，玉人万里外，空想前约。", "雁足书沈，马上弦哀，不尽寒阴砂漠。", "昭君滴滴红冰泪，但顾影、未忺梳掠。", "等恁时、环佩归来，却慰此况萧索。"]'),
('song-ci-36','天香','汪元量','宋','宋词','song-ci','天香','[]','迟日侵阶，和风入户，朱弦欲奏还倦。',116,'宋词/ci.song.18000.json','["迟日侵阶，和风入户，朱弦欲奏还倦。", "一幅鸾笺，五云飞下，赐予内家琴苑。", "音随指动，犹彷佛、虞薰再见。", "妙处谁能解心，和平自无哀怨。", "猩罗帕封古洗，有龙涎、渗花千片。", "骤睹瑶台清品，眼明如电。", "爇白桐窗竹几，渐缕缕腾腾细成篆。", "就祝金闺，天长地远。"]'),
('song-ci-37','摸鱼儿','王学文','宋','宋词','song-ci','摸鱼儿','[]','记当年、舞衫零乱，霖铃忍按新阕。',140,'宋词/ci.song.18000.json','["记当年、舞衫零乱，霖铃忍按新阕。", "杜鹃枝上东风晚，点点泪痕凝血。", "芳信歇。", "念初试琵琶，曾识关山月。", "悲弦易绝。", "奈笑罢颦生，曲终愁在，谁解寸肠结。", "浮云事，又作南柯梦彻。", "一簪聊寄华发。", "乾坤桑海无穷事，才历昆明初劫。", "谁共说。", "都付与焦桐，写入梅花叠。", "黄花送客。", "休更问湘魂，独醒何在，沈醉浩歌发。"]'),
('song-ci-38','满江红','王清惠','宋','宋词','song-ci','满江红','[]','太液芙蓉，浑不似、旧时颜色。',115,'宋词/ci.song.18000.json','["太液芙蓉，浑不似、旧时颜色。", "曾记得、春风雨露，玉楼金阙。", "名播兰簪妃后里，晕潮莲脸君王侧。", "忽一声、颦鼓揭天来，繁华歇。", "龙虎散，风云灭。", "千古恨，凭谁说。", "对山河百二，泪盈襟血。", "客馆夜惊尘土梦，宫车晓碾关山月。", "问嫦娥、於我肯从容，同圆缺。"]'),
('song-ci-39','长相思','章丽贞','宋','宋词','song-ci','长相思','["\u957f\u6c5f"]','吴山秋。',44,'宋词/ci.song.18000.json','["吴山秋。", "越山秋。", "吴越两山相对愁。", "长江不尽流。", "风飕飕。", "雨飕飕。", "万里归人空白头。", "南冠泣楚囚。"]'),
('song-ci-40','长相思','袁正真','宋','宋词','song-ci','长相思','[]','南高峰。',44,'宋词/ci.song.18000.json','["南高峰。", "北高峰。", "南北高峰云淡浓。", "湖山图画中。", "采芙蓉。", "赏芙蓉。", "小小红船西复东。", "相思无路通。"]'),
('song-ci-41','望江南・忆江南','金德淑','宋','宋词','song-ci','望江南・忆江南','[]','春睡起，积雪满燕山。',64,'宋词/ci.song.18000.json','["春睡起，积雪满燕山。", "万里长城横玉带，六街灯火已阑珊，人立蓟楼间。", "空懊恼，独客此时还。", "辔压马头金错落，鞍笼驼背锦斓班。", "肠断唱门关。"]'),
('song-ci-42','望江南・忆江南','连妙淑','宋','宋词','song-ci','望江南・忆江南','[]','寒料峭，独立望长城。',64,'宋词/ci.song.18000.json','["寒料峭，独立望长城。", "木落萧萧天远大，□声羌管遏云行。", "归客若为情。", "樽酒尽，勒马问归程。", "渐近芦沟桥畔路，野墙荒驿夕阳明。", "长短几邮亭。"]'),
('song-ci-43','望江南・忆江南','黄静淑','宋','宋词','song-ci','望江南・忆江南','[]','君去也，晓出蓟门西。',64,'宋词/ci.song.18000.json','["君去也，晓出蓟门西。", "鲁酒千杯人不醉，臂鹰健卒马如飞。", "回首隔天涯。", "云黯黯，万里雪霏霏。", "料得江南人到早，水边篱落忽横枝。", "清兴少人知。"]'),
('song-ci-44','望江南・忆江南','陶明淑','宋','宋词','song-ci','望江南・忆江南','[]','秋夜永，月影上阑干。',64,'宋词/ci.song.18000.json','["秋夜永，月影上阑干。", "客枕梦回燕塞冷，角声吹彻五更寒。", "无语翠眉攒。", "天渐晚，把酒泪先弹。", "塞北江南千万里，别君容易见君难。", "何处是长安。"]'),
('song-ci-45','望江南・忆江南','柳华淑','宋','宋词','song-ci','望江南・忆江南','[]','何处笛，觉妾梦难谐。',64,'宋词/ci.song.18000.json','["何处笛，觉妾梦难谐。", "春色恼人眠不得，卷帘移步下香阶。", "呵冻卜金钗。", "人去也，毕竟信音乖。", "翠锁双蛾空宛转，雁行筝柱强安排。", "终是没情怀。"]'),
('song-ci-46','望江南・忆江南','杨慧淑','宋','宋词','song-ci','望江南・忆江南','[]','江北路，一望雪皑皑。',64,'宋词/ci.song.18000.json','["江北路，一望雪皑皑。", "万里打围鹰隼急，六军刁斗去还来。", "归客别金台。", "江北酒，一饮动千杯。", "客有黄金如粪土，薄情不肯赎奴回。", "挥泪洒黄埃。"]'),
('song-ci-47','望江南・忆江南','华清淑','宋','宋词','song-ci','望江南・忆江南','[]','燕塞雪，片片大如拳。',64,'宋词/ci.song.18000.json','["燕塞雪，片片大如拳。", "蓟上酒楼喧鼓吹，帝城车马走骈阗。", "羁馆独凄然。", "燕塞月，缺了又还圆。", "万里妾心愁更苦，十春和泪看婵娟。", "何日是归年。"]'),
('song-ci-48','望江南・忆江南','梅顺淑','宋','宋词','song-ci','望江南・忆江南','[]','风渐软，暖气满天涯。',64,'宋词/ci.song.18000.json','["风渐软，暖气满天涯。", "莫道穷阴春不透，今朝楼上见桃花。", "花外碾香车。", "围步帐，羯鼓杂琵琶。", "压酒燕妓骑细马，秋千高挂彩绳斜。", "知是阿谁家。"]'),
('song-ci-49','望江南・忆江南','吴昭淑','宋','宋词','song-ci','望江南・忆江南','[]','今夜永，说剑引杯长。',64,'宋词/ci.song.18000.json','["今夜永，说剑引杯长。", "坐拥地炉生石炭，灯前细雨好烧香。", "呵手理丝簧。", "君且住，烂醉又何妨。", "别后相思天万里，江南江北永相忘。", "真个断人肠。"]'),
('song-ci-50','望江南・忆江南','周容淑','宋','宋词','song-ci','望江南・忆江南','[]','春去也，白雪尚飘零。',64,'宋词/ci.song.18000.json','["春去也，白雪尚飘零。", "万里归人骑快马，到家时节藕花馨。", "那更忆长城。", "妾薄命，两鬓渐星星。", "忍唱乾淳供奉曲，断肠人听断肠声。", "肠断泪如倾。"]'),
('song-ci-51','霜天晓角','吴淑真','宋','宋词','song-ci','霜天晓角','[]','塞门桂月。',54,'宋词/ci.song.18000.json','["塞门桂月。", "蔡琰琴心切。", "弹到笳声悲处，千万恨、不能雪。", "愁绝。", "泪还北。", "更与胡儿别。", "一片关山怀抱，如何对、别人说。"]'),
('song-ci-52','满江红','张琼英','宋','宋词','song-ci','满江红','[]','太液芙蓉，浑不似、丹青颜色。',115,'宋词/ci.song.18000.json','["太液芙蓉，浑不似、丹青颜色。", "常记得、春风雨露，玉楼金阙。", "名播兰簪妃后里，晕生莲脸君王侧。", "忽一声、颦鼓拍天来，繁华歇。", "龙虎散，风云灭。", "千古恨，凭谁说。", "对山河百二，泪痕沾血。", "客馆夜惊尘土梦，宫车晓转关山月。", "问嫦娥、垂顾肯相容，同圆缺。"]'),
('song-ci-53','霓裳中序第一','詹玉','宋','宋词','song-ci','霓裳中序第一','[]','一规古蟾魄。',126,'宋词/ci.song.18000.json','["一规古蟾魄。", "瞥过宣和几春色。", "知那个、柳松花怯。", "曾磋玉团香，涂云抹月。", "龙章凤刻。", "是如何、儿女消得。", "便孤了、翠鸾何限，人更在天北。", "磨灭。", "古今难别。", "幸相从、蓟门仙客。", "萧然林下秋叶。", "对云淡星疏，眉青影白。", "佳人已倾国。", "赢得痴铜旧画。", "兴亡事，道人知否，见了也华发。"]'),
('song-ci-54','汉宫春','詹玉','宋','宋词','song-ci','汉宫春','[]','吟发萧萧。',118,'宋词/ci.song.18000.json','["吟发萧萧。", "正古槎秋入，河汉银涛。", "红云甚家院落，一片笙箫。", "晋时言语，问何人、还肯逍遥。", "知几度、落花啼鸟，乡歌犹在儿曹。", "游帷旧时明月，照满庭空翠，剪剪春梢。", "西山笑人底事，流浪宫袍。", "江湖近日，说神仙、多在渔樵。", "千古意，水沈香里，孤枫阴落重霄。"]'),
('song-ci-55','多丽','詹玉','宋','宋词','song-ci','多丽','[]','晚云归，小楼又作阴凉。',171,'宋词/ci.song.18000.json','["晚云归，小楼又作阴凉。", "霎儿间，恨桐招雨，西风叶叶商量。", "醒时心、又还南浦，愁边句、多在夕阳。", "菱碗笼青，莲瓶拖艳，旋倾花水咽茶香。", "怨蛩有、许多言语，说动软心肠。", "夜沈沈，几条凉月，界破晴窗。", "共绣帘吹絮未久，却孤剑水云乡。", "自家书、未能成字，邻家笛、且莫吹商。", "好梦偏悭，闲情未了，隔墙又唱秋娘。", "帕绡衣、旧时香折，戏封做书囊。", "鸳鸯字，见时千万，绣一双双。"]'),
('song-ci-56','桂枝香','詹玉','宋','宋词','song-ci','桂枝香','[]','紫薇花露，潇洒作凉云，点商勾羽。',124,'宋词/ci.song.18000.json','["紫薇花露，潇洒作凉云，点商勾羽。", "字字飞仙，下笔一帘风雨。", "江亭月观今如许。", "叹飘零、墨香千古。", "夕阳芳草，落花流水，依然南浦。", "甚两两、凌风驾虎。", "恁天孙标致，月娥眉妩。", "一笑生春，那学世间儿女。", "笔床砚滴曾窥处，有西山、青眼如故。", "素笺寄与，玉箫声彻，凤鸣鸾舞。"]'),
('song-ci-57','渡江云','詹玉','宋','宋词','song-ci','渡江云','[]','拖阴笼晚暝，商量清苦，阵阵打篷声。',124,'宋词/ci.song.18000.json','["拖阴笼晚暝，商量清苦，阵阵打篷声。", "分明都是泪，不道今宵，篷底有离人。", "松涛摇睡，梦不稳、难湿巫云。", "几点儿、泪痕跳响，休要醒时听。", "销魂。", "灯下无语，□泣梨花，掩重门夜永。", "应是添、伤春滋味，中酒心情。", "东风湖上香泥软，明日去、天色须晴。", "相见也，洛阳沽酒旗亭。"]'),
('song-ci-58','三姝媚','詹玉','宋','宋词','song-ci','三姝媚','["\u897f\u6e56"]','一篷儿别苦。',122,'宋词/ci.song.18000.json','["一篷儿别苦。", "是谁家、花天月地儿女。", "紫曲藏娇，惯锦窠金翠，玉璈锺吕。", "绮席传宣，笑声里、龙楼三鼓。", "歌扇题诗，舞袖笼香，几曾尘土。", "因甚留春不住。", "怎知道人间，匆匆今古。", "金屋银屏，被西风吹换，蓼汀苹渚。", "如此江山，应悔却、西湖歌舞。", "载取断云何处。", "江南烟雨。"]'),
('song-ci-59','一萼红','詹玉','宋','宋词','song-ci','一萼红','["\u897f\u6e56"]','泊沙河。',133,'宋词/ci.song.18000.json','["泊沙河。", "月钩儿挂浪，惊起两鱼梭。", "浅碧依痕，嫩凉生润，山色轻染修蛾。", "钓船在、绿杨阴下，蓦听得、扇底有吴歌。", "一段风情，西湖和靖，赤壁东坡。", "往事水流云去，叹山川良是，富贵人多。", "老树高低，疏星明淡，只有今古销磨。", "是几度、潮生潮落，甚人海、空只恁风波。", "闲著江湖尽宽，谁有渔蓑。"]'),
('song-ci-60','齐天乐','詹玉','宋','宋词','song-ci','齐天乐','[]','相逢唤醒金华梦，吴尘暗斑吟发。',123,'宋词/ci.song.18000.json','["相逢唤醒金华梦，吴尘暗斑吟发。", "倚担评花，认旗沽酒，历历行歌奇迹。", "吹香弄碧。", "又坡柳风情，逋梅月色。", "画鼓红船，满湖春水断桥客。", "当时何限怪侣，甚花天月地，人被云隔。", "却载苍烟，更招白鹭，一醉修江又别。", "今回记得。", "再折柳穿鱼，赏花催雪。", "如此湖山，忍教人更说。"]'),
('song-ci-61','阮郎归','詹玉','宋','宋词','song-ci','阮郎归','[]','斜河一道界相思。',56,'宋词/ci.song.18000.json','["斜河一道界相思。", "好秋都上眉。", "鸾笺象管写心啼。", "搦愁题做诗。", "添别恨，卜欢期。", "灯花红几时。", "看看月上小窗儿。", "夜香今夜迟。"]'),
('song-ci-62','八声甘州','詹玉','宋','宋词','song-ci','八声甘州','[]','从黄石容履，一编书，曾佐汉王关。',117,'宋词/ci.song.18000.json','["从黄石容履，一编书，曾佐汉王关。", "甚殷勤佳约，茹芝人共，引鹤差鸾。", "借手便成羽翼，方略正如闲。", "说道赤松去，还在人间。", "紫绶青春如许，是南辰尊宿，北斗天官。", "问沙堤早晚，喜色满长安。", "传宣能勾凤诏，便玉除前面领仙班。", "功名了，却茶烟琴月，慢慢东山。"]'),
('song-ci-63','桂枝香','詹玉','宋','宋词','song-ci','桂枝香','[]','沈云别浦。',123,'宋词/ci.song.18000.json','["沈云别浦。", "又何苦扁舟，青衫尘土。", "客里相逢，洒洒舌端飞雨。", "只今便把如伊吕。", "是当年、渔翁樵父。", "少知音者，苍烟吾社，白鸥吾侣。", "是如此英雄辛苦。", "知从前、几个适齐去鲁。", "一剑西风，大海鱼龙掀舞。", "自来多被清谈误。", "把刘琨、埋没千古。", "扣舷一笑，夕阳西下，大江东去。"]'),
('song-ci-64','浣溪沙','詹玉','宋','宋词','song-ci','浣溪沙','[]','淡淡青山两点春。',48,'宋词/ci.song.18000.json','["淡淡青山两点春。", "娇羞一点口见樱。", "一梭儿玉一纣云。", "白藕香中见西子。", "玉梅花下遇昭君。", "不曾真个也销魂。"]'),
('song-ci-65','庆清朝慢・庆清朝','詹玉','宋','宋词','song-ci','庆清朝慢・庆清朝','[]','红雨争妍，芳尘生润，将春都揉成泥。',121,'宋词/ci.song.18000.json','["红雨争妍，芳尘生润，将春都揉成泥。", "分明蕙风薇露，持搦花枝。", "款款汗酥薰透，娇羞无奈湿云痴。", "偏厮称，霓裳霞佩，玉骨冰肌。", "梅不似，兰不似，风流处，那更著意闻时。", "蓦地生绡扇底，嫩凉浮动好风微。", "醉得浑无气力，海棠一色睡胭脂。", "闲滋味，殢人花气，韩寿争知。"]'),
('song-ci-66','天香','王沂孙','宋','宋词','song-ci','天香','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','孤峤蟠烟，层涛蜕月，骊宫夜采铅水。',117,'宋词/ci.song.18000.json','["孤峤蟠烟，层涛蜕月，骊宫夜采铅水。", "讯远槎风，梦深薇露，化作断魂心字。", "红瓷候火，还乍识、冰环玉指。", "一缕萦帘翠影，依稀海天云气。", "几回殢娇半醉。", "翦春灯、夜寒花碎。", "更好故溪飞雪，小窗深闭。", "荀令如今顿老，总忘却、樽前旧风味。", "谩惜馀熏，空篝素被。"]'),
('song-ci-67','花犯','王沂孙','宋','宋词','song-ci','花犯','[]','古婵娟，苍鬟素靥，盈盈瞰流水。',126,'宋词/ci.song.18000.json','["古婵娟，苍鬟素靥，盈盈瞰流水。", "断魂十里。", "叹绀缕飘零，难系离思。", "故山岁晚谁堪寄。", "琅玕聊自倚。", "谩记我、绿蓑冲雪，孤舟寒浪里。", "三花两蕊破蒙茸，依依似有恨，明珠轻委。", "云卧稳，蓝衣正、护春憔悴。", "罗浮梦、半蟾挂晓，么凤冷、山中人乍起。", "又唤取、玉奴归去，馀香空翠被。"]'),
('song-ci-68','露华','王沂孙','宋','宋词','song-ci','露华','[]','绀葩乍坼。',111,'宋词/ci.song.18000.json','["绀葩乍坼。", "笑烂漫娇红，不是春色。", "换了素妆，重把青螺轻拂。", "旧歌共渡烟江，却占玉奴标格。", "风霜峭、瑶台种时，付与仙骨。", "闲门昼掩凄侧。", "似淡月梨花，重化清魄。", "尚带睡痕香凝，怎忍攀摘。", "嫩绿渐满溪阴，蔌蔌粉云飞出。", "芳艳冷、刘郎未应认得。"]'),
('song-ci-69','露华','王沂孙','宋','宋词','song-ci','露华','[]','晚寒伫立，记铅轻黛浅，初认冰魂。',115,'宋词/ci.song.18000.json','["晚寒伫立，记铅轻黛浅，初认冰魂。", "绀罗衬玉，犹凝茸唾香痕。", "净洗妒春颜色，胜小红、临水湔裙。", "烟渡远，应怜旧曲，换叶移根。", "山中去年人到，怪月悄风轻，闲掩重门。", "琼肌瘦损，那堪燕子黄昏。", "几片故溪浮玉，似夜归、深雪前村。", "芳梦冷，双禽误宿粉云。"]'),
('song-ci-70','南浦','王沂孙','宋','宋词','song-ci','南浦','[]','柳下碧粼粼，认麴尘乍生，色嫩如染。',125,'宋词/ci.song.18000.json','["柳下碧粼粼，认麴尘乍生，色嫩如染。", "清溜满银塘，东风细、参差縠纹初遍。", "别君南浦，翠眉曾照波痕浅。", "再来涨绿迷旧处，添却残红几片。", "葡萄过雨新痕，正拍拍轻鸥，翩翩小燕。", "帘影蘸楼阴，芳流去，应有泪珠千点。", "沧浪一舸，断魂重唱苹花怨。", "采香幽径鸳鸯睡，谁道湔裙人远。"]'),
('song-ci-71','南浦','王沂孙','宋','宋词','song-ci','南浦','[]','柳外碧连天，漾翠纹渐平，低蘸云影。',125,'宋词/ci.song.18000.json','["柳外碧连天，漾翠纹渐平，低蘸云影。", "应是雪初消，巴山路、蛾眉乍窥清镜。", "绿痕无际，几番漂荡江南恨。", "弄波素袜知甚处，空把落红流尽。", "何时橘里莼乡，泛一舸翩翩，东风归兴。", "孤梦绕沧浪，苹花岸、漠漠雨昏烟暝。", "连筒接缕，故溪深掩柴门静。", "只愁双燕衔芳去，拂破蓝光千顷。"]'),
('song-ci-72','声声慢','王沂孙','宋','宋词','song-ci','声声慢','[]','风声从臾，云意商量，连朝滕六迟疑。',119,'宋词/ci.song.18000.json','["风声从臾，云意商量，连朝滕六迟疑。", "茸帽貂裘，兔园准拟吟诗。", "红炉旋添兽炭，办金船、羔酒熔脂。", "问翦水，恁工夫犹未，还待何时。", "休被梅花争白，好夸奇斗巧，早遍琼枝。", "彩索金铃，佳人等塑狮儿。", "怕寒绣帏慵起，梦梨云、说与春知。", "莫误了，约王猷、船过剡溪。"]'),
('song-ci-73','高阳台','王沂孙','宋','宋词','song-ci','高阳台','[]','霜楮刳皮，冰花擘茧，满腔絮湿湘帘。',121,'宋词/ci.song.18000.json','["霜楮刳皮，冰花擘茧，满腔絮湿湘帘。", "抱瓮工夫，何须待吐吴蚕。", "水香玉色难裁翦，更绣针、茸线休拈。", "伴梅花，暗卷春风，斗帐孤眠。", "篝熏鹊锦熊毡。", "任粉融脂涴，犹怯痴寒。", "我睡方浓，笑他欠此清缘。", "揉来细软烘烘暖，尽何妨、挟纩装锦。", "酒魂醒，半榻梨云，起坐诗禅。"]'),
('song-ci-74','疏影','王沂孙','宋','宋词','song-ci','疏影','[]','琼妃卧月。',134,'宋词/ci.song.18000.json','["琼妃卧月。", "任素裳瘦损，罗带重结。", "石径春寒，碧藓参差，相思曾步芳屧。", "离魂分破东风恨，又梦入、水孤云阔。", "算如今、也厌娉婷，带了一痕残雪。", "犹记冰奁半掩，冷枝画未就，归棹轻折。", "几度黄昏，忽到窗前，重想故人初别。", "苍虬欲卷涟漪去，慢蜕却、连环香骨。", "早又是，翠荫蒙茸，一似一枝清绝。"]'),
('song-ci-75','无闷','王沂孙','宋','宋词','song-ci','无闷','[]','阴积龙荒，寒度雁门，西北高楼独倚。',122,'宋词/ci.song.18000.json','["阴积龙荒，寒度雁门，西北高楼独倚。", "怅短景无多，乱山如此。", "欲唤飞琼起舞，怕搅碎、纷纷银河水。", "冻云一片，藏花护玉，未教轻坠。", "清致。", "悄无似。", "有照水一枝，已搀春意。", "误几度凭栏，莫愁凝睇。", "应是梨花梦好，未肯放、东风来人世。", "待翠管、吹破苍茫，看取玉壶天地。"]'),
('song-ci-76','眉妩','王沂孙','宋','宋词','song-ci','眉妩','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','渐新痕悬柳，澹彩穿花，依约破初暝。',127,'宋词/ci.song.18000.json','["渐新痕悬柳，澹彩穿花，依约破初暝。", "便有团圆意，深深拜，相逢谁在香径。", "画眉未稳，料素娥、犹带离恨。", "最堪爱、一曲银钩小，宝帘挂秋冷。", "千古盈亏休问。", "叹慢磨玉斧，难补金镜。", "太液池犹在，凄凉处、何人重赋清景。", "故山夜永。", "试待他、窥户端正。", "看云外山河，还老尽、桂花影。"]'),
('song-ci-77','水龙吟','王沂孙','宋','宋词','song-ci','水龙吟','[]','晓寒慵揭珠帘，牡丹院落花开未。',126,'宋词/ci.song.18000.json','["晓寒慵揭珠帘，牡丹院落花开未。", "玉栏干畔，柳丝一把，和风半倚。", "国色微酣，天香乍染，扶春不起。", "自真妃舞罢，谪仙赋后，繁华梦、如流水。", "池馆家家芳事。", "记当时、买栽无地。", "争如一朵，幽人独对，水边竹际。", "把酒花前，剩拚醉了，醒来还醉。", "怕洛中、春色匆匆，又入杜鹃声里。"]'),
('song-ci-78','水龙吟','王沂孙','宋','宋词','song-ci','水龙吟','[]','世间无此娉婷，玉环未破东风睡。',126,'宋词/ci.song.18000.json','["世间无此娉婷，玉环未破东风睡。", "将开半敛，似红还白，馀花怎比。", "偏占年华，禁烟才过，夹衣初试。", "叹黄州一梦，燕宫绝笔，无人解、看花意。", "犹记华阴同醉。", "小阑干、月高人起。", "千枝媚色，一庭芳景，清寒似水。", "银烛延娇，绿房留艳，夜深花底。", "怕明朝、小雨濛濛，便化作燕支泪。"]'),
('song-ci-79','水龙吟','王沂孙','宋','宋词','song-ci','水龙吟','["\u6d1e\u5ead\u6e56"]','晓霜初著青林，望中故国凄凉早。',126,'宋词/ci.song.18000.json','["晓霜初著青林，望中故国凄凉早。", "萧萧渐积，纷纷犹坠，门荒径悄。", "渭水风生，洞庭波起，几番秋杪。", "想重崖半没，千峰尽出，山中路、无人到。", "前度题红杳杳。", "溯宫沟、暗流空绕。", "啼螀未歇，飞鸿欲过，此时怀抱。", "乱影翻窗，碎声敲砌，愁人多少。", "望吾庐甚处，只应今夜，满庭谁扫。"]'),
('song-ci-80','水龙吟','王沂孙','宋','宋词','song-ci','水龙吟','[]','淡妆不扫蛾眉，为谁伫立羞明镜。',126,'宋词/ci.song.18000.json','["淡妆不扫蛾眉，为谁伫立羞明镜。", "真妃解语，西施净洗，娉婷顾影。", "薄露初匀，纤尘不染，移根玉井。", "想飘然一叶，飕飕短发，中流卧、浮烟艇。", "可惜瑶台路迥。", "抱凄凉、月中难认。", "相逢还是，冰壶浴罢，牙床酒醒。", "步袜空留，舞裳微褪，粉残香冷。", "望海山依约，时时梦想，素波千顷。"]'),
('song-ci-81','水龙吟','王沂孙','宋','宋词','song-ci','水龙吟','[]','翠云遥拥环妃，夜深按彻霓裳舞。',126,'宋词/ci.song.18000.json','["翠云遥拥环妃，夜深按彻霓裳舞。", "铅华净洗，涓涓出浴，盈盈解语。", "太液荒寒，海山依约，断魂何许。", "甚人间、别有冰肌雪艳，娇无奈、频相顾。", "三十六陂烟雨。", "旧凄凉、向谁堪诉。", "如今谩说，仙姿自洁，芳心更苦。", "罗袜初停，玉珰还解，早凌波去。", "试乘风一叶，重来月底，与修花谱。"]'),
('song-ci-82','绮罗香','王沂孙','宋','宋词','song-ci','绮罗香','[]','屋角疏星，庭阴暗水，犹记藏鸦新树。',128,'宋词/ci.song.18000.json','["屋角疏星，庭阴暗水，犹记藏鸦新树。", "试折梨花，行人小阑深处。", "听粉片、簌簌飘阶，有人在、夜窗无语。", "料如今，门掩孤灯，画屏尘满断肠句。", "佳期浑似如水，还见梧桐几叶，轻敲朱户。", "一片秋声，应作两边愁绪。", "江路远、归雁无凭，写绣笺、倩谁将去。", "谩无聊，犹掩芳樽，醉听深夜雨。"]'),
('song-ci-83','绮罗香','王沂孙','宋','宋词','song-ci','绮罗香','[]','玉杵馀丹，金刀剩彩，重染吴江孤树。',128,'宋词/ci.song.18000.json','["玉杵馀丹，金刀剩彩，重染吴江孤树。", "几点朱铅，几度怨啼秋暮。", "惊旧梦、绿鬓轻凋，诉新恨、绛唇微注。", "最堪怜，同拂新霜，绣蓉一镜晚妆妒。", "千林摇落渐少，何事西风老色，争妍如许。", "二月残花，空误小车山路。", "重认取，流水荒沟，怕犹有、寄情芳语。", "但凄凉、秋苑斜阳，冷枝留醉舞。"]'),
('song-ci-84','绮罗香','王沂孙','宋','宋词','song-ci','绮罗香','[]','夜滴研朱，晨妆试酒，寒树偷分春艳。',128,'宋词/ci.song.18000.json','["夜滴研朱，晨妆试酒，寒树偷分春艳。", "赋冷吴江，一片试霜犹浅。", "惊汉殿、绛点初凝，认隋苑、彩枝重翦。", "问仙丹，炼熟何迟，少年色换已秋晚。", "疏枝频撼暮雨，消得西风几度，舞衣吹断。", "绿水荒沟，终是赋情人远。", "空一似、零落桃花，又等闲、误他刘阮。", "且留取，闲写幽情，石阑三四片。"]'),
('song-ci-85','齐天乐','王沂孙','宋','宋词','song-ci','齐天乐','[]','碧痕初化池塘草，荧荧野光相趁。',123,'宋词/ci.song.18000.json','["碧痕初化池塘草，荧荧野光相趁。", "扇薄星流，盘明露滴，零落秋原飞磷。", "练裳暗近。", "记穿柳生凉，度荷分暝。", "误我残编，翠囊空叹梦无准。", "楼阴时过数点，倚阑人未睡，曾赋幽恨。", "汉苑飘苔，秦陵坠叶，千古凄凉不尽。", "何人为省。", "但隔水馀晖，傍林残影。", "已觉萧疏，更堪秋夜永。"]'),
('song-ci-86','齐天乐','王沂孙','宋','宋词','song-ci','齐天乐','[]','绿槐千树西窗悄，厌厌昼眠惊起。',123,'宋词/ci.song.18000.json','["绿槐千树西窗悄，厌厌昼眠惊起。", "饮露身轻，吟风翅薄，半翦冰笺谁寄。", "凄凉倦耳。", "漫重拂琴丝，怕寻冠珥。", "短梦深宫，向人犹自诉憔悴。", "残虹收尽过雨，晚来频断续，都是秋意。", "病叶难留，纤柯易老，空忆斜阳身世。", "窗明月碎。", "甚已绝馀音，尚遗枯蜕。", "鬓影参差，断魂青镜里。"]'),
('song-ci-87','齐天乐','王沂孙','宋','宋词','song-ci','齐天乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','一襟馀恨宫魂断，年年翠阴庭树。',123,'宋词/ci.song.18000.json','["一襟馀恨宫魂断，年年翠阴庭树。", "乍咽凉柯，还移暗叶，重把离愁深诉。", "西窗过雨。", "怪瑶佩流空，玉筝调柱。", "镜暗妆残，为谁娇鬓尚如许。", "铜仙铅泪似洗，叹携盘去远，难贮零露。", "病翼惊秋，枯形阅世，消得斜阳几度。", "馀音更苦。", "甚独抱清高，顿成凄楚。", "谩想薰风，柳丝千万缕。"]'),
('song-ci-88','齐天乐','王沂孙','宋','宋词','song-ci','齐天乐','[]','冷烟残水山阴道，家家拥门黄叶。',123,'宋词/ci.song.18000.json','["冷烟残水山阴道，家家拥门黄叶。", "故里鱼肥，初寒雁落，孤艇将归时节。", "江南恨切。", "问还与何人，共歌新阙。", "换尽秋芳，想渠西子更愁绝。", "当时无限旧事，叹繁华似梦，如今休说。", "短褐临流，幽怀倚石，山色重逢都别。", "江云冻结。", "算只有梅花，尚堪攀折。", "寄取相思，一枝和夜雪。"]'),
('song-ci-89','齐天乐','王沂孙','宋','宋词','song-ci','齐天乐','[]','十洲三岛曾行处，离情几番凄惋。',123,'宋词/ci.song.18000.json','["十洲三岛曾行处，离情几番凄惋。", "坠叶重题，枯条旧折，萧飒那逢秋半。", "登临顿懒。", "更葵箑难留，苎衣将换。", "试语孤怀，岂无人与共幽怨。", "迟迟终是也别，算何如趁取，凉生江满。", "挂月催程，收风借泊，休忆征帆已远。", "山阴路畔。", "纵鸣壁犹蛩，过楼初雁。", "政恐黄花，笑人归较晚。"]'),
('song-ci-90','一萼红','王沂孙','宋','宋词','song-ci','一萼红','[]','思飘飘。',133,'宋词/ci.song.18000.json','["思飘飘。", "拥仙姝独步，明月照苍翘。", "花候犹迟，庭阴不扫，门掩山意萧条。", "抱芳恨、佳人分薄，似未许、芳魄化春娇。", "雨涩风悭，雾轻波细，湘梦迢迢。", "谁伴碧樽雕俎，笑琼肌皎皎，绿鬓萧萧。", "青凤啼空，玉龙舞夜，遥睇河汉光摇。", "未须赋、疏香淡影，且同倚、枯藓听吹箫。", "听久馀音欲绝，寒透鲛绡。"]'),
('song-ci-91','一萼红','王沂孙','宋','宋词','song-ci','一萼红','[]','玉婵娟。',133,'宋词/ci.song.18000.json','["玉婵娟。", "甚春馀雪尽，犹未跨青鸾。", "疏萼无香，柔条独秀，应恨流落人间。", "记曾照、黄昏淡月，渐瘦影、移上小阑干。", "一点清魂，半枝空色，芳意班班。", "重省嫩寒清晓，过断桥流水，问信孤山。", "冰粟微销，尘衣不浣，相见还误轻攀。", "未须讶、东南倦客，掩铅泪、看了又重看。", "故国吴天树老，雨过风残。"]'),
('song-ci-92','一萼红','王沂孙','宋','宋词','song-ci','一萼红','[]','占芳菲。',133,'宋词/ci.song.18000.json','["占芳菲。", "趁东风妩媚，重拂淡燕支。", "青凤衔丹，琼奴试酒，惊换玉质冰姿。", "甚春色、江南太早，有人怪、和雪杏花飞。", "藓佩萧疏，茜裙零乱，山意霏霏。", "空惹别愁无数，照珊瑚海影，冷月枯枝。", "吴艳离魂，蜀妖浥泪，孤负多少心期。", "岁寒事、无人共省，破丹雾、应有鹤归时。", "可惜鲛绡碎翦，不寄相思。"]'),
('song-ci-93','一萼红','王沂孙','宋','宋词','song-ci','一萼红','[]','翦丹云。',133,'宋词/ci.song.18000.json','["翦丹云。", "怕江皋路冷，千叠护清芬。", "弹泪绡单，凝妆枕重，惊认消瘦冰魂。", "为谁趁、东风换色，任绛雪、飞满绿罗裙。", "吴苑双身，蜀城高髻，忽到柴门。", "欲寄故人千里，恨燕支太薄，寂寞春痕。", "玉管难留，金樽易泣，几度残醉纷纷。", "谩重记、罗浮梦觉，步芳影、如宿杏花村。", "一树珊瑚淡月，独照黄昏。"]'),
('song-ci-94','一萼红','王沂孙','宋','宋词','song-ci','一萼红','[]','小庭深。',133,'宋词/ci.song.18000.json','["小庭深。", "有苍苔老树，风物似山林。", "侵户清寒，捎池急雨，时听飞过啼禽。", "扫荒径、残梅似雪，甚过了、人日更多阴。", "压酒人家，试灯天气，相次登临。", "犹记旧游亭馆，正垂杨引缕，嫩草抽簪。", "罗带同心，泥金半臂，花畔低唱轻斟。", "又争信、风流一别，念前事、空惹恨沈沈。", "野服山筇醉赏，不似如今。"]'),
('song-ci-95','解连环','王沂孙','宋','宋词','song-ci','解连环','[]','万珠悬碧。',130,'宋词/ci.song.18000.json','["万珠悬碧。", "想炎荒树密，□□□□。", "恨绛娣、先整吴帆，政鬟翠逞娇，故林难别。", "岁晚相逢，荐青子、独夸冰颊。", "点红盐乱落，最是夜寒，酒醒时节。", "霜槎猬芒冻裂。", "把孤花细嚼，时咽芳冽。", "断味惜、回涩馀甘，似重省家山，旧游风月。", "崖蜜重尝，到了输他清绝。", "更留人、绀丸半颗，素瓯泛雪。"]'),
('song-ci-96','三姝媚','王沂孙','宋','宋词','song-ci','三姝媚','[]','蓝缸花半绽。',122,'宋词/ci.song.18000.json','["蓝缸花半绽。", "正西窗凄凄，断萤新雁。", "别久逢稀，谩相看华发，共成销黯。", "总是飘零，更休赋、梨花秋苑。", "何况如今，离思难禁，俊才都减。", "今日山高江浅。", "又月落帆空，酒醒人远。", "彩袖乌纱，解愁人、惟有断歌幽婉。", "一信东风，再约看、红腮青眼。", "只恐扁舟西去，苹花弄晚。"]'),
('song-ci-97','三姝媚','王沂孙','宋','宋词','song-ci','三姝媚','[]','红缨悬翠葆。',122,'宋词/ci.song.18000.json','["红缨悬翠葆。", "渐金铃枝深，瑶阶花少。", "万颗燕支，赠旧情、争奈弄珠人老。", "扇底清歌，还记得、樊姬娇小。", "几度相思，红豆都销，碧丝空袅。", "芳意荼䕷开早。", "正夜色瑛盘，素蟾低照。", "荐笋同时，叹故园春事，已无多了。", "赠满筠笼，偏暗触、天涯怀抱。", "谩想青衣初见，花阴梦好。"]'),
('song-ci-98','庆清朝','王沂孙','宋','宋词','song-ci','庆清朝','[]','玉局歌残，金陵句绝，年年负却薰风。',117,'宋词/ci.song.18000.json','["玉局歌残，金陵句绝，年年负却薰风。", "西邻窈窕，独怜入户飞红。", "前度绿阴载酒，枝头色比舞裙同。", "何须拟，蜡珠作蒂，缃彩成丛。", "谁在旧家殿阁，自太真仙去，扫地春空。", "朱幡护取，如今应误花工。", "颠倒绛英满径，想无车马到山中。", "西风后，尚馀数点，还胜春浓。"]'),
('song-ci-99','庆宫春・高阳台','王沂孙','宋','宋词','song-ci','庆宫春・高阳台','[]','明玉擎金，纤罗飘带，为君起舞回雪。',126,'宋词/ci.song.18000.json','["明玉擎金，纤罗飘带，为君起舞回雪。", "柔影参差，幽芳零乱，翠围腰瘦一捻。", "岁华相误，记前度、湘皋怨别。", "哀弦重听，都是凄凉，未须弹彻。", "国香到此谁怜，烟冷沙昏，顿成愁绝。", "花恼难禁，酒销欲尽，门外冰澌初结。", "试招仙魄，怕今夜、瑶簪冻折。", "携盘独出，空想咸阳，故宫落月。"]'),
('song-ci-100','高阳台','王沂孙','宋','宋词','song-ci','高阳台','[]','残萼梅酸，新沟水绿，初晴节序暄妍。',122,'宋词/ci.song.18000.json','["残萼梅酸，新沟水绿，初晴节序暄妍。", "独立雕栏，谁怜枉度华年。", "朝朝准拟清明近，料燕翎、须寄银笺。", "又争知、一字相思，不到呤边。", "双蛾不拂青鸾冷，任花阴寂寂，掩户闲眠。", "屡卜佳期，无凭却恨金钱。", "何人寄与天涯信，趁东风、急整归船。", "纵飘零，满院杨花，犹是春前。"]'),
('song-ci-101','高阳台','王沂孙','宋','宋词','song-ci','高阳台','[]','驼褐轻装，狨鞯小队，冰河夜渡流澌。',122,'宋词/ci.song.18000.json','["驼褐轻装，狨鞯小队，冰河夜渡流澌。", "朔雪平沙，飞花乱拂蛾眉。", "琵琶已是凄凉调，更赋情、不比当时。", "想如今，人在龙庭，初劝金卮。", "一枝芳信应难寄，向山边水际，独抱相思。", "江雁孤回，天涯人自归迟。", "归来依旧秦淮碧，问此愁、还有谁知。", "对东风，空似垂杨，零乱千丝。"]'),
('song-ci-102','高阳台','王沂孙','宋','宋词','song-ci','高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','残雪庭阴，轻寒帘影，霏霏玉管春葭。',122,'宋词/ci.song.18000.json','["残雪庭阴，轻寒帘影，霏霏玉管春葭。", "小帖金泥，不知春在谁家。", "相思一夜窗前梦，奈个人、水隔天遮。", "但凄然，满树幽香，满地横斜。", "江南自是离愁苦，况游骢古道，归雁平沙。", "怎得银笺，殷勤与说年华。", "如今处处生芳草，纵凭高、不见天涯。", "更消他，几度东风，几度飞花。"]'),
('song-ci-103','扫花游・扫地游','王沂孙','宋','宋词','song-ci','扫花游・扫地游','[]','商飚乍发，渐淅淅初闻，萧萧还住。',117,'宋词/ci.song.18000.json','["商飚乍发，渐淅淅初闻，萧萧还住。", "顿惊倦旅。", "背青灯吊影，起吟愁赋。", "断续无凭，试立荒庭听取。", "在何许。", "但落叶满阶，惟有高树。", "迢递归梦阻。", "正老耳难禁，病怀凄楚。", "故山院宇。", "想边鸿孤唳，砌蛩私语。", "数点相和，更著芭蕉细雨。", "避无处。", "这闲愁、夜深尤苦。"]'),
('song-ci-104','扫花游・扫地游','王沂孙','宋','宋词','song-ci','扫花游・扫地游','[]','小庭荫碧，遇骤雨疏风，剩红如扫。',117,'宋词/ci.song.18000.json','["小庭荫碧，遇骤雨疏风，剩红如扫。", "翠交径小。", "问攀条弄蕊，有谁重到。", "谩说青青，比似花时更好。", "怎知道。", "□一别汉南，遗恨多少。", "清昼人悄悄。", "任密护帘寒，暗迷窗晓。", "旧盟误了。", "又新枝嫩子，总随春老。", "渐隔相思，极目长亭路杳。", "扰怀抱。", "听蒙茸、数声啼鸟。"]'),
('song-ci-105','扫花游・扫地游','王沂孙','宋','宋词','song-ci','扫花游・扫地游','[]','卷帘翠湿，过几阵残寒，几番风雨。',117,'宋词/ci.song.18000.json','["卷帘翠湿，过几阵残寒，几番风雨。", "问春住否。", "但匆匆暗里，换将花去。", "乱碧迷人，总是江南旧树。", "谩凝伫。", "念昔日采香，今更何许。", "芳径携酒处。", "又荫得青青，嫩苔无数。", "故林晚步。", "想参差渐满，野塘山路。", "倦枕闲床，正好微曛院宇。", "送凄楚。", "怕凉声、又催秋暮。"]'),
('song-ci-106','扫花游・扫地游','王沂孙','宋','宋词','song-ci','扫花游・扫地游','[]','满庭嫩碧，渐密叶迷窗，乱枝交路。',117,'宋词/ci.song.18000.json','["满庭嫩碧，渐密叶迷窗，乱枝交路。", "断红甚处。", "但匆匆换得，翠痕无数。", "暗影沈沈，静锁清和院宇。", "试凝伫。", "怕一点旧香，犹在幽树。", "浓阴知几许。", "且拂簟清眠，引筇闲步。", "杜郎老去。", "算寻芳较晚，倦怀难赋。", "纵胜花时，到了愁风怨雨。", "短亭暮。", "谩青青、怎遮春去。"]'),
('song-ci-107','锁窗寒・琐寒窗','王沂孙','宋','宋词','song-ci','锁窗寒・琐寒窗','[]','趁酒梨花，催诗柳絮，一窗春怨。',122,'宋词/ci.song.18000.json','["趁酒梨花，催诗柳絮，一窗春怨。", "疏疏过雨，洗尽满阶芳片。", "数东风、二十四番，几番误了西园宴。", "认小帘朱户，不如飞去，旧窠双燕。", "曾见。", "双蛾浅。", "自别后，多应黛痕不展。", "扑蝶花阴，怕看题诗团扇。", "试凭他、流水寄情，潮红不到春更远。", "但无聊、病酒厌厌，夜月荼縻院。"]'),
('song-ci-108','锁窗寒・琐寒窗','王沂孙','宋','宋词','song-ci','锁窗寒・琐寒窗','["\u897f\u6e56"]','料峭东风，廉纤细雨，落梅飞尽。',122,'宋词/ci.song.18000.json','["料峭东风，廉纤细雨，落梅飞尽。", "单衣恻恻，再整金猊香烬。", "误千红、试妆较迟，故园不似清明近。", "但满庭柳色，柔丝羞舞，淡黄犹凝。", "芳景。", "还重省。", "向薄晓窥帘，嫩阴敧枕。", "桐花渐老，已做一番风信。", "又看看、绿遍西湖，早催塞北归雁影。", "等归时、为带将归，并带江南恨。"]'),
('song-ci-109','锁窗寒・琐寒窗','王沂孙','宋','宋词','song-ci','锁窗寒・琐寒窗','[]','出谷莺迟，踏沙雁少，殢阴庭宇。',121,'宋词/ci.song.18000.json','["出谷莺迟，踏沙雁少，殢阴庭宇。", "东风似水，尚掩沈香双户。", "凭莓阶、雪痕乍铺，那回已趁飞梅去。", "奈柳边占得，一庭新暝，又还留住。", "前度。", "西园路。", "记半袖争持，斗娇眉妩。", "琼肌暗怯，醉立千红深处。", "问如今、山馆水村，共谁翠幄蕙炷。", "最难禁、向晚凄凉，化作梨花雨。"]'),
('song-ci-110','应天长','王沂孙','宋','宋词','song-ci','应天长','[]','疏帘蝶粉，幽径燕泥，花间小雨初足。',120,'宋词/ci.song.18000.json','["疏帘蝶粉，幽径燕泥，花间小雨初足。", "又是禁城寒食，轻舟泛晴渌。", "寻芳地，来去熟。", "尚彷佛、大堤南北。", "望杨柳、一片阴阴，摇曳新绿。", "重访艳歌人，听取春声，犹是杜郎曲。", "荡漾去年春色，深深杏花屋。", "东风曾共宿。", "记小刻、近窗新竹。", "旧游远，沈醉归来，满院银烛。"]'),
('song-ci-111','八六子','王沂孙','宋','宋词','song-ci','八六子','[]','扫芳林。',106,'宋词/ci.song.18000.json','["扫芳林。", "几番风雨，匆匆老尽春禽。", "渐薄润侵衣不断，嫩凉随扇初生。", "晚窗自吟。", "沈沈。", "幽径芳寻。", "暗霭苔香帘净，萧疏竹影庭深。", "谩淡却蛾眉，晨妆慵扫，宝钗虫散，绣屏鸾破，当时暗水和云泛酒，空山留月听琴。", "料如今。", "门前数重翠阴。"]'),
('song-ci-112','摸鱼儿','王沂孙','宋','宋词','song-ci','摸鱼儿','[]','洗芳林、夜来风雨。',140,'宋词/ci.song.18000.json','["洗芳林、夜来风雨。", "匆匆还送春去。", "方才送得春归了，那又送君南浦。", "君听取。", "怕此际、春归也过吴中路。", "君行到处。", "便快折湖边，千条翠柳，为我系春住。", "春还住。", "休索吟春伴侣。", "残花今已尘土。", "姑苏台下烟波远，西子近来何许。", "能唤否。", "又恐怕、残春到了无凭据。", "烦君妙语。", "更为我将春，连花带柳，写入翠笺句。"]'),
('song-ci-113','摸鱼儿','王沂孙','宋','宋词','song-ci','摸鱼儿','[]','玉帘寒、翠痕微断，浮空清影零碎。',140,'宋词/ci.song.18000.json','["玉帘寒、翠痕微断，浮空清影零碎。", "碧芽也抱春洲怨，双卷小缄芳字。", "还又似。", "系罗带相思，几点青钿缀。", "吴中旧事。", "怅酪乳争奇，鲈鱼谩好，谁与共秋醉。", "江湖兴，昨夜西风又起。", "年年轻误归计。", "如今不怕归无准，却怕故人千里。", "何况是。", "正落日垂虹，怎赋登临意。", "沧浪梦里。", "纵一舸重游，孤怀暗老，馀恨渺烟水。"]'),
('song-ci-114','声声慢','王沂孙','宋','宋词','song-ci','声声慢','[]','啼螀门静，落叶阶深，秋声又入吾庐。',119,'宋词/ci.song.18000.json','["啼螀门静，落叶阶深，秋声又入吾庐。", "一枕新凉，西窗晚两疏疏。", "旧香旧色换却，但满川、残柳荒蒲。", "茂陵远，任岁华苒苒，老尽相如。", "昨夜西风初起，想莼边呼棹，桔后思书。", "短景凄然，残歌共叩铜壶。", "当时送行共约，雁归时、人赋归欤。", "雁归也，问人归、如雁也无。"]'),
('song-ci-115','声声慢','王沂孙','宋','宋词','song-ci','声声慢','[]','高寒户牖，虚白尊罍，千山尽入孤光。',119,'宋词/ci.song.18000.json','["高寒户牖，虚白尊罍，千山尽入孤光。", "玉影如空，天葩暗落清香。", "平生此兴不浅，记当年、独据胡床。", "怎知道，是岁华换却，处处堪伤。", "已是南楼曲断，纵疏花淡月，也只凄凉。", "冷雨斜风，何况独掩西窗。", "天涯故人总老，谩相思、永夜相望。", "断梦远，趁秋声、一片渡江。"]'),
('song-ci-116','声声慢','王沂孙','宋','宋词','song-ci','声声慢','[]','迎门高髻，倚扇清吭，娉婷未数西州。',119,'宋词/ci.song.18000.json','["迎门高髻，倚扇清吭，娉婷未数西州。", "浅拂朱铅，春风二月梢头。", "相逢靓妆俊语，有旧家、京洛风流。", "断肠句，试重拈彩笔，与赋闲愁。", "犹记凌波欲去，问明珰罗袜，却为谁留。", "枉梦相思，几回南浦行舟。", "莫辞玉樽起舞，怕重来、燕子空楼。", "谩惆怅，抱琵琶、闲过此秋。"]'),
('song-ci-117','金盏子','王沂孙','宋','宋词','song-ci','金盏子','[]','雨叶吟蝉，露草流萤，岁华将晚。',122,'宋词/ci.song.18000.json','["雨叶吟蝉，露草流萤，岁华将晚。", "对静夜无眠，稀星散、时度绛河清浅。", "甚处画角凄凉，引轻寒催燕。", "西楼外，斜月未沈，风急雁行吹断。", "此际怎消遣。", "要相见、除非待梦见。", "盈盈洞房泪眼，看人似、冷落过秋纨扇。", "痛惜小院桐阴，空啼鸦零乱。", "厌厌地，终日为伊，香愁粉怨。"]'),
('song-ci-118','更漏子','王沂孙','宋','宋词','song-ci','更漏子','[]','日衔山，山带雪。',58,'宋词/ci.song.18000.json','["日衔山，山带雪。", "笛弄晚风残月。", "湘梦断，楚魂迷。", "金河秋雁飞。", "别离心，思忆泪。", "锦带已伤憔悴。", "蛩韵急，杵声寒。", "征衣不用宽。"]'),
('song-ci-119','锦堂春・锦堂春慢','王沂孙','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','桂嫩传香，榆高送影，轻罗小扇凉生。',118,'宋词/ci.song.18000.json','["桂嫩传香，榆高送影，轻罗小扇凉生。", "正鸳机梭静，凤渚桥成。", "穿线人来月底，曝衣花入风庭。", "看星残靥碎，露滴珠融，笑掩云扃。", "彩盘凝望仙子，但三星隐隐，一水盈盈。", "暗想恁肩私语，鬓乱钗横。", "蛛网飘丝罥恨，玉签传点催明。", "算人间待巧，似恁匆匆，有甚心情。"]'),
('song-ci-120','青房并蒂莲','王沂孙','宋','宋词','song-ci','青房并蒂莲','[]','醉凝眸。',126,'宋词/ci.song.18000.json','["醉凝眸。", "是楚天秋晓，湘岸云收。", "草绿兰红，浅浅小汀洲。", "芰荷香里鸳鸯浦，恨菱歌、惊起眠鸥。", "望去帆，一片孤光，棹声伊轧橹声柔。", "愁窥汴堤翠柳，曾舞送当时，锦缆龙舟。", "拥倾国、纤腰皓齿，笑倚迷楼。", "空令五湖夜月，也羞照、三十六宫秋。", "正朗吟，不觉回桡，水花枫叶两悠悠。"]'),
('song-ci-121','锦堂春・锦堂春慢','王沂孙','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','露掌秋深，花签漏永，那堪此夕新晴。',115,'宋词/ci.song.18000.json','["露掌秋深，花签漏永，那堪此夕新晴。", "正纤尘飞尽，万籁无声。", "金镜开奁弄影，玉壶盛水侵棱。", "纵帘斜树隔，烛暗花残，不碍虚明。", "美人凝恨歌黛，念径年间阻，只恐云生。", "早是宫鞋鸳小，翠鬓蝉轻。", "蟾润妆梅夜发，桂熏仙骨香清。", "看姮蛾此际，多情又似无情。"]'),
('song-ci-122','如梦令','王沂孙','宋','宋词','song-ci','如梦令','[]','妾似春蚕抽缕。',40,'宋词/ci.song.18000.json','["妾似春蚕抽缕。", "君似筝弦移柱。", "无语结同心，满地落花飞絮。", "归去。", "归去。", "遥指乱云遮处。"]'),
('song-ci-123','醉蓬莱','王沂孙','宋','宋词','song-ci','醉蓬莱','[]','扫西风门径，黄叶凋零，白云萧散。',120,'宋词/ci.song.18000.json','["扫西风门径，黄叶凋零，白云萧散。", "柳换枯阴，赋归来何晚。", "爽气霏霏，翠蛾眉妩，聊慰登临眼。", "故国如尘，故人如梦，登高还懒。", "数点寒英，为谁零落，楚魄难招，暮寒堪揽。", "步屧荒篱，谁念幽芳远。", "一室秋灯，一庭秋雨，更一声秋雁。", "试引芳樽，不知消得，几多依黯。"]'),
('song-ci-124','法曲献仙音','王沂孙','宋','宋词','song-ci','法曲献仙音','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','层绿峨峨，纤琼皎皎，倒压波痕清浅。',113,'宋词/ci.song.18000.json','["层绿峨峨，纤琼皎皎，倒压波痕清浅。", "过眼年华，动人幽意，相逢几番春换。", "记唤酒寻芳处，盈盈褪妆晚。", "已销黯。", "况凄凉、近来离思，应忘却、明月夜深归辇。", "荏苒一枝春，恨东风、人似天远。", "纵有残花，洒征衣、铅泪都满。", "但殷勤折取，自遣一襟幽怨。"]'),
('song-ci-125','淡黄柳','王沂孙','宋','宋词','song-ci','淡黄柳','[]','花边短笛。',79,'宋词/ci.song.18000.json','["花边短笛。", "初结孤山约。", "雨悄风轻寒漠漠。", "翠镜秦鬟钗别，同折幽芳怨摇落。", "素裳薄。", "重拈旧红萼。", "叹携手、转离索。", "料青禽、一梦春无几，后夜相思，素蟾低照，谁扫花阴共酌。"]'),
('song-ci-126','长亭怨・长亭怨慢','王沂孙','宋','宋词','song-ci','长亭怨・长亭怨慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','泛孤艇、东皋过遍。',121,'宋词/ci.song.18000.json','["泛孤艇、东皋过遍。", "尚记当日，绿阴门掩。", "屐齿莓阶，酒痕罗袖事何限。", "欲寻前迹，空惆怅、成秋苑。", "自约赏花人，别后总、风流云散。", "水远。", "怎知流水外，却是乱山尤远。", "天涯梦短。", "想忘了、绮疏雕槛。", "望不尽、苒苒斜阳，抚乔木、年华将晚。", "但数点红英，犹识西园凄婉。"]'),
('song-ci-127','西江月','王沂孙','宋','宋词','song-ci','西江月','[]','褪粉轻盈琼靥，护香重叠冰绡。',58,'宋词/ci.song.18000.json','["褪粉轻盈琼靥，护香重叠冰绡。", "数枝谁带玉痕描。", "夜夜东风不扫。", "溪上横斜影淡，梦中落莫魂销。", "峭寒未肯放春娇。", "素被独眠清晓。"]'),
('song-ci-128','踏莎行','王沂孙','宋','宋词','song-ci','踏莎行','[]','白石飞仙，紫霞凄调。',68,'宋词/ci.song.18000.json','["白石飞仙，紫霞凄调。", "断歌人听知音少。", "几番幽梦欲回时，旧家池馆生青草。", "风月交游，山川怀抱。", "凭谁说与春知道。", "空留离恨满江南，相思一夜苹花老。"]'),
('song-ci-129','醉落魄・一斛珠','王沂孙','宋','宋词','song-ci','醉落魄・一斛珠','[]','小窗银烛。',67,'宋词/ci.song.18000.json','["小窗银烛。", "轻鬟半拥钗横玉。", "数声春调清真曲。", "拂拂朱帘，残影乱红扑。", "垂杨学画蛾眉绿。", "年年芳草迷金谷。", "如今休把佳期卜。", "一掬春情，斜月杏花屋。"]'),
('song-ci-130','醉落魄・一斛珠','王沂孙','宋','宋词','song-ci','醉落魄・一斛珠','[]','揉碎花心，吟碎淡黄雪。',11,'宋词/ci.song.18000.json','["揉碎花心，吟碎淡黄雪。"]'),
('song-ci-131','霜天晓角','王沂孙','宋','宋词','song-ci','霜天晓角','[]','翠簟一池秋水，半床露、半床月。',15,'宋词/ci.song.18000.json','["翠簟一池秋水，半床露、半床月。"]'),
('song-ci-132','谒金门','王沂孙','宋','宋词','song-ci','谒金门','[]','恰似断魂江上柳，越春深越瘦。',14,'宋词/ci.song.18000.json','["恰似断魂江上柳，越春深越瘦。"]'),
('song-ci-133','失调名','王沂孙','宋','宋词','song-ci','失调名','[]','挑云研雪。',5,'宋词/ci.song.18000.json','["挑云研雪。"]'),
('song-ci-134','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','望湖天。',32,'宋词/ci.song.18000.json','["望湖天。", "望湖天。", "绿杨深处鼓鼘鼘。", "好是年年三二月，湖边日日看划船。"]'),
('song-ci-135','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','斗轻桡。',32,'宋词/ci.song.18000.json','["斗轻桡。", "斗轻桡。", "雪中花卷棹声摇。", "天与玻璃三万顷，尽教看得几吴舠。"]'),
('song-ci-136','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','看龙舟。',32,'宋词/ci.song.18000.json','["看龙舟。", "看龙舟。", "两堤未斗水悠悠。", "一片笙歌催闹晚，忽然鼓棹起中流。"]'),
('song-ci-137','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','贺灵鼍。',32,'宋词/ci.song.18000.json','["贺灵鼍。", "贺灵鼍。", "几年翠舞与珠歌。", "看到日斜犹未足，涌金门外涌金波。"]'),
('song-ci-138','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','马如龙。',32,'宋词/ci.song.18000.json','["马如龙。", "马如龙。", "飞过苏堤健斗风。", "柳下系船青作缆，湖边荐酒碧为筒。"]'),
('song-ci-139','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','绣周张。',32,'宋词/ci.song.18000.json','["绣周张。", "绣周张。", "楼台帘幕絮高扬。", "谁赋珠宫并贝阙，怀王去后去沈湘。"]'),
('song-ci-140','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','棹如飞。',32,'宋词/ci.song.18000.json','["棹如飞。", "棹如飞。", "水中万鼓起潜螭。", "最是玉莲堂上好，跃来夺锦看吴儿。"]'),
('song-ci-141','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','建云斿。',32,'宋词/ci.song.18000.json','["建云斿。", "建云斿。", "土风到处总相犹。", "朝了霍山朝岳帝，十分打扮是杭州。"]'),
('song-ci-142','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','踏青青。',32,'宋词/ci.song.18000.json','["踏青青。", "踏青青。", "西泠桥畔草连汀。", "扑得龙船儿一对，画阑倚遍看游人。"]'),
('song-ci-143','潇湘神','黄公绍','宋','宋词','song-ci','潇湘神','[]','月明中。',32,'宋词/ci.song.18000.json','["月明中。", "月明中。", "满湖春水望难穷。", "欲学楚歌歌不得，一场离恨两眉峰。"]'),
('song-ci-144','满江红','黄公绍','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','客子光阴，又还是、杏花阡陌。',115,'宋词/ci.song.18000.json','["客子光阴，又还是、杏花阡陌。", "敧枕听、一窗夜雨，怎生禁得。", "银蜡痕消珠凤小，翠衾香冷文鸳拆。", "叹人生、时序百年心，萍踪迹。", "声不断，楼头滴。", "行不住，街头屐。", "倩新来双燕，探晴消息。", "可煞东君多著意，柳丝染出西湖色。", "待牡丹、开处十分春，催寒食。"]'),
('song-ci-145','念奴娇','黄公绍','宋','宋词','song-ci','念奴娇','[]','山围宽碧，月十分圆满，十分春暮。',120,'宋词/ci.song.18000.json','["山围宽碧，月十分圆满，十分春暮。", "匹似涌金门外看，添得绿阴佳树。", "野阔星垂，天高云敛，不受红尘污。", "徘徊水影，闲中自有佳处。", "乘兴著我扁舟，山阴夜色，渺渺流光溯。", "望美人兮天一角，我欲凌风飞去。", "世事浮沈，人生圆缺，得似烟波趣。", "兴怀赤壁，大江千古东注。"]'),
('song-ci-146','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，去上竹山窠。',32,'宋词/ci.song.18000.json','["思晴好，去上竹山窠。", "自古常言光霁好，如今却恨雨声多。", "奈此坐愁何。"]'),
('song-ci-147','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，试卜那朝晴。',32,'宋词/ci.song.18000.json','["思晴好，试卜那朝晴。", "古木荒村云淰淰，孤灯败壁夜冥冥。", "不寐听檐声。"]'),
('song-ci-148','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，小驻岂无因。',32,'宋词/ci.song.18000.json','["思晴好，小驻岂无因。", "花上半旬春社雨，松间三宿暮山云。", "转住是愁人。"]'),
('song-ci-149','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，春透海棠枝。',32,'宋词/ci.song.18000.json','["思晴好，春透海棠枝。", "刻惜许多过时了，可怜生是我来迟。", "不见软红时。"]'),
('song-ci-150','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，天运几乘除。',32,'宋词/ci.song.18000.json','["思晴好，天运几乘除。", "祗为晴多还又雨，谁知雨过是晴初。", "那得绿阴乎。"]'),
('song-ci-151','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，路滑少人行。',32,'宋词/ci.song.18000.json','["思晴好，路滑少人行。", "早信雨能留得住，尽教尽日自舟横。", "直等到清明。"]'),
('song-ci-152','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，我欲问花神。',32,'宋词/ci.song.18000.json','["思晴好，我欲问花神。", "刚道社公瞋旧水，一回旧也一回新。", "不是雨般春。"]'),
('song-ci-153','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，松路翠光寒。',32,'宋词/ci.song.18000.json','["思晴好，松路翠光寒。", "夜夜竹窠常梦到，天天后土几时乾。", "极目雾漫漫。"]'),
('song-ci-154','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，日影漏些儿。',32,'宋词/ci.song.18000.json','["思晴好，日影漏些儿。", "油菜花间蝴蝶舞，刺桐枝上鹁鸠啼。", "闲坐看春犁。"]'),
('song-ci-155','望江南・忆江南','黄公绍','宋','宋词','song-ci','望江南・忆江南','[]','思晴好，晨起望篱东。',32,'宋词/ci.song.18000.json','["思晴好，晨起望篱东。", "毕竟阴晴排日子，大都行止听天公。", "且住此山中。"]'),
('song-ci-156','花犯','黄公绍','宋','宋词','song-ci','花犯','[]','翠奁空、红鸾蘸影，嫣然弄妆晚。',126,'宋词/ci.song.18000.json','["翠奁空、红鸾蘸影，嫣然弄妆晚。", "雾鬟低颤。", "飞嫩藕仙裳，清思无限。", "象床试锦新翻样，金屏连绣展。", "最好似、阿环娇困，云酣春帐暖。", "寻思水边赋娟娟，新霜□旧约，西风庭院。", "肠断处，秋江上、彩云轻散。", "凭谁向、一筝过雁。", "细说与、眉心杨柳怨。", "且趁此、菊花天气，年年寻醉伴。"]'),
('song-ci-157','喜迁莺','黄公绍','宋','宋词','song-ci','喜迁莺','[]','乱红飞雨。',125,'宋词/ci.song.18000.json','["乱红飞雨。", "怅春心一似，腾腾闷暑。", "密绾柔情，暗传芳意，人在垂杨深宇。", "晓雪一帘幽梦，半点檀心知否。", "春不管，想粉香凝泪，翠颦含趣。", "谁念芳径小，新绿笺笺，问讯今何许。", "玉冷钗头，罗宽带眼，缥缈青鸾难遇。", "望断碧云深处，倚遍画阑将暮。", "空惆怅，更江头桃叶，溜横波渡。"]'),
('song-ci-158','汉宫春','黄公绍','宋','宋词','song-ci','汉宫春','[]','身到瑶池。',118,'宋词/ci.song.18000.json','["身到瑶池。", "正□永芙蓉，跕素鸾飞。", "绿云淡笼波面，鸳影差差。", "青冥世界，向龙宫、涌出江妃。", "凝望久，夜凉如水，人间惆怅芳时。", "池上方壶仙伯，是珊珊月佩，绰棹冰肌。", "重来碧环胜处，笑引琼卮。", "谁歌白雪，坐中客、赛过玄晖。", "醉归也，玉绳低转，晓风轻拂荷衣。"]'),
('song-ci-159','莺啼序','黄公绍','宋','宋词','song-ci','莺啼序','[]','银云卷晴缥缈，卧长龙一带。',292,'宋词/ci.song.18000.json','["银云卷晴缥缈，卧长龙一带。", "柳丝蘸、几簇柔烟，两市帘栋如画。", "芳草岸、弯环半玉，鳞鳞曲港双流会。", "看碧天连水，翻成箭样风快。", "白露横江，一苇万顷，问灵槎何在。", "空翠湿衣不胜寒，日华金掌沆瀣。", "甃花平、绿文衬步，琼田涌出神仙界。", "黛眉修，依约雾鬟，在秋波外。", "阁嘘青蜃，楼啄彩虹，飞盖蹴鳌背。", "灯火暮，相轮倒影，偷睇别浦，片片归帆，远自天际。", "舞蛟幽壑，栖鸦古木，有人翦取松江水，忆细鳞巨口鱼堪鲙。", "波涵笠泽，时见静影浮光，霏阴万貌千态。", "蒹葭深处，应有闲鸥，寄语休见怪。", "倩洗却、香红尘面，买个扁舟，身世飘萍，名利微芥。", "阑干拍遍，除东曹掾，与天随子是我辈，尽胸中、著得乾坤大。", "亭前无限惊涛，总把遥吟，月明满载。"]'),
('song-ci-160','明月棹孤舟・夜行船','黄公绍','宋','宋词','song-ci','明月棹孤舟・夜行船','[]','雁带愁来寒事早。',67,'宋词/ci.song.18000.json','["雁带愁来寒事早。", "西风把鬓华吹老。", "猛省中秋，都来几日，先自木樨开了。", "淰淰轻阴天弄晓。", "平白地、被花相恼。", "一枕云闲，半窗秋晓，时有阵香吹到。"]'),
('song-ci-161','踏莎行','黄公绍','宋','宋词','song-ci','踏莎行','[]','蟾苑萧疏，云岩芳馥。',68,'宋词/ci.song.18000.json','["蟾苑萧疏，云岩芳馥。", "仙娥寄种来溪曲。", "晓烟薰上古龙涎，西风展破黄金粟。", "庾岭未梅，陶园休菊。", "天教占取清香独。", "胆瓶枕畔两三枝，梦回疑在瑶台宿。"]'),
('song-ci-162','洞仙歌','黄公绍','宋','宋词','song-ci','洞仙歌','[]','银菟分竹，是君王亲付。',100,'宋词/ci.song.18000.json','["银菟分竹，是君王亲付。", "州在扶舆最清处。", "紫云楼、记取天语丁宁，襦绔手，好好为吾摩拊。", "望公如望月，见说郴江，父老多时问来暮。", "旌旆试初凉，紫马西来，青丝络、秋风满路。", "早桔井丹成入仙班，有乔木前芳，事须公做。"]'),
('song-ci-163','喜迁莺','黄公绍','宋','宋词','song-ci','喜迁莺','[]','世情冰尽。',126,'宋词/ci.song.18000.json','["世情冰尽。", "算耐久祗是，陇头芳信。", "惆怅人间，几千年□，留得陆郎馀韵。", "朔云解识花意，遮断疏狂蝶粉。", "岁寒了，狂风传香远，月移影近。", "清润。", "无点涴，不曰坚乎，如玉真难尽。", "除宋广平，与林和靖，肉眼有谁能认。", "仙丰道骨如许，相对霜髯雪鬓。", "长健也，好年年管领，春光随分。"]'),
('song-ci-164','凤凰台上忆吹箫','彭履道','宋','宋词','song-ci','凤凰台上忆吹箫','[]','劝客新楼，鸣筝上酒，夜凉人爱秋深。',118,'宋词/ci.song.18000.json','["劝客新楼，鸣筝上酒，夜凉人爱秋深。", "何似过、赏心佳处，依约湖阴。", "东望寒光缥缈，烟水阔、短笛销沈。", "阑干近，胜时种柳，清到如今。", "凌波又成误约，自佩环飞去，暗想遗音。", "重省江城倦客，醉拥秋衾。", "谁家一掬红泪，孤雁远、湿逗罗襟。", "石城晓，数声又递寒砧。"]'),
('song-ci-165','兰陵王','彭履道','宋','宋词','song-ci','兰陵王','[]','章台路。',157,'宋词/ci.song.18000.json','["章台路。", "西出重城几步。", "秦楼晓、花气未明，一霎空濛洗高树。", "行人半倚户。", "飞去黄鹂自语。", "秋千小，不系柳条，惟有轻阴约飞絮。", "钿车暗相遇。", "早拂拭红巾，初放鹦鹉。", "闻歌犹是淋铃处。", "掩面鸣筝，倚垆呼酒，东风重记旧眉妩。", "报伊共歌舞。", "西去。", "屡回顾。", "渐客舍荒凉，嘶马先驻。", "玉关万里知何许。", "但倦拥荒泽，瓜洲难渡。", "将军垂老，望故国，夜寒苦。"]'),
('song-ci-166','疏影','彭履道','宋','宋词','song-ci','疏影','[]','银云缥缈。',132,'宋词/ci.song.18000.json','["银云缥缈。", "正石梁倒挂，飞下晴昊。", "早挽悬河，高泻鲸宫，洪声百步低小。", "分明仙仗崆峒过，又化作，归帆杳杳。", "倚参差，翠影红霞，远落明湖残照。", "曾共呼龙夭矫。", "几回过月下，先种瑶草。", "九叠屏风，青鸟冥冥，更约谪仙重到。", "昨梦骑黄鹄，飞不去、和天也笑。", "等恁时、秋夜携琴，已落洞天霜晓。"]'),
('song-ci-167','摸鱼儿','韦居安','宋','宋词','song-ci','摸鱼儿','[]','绕苕城、水平坡渺，双明遥睇无际。',140,'宋词/ci.song.18000.json','["绕苕城、水平坡渺，双明遥睇无际。", "就中惟有鱼湾好，占得西关佳致。", "杨柳外、羡泛宅浮家，当日元真子。", "溪山信美。", "叹陈迹犹存，前贤已往，谁会景中意。", "萧闲甚，筑屋三间近水。", "汀洲香泛兰芷。", "清风明月知多少，肯滞软红尘里。", "垂钓饵。", "这春水生时，剩有桃花鳜。", "烦襟净洗。", "待办取轻蓑，来分半席，相对弄清泚。"]'),
('song-ci-168','唱金缕・贺新郎','柴元彪','宋','宋词','song-ci','唱金缕・贺新郎','[]','春到云中早。',142,'宋词/ci.song.18000.json','["春到云中早。", "恰梅花、雪后□□，锁窗寒悄。", "鼓吹喧天灯市闹，在处鳌山蓬岛。", "正新岁、金鸡唱晓。", "一点魁星光焰里，这水晶、庭院知多少。", "鸣凤舞，洞箫袅。", "太平官府人嘻笑。", "道紫微、魁星聚会，参差联照。", "借地栽花河阳县，桃李芳菲正好。", "暖沁入、东风池沼。", "百里楼台天不夜，看祥烟、瑞谒相缭绕。", "生意满，翠庭草。"]'),
('song-ci-169','水龙吟','柴元彪','宋','宋词','song-ci','水龙吟','[]','秋云元自无心，那曾系得归心住。',126,'宋词/ci.song.18000.json','["秋云元自无心，那曾系得归心住。", "阳关酒尽，灞桥人远，也须别去。", "□□□□，□□□□，□□□□。", "有哀雁声声，愁蛩切切，悄悄地、听人语。", "回首琵琶旧恨，叹西风、□兴如许。", "江左百年，风流云散，不堪重举。", "怎得归来，樵歌互答，自相容与。", "又何须□□，三五蟾光，重阳风雨。"]'),
('song-ci-170','踏莎行','柴元彪','宋','宋词','song-ci','踏莎行','[]','浅柳平芜，乱烟疏雨。',68,'宋词/ci.song.18000.json','["浅柳平芜，乱烟疏雨。", "雁声叫彻芦花渚。", "亭前落叶又西风，断送离怀无著处。", "切切归期，盈盈尺素。", "断魂正在西兴渡。", "满船空载暮愁来，潮头一吼推将去。"]'),
('song-ci-171','蝶恋花','柴元彪','宋','宋词','song-ci','蝶恋花','[]','去年走马章台路。',70,'宋词/ci.song.18000.json','["去年走马章台路。", "送酒无人，寂寞黄花雨。", "又是重阳秋欲暮。", "西风此恨谁分付。", "无限归心归不去。", "却梦佳人，约我花间住。", "蓦地觉来无觅处。", "雁声叫断潇湘浦。"]'),
('song-ci-172','苏幕遮','柴元彪','宋','宋词','song-ci','苏幕遮','[]','晚晴初，斜照里。',76,'宋词/ci.song.18000.json','["晚晴初，斜照里。", "远水连天，天外帆千里。", "百尺高楼谁独倚。", "滴落梧桐，一片相思泪。", "马又嘶，风又起。", "断续寒砧，又送黄昏至。", "明月照人人不睡。", "愁雁声声，更切愁人耳。"]'),
('song-ci-173','海棠春','柴元彪','宋','宋词','song-ci','海棠春','[]','阳关可是登高路。',58,'宋词/ci.song.18000.json','["阳关可是登高路。", "算到底、不如归去。", "时节近中秋，那更黄花雨。", "酒病恹恹，羁愁缕缕。", "且是没人分诉。", "何似白云深，更向深深处。"]'),
('song-ci-174','惜分飞','柴元彪','宋','宋词','song-ci','惜分飞','[]','候馆天寒灯半灭。',58,'宋词/ci.song.18000.json','["候馆天寒灯半灭。", "对着灯儿泪咽。", "此恨难分说。", "能禁几度黄花别。", "乍转寒更敲未歇。", "蛩语更添凄恻。", "今夜归心切。", "砧声敲碎谁家月。"]'),
('song-ci-175','高阳台','柴元彪','宋','宋词','song-ci','高阳台','["\u897f\u6e56"]','丹碧归来，天荒地老，骎骎华发相催。',122,'宋词/ci.song.18000.json','["丹碧归来，天荒地老，骎骎华发相催。", "见说钱塘，北高峰更崔嵬。", "琼林侍宴簪花处，二十年、满地苍苔。", "倩阿谁，为我起居，坡柳逋梅。", "凄凉往事休重省，且凭阑感慨，抚景衔杯。", "冷暖由天，任他花谢花开。", "知心只有西湖月，尚依依、照我徘徊。", "更多情，不间朝昏，潮去潮来。"]'),
('song-ci-176','百字令・念奴娇','东冈','宋','宋词','song-ci','百字令・念奴娇','[]','排云拓月，向天上移下，神仙华屋。',120,'宋词/ci.song.18000.json','["排云拓月，向天上移下，神仙华屋。", "画栋飞檐千万落，黼黼城南乔木。", "出谷莺迁，趋庭燕尔，袍绾登科绿。", "嫦娥分付，广寒今夜花烛。", "遥想高越于门，烂盈百辆，夹道争车毂。", "春满剡溪溪上路，一任瑶华飞六。", "舆奉潘慈，楼高华萼，坐享齐眉福。", "庭槐列戟，公侯衮衮相属。"]'),
('song-ci-177','意难忘','范文','宋','宋词','song-ci','意难忘','[]','清泪如铅。',114,'宋词/ci.song.18000.json','["清泪如铅。", "叹咸阳送远，露冷铜仙。", "岩花粉堕雪，津柳暗生烟。", "寒食后，暮江边。", "草色更芊芊。", "四十年，留春意绪，不似今年。", "山阴欲棹归船。", "暂停杯雨外，舞剑灯前。", "重逢应未卜，此别转堪怜。", "凭急管，倩繁弦。", "思苦调难传。", "望故乡，都将往事，付与啼鹃。"]'),
('song-ci-178','失调名','叶李','宋','宋词','song-ci','失调名','[]','君来路。',64,'宋词/ci.song.18000.json','["君来路。", "吾归路。", "来来去去何时住。", "公田关子竟何如，国事当时谁汝误。", "雷州户。", "崖州户。", "人生会有相逢处。", "客中颇恨乏蒸羊，聊赠一篇长短句。"]'),
('song-ci-179','念奴娇','梁栋','宋','宋词','song-ci','念奴娇','[]','一场春梦，待从头，说与旁人听著。',120,'宋词/ci.song.18000.json','["一场春梦，待从头，说与旁人听著。", "罨画溪山红锦障，舞燕歌莺台阁。", "碧海倾春，黄金买夜，犹道看承薄。", "雕香剪玉，今生今世盟约。", "须信欢乐过情，闲嗔冷妒，一阵东风恶。", "韵白娇红消瘦尽，江北江南零落。", "骨朽心存，恩深缘浅，忍把罗衣著。", "蓬莱何处，云涛天际冥漠。"]'),
('song-ci-180','摸鱼儿','梁栋','宋','宋词','song-ci','摸鱼儿','[]','枕寒流、碧萦衣带，高台平与云倚。',140,'宋词/ci.song.18000.json','["枕寒流、碧萦衣带，高台平与云倚。", "燕来莺去谁为主，磨灭谪仙吟墨。", "愁思里。", "待说与山灵，还又羞拈起。", "萧韶已矣。", "甚竹实风摧，桐阴雨瘦，景物变新丽。", "江山在，认得刘郎阿寄。", "年来声誉休废。", "英雄不博胭脂井，谁念故人衰悴。", "时有几。", "便凤去台空，莫厌频游此。", "兴亡过耳。", "任北雪迷空，东风换绿，都付梦和醉。"]'),
('song-ci-181','一萼红','梁栋','宋','宋词','song-ci','一萼红','[]','怨东风。',133,'宋词/ci.song.18000.json','["怨东风。", "把韶华付去，秾李小桃红。", "黄落山空，香销水冷，此际才与君逢。", "敛秋思、愁肠九结，拥翠袖、应费剪裁工。", "晕脸迎霜，幽姿泣露，寂寞谁同。", "休笑梳妆淡薄，看浮花浪蕊，眼底俱空。", "夜帐云闲，寒城月浸，有人吟遍深丛。", "自前度、王郎去后，旧游处、烟草接吴宫。", "惟有芳卿寄言，蹙损眉峰。"]'),
('song-ci-182','水龙吟','莫','宋','宋词','song-ci','水龙吟','[]','镜寒香歇江城路，今度见春全懒。',126,'宋词/ci.song.18000.json','["镜寒香歇江城路，今度见春全懒。", "断云过雨，花前歌扇，梅边酒盏。", "离思相欺，万丝萦绕，一襟销黯。", "但年光暗换，人生易感，西归水、南飞雁。", "也拟与愁排遣。", "奈江山、遮拦不断。", "娇讹梦语，湿荧啼袖，迷心醉眼。", "绣毂华茵，锦屏罗荐，何时拘管。", "但良宵空有，亭亭霜月，作相思伴。"]'),
('song-ci-183','玉楼春','莫','宋','宋词','song-ci','玉楼春','[]','绿杨芳径莺声小。',64,'宋词/ci.song.18000.json','["绿杨芳径莺声小。", "帘幕烘香桃杏晓。", "馀寒犹峭雨疏疏，好梦自惊人悄悄。", "凭君莫问情多少。", "门外江流罗带绕。", "直饶明日便相逢，已是一春闲过了。"]'),
('song-ci-184','生查子','莫','宋','宋词','song-ci','生查子','[]','三两信凉风，七八分圆月。',48,'宋词/ci.song.18000.json','["三两信凉风，七八分圆月。", "愁绪到今年，又与前年别。", "衾单容易寒，独暗相将灭。", "欲识此时情，听取鸣蛩说。"]'),
('song-ci-185','卜算子','莫','宋','宋词','song-ci','卜算子','[]','红底过丝明，绿外飞绵小。',52,'宋词/ci.song.18000.json','["红底过丝明，绿外飞绵小。", "不道东风上海棠，白地春归了。", "月笛曲栏留，露舄芳池绕。", "争得闲情似旧时，遍索檐花笑。"]'),
('song-ci-186','摸鱼儿','莫','宋','宋词','song-ci','摸鱼儿','[]','听春教、燕颦莺诉。',141,'宋词/ci.song.18000.json','["听春教、燕颦莺诉。", "朝朝花困风雨。", "六桥忘却清明后，碧尽柳丝千缕。", "蜂蝶侣。", "正闲觅闲花，闲草闲歌舞。", "最怜西子。", "尚薄薄云情，盈盈波泪，点点旧眉妩。", "流红记，空泛秋宫怨句。", "才色何处娇妒。", "落红无风限随风絮。", "诗恨有谁曾遇。", "堪恨处。", "恨二十四番，花信催花去。", "东君暗苦。", "更多嘱多情，多愁杜宇，多诉断肠语。"]'),
('song-ci-187','摸鱼儿','姚云文','宋','宋词','song-ci','摸鱼儿','[]','渺人间、蓬瀛何许，一朝飞入梁苑。',140,'宋词/ci.song.18000.json','["渺人间、蓬瀛何许，一朝飞入梁苑。", "辋川梯洞层瑰出，带取鬼愁龙怨。", "穷游宴。", "谈笑里，金风吹折桃花扇。", "翠华天远。", "怅莎沼黏萤，锦屏烟合，草露泣苍藓。", "东华梦，好在牙樯雕辇。", "画图历历曾见。", "落红万点孤臣泪，斜日牛羊春晚，摩双眼。", "看尘世，鳌宫又报鲸波浅。", "吟鞘拍断。", "便乞与娲皇，化成精卫，真不尽遗恨。"]'),
('song-ci-188','玲珑玉','姚云文','宋','宋词','song-ci','玲珑玉','[]','开岁春迟，早赢得、一白潇潇。',125,'宋词/ci.song.18000.json','["开岁春迟，早赢得、一白潇潇。", "风窗淅簌，梦惊金帐春娇。", "是处貂裘透暖，任尊前回舞，红倦柔腰。", "今朝。", "亏陶家、茶鼎寂寥。", "料得东皇戏剧，怕蛾儿街柳，先斗元宵。", "宇宙低迷，倩谁分、浅凸深凹。", "休嗟空花无据，便真个、琼雕玉琢，总是虚飘。", "虚飘。", "且沈醉，趁楼头、零片未消。"]'),
('song-ci-189','木兰花慢','姚云文','宋','宋词','song-ci','木兰花慢','[]','笑花神较懒，似忘却、趁清明。',124,'宋词/ci.song.18000.json','["笑花神较懒，似忘却、趁清明。", "更油幄晴悭，箬庵寒浅，湿重红云。", "东君似怜花透，环碧ㄓ、遮住怕渠惊。", "惆怅犊车人远，绿杨深闭重城。", "香名。", "谁误娉婷。", "曾注谱、上金屏。", "问洛中亭馆、竹西鼓吹，人醉花醒。", "且莫煎酥涴却，一枝枝、封蜡付铜瓶。", "三十六宫春在，人间风雨无情。"]'),
('song-ci-190','紫萸香慢','姚云文','宋','宋词','song-ci','紫萸香慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','近重阳、偏多风雨，绝怜此日暄明。',142,'宋词/ci.song.18000.json','["近重阳、偏多风雨，绝怜此日暄明。", "问秋香浓未，待携客、出西城。", "正自羁怀多感，怕荒台高处，更不胜情。", "向尊前、又忆洒酒插花人。", "只座上、已无老兵。", "凄情。", "浅醉还醒。", "愁不肯、与诗平。", "记长楸走马，雕弓ㄇ柳，前事休评。", "紫萸一枝传赐，梦谁到、汉家陵。", "尽乌纱、便随风去，要天知道，华发如此星星。", "歌罢涕零。"]'),
('song-ci-191','洞仙歌','姚云文','宋','宋词','song-ci','洞仙歌','[]','燕窠香湿，误天涯芳信。',100,'宋词/ci.song.18000.json','["燕窠香湿，误天涯芳信。", "社近阴晴未前定。", "听莺簧宛转，似羽疑宫，歌未断，落落旧愁都醒。", "疏狂追少日，杜曲樊楼，拼把黄金买春恨。", "回首武陵溪，花待郎归，洞云深、未知春尽。", "问杨柳梢头几分青，消不得，朝来雨寒一阵。"]'),
('song-ci-192','齐天乐','姚云文','宋','宋词','song-ci','齐天乐','[]','柳花引过横塘路，萦回曲蹊通圃。',123,'宋词/ci.song.18000.json','["柳花引过横塘路，萦回曲蹊通圃。", "插槿编篱，挨梅砌石，次第海棠成坞。", "吟筇独拄。", "待寻访斜桥，水边窥户。", "已约青山，云深不碍客来处。", "繁华阅人无数。", "问旧日平原，君还知否。", "啼鸟窗幽，画阴人寂，慵困不如飞絮。", "匆匆燕语。", "似迎得春来，且留春住。", "惜取名花，一枝堪寄与。"]'),
('song-ci-193','蝶恋花','姚云文','宋','宋词','song-ci','蝶恋花','[]','春到海棠花几信。',70,'宋词/ci.song.18000.json','["春到海棠花几信。", "堠馆馀寒，欲雨征衣润。", "燕认杏梁栖未稳。", "牡丹忽报清明近。", "恨入青山连晓镜。", "香雪柔酥，应被春消尽。", "绣阁深深人半醒。", "烛花贴在金钗影。"]'),
('song-ci-194','如梦令','姚云文','宋','宋词','song-ci','如梦令','[]','昨夜佳人凭酒。',40,'宋词/ci.song.18000.json','["昨夜佳人凭酒。", "隔著罗衾厮守。", "听彻五更钟，陡觉霜飞寒逗。", "却又。", "却又。", "陪笑倩人温手。"]'),
('song-ci-195','八声甘州','姚云文','宋','宋词','song-ci','八声甘州','[]','卷丝丝、雨织半晴天，棹歌发清舷。',120,'宋词/ci.song.18000.json','["卷丝丝、雨织半晴天，棹歌发清舷。", "甚苍虬怒耀，灵鼍急吼，雪涌平川。", "楼外榴裙几点，描破绿杨烟。", "把画罗遥指，助啸争先。", "憔悴潘郎曾记，得青龙千舸，采石矶边。", "叹内家帖子，闲却缕金笺。", "觉素标、插头如许，尽风情、终不似斗赢船。", "人声断，虚斋半掩，月印枯禅。"]'),
('song-ci-196','绮罗香','赵必□','宋','宋词','song-ci','绮罗香','[]','办一枝藤，蜡一双屐，纵步翠微深处。',129,'宋词/ci.song.18000.json','["办一枝藤，蜡一双屐，纵步翠微深处。", "无限芳心，付与蜂媒蝶侣。", "红堆里、杏脸匀妆，翠围外、柳腰娇舞。", "有吟翁、热恼心肠，肯拈出、美成佳句。", "九十光阴箭过，趁取芳晴追逐，春风杖屦。", "消得几番，风和雨、春归去。", "怅莺老、对景多愁，倩燕语、苦难留住。", "秋千影里送斜阳，梨花深院宇。"]'),
('song-ci-197','念奴娇','赵必□','宋','宋词','song-ci','念奴娇','[]','一时四美，对重阳、那更无风无雨。',120,'宋词/ci.song.18000.json','["一时四美，对重阳、那更无风无雨。", "尘世难逢开口笑，不饮黄花有语。", "云谷春生，星岩秋好，引领群仙去。", "满襟霁月，山中一洗尘雾。", "濂翁旧说犹存，渊明独爱菊，风流千古。", "拄杖笑谈卿与我，不减晋人风度。", "破帽敧风，空尊眠月，也有悠然趣。", "秋容未老，晚香尤有佳处。"]'),
('song-ci-198','兰陵王','赵必��','宋','宋词','song-ci','兰陵王','[]','画阑直。',159,'宋词/ci.song.18000.json','["画阑直。", "饾饤千红万碧。", "无端被，怪雨狂风，僽柳僝花禁春色。", "寻芳遍楚国。", "谁识。", "五陵俊客。", "流水远，题叶无情，雁足不来杳笺尺。", "浮生等萍迹。", "才卸却归鞍，坐未温席。", "匆匆还又京华食。", "叹聚少离多，漂零因甚，江南逢梅望寄驿。", "美人兮天北。", "悲恻。", "恨成积。", "怅钗玉尘生，猊金烟寂。", "绿杨芳草情何极。", "偏懒拨琵琶，愁听羌笛。", "梨花院落，黄昏后，珠泪滴。"]'),
('song-ci-199','风流子','赵必□','宋','宋词','song-ci','风流子','[]','旧梦忆钱塘。',135,'宋词/ci.song.18000.json','["旧梦忆钱塘。", "笙歌里、几度醉斜阳。", "曾载月一篷，眠杨柳岸，买春深巷，过杏花墙。", "肠恼断，香鬟盘凤髻，樱口啭莺簧。", "钗玉分轻，梦孤宵枕，歌纨蠹久，愁对春觞。", "司空曾见惯，相逢处，还又联步西厢。", "底用十分迷殢，翠阵红行。", "记鸳荚题情，离怀如诉，鲛绡粉湿、别泪犹香。", "年少抛人易去，苦也相妨。"]'),
('song-ci-200','风流子','赵必□','宋','宋词','song-ci','风流子','[]','春光才一半，春未老、谁肯放春归。',135,'宋词/ci.song.18000.json','["春光才一半，春未老、谁肯放春归。", "问买春价数，酒边商略，寻春巷陌，鞭影参差。", "春无尽，春莺调巧舌，春燕垒香泥。", "好趁春光，爱花惜柳，莫教春去，柳怨花悲。", "春心犹未足，春帏暖，炉薰香透春衣。", "说与重欢后约，春以为期。", "记春雁回时，锦笺须寄，春山锁处，珠泪长垂。", "多少愁风恨雨，惟有春知。"]'),
('song-ci-201','齐天乐','赵必□','宋','宋词','song-ci','齐天乐','[]','东南半壁乾坤窄，渺人物、消磨尽。',124,'宋词/ci.song.18000.json','["东南半壁乾坤窄，渺人物、消磨尽。", "官爵网罗，功名钓饵，眼底纷纷蛙井。", "暮更朝令。", "捍格了多少，英雄豪俊。", "身事悠悠，儒冠误矣文章病。", "休休蕉鹿梦省。", "早牛衣无恙，鸥盟未冷。", "相越平吴，终成底用，不似五湖舟稳。", "浩歌狂饮。", "休说我命通，待他心肯。", "浮世南柯，梦邯郸一枕。"]'),
('song-ci-202','华胥引','赵必��','宋','宋词','song-ci','华胥引','[]','沧浪矶外，小舣兰舟，旋沽竹叶。',102,'宋词/ci.song.18000.json','["沧浪矶外，小舣兰舟，旋沽竹叶。", "雨过溪肥，波心荡漾鸥对唼。", "烟晚欸乃渔歌，和橹声咿轧。", "要泛五湖，祗恐西施羞怯。", "年少飘零，鬓未霜，底须轻镊。", "江南归雁，寄来鸳笺细阅。", "盟言誓语，满鲛绡罗箧。", "撩弄相思，琴心寸寸三叠。"]'),
('song-ci-203','意难忘','赵必□','宋','宋词','song-ci','意难忘','[]','魏紫姚黄。',114,'宋词/ci.song.18000.json','["魏紫姚黄。", "属吟翁管领，曾醉春觞。", "盟寒钗凤股，灰冷宝猊香。", "前事远，此心凉。", "去也棹沧浪。", "把年时、芳情付与，鸳颈交相。", "灯前吊影成双。", "叹星星丝鬓，老矣潘郎。", "愁偏欺客枕，样不入时妆。", "尘面目，铁心肠。", "归隐又何妨。", "小滩头、曲竿直钓，谁识严光。"]'),
('song-ci-204','宴清都','赵必□','宋','宋词','song-ci','宴清都','[]','远远渔村鼓。',127,'宋词/ci.song.18000.json','["远远渔村鼓。", "斜阳外、宾鸿三两飞度。", "茅檐春小，白云隐几，青山当户。", "骚翁底事飘蓬，浑忘却、耕徒钓侣。", "何时寻、斗酒江鲈，悠悠千古坡赋。", "风流种柳渊明，折腰五斗，身为名苦。", "有秫田贰顷，菊松三迳，不如归去。", "山灵休勒俗驾，容我卧、草堂深处。", "问故园、怨鹤啼猿，今无恙否。"]'),
('song-ci-205','锁窗寒・琐寒窗','赵必□','宋','宋词','song-ci','锁窗寒・琐寒窗','[]','乳燕双飞，黄莺百啭，深深庭户。',122,'宋词/ci.song.18000.json','["乳燕双飞，黄莺百啭，深深庭户。", "海棠开遍，零乱一帘红雨。", "绣帘低、卷起春风，香肩倦倚娇无语。", "叹玉堂底事。", "匆匆聚散，又江南旅。", "春暮。", "人何处。", "想歌馆睡浓，日高丈五。", "旧迷未醒，莫负孤眠凤侣。", "长安道、载酒寻芳，故园桃李还忆否。", "早旧来、整过阑干，花下携春俎。"]'),
('song-ci-206','隔浦莲・隔浦莲近拍','赵必□','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','东风吹长嫩葆。',85,'宋词/ci.song.18000.json','["东风吹长嫩葆。", "花坞穿青窈。", "玉管新声，金铃颤响惊青鸟。", "行乐莫草草。", "春光闹。", "鸳浴垂杨沼。", "红娇小。", "梳宫样、髻云钗凤斜倒。", "酒边轻别，一枕相思到晓。", "巫山难梦到。", "愁觉。", "一些心事谁表。"]'),
('song-ci-207','苏幕遮','赵必□','宋','宋词','song-ci','苏幕遮','[]','远迎风，回避暑。',76,'宋词/ci.song.18000.json','["远迎风，回避暑。", "人似荷花，笑隔荷花语。", "无限情云并意雨。", "惊散鸳鸯，兰棹波心举。", "约重游，轻别去。", "断桥风月，梦断飘蓬旅。", "旧日秋娘犹在否。", "雁足不来，声断衡阳浦。"]'),
('song-ci-208','齐天乐','赵必□','宋','宋词','song-ci','齐天乐','[]','红纷绿闹东风透，暖得枳花香也。',123,'宋词/ci.song.18000.json','["红纷绿闹东风透，暖得枳花香也。", "雪柳拈金，玉梅铺粉，妆点春光无价。", "鳌蓬如画。", "簇万顷芙蕖，桂华相射。", "艳冶逢迎，香尘满路飘兰麝。", "人生行乐聊尔，况良辰美景，好天晴夜。", "茧帖争先，芋郎卜巧，细说成都旧话。", "传觞立马。", "看翠阵珠围，歌朋舞社。", "酒尽更阑，月在蒲萄架。"]'),
('song-ci-209','烛影摇红','赵必□','宋','宋词','song-ci','烛影摇红','[]','月浸芙蕖，冰壶天地波凝碧。',116,'宋词/ci.song.18000.json','["月浸芙蕖，冰壶天地波凝碧。", "太平歌舞醉东风，花市人如织。", "桃李一城春色。", "玉梅娇、闹娥无力。", "粉围红阵，灯火楼台，绮罗巷陌。", "乐事还同，遨头引领神仙客。", "高烧银烛照红妆，香雾穿瑶席。", "款款檀牙细拍。", "醉金尊、东方未白。", "传柑相遗，探茧争先，明年何夕。"]'),
('song-ci-210','沁园春','赵必□','宋','宋词','song-ci','沁园春','[]','看做官来，只似儿时，掷选官图。',139,'宋词/ci.song.18000.json','["看做官来，只似儿时，掷选官图。", "如琼崖儋岸，浑么便去，翰林给舍，喝采曾除。", "都一掷间，许多般样，输了还赢赢了输。", "回头看，这浮云富贵，到底花虚。", "吾生谁毁谁誉。", "任荆棘丛丛满仕途。", "叹塞翁失马，祸也福也，蕉间得鹿，真欤梦欤。", "何怨何尤，自歌自笑，天要吾侪更读书。", "归去也，向竹松深处，结个茅庐。"]'),
('song-ci-211','贺新郎','赵必��','宋','宋词','song-ci','贺新郎','[]','绣口琅玕腹。',142,'宋词/ci.song.18000.json','["绣口琅玕腹。", "美人兮、阳春一曲，华貂难续。", "唤醒荷花归棹梦，犹忆红尘迷目。", "只消得、乌飞兔逐。", "往事已随流水去，眇愁予、郁郁哀时俗。", "恨千缕，泪一掬。", "不使清史流芳馥。", "也不须、荣华富贵，尊前频祝。", "但得山中茅屋在，莫遣鹤悲猿哭。", "随意种、荼薇蹢躅。", "莼菜可羹鲈可鲙，听渔舟、晚唱清溪曲。", "醉又醒，唤芳醁。"]'),
('song-ci-212','夏日燕黉堂','赵必□','宋','宋词','song-ci','夏日燕黉堂','[]','赤城中。',121,'宋词/ci.song.18000.json','["赤城中。", "奏鹤笙一曲，玉佩丁东。", "蒲节后七日，宴翠阆琼宫。", "年年王母来称寿，醉蟠桃、几度东风。", "簇花间五马，轻裘短帽，雪鬓吟翁。", "魁宿耀三雍。", "曾归车共载，非虎非熊。", "急流勇退，渊底卧骊龙。", "山中不用官三品，垫角巾、人慕林宗。", "记亳州旧事，画鸱夷子，献与恭公。"]'),
('song-ci-213','水调歌头','赵必□','宋','宋词','song-ci','水调歌头','[]','百岁人能几，七十世间稀。',114,'宋词/ci.song.18000.json','["百岁人能几，七十世间稀。", "何况先生八十，蔗境美如饴。", "好与七松处士，更与梅花君子，永结岁寒知。", "菊节先五日，满酌紫霞卮。", "美成词，山谷字，老坡诗。", "三径田园如昨，久矣赋归辞。", "不是商山四皓，便是香山九老，红颊白须眉。", "九十尚入相，绿竹颂猗猗。"]'),
('song-ci-214','贺新郎','赵必□','宋','宋词','song-ci','贺新郎','[]','寿酒浮萸菊。',142,'宋词/ci.song.18000.json','["寿酒浮萸菊。", "记年年、重阳嘉节，开尊华屋。", "绿鬓朱颜春不改，彼美人兮如玉。", "有锦绣、珠玑满腹。", "户外红尘飞不到，受人间、倒大清闲福。", "数花甲，才八六。", "十分秋色呈新绿。", "一簇儿、池馆亭台，左梅右竹。", "柳下系船花下饮，不减西园金谷。", "更桔外、安排棋局。", "独立小桥明月夜，唤莺莺、低唱双飞曲。", "有子也，万事足。"]'),
('song-ci-215','贺新郎','赵必��','宋','宋词','song-ci','贺新郎','[]','低唱芙蓉菊。',142,'宋词/ci.song.18000.json','["低唱芙蓉菊。", "有吟翁、坐拥红娇，宴黄金屋。", "恰则绂鳞三日后，灿灿晬盘珠玉。", "不待梦、燕怀枫腹。", "自是嫦娥分桂种，伴灵椿、千岁延清福。", "回笑我，龟藏六。", "归欤老圃锄春绿。", "吾菟裘、三径荒苔，一庭瘦竹。", "欲隐贫无山可买，聊尔徜徉盘谷。", "更管甚、云台玉局。", "紧闭柴门传语客，道主人、高枕南窗曲。", "有酒蟹，此生足。"]'),
('song-ci-216','贺新郎','赵必□','宋','宋词','song-ci','贺新郎','[]','沙上盟鸥鹭。',142,'宋词/ci.song.18000.json','["沙上盟鸥鹭。", "笑吟翁、梦今不到，草堂深处。", "金屋重重春睡暖，傍翠偎香步步。", "已自摘、蟠桃三度。", "旧日画眉情性在，更君房、妙绝文章语。", "消受得，乘鸾侣。", "楼中燕燕谁家住。", "又从新、移根换叶，栽花千树。", "第一信风春事觉，莫遣绿羞红污。", "早早做、阑干遮护。", "天上姻缘千里合，喜乘槎、先入银河路。", "人似玉，衣金缕。"]'),
('song-ci-217','满江红','赵必□','宋','宋词','song-ci','满江红','["\u957f\u6c5f"]','如此风涛，又断送、一番蒲节。',115,'宋词/ci.song.18000.json','["如此风涛，又断送、一番蒲节。", "何处寄、黍简彩线，龙馋蛟啮。", "已矣骚魂招不返，兰枯蕙老馀香歇。", "俯仰间、万事总成陈，新愁结。", "梅子雨，荷花月。", "消几度，头如雪。", "叹英雄虚老，凄其一吷。", "回首百年歌舞地，胥涛点点孤臣血。", "问长江、此恨几时平，茫无说。"]'),
('song-ci-218','念奴娇','赵必□','宋','宋词','song-ci','念奴娇','[]','烧灯过也，倩东风、又翦芙蕖千朵。',120,'宋词/ci.song.18000.json','["烧灯过也，倩东风、又翦芙蕖千朵。", "翠阵珠围依然是，旧日笙歌社火。", "一曲乘莺，万钱骑鹤，仙子来蓬岛。", "金尊满酌，不妨斜戴花帽。", "人生能几欢娱，趁良辰美景，绿娇红小。", "洞里桃花应笑道，前度刘郎未老。", "眼雨眉云，情香粉态，恨不相逢早。", "明年今夕，犀钱玉果分我。"]'),
('song-ci-219','念奴娇','赵必□','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','中年怕别，唱阳关未了，情怀先恶。',122,'宋词/ci.song.18000.json','["中年怕别，唱阳关未了，情怀先恶。", "回首西湖十年梦，几夜檐花清酌。", "人世如萍，客愁似海，吟鬓俱非昨。", "风涛如许，只应高卧林壑。", "菊松尽可归欤，叹折腰为米，渊明已错。", "相越平吴，终成底事，一舸五湖差乐。", "细和陶诗，径寻坡隐，时访峰头鹤。", "罗浮咫尺，春风寄我梅萼。"]'),
('song-ci-220','醉落魄・一斛珠','赵必□','宋','宋词','song-ci','醉落魄・一斛珠','[]','西园饮歇。',68,'宋词/ci.song.18000.json','["西园饮歇。", "倚阑干、玉箫声彻。", "荷枯菊老秋芳歇。", "两蕊三花、九月南州雪。", "何郎情思逋仙骨。", "观桃墙杏成疏阔。", "醉骑玉凤游银阙。", "满树西风、吹动暗香月。"]'),
('song-ci-221','浣溪沙','赵必□','宋','宋词','song-ci','浣溪沙','[]','只为相思怕上楼。',56,'宋词/ci.song.18000.json','["只为相思怕上楼。", "离莺一操恨悠悠。", "十二翠屏烟篆冷，晓窗秋。", "绣线未拈心已懒，花笺欲寄写还羞。", "懊恨郎边无个信，暮云愁。"]'),
('song-ci-222','菩萨蛮','赵必□','宋','宋词','song-ci','菩萨蛮','[]','红娇翠溜歌喉急。',52,'宋词/ci.song.18000.json','["红娇翠溜歌喉急。", "旧弦拨断新腔入。", "往事水东流。", "菱花晓带秋。", "帏香双凤集。", "清泪层绡湿。", "残梦五更头。", "酒醒依旧愁。"]'),
('song-ci-223','朝中措','赵必□','宋','宋词','song-ci','朝中措','[]','凤凰台上听吹箫。',57,'宋词/ci.song.18000.json','["凤凰台上听吹箫。", "银烛万红摇。", "要觅琼浆玉饮，隔墙便是蓝桥。", "大儿清彻，小乔初嫁，雨腻云娇。", "愁怕沈郎销瘦，不堪十万缠腰。"]'),
('song-ci-224','朝中措','赵必□','宋','宋词','song-ci','朝中措','["\u897f\u6e56"]','冰肌玉骨为谁癯。',57,'宋词/ci.song.18000.json','["冰肌玉骨为谁癯。", "只为故人疏。", "憔悴粉销香减，风流不似当初。", "聚能几日，匆匆又散，骑鹤西湖。", "整整一年相别，到家传语林逋。"]'),
('song-ci-225','朝中措','赵必□','宋','宋词','song-ci','朝中措','[]','桔肥梅小蜡橙黄。',57,'宋词/ci.song.18000.json','["桔肥梅小蜡橙黄。", "薄薄板桥霜。", "春透谢娘庭院，雅宜倚玉偎香。", "旧情如纸，新情如海，冷热心肠。", "谁为移根换叶，桃花自识刘郎。"]'),
('song-ci-226','鹧鸪天','赵必□','宋','宋词','song-ci','鹧鸪天','[]','湖海相逢尽赏音。',64,'宋词/ci.song.18000.json','["湖海相逢尽赏音。", "囊中粒剂值千金。", "单传扁鹊卢医术，不用杨高郭玉针。", "三斛火，一壶冰。", "蓝桥捣熟隔云深。", "无方可疗相思病，有药难医薄幸心。"]'),
('song-ci-227','大江东去・念奴娇','黎廷瑞','宋','宋词','song-ci','大江东去・念奴娇','[]','鲍鱼腥断，楚将军、鞭虎驱龙而起。',120,'宋词/ci.song.18000.json','["鲍鱼腥断，楚将军、鞭虎驱龙而起。", "空费咸阳三月火，铸就金刀神器。", "垓下兵稀，阴陵道隘，月黑云如垒。", "楚歌哄发，山川都姓刘矣。", "悲泣呼醒虞姬，和伊死别，雪刃飞花髓。", "霸业休休骓不逝，英气乌江流水。", "古庙颓垣，斜阳老树，遗恨鸦声里。", "兴亡休问，高陵秋草空翠。"]'),
('song-ci-228','蝶恋花','黎廷瑞','宋','宋词','song-ci','蝶恋花','[]','密炬瑶霞光颤酒。',70,'宋词/ci.song.18000.json','["密炬瑶霞光颤酒。", "翠柏红椒，细翦青丝韭。", "且劝金樽千万寿。", "年时芳梦休回首。", "小雨轻寒风满袖，下却帘儿，莫道梅花瘦。", "万点鹅黄春色透。", "玉箫吹上江南柳。"]'),
('song-ci-229','八声甘州','黎廷瑞','宋','宋词','song-ci','八声甘州','["\u957f\u6c5f"]','恨巨灵、多事凿长江，消沈几英雄。',119,'宋词/ci.song.18000.json','["恨巨灵、多事凿长江，消沈几英雄。", "恨乌江亭长，天机轻泄，说与重瞳。", "更恨南阳耕叟，撺掇紫髯翁。", "一弹金陵土，战虎争龙。", "杯酒凤凰台上，对石城流水，锺阜诸峰。", "问六朝陵阙，何处是遗踪。", "后庭花、更无留声，渺春潮、残照笛声中。", "悲欢梦，芜城杨柳，几度春风。"]'),
('song-ci-230','水龙吟','黎廷瑞','宋','宋词','song-ci','水龙吟','[]','不知玄武湖中，一瓢春水何人借。',127,'宋词/ci.song.18000.json','["不知玄武湖中，一瓢春水何人借。", "裁冰翦雨，等闲占断，桃花春社。", "古阜花城，玉龙盐虎，夕阳图画。", "是东风吹就，明朝吹散，又还是、东风也。", "回首当时光景，渺秦淮、绿波东下。", "滔滔江水，依依山色，悠悠物化。", "璧玉琼花，世间消得，几多朝夜。", "笑乌衣、不管春寒，只管说、兴亡话。"]'),
('song-ci-231','南乡子','黎廷瑞','宋','宋词','song-ci','南乡子','[]','醉罢黑瑶池。',66,'宋词/ci.song.18000.json','["醉罢黑瑶池。", "渺渺春云海峤归。", "画楝珠帘成昨梦，谁知。", "百姓人家几度非。", "相对语斜晖。", "肠断江城柳絮飞。", "再见玉郎应不认，堪悲。", "也被缁尘染素衣。"]'),
('song-ci-232','清平乐','黎廷瑞','宋','宋词','song-ci','清平乐','[]','秋怀骚屑。',54,'宋词/ci.song.18000.json','["秋怀骚屑。", "卧听萧萧叶。", "四壁寒蛩吟不歇，旧恨新愁都说。", "疏疏雨打栖鸦。", "月痕犹在窗纱。", "一夜西风能紧，明朝瘦也黄花。"]'),
('song-ci-233','浪淘沙','黎廷瑞','宋','宋词','song-ci','浪淘沙','[]','别易见时难。',64,'宋词/ci.song.18000.json','["别易见时难。", "万水千山。", "参商烟树暮云间。", "料想凤凰城里梦，夜夜归鞍。", "杨柳小楼闲。", "倚遍阑干。", "东风翦翦雨珊珊。", "落尽桃花无可落，只管春寒。"]'),
('song-ci-234','浣溪沙','黎廷瑞','宋','宋词','song-ci','浣溪沙','[]','一曲离愁浅黛嚬。',48,'宋词/ci.song.18000.json','["一曲离愁浅黛嚬。", "云帆渺渺下烟津。", "山长水远客愁新。", "柳絮低迷千里梦，桃花荡洋一江春。", "小楼疏雨可怜人。"]'),
('song-ci-235','祝英台近','黎廷瑞','宋','宋词','song-ci','祝英台近','[]','彩云空，香雨霁。',97,'宋词/ci.song.18000.json','["彩云空，香雨霁。", "一梦千年事。", "碧幌如烟，却扇试新睡。", "恁时杨柳阑干，芙蓉池馆，还只似、如今天气。", "远山翠。", "空相思，淡扫修眉，盈盈照秋水。", "落日西风，借问雁来未。", "只愁雁到来时，又无消息，只落得，一番憔悴。"]'),
('song-ci-236','水调歌・水调','黎廷瑞','宋','宋词','song-ci','水调歌・水调','[]','腰缠十万贯，骑鹤上扬州。',114,'宋词/ci.song.18000.json','["腰缠十万贯，骑鹤上扬州。", "诗翁那得有此，天地一扁舟。", "二十四番风信，二十四桥风景，正好及春游。", "挂席欲东下，烟雨暗层楼。", "紫绮冠，绿玉杖，黑貂裘。", "沧波万里，浩荡踪迹寄浮鸥。", "想杀南台御史，笑杀南州孺子，何事此淹留。", "远思渺无极，日夜大江流。"]'),
('song-ci-237','满江红','黎廷瑞','宋','宋词','song-ci','满江红','[]','千亩君封，新移就、美泉天禄。',115,'宋词/ci.song.18000.json','["千亩君封，新移就、美泉天禄。", "形制古，椰樽嫌窄，瓠壶嫌俗。", "爱酒步兵缘业重，平生所愿何时足。", "再来生、竟堕此林中，充其腹。", "秋入洞，鉴金筑。", "春出户，跳珠玉。", "想宜城九酝，叶光凝绿。", "驴背夕阳同倒载，醉乡只在篔筜谷。", "问东坡、何独饮松醪，还思肉。"]'),
('song-ci-238','唐多令','黎廷瑞','宋','宋词','song-ci','唐多令','[]','回棹百花洲。',74,'宋词/ci.song.18000.json','["回棹百花洲。", "迢迢碧玉流。", "听笛声、何处高楼。", "如此江山无此客，虽有酒、奈何秋。", "呼月出云头。", "问渠能饮不。", "笑人间、元自无愁。", "可惜月翁呼不出，呼得出、载同游。"]'),
('song-ci-239','朝中措','黎廷瑞','宋','宋词','song-ci','朝中措','[]','游丝千万暖风柔，只系得春愁。',57,'宋词/ci.song.18000.json','["游丝千万暖风柔，只系得春愁。", "恨杀啼莺句引，孤他语燕攀留。", "纵然留住，香红吹尽，春也堪羞。", "去去不堪回首，斜阳一点西楼。"]'),
('song-ci-240','眼儿媚','黎廷瑞','宋','宋词','song-ci','眼儿媚','[]','暖云挟雨洗尘埃。',58,'宋词/ci.song.18000.json','["暖云挟雨洗尘埃。", "剗地峭寒翠。", "燕儿知否，莺儿知否，厮句春回。", "小楼日日重帘卷，应是把人猜。", "杏花如许，桃花如许，不见归来。"]'),
('song-ci-241','诉衷情','黎廷瑞','宋','宋词','song-ci','诉衷情','[]','曲屏深院赴幽期。',54,'宋词/ci.song.18000.json','["曲屏深院赴幽期。", "心事梦云知。", "佩环零乱何处，江上草离离。", "日平西，天似幕，月如眉。", "依稀还记，两岸杨花，送上船时。"]'),
('song-ci-242','贺新郎','黎廷瑞','宋','宋词','song-ci','贺新郎','[]','帆影斜阳里。',143,'宋词/ci.song.18000.json','["帆影斜阳里。", "与芦花、分风飞过，落星遗此。", "瓦老苔荒钟鼓陋，斑剥，残碑无几。", "想此处、阅人多矣。", "天上白榆犹落去，况人间、一瞬浮花蕊。", "问五老，笑而已。", "仙翁当日曾挥麈。", "拍阑干、浩歌音响，振鱼龙耳。", "九十馀年无人问，遗韵半江烟水。", "慨宇宙、风涛如许。", "安得六丁移此石，去横身、作个中流砥。", "长唱罢，冥鸿起。"]'),
('song-ci-243','青玉案','黎廷瑞','宋','宋词','song-ci','青玉案','[]','巨舟双橹鸣鹅鹳。',80,'宋词/ci.song.18000.json','["巨舟双橹鸣鹅鹳。", "千万顷、玻璃面。", "宇宙浮萍堪永叹。", "黄唐开辟，秦隋争战。", "不把江山换。", "芦花新雪秋撩乱。", "何处渔舟起孤管。", "一片古愁萦不断。", "平沙矮树，溪烟荒岸。", "落日西风雁。"]'),
('song-ci-244','酹江月・念奴娇','黎廷瑞','宋','宋词','song-ci','酹江月・念奴娇','["\u897f\u6e56"]','远山如簇，对楼前、浓抹淡妆新翠。',120,'宋词/ci.song.18000.json','["远山如簇，对楼前、浓抹淡妆新翠。", "应是西湖湖上景，移过江南千里。", "旧日春光，重归杨柳，苒苒黄金缕。", "市声分付，画桥之外流水。", "最好叠观泥金，危城带粉，文笔双峰倚。", "烟寺晚钟渔浦笛，都入王维画里。", "敧枕方床，凭阑往古，世界浮萍耳。", "湖天风紧，白鸥欲下还起。"]'),
('song-ci-245','酹江月・念奴娇','黎廷瑞','宋','宋词','song-ci','酹江月・念奴娇','["\u897f\u6e56"]','锦袍何处，向旧江、衰草寒芦萧瑟。',121,'宋词/ci.song.18000.json','["锦袍何处，向旧江、衰草寒芦萧瑟。", "瀛馆神仙挥玉尘，唤醒诗酒魂魄。", "走电飞红，惊涛触石，举目乾坤窄。", "油然归去，短篷多载风月。", "好在雨外云根，水边石上，鸥鹭盟重结。", "见说西湖湖上路，香沁梅梢新雪。", "驾白麒麟，鞭青鸾凤，次第孤山客。", "吾今西啸，寄诗先与逋仙说。"]'),
('song-ci-246','一翦梅','黎廷瑞','宋','宋词','song-ci','一翦梅','[]','小小黄花尔许愁。',72,'宋词/ci.song.18000.json','["小小黄花尔许愁。", "楚事悠悠。", "晋事悠悠。", "荒芜三径渺中洲。", "开几番秋。", "落几番秋。", "不是孤芳万古留。", "餐亦堪羞。", "采亦堪羞。", "离骚赋罢酒新篘。", "醒也风流。", "醉也风流。"]'),
('song-ci-247','水龙吟','黎廷瑞','宋','宋词','song-ci','水龙吟','[]','荒城落日西风，满街芳草无行路。',126,'宋词/ci.song.18000.json','["荒城落日西风，满街芳草无行路。", "楼台羽化，萤飞故苑，蛩吟残础。", "不减承平，半湖秋月，隔溪烟树。", "慨江南风景，一朝如许，教人恨、王夷甫。", "对酒强推愁去。", "酒醒来、愁还如故。", "青萍三尺，阴符一卷，土花尘蠹。", "试问黄花，花知余否，沈吟无语。", "拍阑干，空羡平沙落雁，沧波归鹭。"]'),
('song-ci-248','清平乐','黎廷瑞','宋','宋词','song-ci','清平乐','[]','清明寒食。',54,'宋词/ci.song.18000.json','["清明寒食。", "过了空相忆。", "千里音书无处觅。", "渺渺乱芜摇碧。", "苍天雨细风斜。", "小楼燕子谁家。", "只道春寒都尽，一分犹在桐花。"]'),
('song-ci-249','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','云根屋。',56,'宋词/ci.song.18000.json','["云根屋。", "东风四壁花如玉。", "花如玉。", "水仙伤婉。", "山矾伤俗。", "高标懒趁时妆束。", "一丘一壑便幽独。", "便幽独。", "商山四皓，首阳孤竹。"]'),
('song-ci-250','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','罗浮暮。',56,'宋词/ci.song.18000.json','["罗浮暮。", "青松林下相逢处。", "相逢处。", "缟衣素袂，沈吟无语。", "行云飞入瑶台路。", "梦回飘渺香风度。", "香风度。", "参横月落，几声翠羽。"]'),
('song-ci-251','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','叶叶里。',56,'宋词/ci.song.18000.json','["叶叶里。", "一枝冷浸铜瓶水。", "铜瓶水。", "飞英簇簇，砚屏香几。", "夜来雪片敲窗纸。", "半衾芳梦相料理。", "相料理。", "梨花漠漠，江南千里。"]'),
('song-ci-252','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','春脉脉。',56,'宋词/ci.song.18000.json','["春脉脉。", "含章檐下妆宫额。", "妆宫额。", "也还点画，春烟茅结。", "人间天上俱清绝。", "风流大似东坡客。", "东坡客。", "玉堂如玉，雪堂如雪。"]'),
('song-ci-253','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','红苞拆。',56,'宋词/ci.song.18000.json','["红苞拆。", "巡檐一笑风情别。", "风情别。", "广平空道，心肠如铁。", "灞桥更有狂吟客。", "短鞭破帽貂裘窄。", "貂裘窄。", "瘦驴卓耳，一鞍风雪。"]'),
('song-ci-254','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','春来了。',56,'宋词/ci.song.18000.json','["春来了。", "孤根矫树花开早。", "花开早。", "水村山郭，嫩红晴晓。", "陇头何处鳞鸿香。", "一枝欲寄行人少。", "行人少。", "大江南岸，北风低草。"]'),
('song-ci-255','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','齐山硕。',56,'宋词/ci.song.18000.json','["齐山硕。", "扫开残雪簪花饮。", "簪花饮。", "樽前人唱，暗香疏影。", "枝南枝北迢迢恨。", "春风旧梦难重省。", "难重省。", "小窗斜月，薄酲残醒。"]'),
('song-ci-256','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','花孤冷。',56,'宋词/ci.song.18000.json','["花孤冷。", "海棠聘与花应肯。", "花应肯。", "海棠只是，无香堪恨。", "香无却有仙风韵。", "能争几日芳期近。", "芳期近。", "东风何事，不留花等。"]'),
('song-ci-257','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','醒人眼。',56,'宋词/ci.song.18000.json','["醒人眼。", "一枝玉雪疏篱晚。", "疏篱晚。", "精神旷逸。", "风姿凝远。", "幽香零乱无人管。", "依依春恨天涯满。", "天涯满。", "霜城戍角，月楼羌管。"]'),
('song-ci-258','秦楼月・忆秦娥','黎廷瑞','宋','宋词','song-ci','秦楼月・忆秦娥','[]','幽香歇。',56,'宋词/ci.song.18000.json','["幽香歇。", "玉龙吹彻花如雪。", "花如雪。", "小桥流水，不胜愁绝。", "横梢翦入生绡墨。", "翠阴青子盈盈结。", "盈盈结。", "淡烟微雨，江南三月。"]'),
('song-ci-259','贺新郎','李震','宋','宋词','song-ci','贺新郎','[]','楼据湖山背。',142,'宋词/ci.song.18000.json','["楼据湖山背。", "倚高寒、尘飞不到，越山相对。", "老月腾辉群动息，独坐清分沆瀣。", "更满听、潮声澎湃。", "醉里诗成神鬼泣，景苍凉、又在新诗外。", "浑忘却、功名债。", "凭谁妙笔能图绘。", "羡中郎、前身摩诘，宛然心会。", "拈出清宵无限意，半幅溪藤光怪。", "方信有、人间仙界。", "云淡天低奇绝处，笑僧殊、未识丹青在。", "留此轴，夸千载。"]'),
('song-ci-260','贺新郎','陈纪','宋','宋词','song-ci','贺新郎','[]','趁拍哀弦促。',141,'宋词/ci.song.18000.json','["趁拍哀弦促。", "听泠泠、弦间细语，手间推覆。", "莺语间关花底滑，急雨斜穿梧竹。", "又涧底、松风簌簌。", "铁拨鵾弦春夜永，对金钗锺乳人如玉。", "敲象板，翦银烛。", "六么声断凉州续。", "怅梅花、岁晚天寒，佳人空谷。", "有限弦声无限意，沦落天涯幽独。", "顿唤起、闲愁千斛。", "贺老定场无处问，到如今，只鼓昭君曲。", "呼羯鼓，泻醽醁。"]'),
('song-ci-261','念奴娇','陈纪','宋','宋词','song-ci','念奴娇','[]','断桥流水，见横斜清浅，一枝孤袅。',120,'宋词/ci.song.18000.json','["断桥流水，见横斜清浅，一枝孤袅。", "清气乾坤能有几，都被梅花占了。", "玉质生香，冰肌不栗，韵在霜天晓。", "林间姑射，高情迥出尘表。", "除是孤竹夷齐，商山四皓，与尔方向调。", "世上纷纷巡檐者，尔辈何堪一笑。", "风雨忧愁，年来何逊，孤负渠多少。", "参横月落，有怀付与青鸟。"]'),
('song-ci-262','满江红','陈纪','宋','宋词','song-ci','满江红','[]','凤去台空，庭叶下、嫩寒初透。',115,'宋词/ci.song.18000.json','["凤去台空，庭叶下、嫩寒初透。", "人世上、几番风雨，几番重九。", "列岫迢迢供远目，晴空荡荡容长袖。", "把中年、怀抱更登台，秋知否。", "天亦老，山应瘦。", "时易失，欢难久。", "到于今惟有，黄花依旧。", "岁晚凄其诸葛恨，乾坤只可渊明酒。", "忆坡头、老菊晚香寒，空搔首。"]'),
('song-ci-263','倦寻芳','陈纪','宋','宋词','song-ci','倦寻芳','[]','满簪霜雪，一帽尘埃，消几寒食。',118,'宋词/ci.song.18000.json','["满簪霜雪，一帽尘埃，消几寒食。", "手拈梨花，还是年时岑寂。", "簌簌落红春似梦，萋萋柔绿愁如织。", "怪东君、太匆匆，亦是人间行客。", "问几度、五侯传烛，但回首东风，吹尽尘迹。", "笑杜陵泪洒，金波如积。", "对酒且宽愁意绪，题诗与寄真消息。", "待归来，细温存、慰伊相忆。"]'),
('song-ci-264','摸鱼儿','仇远','宋','宋词','song-ci','摸鱼儿','[]','爱青山、去红尘远，清清谁似巢许。',140,'宋词/ci.song.18000.json','["爱青山、去红尘远，清清谁似巢许。", "白云窗冷灯花小，夜静对床听雨。", "愁不语。", "念锦屋瑶筝，却伴闲云住。", "莲心尚苦。", "谩自折兰苕，答书蕉叶，都是断肠句。", "鸥沙外，还笑失群鸳鸯。", "凄凉烟水深处。", "碧笺空寄江南弄，鸦墨乱无行数。", "梅半树。", "怅未识、佳人日暮情谁与。", "何时辇路。", "共系柳游鞯，印苔金屐，湖曲步春去。"]'),
('song-ci-265','摸鱼儿','仇远','宋','宋词','song-ci','摸鱼儿','[]','恼晴空、日长无力，风吹不尽愁绪。',140,'宋词/ci.song.18000.json','["恼晴空、日长无力，风吹不尽愁绪。", "马头零乱流光转，粟粟巧黏红树。", "闲意度。", "似特地、随他燕子穿帘去。", "徘徊不语。", "谩彷弗眉尖，留连眼底，芳草正如雾。", "冥濛处。", "独凭阑干凝伫。", "翠蛾今在何许。", "隔花箫鼓春城暮。", "肠断小窗微雨。", "休更舞。", "明日看、池萍始信低飞误。", "长桥短浦。", "怅不似危红，苍苔点遍，犹涩马蹄驻。"]'),
('song-ci-266','诉衷情','仇远','宋','宋词','song-ci','诉衷情','[]','渚莲香贮一房秋。',54,'宋词/ci.song.18000.json','["渚莲香贮一房秋。", "秋叶上人头。", "年光鬓影偷换，堪叹不堪留。", "人渺渺，事休休。", "恨悠悠。", "莼鲈不梦，也□归舟。", "家住沧洲。"]'),
('song-ci-267','台城路・齐天乐','仇远','宋','宋词','song-ci','台城路・齐天乐','[]','暮云春树江东远，十年软红尘井。',123,'宋词/ci.song.18000.json','["暮云春树江东远，十年软红尘井。", "雨屋酣歌，月楼醉倚，还倩天风吹醒。", "青镫耿耿。", "算除却渊明，谁怜孤影。", "自卷荷衣，石床高卧翠微冷。", "山空但觉昼永。", "旧游花柳梦，不忍重省。", "燕子梁空，鸡儿巷静，休说长安风景。", "丹台路迥。", "怎见得玄都，□□芳径。", "共理瑶笙，凤凰花外听。"]'),
('song-ci-268','临江仙','仇远','宋','宋词','song-ci','临江仙','[]','湘水晓行无酒，楚乡客久思家。',68,'宋词/ci.song.18000.json','["湘水晓行无酒，楚乡客久思家。", "空城暗柳老愁芽。", "燕归才社后，人老尚天涯。", "记得津头轻别，离觞愁听琵琶。", "东风吹泪落鸥沙。", "一番新雨重，飞不起杨花。"]'),
('song-ci-269','糖多令・唐多令','仇远','宋','宋词','song-ci','糖多令・唐多令','[]','凉露湿秋芜。',74,'宋词/ci.song.18000.json','["凉露湿秋芜。", "空庭啼蟪蛄。", "紫苔衣、犹护金铺。", "疏箔翠眉人不见，流水急，泣鳏鱼。", "恨草倩谁锄。", "西风吹鬓疏。", "问刘郎、别后何如。", "纵有桃花千万树，也不似，旧玄都。"]'),
('song-ci-270','如梦令','仇远','宋','宋词','song-ci','如梦令','[]','特特问花消息。',40,'宋词/ci.song.18000.json','["特特问花消息。", "结果剩红残白。", "芍药可人怜，相约荼䕷留客。", "消得。", "消得。", "犹有一分春色。"]'),
('song-ci-271','如梦令','仇远','宋','宋词','song-ci','如梦令','[]','听尽西窗风雨。',40,'宋词/ci.song.18000.json','["听尽西窗风雨。", "又听东邻砧杵。", "犹自立危阑，阑外青山无语。", "何处。", "何处。", "一树乱鸦啼暮。"]'),
('song-ci-272','南歌子','仇远','宋','宋词','song-ci','南歌子','["\u897f\u6e56"]','结屋依苍树，开窗对碧山。',62,'宋词/ci.song.18000.json','["结屋依苍树，开窗对碧山。", "西湖不厌久长看。", "玉勒钿车偏在、六桥间。", "露柳凝朝润，烟花敛暮寒。", "才经人赏便阑残。", "谢柳辞花、醉策瘦筇还。"]'),
('song-ci-273','南歌子','仇远','宋','宋词','song-ci','南歌子','[]','细细金丝柳，重重青黛山。',62,'宋词/ci.song.18000.json','["细细金丝柳，重重青黛山。", "玉人楼上倚愁看。", "移得浅颦深恨，上眉间。", "泪湿红绡薄，香凝碧绮寒。", "多情别去未春残。", "归趁海棠开后、燕双还。"]'),
('song-ci-274','点绛唇','仇远','宋','宋词','song-ci','点绛唇','[]','黄帽棕鞋，出门一步为行客。',50,'宋词/ci.song.18000.json','["黄帽棕鞋，出门一步为行客。", "几时寒食。", "岸岸梨花白。", "马首山多，雨外青无色。", "谁禁得。", "残鹃孤驿。", "扑地春云黑。"]'),
('song-ci-275','点绛唇','仇远','宋','宋词','song-ci','点绛唇','[]','千里平阑，水天低处山无数。',50,'宋词/ci.song.18000.json','["千里平阑，水天低处山无数。", "断城孤树。", "城外人来去。", "欲问青鸾，杳杳随烟雾。", "空怀古。", "巴山何处。", "自翦镫听雨。"]'),
('song-ci-276','蝶恋花','仇远','宋','宋词','song-ci','蝶恋花','[]','碧树残鹃啼未歇。',70,'宋词/ci.song.18000.json','["碧树残鹃啼未歇。", "昨夜春归，不与行人别。", "留得绿杨枝上月。", "晓风吹作晴天雪。", "龟甲屏低红叠叠。", "火暖萸烟。", "罗荐鸳鸯热。", "一插宝簪云妥贴。", "下阶先拣花枝折。"]'),
('song-ci-277','蝶恋花','仇远','宋','宋词','song-ci','蝶恋花','[]','深院萧萧梧叶雨。',70,'宋词/ci.song.18000.json','["深院萧萧梧叶雨。", "知道秋来，不见秋来处。", "云压小桥人不渡。", "黄芦苦竹愁如雾。", "四壁秋声谁更赋。", "人只留春，不解留春住。", "秋又欲归天又暮。", "斜阳红影随鸦去。"]'),
('song-ci-278','虞美人','仇远','宋','宋词','song-ci','虞美人','[]','满城风雨消凝处。',66,'宋词/ci.song.18000.json','["满城风雨消凝处。", "谁是潘郎句。", "萧萧杨柳□凋黄。", "醉渡官桥瘦马、踏轻霜。", "旧时都道游春好。", "不似秋光小。", "菊花过了海棠来。", "定是催归锦字、不须开。"]'),
('song-ci-279','阮郎归','仇远','宋','宋词','song-ci','阮郎归','[]','教他双燕意循循。',56,'宋词/ci.song.18000.json','["教他双燕意循循。", "隔湖杨柳深。", "芹香泥滑趁新晴。", "差池来往频。", "春浪暖，绿无痕。", "醒人也醉人。", "断桥日落水云昏。", "归舟个个轻。"]'),
('song-ci-280','阮郎归','仇远','宋','宋词','song-ci','阮郎归','[]','桃花坊陌散香红。',56,'宋词/ci.song.18000.json','["桃花坊陌散香红。", "捎鞭骤玉骢。", "官河柳带结春风。", "高楼小燕空。", "山暗霭，草蒙茸。", "江南春正浓。", "王孙家在画桥东。", "相寻无路通。"]'),
('song-ci-281','渡江云','仇远','宋','宋词','song-ci','渡江云','[]','流莺啼怨粉，嫩寒著柳，语尚困东风。',124,'宋词/ci.song.18000.json','["流莺啼怨粉，嫩寒著柳，语尚困东风。", "问荒垣旧藓，烟雨何时，溅泪瘗危红。", "□愁不尽，对乱花、芳草茸茸。", "嗟绮尘、漂零无定，绡幕燕巢空。", "匆匆。", "玉銮声杳，绣屋香消，谩精神入梦。", "记旧家、定场声价，曾冠深宫。", "香魂彷佛留环佩，正淡月、春雾朦朦。", "花影底，长年恨锁云容。"]'),
('song-ci-282','卜算子','仇远','宋','宋词','song-ci','卜算子','[]','疏树小花风，别浦残鹃雨。',52,'宋词/ci.song.18000.json','["疏树小花风，别浦残鹃雨。", "不是王孙忘却归，草没归来路。", "空积琐窗尘，谁按琼箫谱。", "暗把金钱卜远人，争敢分明语。"]'),
('song-ci-283','眼儿媚','仇远','宋','宋词','song-ci','眼儿媚','[]','谢家池馆占花中。',58,'宋词/ci.song.18000.json','["谢家池馆占花中。", "微雨湿春风。", "艳红修碧，浓香疏影，浮动帘栊。", "娇蛾聚翠寻春梦，衣上泪痕重。", "闲窗愁对，金笼鹦鹉，彩带芙蓉。"]'),
('song-ci-284','眼儿媚','仇远','宋','宋词','song-ci','眼儿媚','[]','伤春情味酒频中。',58,'宋词/ci.song.18000.json','["伤春情味酒频中。", "困倚小屏风。", "宝钗斜插，懒来梳洗，懒出帘栊。", "云鬟䰀鬌娇无力，此醉不禁重。", "分明彷佛，未央杨柳，太液芙蓉。"]'),
('song-ci-285','谒金门','仇远','宋','宋词','song-ci','谒金门','[]','但病酒。',53,'宋词/ci.song.18000.json','["但病酒。", "愁对清明时候。", "不为吟诗应也瘦。", "坐久衣痕皱。", "曾约花间携手。", "空忆洛阳耆旧。", "道不相逢还却又。", "海棠开厮句。"]'),
('song-ci-286','南乡子','仇远','宋','宋词','song-ci','南乡子','[]','急雨涨潮头。',66,'宋词/ci.song.18000.json','["急雨涨潮头。", "越树吴城势拍浮。", "海鹤一声苍竹裂，扁舟。", "轻载行云压水流。", "独倚最高楼。", "回首屏山叠叠秋。", "江上数峰人不见，沙鸥。", "曾识西风独客愁。"]'),
('song-ci-287','酹江月・念奴娇','仇远','宋','宋词','song-ci','酹江月・念奴娇','[]','探春消息，觉南枝开遍，北枝犹阙。',120,'宋词/ci.song.18000.json','["探春消息，觉南枝开遍，北枝犹阙。", "越女娉婷天下白，堪与冰霜争洁。", "孤影棱棱，暗香楚楚，水月成三绝。", "行云不动，素波轻浣尘袜。", "回首雪里关山，玉龙吹怨，似替人幽咽。", "溪上园林应满树，一径莓苔萦折。", "金马疏篱，玉堂茅舍，终是风光别。", "寻花欲语，对花却又无说。"]'),
('song-ci-288','酹江月・念奴娇','仇远','宋','宋词','song-ci','酹江月・念奴娇','["\u897f\u6e56"]','片云凝墨，看荷花才湿，依然无雨。',120,'宋词/ci.song.18000.json','["片云凝墨，看荷花才湿，依然无雨。", "水槛空明人少到，却却幽禽相语。", "曲几横陈，长琴高挂，自奏南风谱。", "俄闻刀尺，隔窗人翦霜苎。", "因念西子湖边，闹红一舸，曾宿鸳鸯浦。", "翠羽不传沧岛信，日暮闲情□与。", "懒拂鸾笺，懒拈象管，秀句同谁赋。", "孤鸿程杳，夕阳低下平楚。"]'),
('song-ci-289','玉蝴蝶','仇远','宋','宋词','song-ci','玉蝴蝶','[]','独立软红尘表，远吞翠雾，平挹纹澜。',123,'宋词/ci.song.18000.json','["独立软红尘表，远吞翠雾，平挹纹澜。", "草长西垣，生怕隔断双鬟。", "树梢明、夕阳未冷，菱叶静、新雨初乾。", "倚阑干。", "一声鹅管，人影高寒。", "休寻王孙桂隐，白云鸡犬，曾识刘安。", "羽扇纶巾，不知门外有人闲。", "袖素手、懒招黄鹄，写碧笺、空寄青鸾。", "且盘桓。", "听风听雨，山川山南。"]'),
('song-ci-290','玉蝴蝶','仇远','宋','宋词','song-ci','玉蝴蝶','["\u897f\u6e56"]','野树昏鸦归尽，素烟如练，低罩平芜。',124,'宋词/ci.song.18000.json','["野树昏鸦归尽，素烟如练，低罩平芜。", "断壁飞楼，红翠似有还无。", "女墙矮、月笼粉雉，娃馆静、尘暗金铺。", "问清都。", "广寒仙子，别后何如。", "愁予。", "十年梦境，浅歌短酒，总是欢娱。", "寂寞秦郎，不堪离镜照鸾孤。", "记曲径、共携素手，向闲窗、频拈吟须。", "怕西湖。", "少年游伴，说著当初。"]'),
('song-ci-291','金缕曲・贺新郎','仇远','宋','宋词','song-ci','金缕曲・贺新郎','[]','仙骨清无暑。',142,'宋词/ci.song.18000.json','["仙骨清无暑。", "爱兰桡、撑入鸳波，锦云深处。", "休唱采莲双浆曲，老却鸥朋鹭侣。", "算只有、青山如故。", "旧雨初晴新水涨，画桥低、杳霭迷苍渚。", "头戴笠，日亭午。", "独醒耿耿空怀楚。", "渺愁予、岸芷江蓠，尚青青否。", "锦瑟谩弹斑竹恨，难写湘妃怨语。", "怅谁与、孤芳为主。", "流水无声云不动，向渔郎、欲觅桃园路。", "船尾带，落花去。"]'),
('song-ci-292','霜天晓角','仇远','宋','宋词','song-ci','霜天晓角','[]','绮帷高揭。',54,'宋词/ci.song.18000.json','["绮帷高揭。", "风动流苏结。", "兴在夜凉多处，兰烬短、半明灭。", "醉彻。", "香未绝。", "紫箫声乍歇。", "声入碧云堆里，还起舞、桂花月。"]'),
('song-ci-293','浪淘沙','仇远','宋','宋词','song-ci','浪淘沙','[]','芍药小纱窗。',64,'宋词/ci.song.18000.json','["芍药小纱窗。", "唾碧茸长。", "粉香犹涴旧时妆。", "玉佩丁东仙步远，好处难忘。", "草草赋高唐。", "终是荒凉。", "凉蟾飞入合欢床。", "争得花阴重邂逅，才不思量。"]'),
('song-ci-294','烛影摇红','仇远','宋','宋词','song-ci','烛影摇红','[]','中酒情怀，怨春羞见桃花面。',116,'宋词/ci.song.18000.json','["中酒情怀，怨春羞见桃花面。", "王孙别去草萋萋，十里青如染。", "不恨梨云梦远。", "恨只恨、盟深交浅。", "一般孤闷，两下相思，黄昏依黯。", "楼依斜阳，翠鸾不到音书远。", "绿窗空对绣鸳鸯，□缕凭谁翦。", "知在新亭旧院。", "杜鹃啼、东风意懒。", "便归来后，也过清明，花飞春减。"]'),
('song-ci-295','生查子','仇远','宋','宋词','song-ci','生查子','[]','飞尘入建章，乐事难重见。',48,'宋词/ci.song.18000.json','["飞尘入建章，乐事难重见。", "白发故宫娃，闲说沈香宴。", "霓裳秋梦寒，□靸黏冰片。", "萤火起庭莎，犹忆轻罗扇。"]'),
('song-ci-296','醉落魄・一斛珠','仇远','宋','宋词','song-ci','醉落魄・一斛珠','[]','水西云北。',67,'宋词/ci.song.18000.json','["水西云北。", "锦苞泫露无颜色。", "夜寒花外眠双鶒。", "莫唱江南，谁是鹧鸪客。", "薄情青女司花籍。", "粉愁红怨啼螀急。", "月明倦听山阳笛。", "渺渺征鸿，千里楚天碧。"]'),
('song-ci-297','江神子・江城子','仇远','宋','宋词','song-ci','江神子・江城子','[]','云阶步影夜凄凉。',86,'宋词/ci.song.18000.json','["云阶步影夜凄凉。", "采丹房。", "宿芽黄。", "万粟千萤，风露四阑香。", "歌断小山枝上月，环佩冷，怯流光。", "年时金屋罩琴床。", "忆情郎。", "淡梳妆。", "笋玉春纤，挼蕊细浮觞。", "愁夜满城今旧雨，分付菊，自重阳。"]'),
('song-ci-298','八声甘州','仇远','宋','宋词','song-ci','八声甘州','[]','敛双蛾、冷雨立毡车，离思上青枫。',119,'宋词/ci.song.18000.json','["敛双蛾、冷雨立毡车，离思上青枫。", "想天阶辞辇，长门分镜，征骑西东。", "应被婵娟早误，谁遣出深宫。", "鸾袖不堪绾，前事成空。", "独掩琵琶无语，恨主恩太薄，泪脸弹红。", "又争如汉月，深夜照帘栊。", "草青青、年年归梦，算北来、应自有征鸿。", "还堪笑，玉关何事，不锁春风。"]'),
('song-ci-299','清平乐','仇远','宋','宋词','song-ci','清平乐','[]','寒泉如线。',54,'宋词/ci.song.18000.json','["寒泉如线。", "莎石绵云软。", "十里梅花香一片。", "不记入山深浅。", "谩留两袖春风。", "罗浮旧梦成空。", "独对阑干明月，教人犹忆山中。"]'),
('song-ci-300','清平乐','仇远','宋','宋词','song-ci','清平乐','[]','苑秋凉早，石径幽花小。',54,'宋词/ci.song.18000.json','["苑秋凉早，石径幽花小。", "霜絮飞飞风草草。", "翠碧斓斑驰道。", "香沟诗叶难寻。", "依然绿浅红深。", "倚竹空歌黄鹄，谁招青冢游云。"]'),
('song-ci-301','塞翁吟','仇远','宋','宋词','song-ci','塞翁吟','[]','短绿抽堤草，芳信未许花知。',114,'宋词/ci.song.18000.json','["短绿抽堤草，芳信未许花知。", "尚留冻梗冰枝。", "藓石雪消迟。", "方塘水浅鸳鸯冷，沙际水翼相依。", "拾翠约，踏青期。", "终是乐游稀。", "相思。", "江南远，渔汀渺渺，还又是、梅花谢时。", "有多少、旧愁新恨，纵罗虬、妙曲风流，怎比红儿。", "何时再得，画鹢摇春，丰乐楼西。"]'),
('song-ci-302','塞翁吟','仇远','宋','宋词','song-ci','塞翁吟','[]','风柳吹残醉，惟枕梦便难寻。',115,'宋词/ci.song.18000.json','["风柳吹残醉，惟枕梦便难寻。", "小院静，曲屏深。", "翦不断轻阴。", "新蚕乍扫鹅毛细，纤手镂叶如针。", "又负了，赏花心。", "听高树鸣禽。", "千金。", "嗟难买，飘红坠粉，怕容易、愁痕暗侵。", "但惜取、婵娟好在，任千里、杳杳鸿迷，渺渺鱼沈。", "相如未老，尽把衷肠，分付瑶琴。"]'),
('song-ci-303','忆旧游','仇远','宋','宋词','song-ci','忆旧游','["\u897f\u6e56"]','忆寒烟古驿，淡月孤舟，无限江山。',124,'宋词/ci.song.18000.json','["忆寒烟古驿，淡月孤舟，无限江山。", "落叶牵离思，到秋来，夜夜梦入长安。", "故人翦烛清话，风雨半窗寒。", "甚宦海漂流，客毡寂寞，忍说闲关。", "征衫。", "赋归去，喜故里西湖，不厌重看。", "莫待青春晚，趁莺花未老，觅醉寻欢。", "故园更有松竹，富贵不如闲。", "却指顾斜阳，长歌李白行路难。"]'),
('song-ci-304','忆旧游','仇远','宋','宋词','song-ci','忆旧游','[]','对庭芜黯淡，院柳萧疏，还又深秋。',123,'宋词/ci.song.18000.json','["对庭芜黯淡，院柳萧疏，还又深秋。", "正一星镫暗，更一声雁过，一点萤流。", "合成一片离思，都在小红楼。", "想扑地阴云，人愁不尽，诗与天愁。", "酸风未应□，雨簌簌潇潇，欲下还收。", "忆绣帏贪睡，任花悄晨影，移上帘钩。", "被池半卷红浪，衣冷复熏篝。", "怎忘得江南，风流庾信空白头。"]'),
('song-ci-305','小秦王','仇远','宋','宋词','song-ci','小秦王','[]','眼溜秋潢脸晕霞。',32,'宋词/ci.song.18000.json','["眼溜秋潢脸晕霞。", "宝钗斜压两盘鸦。", "分明认得萧郎是，佯凭阑干唤卖花。"]'),
('song-ci-306','小秦王','仇远','宋','宋词','song-ci','小秦王','[]','水拍江堤没软沙。',32,'宋词/ci.song.18000.json','["水拍江堤没软沙。", "菰蒲深处钓鱼家。", "罾头免得黏风絮，船尾依然带落花。"]'),
('song-ci-307','木兰花令','仇远','宋','宋词','song-ci','木兰花令','[]','月堕觚棱寒鹊起。',64,'宋词/ci.song.18000.json','["月堕觚棱寒鹊起。", "露拭秋空清似水。", "西风昨起过江南，红叶黄芜三四里。", "香莼先近幽人齿。", "断杵偏来征客耳。", "沧洲无路迷将归，□叠楚山□梦里。"]'),
('song-ci-308','八拍蛮','仇远','宋','宋词','song-ci','八拍蛮','[]','翠袖笼香醒宿酒，银瓶汲水瀹新茶。',32,'宋词/ci.song.18000.json','["翠袖笼香醒宿酒，银瓶汲水瀹新茶。", "几处杜鹃啼暮雨，来禽空老一春花。"]'),
('song-ci-309','好女儿','仇远','宋','宋词','song-ci','好女儿','[]','恨结眉峰。',76,'宋词/ci.song.18000.json','["恨结眉峰。", "两抹青浓。", "不忺人、昨夜曾中酒，甚小蛮绿困，太真红醉，肯嫁东风。", "无奈游丝堕蕊，尽日□逐花蓬。", "把西园、斗草芳期阻，怕明朝微雨，庭莎翠滑，湿透莲弓。"]'),
('song-ci-310','桃园忆故人・桃源忆故人','仇远','宋','宋词','song-ci','桃园忆故人・桃源忆故人','[]','苎萝山下花藏路。',56,'宋词/ci.song.18000.json','["苎萝山下花藏路。", "只许流莺来去。", "吹落梨花无数。", "香雪迷官渡。", "浣纱溪浅人何许。", "空对碧云凝暮。", "归去春愁如雾。", "奈五更风雨。"]'),
('song-ci-311','忆闷令','仇远','宋','宋词','song-ci','忆闷令','[]','岸柳丝丝青尚浅。',56,'宋词/ci.song.18000.json','["岸柳丝丝青尚浅。", "渐春归吴苑。", "缭垣不隔花屏，爱翠深红远。", "瞥地飞来何处燕。", "小乌衣新翦。", "想芹短、未出香泥，波面时时点。"]'),
('song-ci-312','极相思','仇远','宋','宋词','song-ci','极相思','[]','云头灰冷，金彝熏透茜罗衫。',60,'宋词/ci.song.18000.json','["云头灰冷，金彝熏透茜罗衫。", "可人犹带，紫陌青门，珠泪斑斑。", "自恨移根无宿土，红姿减、绿意阑珊。", "有谁知我，花明眼暗，如雾中看。"]'),
('song-ci-313','少年游','仇远','宋','宋词','song-ci','少年游','[]','钗云垂耳未胜冠，私语别青鸾。',60,'宋词/ci.song.18000.json','["钗云垂耳未胜冠，私语别青鸾。", "露帐银床，海棠睡足，偏称晚来看。", "一年一梦青楼曲，香浅被池寒。", "却听西风，小窗残雨，红叶满长安。"]'),
('song-ci-314','燕归来・喜迁莺','仇远','宋','宋词','song-ci','燕归来・喜迁莺','[]','三叠曲，四愁诗。',58,'宋词/ci.song.18000.json','["三叠曲，四愁诗。", "心事少人知。", "西风未老燕迟归。", "巢冷半乾泥。", "流红句，回文字。", "除燕知，谁能记。", "一声却到画楼西。", "云压小鸿低。"]'),
('song-ci-315','睡花阴令・醉花阴','仇远','宋','宋词','song-ci','睡花阴令・醉花阴','[]','愁云歇雨，净洗一奁秋霁。',56,'宋词/ci.song.18000.json','["愁云歇雨，净洗一奁秋霁。", "枝上鹊、欲栖还起。", "曲阑人独倚。", "持杯酌月，月未醉、笑人先醉。", "忘醉倚、木犀花睡。", "满衣花影碎。"]'),
('song-ci-316','望仙楼・胡捣练','仇远','宋','宋词','song-ci','望仙楼・胡捣练','[]','九仙山晓。',56,'宋词/ci.song.18000.json','["九仙山晓。", "雾冥冥、一鹤飞来华表。", "衔得红云花岛。", "双蒂仙桃小。", "破罂旋汲香泉，短鑺闲锄春草。", "愁种愁深多少。", "头白鸳鸯老。"]'),
('song-ci-317','眼儿媚','仇远','宋','宋词','song-ci','眼儿媚','[]','苔笺醉草调清平。',58,'宋词/ci.song.18000.json','["苔笺醉草调清平。", "鸦墨湿浮云。", "霓裳步冷，琼箫声断，旧梦关心。", "小乔不恋周郎老，翠被折秋痕。", "那堪门外，黄花红叶，细雨更深。"]'),
('song-ci-318','爱月夜眠迟・爱月夜眠迟慢','仇远','宋','宋词','song-ci','爱月夜眠迟・爱月夜眠迟慢','[]','小市收镫，渐柝声隐隐，人语沈沈。',125,'宋词/ci.song.18000.json','["小市收镫，渐柝声隐隐，人语沈沈。", "月华如水，香街尘冷，阑干琐碎花阴。", "罗帏不隔婵娟，多情伴人，孤枕最分明。", "见屏山翠叠，遮断行云。", "因记款曲西厢，趁凌波步影，笑拾遗簪。", "元宵相次近也，沙河箫鼓，却是如今。", "行行舞袖歌裙。", "归还不管更深。", "黯无言，新愁旧月，空照黄昏。"]'),
('song-ci-319','花心动','仇远','宋','宋词','song-ci','花心动','[]','醒眼明霞，问染成、晴堤几分秋色。',127,'宋词/ci.song.18000.json','["醒眼明霞，问染成、晴堤几分秋色。", "腻困未醒，欲语还羞，掩映雾笼烟幂。", "艳姿相亚柔枝妥，恁娇倚、西风无力。", "只疑是、彩云散影，误留仙魄。", "不见芳卿消息。", "但晓沁嫣红，雨湿轻白。", "落日光中，窥影横塘，却似试妆脉脉。", "芳心空有韶华想，忍拼与、清霜狼籍。", "雁声里、丹枫伴人泪滴。"]'),
('song-ci-320','薄幸','仇远','宋','宋词','song-ci','薄幸','[]','眼波横秀。',130,'宋词/ci.song.18000.json','["眼波横秀。", "乍睡起、茸窗倦绣。", "甚脉脉、阑干凭晓，一握乱丝如柳。", "最恼人、微雨悭晴，飞红满地春风骤。", "记帕折香绡，簪敲凉玉，小约清明前后。", "昨梦云何处，应只在，春城迷酒。", "对溪桃羞语，海棠贪困，莺声唤醒愁仍旧。", "劝花休瘦。", "看钗盟再合，秋千小院同携手。", "回文锦字，寄与知他信否。"]'),
('song-ci-321','风流子','仇远','宋','宋词','song-ci','风流子','[]','红锦旧同心。',133,'宋词/ci.song.18000.json','["红锦旧同心。", "西池上、曾与系青禽。", "记山水写情，秋桐促轸，鸳鸯萦恨，春绣停针。", "常叹好风妨画扇，明月堕瑶簪。", "短梦易残，一声长笛，新愁无限，何处孤砧。", "香奁依然在，但鸾镜、孤影渺渺难寻。", "雨后胭脂，应想粉蚀尘侵。", "怅去帆渐杳，鱼鳞浪浅，远笺难寄，鸿尾云深。", "回首高楼，不堪烟雨平林。"]'),
('song-ci-322','清商怨','仇远','宋','宋词','song-ci','清商怨','[]','黄花丹叶绀草。',51,'宋词/ci.song.18000.json','["黄花丹叶绀草。", "染恨西园晓。", "梦度秦楼，孤鸿云影倒。", "连环旧约忘了。", "应记□、绿珠娇小。", "莫翦回文，玉关人未老。"]'),
('song-ci-323','台城路・齐天乐','仇远','宋','宋词','song-ci','台城路・齐天乐','[]','海棠才试春光小，西风便吹秋去。',123,'宋词/ci.song.18000.json','["海棠才试春光小，西风便吹秋去。", "白石粼粼，丹林点点，装缀东皋南浦。", "清游顿阻。", "谩空有园林，可无钟鼓。", "一曲庭花，隔江谁与问商女。", "离怀浑似梦里，碧云犹冉冉，佳人何处。", "越岫难盟，秦楼燕约，争奈年华已暮。", "凭高吊古。", "算只有梅花，伴人凄楚。", "极目天长，淡霞明断雨。"]'),
('song-ci-324','醉公子','仇远','宋','宋词','song-ci','醉公子','[]','晓入蓬莱岛。',48,'宋词/ci.song.18000.json','["晓入蓬莱岛。", "松下锄瑶草。", "贪看碧桃花。", "误游金母家。", "一酌洼尊露。", "醉失归来路。", "不见董双成。", "隔花闻笛声。"]'),
('song-ci-325','台城路・齐天乐','仇远','宋','宋词','song-ci','台城路・齐天乐','[]','画楼西送斜阳下，不随逝波东去。',123,'宋词/ci.song.18000.json','["画楼西送斜阳下，不随逝波东去。", "野旷莎长，山空木短，零落红衣南浦。", "游云路阻。", "便魂断苍梧，怨弦谁鼓。", "空采江蓠，□□□□吊湘女。", "迢迢千里万里。", "碧天空雁信，传意无处。", "翠袖闲笼，珠帏怨卧，几度黄昏□暮。", "相思自古。", "怅独客三吴，故人三楚。", "懒话巴山，翦镫同听雨。"]'),
('song-ci-326','庆春宫・高阳台','仇远','宋','宋词','song-ci','庆春宫・高阳台','[]','江影涵空，山光浮水，画楼直倚东城。',126,'宋词/ci.song.18000.json','["江影涵空，山光浮水，画楼直倚东城。", "落叶声稀，归鸿声杳，晚风却递钟声。", "去天咫尺，祗疑是、齐云摘星。", "阑干疑伫，愁见垂杨，烟絮萦萦。", "官梅冷笑相迎。", "□怕繁枝，容易凋零。", "因念□□，吟仙鹤去，断桥谁赋疏清。", "染云如黛，这雪意、看看做成。", "有谁知得，庾信闲愁，陶令闲情。"]'),
('song-ci-327','阳台怨','仇远','宋','宋词','song-ci','阳台怨','[]','月明如白日。',54,'宋词/ci.song.18000.json','["月明如白日。", "遮径花阴密密。", "未见黄云衬袜来，空伴花阴立。", "疑是碧瑶台，不放彩鸾飞出。", "隐隐隔花清漏急。", "一巾红露湿。"]'),
('song-ci-328','梦江南・忆江南','仇远','宋','宋词','song-ci','梦江南・忆江南','["\u897f\u6e56"]','花露湿，黯黯覆庭燕。',64,'宋词/ci.song.18000.json','["花露湿，黯黯覆庭燕。", "十二阑干空见月，谁教凉影伴人孤。", "素被带香铺。", "情荏苒，金屋又笙竽。", "天际有云难载鹤，墙东无树可啼乌。", "春梦绕西湖。"]'),
('song-ci-329','巫山一段云','仇远','宋','宋词','song-ci','巫山一段云','[]','酒力欺愁薄，轻红晕脸微。',52,'宋词/ci.song.18000.json','["酒力欺愁薄，轻红晕脸微。", "双鸳谁袖出青闺。", "剗袜步东西。", "倦蝶栖香懒，雏莺调语低。", "钗盟惟有烛花知。", "半醉欲归时。"]'),
('song-ci-330','忆秦娥','仇远','宋','宋词','song-ci','忆秦娥','[]','秋乍觉。',56,'宋词/ci.song.18000.json','["秋乍觉。", "露凉顿觉罗衾薄。", "罗衾薄。", "黄昏庭院，水风帘幕。", "阑干待月花时约。", "愁长梦短浑忘却。", "浑忘却。", "南山猿鹤，北枝乌鹊。"]'),
('song-ci-331','八犯玉交枝・八宝妆','仇远','宋','宋词','song-ci','八犯玉交枝・八宝妆','[]','沧岛云连，绿瀛秋入，暮景欲沈洲屿。',132,'宋词/ci.song.18000.json','["沧岛云连，绿瀛秋入，暮景欲沈洲屿。", "无浪无风天地白，听得潮生人语。", "擎空孤柱。", "翠倚高阁恁虚，中流苍碧迷烟雾。", "惟见广寒门外，青无重数。", "遥想贝阙珠宫，琼林玉树。", "不知还是何处。", "倩谁问、凌波轻步。", "谩凝睇、乘鸾秦女。", "想庭曲、霓裳正舞。", "莫须长笛吹愁去。", "怕唤起鱼龙，三更喷作前山雨。"]'),
('song-ci-332','夜行船','仇远','宋','宋词','song-ci','夜行船','[]','十二阑干和露倚。',68,'宋词/ci.song.18000.json','["十二阑干和露倚。", "银潢淡、玉蟾如洗。", "万籁无声，纤云不染。", "目断楚天千里。", "自把黄花闲数蕊。", "空招隐、湘君山鬼。", "古剑埋光，孤灯倒影，咄咄树犹如此。"]'),
('song-ci-333','荐金蕉','仇远','宋','宋词','song-ci','荐金蕉','[]','梅边当江南信。',32,'宋词/ci.song.18000.json','["梅边当江南信。", "醉语无恁准。", "斜阳丹叶一帘秋。", "燕去鸿来，相忆几时休。"]'),
('song-ci-334','思佳客','仇远','宋','宋词','song-ci','思佳客','[]','落尽红雨乍收。',63,'宋词/ci.song.18000.json','["落尽红雨乍收。", "新篁静院叫钩輈。", "柳丝轻拂阑干角，怕引闲愁懒上楼。", "春淡淡，水悠悠。", "椅窗曾为牡丹留。", "转头千载真成梦，赢得春风一枕愁。"]'),
('song-ci-335','思佳客','仇远','宋','宋词','song-ci','思佳客','[]','日影扶花一万重。',63,'宋词/ci.song.18000.json','["日影扶花一万重。", "秋香阁下又芙蓉。", "旧时楚楚霓裳，移入长杨短柳中。", "文甃碧，朱墙红。", "金舆苍鼠玉华宫。", "行人忍听啼乌怨，笛里阑干落叶风。"]'),
('song-ci-336','蝶恋花','仇远','宋','宋词','song-ci','蝶恋花','[]','燕燕楼空帘意静。',70,'宋词/ci.song.18000.json','["燕燕楼空帘意静。", "露叶如啼，红沁胭脂井。", "浅约深盟期未定。", "木犀风里鸳鸯径。", "楚岫秦眉相入映。", "私倚云阑，淡月笼花顶。", "今夕兰釭空吊影。", "绣衾罗荐馀香冷。"]'),
('song-ci-337','秋蕊香','仇远','宋','宋词','song-ci','秋蕊香','[]','三径归来秋早。',57,'宋词/ci.song.18000.json','["三径归来秋早。", "门外金铺谁扫。", "东篱不种闲花草。", "恼乱西风未了。", "霜华侵鬓渊明老。", "南山晓。", "啼红怨绿骎骎少。", "自采落叶英黄小。"]'),
('song-ci-338','解连环','仇远','宋','宋词','song-ci','解连环','[]','绮疏人独。',132,'宋词/ci.song.18000.json','["绮疏人独。", "记芙蓉院宇，玉箫同宿。", "尚隐约、屏窄山多，□衾暖浪浮，帐香云扑。", "步袜蹁然，又何处、秦筝金屋。", "□柔簪易折，破镜难留，断缕难续。", "斜阳谩穷倦目。", "甚天寒袖薄，犹倚修竹。", "待听雨、闲说前期，奈心在江南，人在江北。", "老却休文，自笑我、腰围如束。", "莫思量，寻花傍柳，旧时杜曲。"]'),
('song-ci-339','雪狮儿','仇远','宋','宋词','song-ci','雪狮儿','[]','武林春早，乘兴试问，孤山枝南枝北。',112,'宋词/ci.song.18000.json','["武林春早，乘兴试问，孤山枝南枝北。", "见说椒红，初破芳苞犹绿。", "罗浮梦熟。", "记曾有、幽禽同宿。", "依稀是、缟衣楚楚，佳人空谷。", "娇小春意未足。", "甚娇羞，怕入玉堂金屋。", "误学宫妆，粉额蜂黄轻扑。", "江空岁晚，最难是、旧交松竹。", "忒幽独。", "笛倚画楼西曲。"]'),
('song-ci-340','探芳信','仇远','宋','宋词','song-ci','探芳信','[]','坐清昼。',109,'宋词/ci.song.18000.json','["坐清昼。", "记步幄行春，短亭呼酒。", "怅湔裙香远，波痕尚依旧。", "亦阑桥下桃花观，寒勒花枝瘦。", "转回廊、古瓦生松，暗泉鸣甃。", "山雨夜来骤。", "便绿涨平堤，云横远岫。", "细认沙头，还见有落红否。", "杨花自趁东风去，空白鸳鸯首。", "劝游人、莫把骄骢系柳。"]'),
('song-ci-341','琐窗寒','仇远','宋','宋词','song-ci','琐窗寒','[]','小袖啼红，残茸唾碧，深愁如织。',120,'宋词/ci.song.18000.json','["小袖啼红，残茸唾碧，深愁如织。", "闲愁不断，冉冉舞丝千尺。", "倚修筠、袖笼浅寒，望人在水西云北。", "想绿杨影里，兰舟轻舣，赤阑桥侧。", "游剧归来，恨汗湿酥融，步悭袜窄。", "兰情蕙盼，付与栖鸾消息。", "奈无情、风雨做愁，帐镫闪闪春寂寂。", "梦相思、一枕巫山，更画楼吹笛。"]'),
('song-ci-342','一寸金','仇远','宋','宋词','song-ci','一寸金','[]','楼倚寒城，隔岸江山见东越。',131,'宋词/ci.song.18000.json','["楼倚寒城，隔岸江山见东越。", "望远红千尺，游丝起舞，空青一段，斜阳明灭。", "孤树秋声歇。", "霜枝袅、尚留病叶。", "阑干外、带郭人家，蜂房几盘折。", "我独逍遥，乘虚凭远，天风醒毛发。", "问西窗停烛，谁吟巴雨，连床鼓瑟，谁弹湘月。", "消得青鸾下，分明是、绛台紫阙。", "何时约、姑射仙人，试手回翦雪。"]'),
('song-ci-343','声声慢','仇远','宋','宋词','song-ci','声声慢','[]','藏莺院静，浮鸭池荒。',119,'宋词/ci.song.18000.json','["藏莺院静，浮鸭池荒。", "绿阴不减红芳。", "高卧虚堂。", "南风时送微凉。", "游鞯践香未遍，怪青春、别我堂堂。", "闲里好，有故书盈箧，新酒盈缸。", "只怕吴霜侵鬓，叹春深铜雀，空老周郎。", "弱絮沾泥，如今梦冷平康。", "翻思旧游踪迹，认断云、低度横塘。", "离恨满，甚月明、偏照小窗。"]'),
('song-ci-344','越山青・长相思','仇远','宋','宋词','song-ci','越山青・长相思','[]','四月时。',44,'宋词/ci.song.18000.json','["四月时。", "五月时。", "柳絮无风不肯飞。", "卷帘看燕归。", "雨凄凄。", "草凄凄。", "及早关门睡起迟。", "省人多少诗。"]'),
('song-ci-345','尾犯','仇远','宋','宋词','song-ci','尾犯','[]','宝蜡夜笼花，不碍画楼，无限清景。',116,'宋词/ci.song.18000.json','["宝蜡夜笼花，不碍画楼，无限清景。", "病叶分秋，翦愁桐金井。", "银汉外、尘飞不到，暮云收、琉璃万顷。", "弁山横翠，好倩西风，送上江心镜。", "霓裳空楚楚，钧天旧梦难醒。", "最忆婵娟，□钗钿香冷。", "欲高跨、娇鸾归去，又还愁、乌啼酒醒。", "独思前事，夜永谁问相如病。"]'),
('song-ci-346','两同心','仇远','宋','宋词','song-ci','两同心','[]','踏青归后，小步西园。',86,'宋词/ci.song.18000.json','["踏青归后，小步西园。", "翠袖薄、新篁难倚，绿窗润、弱絮轻黏。", "春风急，暮雨凄然。", "早听啼鹃。", "忆昔几度湖边。", "款曲花前。", "约俊客、同倾凿落，看游女、同上秋千。", "春无主，落日低烟。", "芳草年年。"]'),
('song-ci-347','瑶花慢','仇远','宋','宋词','song-ci','瑶花慢','[]','疏疏密密，漠漠纷纷，乍舞风无力。',126,'宋词/ci.song.18000.json','["疏疏密密，漠漠纷纷，乍舞风无力。", "残砖断础，才转眼、化作方圭园壁。", "非花非絮，似骋巧、先投窗隙。", "立小楼、不见青山，万里鸟飞无迹。", "休邻冻梗冰苔，算飞入园林，都是春色。", "年华婉娩，谁信道、老却梁园词客。", "踏青近也，且一白、何消三白。", "把一白、分与梅花，要点寿阳妆额。"]'),
('song-ci-348','破阵子','仇远','宋','宋词','song-ci','破阵子','[]','柳浪六桥春碧，香尘十里香风。',72,'宋词/ci.song.18000.json','["柳浪六桥春碧，香尘十里香风。", "好是烂游浓醉后，画□阑干见小红。", "红明绿暗中。", "旧约涌金门道，纱笼毕竟相逢。", "只恐入城归路杂，便转头树北云东。", "侯门深几重。"]'),
('song-ci-349','凤凰阁','仇远','宋','宋词','song-ci','凤凰阁','[]','晴绵欺雪，扑扑红楼锦幄。',82,'宋词/ci.song.18000.json','["晴绵欺雪，扑扑红楼锦幄。", "小晴蜓载水花泊。", "犹记横波浅笑，香云深约。", "甚可怪、匆匆忘却。", "寻芳人老，那得心情问著。", "雁程不到怨无托。", "还又月笛幽院，风镫疏箔。", "谩傍竹、寒笼翠薄。"]'),
('song-ci-350','归田乐','仇远','宋','宋词','song-ci','归田乐','[]','略彴横溪曲。',80,'宋词/ci.song.18000.json','["略彴横溪曲。", "映带短莎修竹。", "傍岸谁家屋。", "爱水护遥碧，林拥深绿。", "呼布谷。", "东里西邻才一簇。", "社鼓初鸣春酒熟。", "长衫方帽，翁醉扶黄犊。", "断霞倦鹊，未晚先争宿。", "门外月明三六六。"]'),
('song-ci-351','解佩令','仇远','宋','宋词','song-ci','解佩令','[]','浅莎深苑，流萤暗度。',84,'宋词/ci.song.18000.json','["浅莎深苑，流萤暗度。", "问霜纨、藏在何处。", "一自西风，乱翦翦、枝头红露。", "怕因循、彩鸾尘蠹。", "歌台香散，离宫烛暗，谩消凝、凌波微步。", "最怕黄昏，小楼外、零云残雨。", "把相思、共青镫诉。"]'),
('song-ci-352','何满子・河满子','仇远','宋','宋词','song-ci','何满子・河满子','[]','舞褥行云衬步，歌纨片月生怀。',86,'宋词/ci.song.18000.json','["舞褥行云衬步，歌纨片月生怀。", "歌残舞罢花困软，凝情犹小徘徊。", "髻滑频扶堕珥，裙低略露弓鞋。", "当日凝香清燕，惯听八拍三台。", "谢娘荀令都□老，匆匆好梦惊回。", "闲指青衫旧泪，空连半股鸾钗。"]'),
('song-ci-353','更漏子','仇远','宋','宋词','song-ci','更漏子','[]','楝花风，都过了。',58,'宋词/ci.song.18000.json','["楝花风，都过了。", "冷落绿阴池沼。", "春草草，草离离。", "离人归未归。", "暗魂消，频梦见。", "依约旧时庭院。", "红笑浅，绿颦深。", "东风不自禁。"]'),
('song-ci-354','庆清朝','仇远','宋','宋词','song-ci','庆清朝','[]','山束滩声，月移石影，寒江夜色空浮。',118,'宋词/ci.song.18000.json','["山束滩声，月移石影，寒江夜色空浮。", "丹青古壁，风幡横卧东流。", "小舣载云轻棹，湖痕渐落葑泥稠。", "津亭外，隔船吹笛，唤起眠鸥。", "非但予愁渺渺，料那人，应自有、一襟愁。", "霜栖露泊，容易吹白人头。", "漠漠荻花胜雪，拟寻静岸略移舟。", "留闲耳，听莺小院，听雨西楼。"]'),
('song-ci-355','一落索','仇远','宋','宋词','song-ci','一落索','[]','尽日西阑凭醉。',56,'宋词/ci.song.18000.json','["尽日西阑凭醉。", "新寒难睡。", "袖炉烟冷帐云宽，倩倩倩、先温被。", "空对短屏山水。", "清清无寐。", "却思十里小红楼，应不报、平安字。"]'),
('song-ci-356','相思引','仇远','宋','宋词','song-ci','相思引','[]','鸦墨斜行印粉香。',54,'宋词/ci.song.18000.json','["鸦墨斜行印粉香。", "倚楼凝望过鸿将。", "寸心天远，月冷梦浮湘。", "题恨谩留诗叶小，合欢空恋舞衣长。", "旧愁千斛，深浅倩谁量。"]'),
('song-ci-357','生查子','仇远','宋','宋词','song-ci','生查子','[]','钗头缀玉虫，耿耿东窗晓。',48,'宋词/ci.song.18000.json','["钗头缀玉虫，耿耿东窗晓。", "京洛少年游，犹恨归来早。", "寒食正梨花，古道多芳草。", "今夜试青镫，依旧春花小。"]'),
('song-ci-358','合欢带','仇远','宋','宋词','song-ci','合欢带','[]','令巍巍、一段风流。',130,'宋词/ci.song.18000.json','["令巍巍、一段风流。", "看情性、忒温柔。", "记得河桥曾识面，雨凝晴、欲问还羞。", "沈吟半晌，蝉敧舞鬓、莺涩歌喉。", "到黄昏饮散，□虽未语，心已相留。", "纱窗低转，红袖同携，随花归去秦楼。", "酒力难禁花易软，聚眉峰、点点清愁。", "瞋人笑语，朦胧娇眼，䰀鬌扶头。", "醒来时、月转西厢，隔窗犹听箜篌。"]'),
('song-ci-359','思佳客','仇远','宋','宋词','song-ci','思佳客','[]','家住银塘东复东。',64,'宋词/ci.song.18000.json','["家住银塘东复东。", "赤阑桥下笑相逢。", "春风豆蔻抽新绿，夜雨茱萸湿老红。", "鸥鸟散，水天空。", "绮窗昨夜已无踪。", "月昏云淡沙汀小，帘影重重花影中。"]'),
('song-ci-360','思佳客','仇远','宋','宋词','song-ci','思佳客','[]','东壁谁家夜捣砧。',64,'宋词/ci.song.18000.json','["东壁谁家夜捣砧。", "荆江流滞客偏闲。", "三三五五潇湘雁，飞尽南云入北云。", "人独自，月黄昏。", "青镫红蕊落缤纷。", "野篁谩白秋萧索，无风无雨也闭门。"]'),
('song-ci-361','思佳客','仇远','宋','宋词','song-ci','思佳客','[]','霜醉秋花锦覆堤。',64,'宋词/ci.song.18000.json','["霜醉秋花锦覆堤。", "西风一舸小桥西。", "闲将窗下红兰梦，写入江南白苎词。", "芳绪断，旧游非。", "空遗香墨湿乌丝。", "碧云冉冉无穷恨，只有山阳短笛知。"]'),
('song-ci-362','满江红','仇远','宋','宋词','song-ci','满江红','[]','脂雨东流，觉春去、绿阴如幄。',115,'宋词/ci.song.18000.json','["脂雨东流，觉春去、绿阴如幄。", "尝记得、桃花碧径，自怜幽独。", "日暮碧云空冉冉，摘花小袖犹依竹。", "望江南、草色欲连天，人江北。", "谁共翦，西窗烛。", "谁共度，西园曲。", "甚采香情懒，楚骚谁续。", "海远休寻双燕信，夜长争忍孤鸾宿。", "夹缃签、曾有旧题诗，镫前读。"]'),
('song-ci-363','浣溪沙','仇远','宋','宋词','song-ci','浣溪沙','[]','鸦墨鸳茸暗小窗。',48,'宋词/ci.song.18000.json','["鸦墨鸳茸暗小窗。", "栀花时递淡中香。", "何须华屋艳红妆。", "栊月凉筛金琐碎，床琴清写玉丁当。", "风车闲倚在回廊。"]'),
('song-ci-364','浣溪沙','仇远','宋','宋词','song-ci','浣溪沙','[]','薄薄梳妆细扫眉。',48,'宋词/ci.song.18000.json','["薄薄梳妆细扫眉。", "鬟鸦双叠岭云低。", "对人浓笑问归期。", "荀令老来香已减，谢娘别后梦应迷。", "一番心事只春知。"]'),
('song-ci-365','浣溪沙','仇远','宋','宋词','song-ci','浣溪沙','[]','红紫妆林绿满池，游丝飞絮两依依。',48,'宋词/ci.song.18000.json','["红紫妆林绿满池，游丝飞絮两依依。", "正当谷雨弄晴时。", "射鸭矮阑苍藓滑，画眉小槛晚花迟。", "一年弹指又春归。"]'),
('song-ci-366','浣溪沙','仇远','宋','宋词','song-ci','浣溪沙','[]','豆蔻枝头冷蝶飞。',48,'宋词/ci.song.18000.json','["豆蔻枝头冷蝶飞。", "荼縻花里老莺啼。", "懒留春住听春归。", "北海芳尊谁共醉，东山游屐近应稀。", "小窗寒草送春时。"]'),
('song-ci-367','西江月','仇远','宋','宋词','song-ci','西江月','[]','犹记春风庭院，桃花初识刘郎。',58,'宋词/ci.song.18000.json','["犹记春风庭院，桃花初识刘郎。", "绿腰传得旧官腔。", "自向花前学唱。", "锦瑟空寻小袖，翠衾尚带馀香。", "一番拈起一思量。", "又是桃花月上。"]'),
('song-ci-368','西江月','仇远','宋','宋词','song-ci','西江月','[]','楚塞残星几点，关山明月三年。',58,'宋词/ci.song.18000.json','["楚塞残星几点，关山明月三年。", "长亭犹有竹如椽。", "可惜中郎不见。", "折柳新愁未歇，落梅旧梦谁圆。", "何人吹向内门前。", "一片鹧鸪清怨。"]'),
('song-ci-369','西江月','仇远','宋','宋词','song-ci','西江月','["\u897f\u6e56"]','漠漠河桥柳外，愔愔门巷镫初。',58,'宋词/ci.song.18000.json','["漠漠河桥柳外，愔愔门巷镫初。", "笙歌饮散醉相扶。", "明月伴人归去。", "娃馆深藏云木，女墙斜掠烟芜。", "水天空阔见西湖。", "鹤立夜寒多处。"]'),
('song-ci-370','西江月','仇远','宋','宋词','song-ci','西江月','[]','暗柳荒城叠鼓，小花静院深镫。',58,'宋词/ci.song.18000.json','["暗柳荒城叠鼓，小花静院深镫。", "年年寒食可曾晴。", "今夜晴犹未稳。", "豆蔻梢头二月，杜鹃枝上三更。", "春风知得此时情。", "吹动秋千红影。"]'),
('song-ci-371','西江月','仇远','宋','宋词','song-ci','西江月','[]','小立画桥西畔，仙车蓦送香风。',58,'宋词/ci.song.18000.json','["小立画桥西畔，仙车蓦送香风。", "多情问我太匆匆。", "疑是当年小宋。", "须识蓬山不远，梨云路杳无踪。", "觉来斜月隔帘栊。", "不是相逢是梦。"]'),
('song-ci-372','满庭芳','仇远','宋','宋词','song-ci','满庭芳','[]','寒食无情，阳春如客。',118,'宋词/ci.song.18000.json','["寒食无情，阳春如客。", "晚风吹尽繁枝。", "落红堆径，小槛立移时。", "乐事不堪再省，吴乡远、愁思依依。", "谁家燕，斜穿绣幕，轻惹画梁泥。", "还知。", "人寂寞，殷勤软语，来说差池。", "怕王孙归去，芳草离离。", "倚翠屏山梦断，无心听、啼鸟催归。", "何时向，溪流练带，一舸载鸱夷。"]'),
('song-ci-373','减字木兰花','仇远','宋','宋词','song-ci','减字木兰花','[]','鸡儿画曲。',51,'宋词/ci.song.18000.json','["鸡儿画曲。", "处处筝鸣雨屋。", "十载重游。", "柳外啼乌也怨秋。", "粉楹醉墨。", "燕去楼空人不识。", "醉踏花阴。", "错认人家月下门。"]'),
('song-ci-374','减字木兰花','仇远','宋','宋词','song-ci','减字木兰花','[]','三生杜牧。',52,'宋词/ci.song.18000.json','["三生杜牧。", "惯识小红楼上宿。", "压帽花斜。", "醉跨门前白鼻騧。", "归来寻睡。", "懒拨熏炉温素被。", "两袖香尘。", "肯信春风老得人。"]'),
('song-ci-375','减字木兰花','仇远','宋','宋词','song-ci','减字木兰花','[]','一番春暮。',52,'宋词/ci.song.18000.json','["一番春暮。", "恼人更下潇潇雨。", "花片纷纷。", "燕子人家都是春。", "莫留春住。", "问春归去家何处。", "春与人期。", "春未归时人未归。"]'),
('song-ci-376','木兰花慢','仇远','宋','宋词','song-ci','木兰花慢','[]','远钟消断梦，又霜信、到纹窗。',123,'宋词/ci.song.18000.json','["远钟消断梦，又霜信、到纹窗。", "有六曲屏山，四垂斗帐，重锦方床。", "轻寒画眉尚懒，想留连、一线枕痕香。", "无语因谁悒怏，何心重理丝簧。", "花房。", "空记旧周郎。", "指印□鸳鸯。", "悄不堪□□，暗尘绣陌，淡月幽坊。", "休恁败红寄远，怕惊波、侵字不成行。", "坐忆江南信息，断肠蘸甲清觞。"]'),
('song-ci-377','木兰花慢','仇远','宋','宋词','song-ci','木兰花慢','[]','泥凉闲倚竹，奈冉冉、碧云何。',124,'宋词/ci.song.18000.json','["泥凉闲倚竹，奈冉冉、碧云何。", "爱水槛空明，风疏画扇，雪透香罗。", "惺松未成楚梦，看玲珑、清影罩平坡。", "便有一庭秋意，碎蛩声乱寒莎。", "银河。", "不起纤波。", "天似水，月明多。", "算江南再有，贺方回在，空费吟哦。", "年年自圆自缺，恨紫箫、声断玉人歌。", "谩对双鸳素被，翠屏十二嵯峨。"]'),
('song-ci-378','木兰花令','仇远','宋','宋词','song-ci','木兰花令','[]','一声啼鴂无芳草。',64,'宋词/ci.song.18000.json','["一声啼鴂无芳草。", "南浦晴波云渺渺。", "蠹尘珠网满香车，三十六桥春悄悄。", "垂杨柳舞吹笙道。", "红粉台空灰蝶小。", "惜花心性不禁愁，莫放堕香随去鸟。"]'),
('song-ci-379','菩萨蛮','仇远','宋','宋词','song-ci','菩萨蛮','[]','翠鸾不隔巫山路。',52,'宋词/ci.song.18000.json','["翠鸾不隔巫山路。", "无人肯指行云处。", "徙倚最高楼。", "秋波春望愁。", "先来愁似雾。", "更下丝丝雨。", "芳径溅香泥。", "苔花滑马蹄。"]'),
('song-ci-380','菩萨蛮','仇远','宋','宋词','song-ci','菩萨蛮','[]','瑶琴欲把相思谱。',52,'宋词/ci.song.18000.json','["瑶琴欲把相思谱。", "殷勤难写相思语。", "人在碧苕滨。", "相思烟水深。", "鳞波流碎月。", "荏苒年芳歇。", "何处寄相思。", "白苹秋一枝。"]'),
('song-ci-381','水龙吟','仇远','宋','宋词','song-ci','水龙吟','[]','晓星低射疏櫺，殢寒却枕还慵起。',126,'宋词/ci.song.18000.json','["晓星低射疏櫺，殢寒却枕还慵起。", "炊烟逗屋，隔房人语，镫前行李。", "霜滑平桥，雾迷衰草，时间流水。", "怅雕鞍独拥，清寒满袖，入斜月、空山里。", "谩把鞭梢暗指。", "酒旗边、柴门又闭。", "分水点墨，因风欲寄，梅花万里。", "宝帐春慵，梦中肯信，有人憔悴。", "待归来、别倚新腔，换却泪毫愁纸。"]'),
('song-ci-382','早梅芳近・早梅芳','仇远','宋','宋词','song-ci','早梅芳近・早梅芳','[]','碧溪湾，疏竹外，正小春天气。',100,'宋词/ci.song.18000.json','["碧溪湾，疏竹外，正小春天气。", "绿珠羞涩，半吐椒红可人意。", "月香传瘦影，露脸凝清泪。", "笑倡条冶叶，怕冷尚贪睡。", "马行迟，雪未霁。", "还忆前村里。", "青禽啁哳，疑是当时梦初起。", "旧愁归塞管，远恨潇湘水。", "望江南，故人家万里。"]'),
('song-ci-383','齐天乐','仇远','宋','宋词','song-ci','齐天乐','[]','夕阳门巷荒城曲，清音早鸣秋树。',123,'宋词/ci.song.18000.json','["夕阳门巷荒城曲，清音早鸣秋树。", "薄翦绡衣，凉生鬓影，独饮天边风露。", "朝朝暮暮。", "奈一度凄吟，一番凄楚。", "尚有残声，蓦然飞过别枝去。", "齐宫往事谩省，行人犹与说，当时齐女。", "雨歇空山，月笼古柳，彷佛旧曾听处。", "离情正苦。", "甚懒拂冰笺，倦拈琴谱。", "满地霜红，浅莎寻蜕羽。"]'),
('song-ci-384','湘月・念奴娇','董嗣杲','宋','宋词','song-ci','湘月・念奴娇','[]','莲幽竹邃，旧池亭几处，多爱君子。',120,'宋词/ci.song.18000.json','["莲幽竹邃，旧池亭几处，多爱君子。", "醉玉吹香还认取，忙里得闲标致。", "心逐云帆，情随烟笛，高会知谁继。", "宵筵会启，蓦然身外浮世。", "因见杜牧疏狂，前缘梦里，谩蹙双眉翠。", "香满屏山春满几，炉拥麝焦禽睡。", "月落梅空，霜浓窗掩，两耳风声起。", "艳歌终散，输他鹤帐清寐。"]'),
('song-ci-385','齐天乐','董嗣杲','宋','宋词','song-ci','齐天乐','["\u897f\u6e56"]','玉山曾醉凉州梦，图芳敻无今古。',123,'宋词/ci.song.18000.json','["玉山曾醉凉州梦，图芳敻无今古。", "露颗虬藤，风枝蠹叶，遗墨何人收取。", "当时赠与。", "记轻别西湖，笑离南浦。", "万里奚囊，岂知随处助吟苦。", "归来情寄谩远，旧寻犹在望，荒亭荒圃。", "绀蕾攒冰，苍阴弄月，休说堆盘马乳。", "云梯尚阻。", "袖一幅秋烟，扫空尘土。", "静想山窗，半乘寒架雨。"]'),
('song-ci-386','失调名','高远','宋','宋词','song-ci','失调名','[]','梦绕荆溪，蟹肥春瓮满。',11,'宋词/ci.song.18000.json','["梦绕荆溪，蟹肥春瓮满。"]'),
('song-ci-387','霜天晓角','杨均','宋','宋词','song-ci','霜天晓角','[]','丹楹转月。',53,'宋词/ci.song.18000.json','["丹楹转月。", "金绣纷幢钺。", "勋在有唐宗社，人千载、仰英烈。", "维辰嗟尽节。", "故里昭虔揭。", "临御雍雍来下，歆初荐、俎羞洁。"]'),
('song-ci-388','霜天晓角','杨均','宋','宋词','song-ci','霜天晓角','[]','当年宋壁。',51,'宋词/ci.song.18000.json','["当年宋壁。", "血拥河流赤。", "全护东南形胜，百易万、五神力。", "人心同奋激。", "立此生民极。", "哀角载歌霜晓，琼、圣容怿。"]'),
('song-ci-389','霜天晓角','杨均','宋','宋词','song-ci','霜天晓角','[]','忠忱谊愊。',53,'宋词/ci.song.18000.json','["忠忱谊愊。", "对越如丹赤。", "缅想遗风馀烈，犹身见、古颜色。", "惟馨非黍稷。", "穆穆歆明德。", "簟滟芳彝须醉，回云旞、佑乡国。"]'),
('song-ci-390','水调歌头','胡幼黄','宋','宋词','song-ci','水调歌头','[]','有喜君初度，风雨作秋声。',114,'宋词/ci.song.18000.json','["有喜君初度，风雨作秋声。", "连旬烈日，稻畦麦垅欲扬尘。", "好似天瓢在手，笑把群龙呵叱，四野注如倾。", "勃勃生意满，翠浪涌纵横。", "君知否，仁者寿，寿斯仁。", "自从三代而下，民命寄苍旻。", "满目桑麻谷粟，满目簿书期会，试说与仁人。", "小试作霖手，苏醒永新民。"]'),
('song-ci-391','婆罗门引','熊禾','宋','宋词','song-ci','婆罗门引','[]','秋宵倦起，起来风露湿人衣。',94,'宋词/ci.song.18000.json','["秋宵倦起，起来风露湿人衣。", "休休未是早行时。", "旋摘青蔬炊饭，暖酒就炉围。", "值青山有意，且把诗题。", "兴阑便归，忽邂逅、故人期。", "道是游山正叔，消息曾知。", "茶烟午灶，听击棹、歌声笑语迟。", "云霭散、皓月呈辉。"]'),
('song-ci-392','沁园春','熊禾','宋','宋词','song-ci','沁园春','[]','自笑生身，历事以来，垂六十年。',138,'宋词/ci.song.18000.json','["自笑生身，历事以来，垂六十年。", "今浮沈闾里，半非识面，交游朋友，各已华颠。", "富贵不来，少年已去，空见悠悠岁月迁。", "虽然是，壮心一点，犹自依然。", "新阳又长天边。", "人指似山间诗酒仙。", "算胸次崔嵬，不胜百榼，笔端枯槁，难足千篇。", "隐几杖藜，相耕听诵，聊看诸郎相后先。", "馀何事，但读书煮茗，日晏高眠。"]'),
('song-ci-393','满庭芳','熊禾','宋','宋词','song-ci','满庭芳','[]','斗转旋霄，梧飘金井，洞天秋气方新。',121,'宋词/ci.song.18000.json','["斗转旋霄，梧飘金井，洞天秋气方新。", "幔亭仙子，飞佩下瑶京。", "霞袂霓裳缥缈，冰肌莹、月作精神。", "云璈动，琼仙歌舞，共庆捧瑶觥。", "蟾宫，人未老，纵横礼乐，谈笑功句名。", "从今去，有多少、富贵光荣。", "且听宾云奏曲，千秋岁、更引清声。", "齐眉处，朱颜绿鬓，相与共长生。"]'),
('song-ci-394','瑞鹤仙','熊禾','宋','宋词','song-ci','瑞鹤仙','[]','翠旗迎风辇。',127,'宋词/ci.song.18000.json','["翠旗迎风辇。", "正金母、西游瑶台宝殿。", "蓬莱都历遍。", "□飘然来到，笙歌庭院。", "朱颜绿鬓。", "须尽道、人间罕见。", "更恰恰占得，美景良辰，小春天暖。", "开宴。", "画堂深处，银烛高烧，珠帘任卷。", "香浮宝篆。", "翻舞袖，掩歌扇。", "看兰孙桂子，成团成簇，共捧金荷齐劝。", "□从今、鹤算龟龄，天长地远。"]'),
('song-ci-395','鹊桥仙','詹无咎','宋','宋词','song-ci','鹊桥仙','[]','龟儿吐火，鹤儿衔火。',74,'宋词/ci.song.18000.json','["龟儿吐火，鹤儿衔火。", "药线上、轮儿走火。", "十胜一斗七星毯，一架上、有许多包裹。", "梨花数朵。", "杏花数朵。", "又开放、牡丹数朵。", "便当场好手路歧人，也须教、点头咽唾。"]'),
('song-ci-396','贺新郎','詹无咎','宋','宋词','song-ci','贺新郎','[]','梅子黄时雨。',142,'宋词/ci.song.18000.json','["梅子黄时雨。", "对幽窗、依依抱独，几多愁绪。", "润逼琴丝无雅韵，难续文园旧诣。", "头白尽、相如谁顾。", "燕子楼空尘又锁，望天涯、不寄红丝缕。", "嗟往事，且休语。", "伤情当日班衣舞。", "更宫衣、香罗乍带，九天繁露。", "一寸草心迎永日，更把葵心自许。", "怎料有、风推雨如。", "惹起灵均千古恨，转凄凉、更不成端午。", "拼小醉，读骚句。"]'),
('song-ci-397','水龙吟','王槐建','宋','宋词','song-ci','水龙吟','[]','武夷一片闲云，被风吹落清原顶。',127,'宋词/ci.song.18000.json','["武夷一片闲云，被风吹落清原顶。", "溪梅馥馥，飞来相傍，不嫌凄冷。", "瓦釜争鸣，丝桐一曲，满城倾听。", "奈阳春未了，骊驹已驾，桐阴底、梦魂醒。", "何限吟笺赋笔，甚乡心、分却清兴。", "鳌峰胜处，遥知风月，属谁管领。", "邂逅何时，无穷事业，有穷光景。", "但相期、不负初心，此外分、皆前定。"]'),
('song-ci-398','祝英台近','刘应李','宋','宋词','song-ci','祝英台近','[]','濯沧浪，歌窈窕，云日弄微霁。',95,'宋词/ci.song.18000.json','["濯沧浪，歌窈窕，云日弄微霁。", "屏倚曾空，鹤去几何岁。", "尚留洞草芊青，岩花重碧，游泳处、露中风袂。", "木兰舣。", "亭外冉冉斜阳，杯行尚联断。", "独凭危阑，解渴漱寒水。", "少须酒力还低，茶香不断，清与处、月明川底。"]'),
('song-ci-399','摸鱼儿','王梦应','宋','宋词','song-ci','摸鱼儿','[]','问谁歌、暗香疏影，此花堪照人世。',154,'宋词/ci.song.18000.json','["问谁歌、暗香疏影，此花堪照人世。", "起持霜月为花寿，天亦愿花千岁。", "谁有意。", "著如此人间，更著花如此。", "高寒洒洒。", "看浩荡刚风，跨虬飞佩，玉影乱如水。", "行春处，一笑人间紫翠。", "纷纷窥此天地。", "寿如川至。", "□好是、涧翁兹岁喜。", "荣沾南儒恩例。", "捧觞更喜郎君美。", "任夜来归侍。", "见说生辰，恰逢本命，寿筵且未。", "听老聃孙子。", "祝公耆艾，祝公富贵。"]'),
('song-ci-400','锦堂春・锦堂春慢','王梦应','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','浅帻分秋，凉尊试月，西风未雁犹蝉。',118,'宋词/ci.song.18000.json','["浅帻分秋，凉尊试月，西风未雁犹蝉。", "看芙蓉影里，绿鬓年年。", "日上云帆压海，尘清玉马行天。", "更烟楼凤举，风幕麟游，锦后珠前。", "绿阴池馆如画，记晴春药径，雨晓芝田。", "已办十年笑语，小聚云边。", "舞称香围艳雪，歌迟酒落红船。", "早群仙归去，柳掖花扶，似雾非烟。"]'),
('song-ci-401','念奴娇','王梦应','宋','宋词','song-ci','念奴娇','[]','欲霜更雨，记青云篱落，东风前此。',120,'宋词/ci.song.18000.json','["欲霜更雨，记青云篱落，东风前此。", "帘外客秋人共老，雁与愁飞千里。", "水郭烟明，竹陂波小，万叶寒声起。", "凭高那更，九嶷吹尽云气。", "婉娩空复多情，年年晋梦，花与柴桑是。", "谁解意消风日晚，短笛孤舟林水。", "江蟹笼新，露萸斟浅，浇得乡关思。", "平芜天远，一痕黄抹秋霁。"]'),
('song-ci-402','疏影','王梦应','宋','宋词','song-ci','疏影','[]','瞢腾晓被，听堕冰屋角，晴哢仍未。',134,'宋词/ci.song.18000.json','["瞢腾晓被，听堕冰屋角，晴哢仍未。", "土湿烟生，庭掩寒青，障泥懒为春试。", "东风旧与花飞去，料记得、年年沙际。", "忍落梅、万点苔根，化作一窗离思。", "犹忆蔫红稚绿，断桥雪未扫，天近春易。", "老对荒寒，事旧人新，雁后不成情味。", "人间解有花如海，待一片、不教随水。", "但玉香、酥影玲珑，逐日暖红云里。"]'),
('song-ci-403','醉太平','王梦应','宋','宋词','song-ci','醉太平','[]','寒窗月晴。',46,'宋词/ci.song.18000.json','["寒窗月晴。", "寒梢露明。", "一痕归影灯青。", "又分携短亭。", "蘅皋佩云。", "蒸溪酒春。", "有谁勤说归程。", "是峰头雁声。"]'),
('song-ci-404','渔父词・渔父','孙锐','宋','宋词','song-ci','渔父词・渔父','[]','平湖千顷浪花飞。',32,'宋词/ci.song.18000.json','["平湖千顷浪花飞。", "春后银鱼霜更肥。", "菱叶饭，芦花衣。", "酒酣载月忙呼归。"]'),
('song-ci-405','水调歌头','孙锐','宋','宋词','song-ci','水调歌头','[]','渔钓有遗逸，天子宠元真。',114,'宋词/ci.song.18000.json','["渔钓有遗逸，天子宠元真。", "赐之奴仆，得随妫艳下神京。", "几度苹汀蓼岸，不问金钩无饵，谈笑取冰鳞。", "珍重主人意，名我曰樵青。", "肩兰桨，萦桂棹，出波津。", "凌虚上□□□，□□会群真。", "卸下绿蓑青笠，付与渔童收管，相与□红尘。", "归去又□□，同赏洞中春。"]'),
('song-ci-406','满江红','李琳','宋','宋词','song-ci','满江红','[]','碧醮江山，鹤唳晓、云献画屏。',115,'宋词/ci.song.18000.json','["碧醮江山，鹤唳晓、云献画屏。", "瑶宫敞，舞金翔翠，巍枕春城。", "龙背神瓢飞旱雨，虹光花石转阴晴。", "蔼昼香、飞雾福苍生，千古灵。", "箫莺响，笙鹤鸣。", "瑞烟起，彩云行。", "满阑干花影，绣扬帘旌。", "佛界三千笼日月，仙楼十二挂星辰。", "望赭袍、霞佩并云軿，游紫清。"]'),
('song-ci-407','木兰花慢','李琳','宋','宋词','song-ci','木兰花慢','[]','蕊珠仙驭远，横羽葆、簇霓旌。',122,'宋词/ci.song.18000.json','["蕊珠仙驭远，横羽葆、簇霓旌。", "甚鸾月流辉，凤云布彩，翠绕蓬瀛。", "舞衣怯环佩冷，问梨园、几度沸歌声。", "梦里芝田八骏，禁中花漏三更。", "繁华一瞬化飞尘，辇路劫灰平。", "恨碧灭烟销，红凋露粉，寂寞秋城。", "兴亡事空陈迹，只青山、淡淡夕阳明。", "懒向沙鸥说得，柳风吹上旗亭。"]'),
('song-ci-408','六么令','李琳','宋','宋词','song-ci','六么令','[]','淡烟疏雨，香径渺啼鴂。',112,'宋词/ci.song.18000.json','["淡烟疏雨，香径渺啼鴂。", "新晴昼帘闲卷，燕外寒犹力。", "依约天涯芳草，染得春风碧。", "人间陈迹。", "斜阳今古，几缕游丝趁飞蝶。", "柳向尊前起舞，又觉春如客。", "翠袖折取嫣红，笑与簪华发。", "回首青山一点，檐外寒云叠。", "梨花淡白，柳花飞絮，梦绕阑干一株雪。"]'),
('song-ci-409','一翦梅','醴陵士人','宋','宋词','song-ci','一翦梅','[]','宰相巍巍坐庙堂。',72,'宋词/ci.song.18000.json','["宰相巍巍坐庙堂。", "说着经量。", "便要经量。", "那个臣僚上一章。", "头说经量。", "尾说经量。", "轻狂太守在吾邦。", "闻说经量。", "星夜经量。", "山东河北久抛荒。", "好去经量。", "胡不经量。"]'),
('song-ci-410','百字令・念奴娇','褚生','宋','宋词','song-ci','百字令・念奴娇','[]','半堤花雨。',120,'宋词/ci.song.18000.json','["半堤花雨。", "对芳辰消遣，无奈情绪。", "春色尚堪描画在，万紫千红尘土。", "鹃促归期，莺收佞舌，燕作留人语。", "绕栏红药，韶华留作孤主。", "真个恨杀东风，几番过了，不似今番苦。", "乐事赏心磨灭尽，忽见飞书传羽。", "湖水湖烟，峰南峰北，总是堪伤处。", "新塘杨柳，小腰犹自歌舞。"]'),
('song-ci-411','祝英台近','褚生','宋','宋词','song-ci','祝英台近','[]','倚危栏，斜日暮。',93,'宋词/ci.song.18000.json','["倚危栏，斜日暮。", "蓦蓦甚情绪。", "稚柳娇黄，全未禁风雨。", "春江万里云涛，扁舟飞渡。", "那更听、塞鸿无数。", "叹离阻。", "有恨落天涯，谁念孤旅。", "满目风尘，冉冉如飞雾。", "是何人惹愁来，那人何处。", "怎知道、愁来不去。"]'),
('song-ci-412','满庭芳','徐君宝妻','宋','宋词','song-ci','满庭芳','["\u5cb3\u9633\u697c"]','汉上繁华，江南人物，尚遗宣政风流。',117,'宋词/ci.song.18000.json','["汉上繁华，江南人物，尚遗宣政风流。", "绿窗朱户，十里烂银钩。", "一旦刀兵齐举，旌旗拥、百万貔貅。", "长驱入，歌台舞榭，风卷落花愁。", "清平三百载，典章人物，扫地俱休。", "幸此身未北，犹客南州。", "破鉴徐郎何在，空惆怅、相见无由。", "从今后，梦魂千里，夜夜岳阳楼。"]'),
('song-ci-413','霜天晓角','徐君宝妻','宋','宋词','song-ci','霜天晓角','[]','双峦斗碧，寒玉雕秋壁。',53,'宋词/ci.song.18000.json','["双峦斗碧，寒玉雕秋壁。", "两道凝螺天半，横无限、青青色。", "拍案涛声急。", "似鼓临邛瑟。", "窗下镜台鸾去，空留得、春山迹。"]'),
('song-ci-414','沁园春','刘氏','宋','宋词','song-ci','沁园春','[]','我生不辰，逢此百罹，况乎乱离。',140,'宋词/ci.song.18000.json','["我生不辰，逢此百罹，况乎乱离。", "奈恶因缘到，不夫不主，被擒捉去。", "为妾为妻。", "父母公姑，弟兄姐妹，流落不知东与西。", "心中事，把家书写下，分付伊谁。", "越人北向燕支。", "回首望、雁峰天一涯。", "奈翠鬟云软，笠儿怎带，柳腰春细，马性难骑。", "缺月疏桐，淡烟衰草，对此如何不泪垂。", "君知否，我生於何处，死亦魂归。"]'),
('song-ci-415','沁园春','无闻翁','宋','宋词','song-ci','沁园春','[]','埋怨姐姐，衔恨婆婆。',10,'宋词/ci.song.18000.json','["埋怨姐姐，衔恨婆婆。"]'),
('song-ci-416','沁园春','杨氏','宋','宋词','song-ci','沁园春','[]','便归去，懒东涂西抹，学少年婆。',15,'宋词/ci.song.18000.json','["便归去，懒东涂西抹，学少年婆。"]'),
('song-ci-417','满庭芳','杨氏','宋','宋词','song-ci','满庭芳','[]','错应谁铸。',5,'宋词/ci.song.18000.json','["错应谁铸。"]'),
('song-ci-418','更漏子','张淑芳','宋','宋词','song-ci','更漏子','[]','墨痕香，红蜡泪。',58,'宋词/ci.song.18000.json','["墨痕香，红蜡泪。", "点点愁人离思。", "桐叶落，蓼花残。", "雁声天外寒。", "五云岭，九溪坞。", "待到秋来更苦。", "风淅淅，水淙淙。", "不教蓬径通。"]'),
('song-ci-419','满路花・促拍满路花','张淑芳','宋','宋词','song-ci','满路花・促拍满路花','[]','罗襟湿未乾，又是凄凉雪。',101,'宋词/ci.song.18000.json','["罗襟湿未乾，又是凄凉雪。", "欲睡难成寐、音书绝。", "窗前竹叶，凛凛狂风折。", "寒衣弱不胜，有甚遥肠，望到春来时节。", "孤灯独照，字字吟成血。", "仅梅花知苦、香来接。", "离愁万种，提起心头切。", "比霜风更烈。", "瘦似枯枝，待何人与分说。"]'),
('song-ci-420','浣溪沙','张淑芳','宋','宋词','song-ci','浣溪沙','[]','散步山前春草香。',48,'宋词/ci.song.18000.json','["散步山前春草香。", "朱阑绿水绕吟廊。", "花枝惊堕绣衣裳。", "或定或摇江上柳，为莺为凤月中篁。", "为谁掩抑锁芸窗。"]'),
('song-ci-421','齐天乐','王易简','宋','宋词','song-ci','齐天乐','[]','宫烟晓散春如雾。',123,'宋词/ci.song.18000.json','["宫烟晓散春如雾。", "参差护晴窗户。", "柳色初分，饧香未冷，正是清明百五。", "临流笑语。", "映十二阑干，翠嚬红妒。", "短帽轻鞍，倦游曾遍断桥路。", "东风为谁媚妩。", "岁华顿感慨，双鬓何许。", "前度刘郎，三生杜牧，赢得征衫尘土。", "心期暗数。", "总寂寞当年，酒筹花谱。", "付与春愁，小楼今夜雨。"]'),
('song-ci-422','酹江月・念奴娇','王易简','宋','宋词','song-ci','酹江月・念奴娇','[]','暗帘吹雨，怪西风梧井，凄凉何早。',120,'宋词/ci.song.18000.json','["暗帘吹雨，怪西风梧井，凄凉何早。", "一寸柔情千万缕，临镜霜痕惊老。", "雁影关山，蛩声院宇，做就新怀抱。", "湘皋遗佩，故人空寄瑶草。", "已是摇落堪悲，飘零多感，那更长安道。", "衰草寒芜吟未尽，无那平烟残照。", "千古闲愁，百年往事，不了黄花笑。", "渔樵深处，满庭红叶休扫。"]'),
('song-ci-423','庆宫春・高阳台','王易简','宋','宋词','song-ci','庆宫春・高阳台','[]','庭草春迟，汀苹香老，数声珮悄苍玉。',126,'宋词/ci.song.18000.json','["庭草春迟，汀苹香老，数声珮悄苍玉。", "年晚江空，天寒日暮，壮怀聊寄幽独。", "倦游多感，更西北、高楼送目。", "佳人不见，慷慨悲歌，夕阳乔木。", "紫霞洞窅云深，袅袅馀香，凤箫谁续。", "桃花赋在，竹枝词远，此恨年年相触。", "翠笺芳字，谩重省、当时顾曲。", "因君凝伫，依约吴山，半痕蛾绿。"]'),
('song-ci-424','天香','王易简','宋','宋词','song-ci','天香','[]','烟峤收痕，云沙拥沫，孤槎万里春聚。',116,'宋词/ci.song.18000.json','["烟峤收痕，云沙拥沫，孤槎万里春聚。", "蜡杵冰尘，水研花片，带得海山风露。", "纤痕透晓，银镂小、初浮一缕。", "重剪纱窗暗烛，深垂绣帘微雨。", "馀馨恼人最苦。", "染罗衣、少年情绪。", "谩省佩珠曾解，蕙羞兰妒。", "好是芳钿翠妩。", "恨素被浓薰梦无据。", "待剪秋云，殷勤寄与。"]'),
('song-ci-425','水龙吟','王易简','宋','宋词','song-ci','水龙吟','[]','翠裳微护冰肌，夜深暗泣瑶台露。',127,'宋词/ci.song.18000.json','["翠裳微护冰肌，夜深暗泣瑶台露。", "芳容淡泞，风神萧散，凌波晚步。", "西子残妆，环儿初起，未须匀注。", "看明珰素袜，相逢憔悴，当应被、西风误。", "十里云愁雪妒。", "抱凄凉、盼娇无语。", "当时姐妹，朱颜楼褪酒，红衣按舞。", "别浦重寻，旧盟唯有，一行鸥鹭。", "伴玉颜月晓，盈盈冷艳，洗人间暑。"]'),
('song-ci-426','摸鱼儿','王易简','宋','宋词','song-ci','摸鱼儿','[]','怪鲛宫、水晶帘卷，冰痕初断香缕。',140,'宋词/ci.song.18000.json','["怪鲛宫、水晶帘卷，冰痕初断香缕。", "澄波荡桨人初到，三十六陂烟雨。", "春又去。", "伴点点荷钱，隐约吴中路。", "相思日暮。", "恨洛浦娉婷，芳钿翠剪，奁影照凄楚。", "功名梦，消得西风一度。", "高人今在何许。", "鲈香菰冷斜阳里，多少天涯意绪。", "谁记取。", "但枯豉红盐，溜玉凝秋箸。", "尊前起舞。", "算唯有渊明，黄花岁晚，此兴共千古。"]'),
('song-ci-427','齐天乐','王易简','宋','宋词','song-ci','齐天乐','[]','翠云深锁齐姬恨，纤柯暗翻冰羽。',123,'宋词/ci.song.18000.json','["翠云深锁齐姬恨，纤柯暗翻冰羽。", "锦瑟重调，绡衣乍著，聊饮人间风露。", "相逢甚处。", "记槐影初凉，柳阴新雨。", "听尽残声，为谁惊起又飞去。", "商量秋信最早。", "晚来吟未彻，却是凄楚。", "断韵还连，馀悲似咽，欲和愁边佳句。", "幽期谁语。", "怕寒叶凋零，蜕痕尘土。", "古木斜晖，向人怀抱苦。"]'),
('song-ci-428','天香','冯应瑞','宋','宋词','song-ci','天香','[]','枯石流痕，残沙拥沫，骊宫夜蛰惊起。',116,'宋词/ci.song.18000.json','["枯石流痕，残沙拥沫，骊宫夜蛰惊起。", "海市收时，鲛人分处，误入众芳丛里。", "春霖未就，都化作、凄凉云气。", "惟有清寒一点，消磨小窗残醉。", "当年翠篝素被。", "拂馀薰、倦怀如水。", "谩惜舞红犹在，为谁重试。", "几片金昏字古，向故箧聊将伴憔悴。", "□□□□，□□□□。"]'),
('song-ci-429','天香','唐艺孙','宋','宋词','song-ci','天香','[]','螺甲磨星，犀株杵月，蕤英嫩压拖水。',116,'宋词/ci.song.18000.json','["螺甲磨星，犀株杵月，蕤英嫩压拖水。", "海蜃楼高，仙蛾钿小，缥缈结成心字。", "麝煤候暖，载一朵、轻云不起。", "银叶初生薄晕，金猊旋翻纤指。", "芳杯恼人渐醉。", "碾微馨、凤团闲试。", "满架舞红都换，懒收珠佩。", "几片菱花镜里，更摘索双鬟伴秋睡。", "早是新凉，重薰翠被。"]'),
('song-ci-430','齐天乐','唐艺孙','宋','宋词','song-ci','齐天乐','[]','柳风微扇闲池阁，深林翠阴人静。',123,'宋词/ci.song.18000.json','["柳风微扇闲池阁，深林翠阴人静。", "渐理琴丝，谁调金奏，凄咽流空清韵。", "虹明雨润。", "正乍集庭柯，凭阑新听。", "午梦惊回，有人娇困酒初醒。", "西轩晚凉又嫩。", "向枝头占得，银露千顷。", "蜕翦花轻，羽翻纸薄，老去易惊秋信。", "残声送暝。", "恨秦树斜阳，暗催光景。", "淡月疏桐，半窗留鬓影。"]'),
('song-ci-431','桂枝香','唐艺孙','宋','宋词','song-ci','桂枝香','[]','收帆渡口。',124,'宋词/ci.song.18000.json','["收帆渡口。", "认远岸夜篝，松炬如昼。", "还见沙痕雪涨，水纹霜后。", "秦宫梦到无肠断，望明河、月斜疏柳。", "琐窗相对，茶边犹记，眼波频溜。", "渐嫩菊、初篘绿酒。", "叹风味尊前，潇洒如旧。", "几度金橙香雾，玉盘纤手。", "清愁小醉凄凉里，拼今生、容易消瘦。", "草心春浅，年年相忆，看灯时候。"]'),
('song-ci-432','天香','吕同老','宋','宋词','song-ci','天香','[]','冰片熔肌，水沈换骨，蜿蜒梦断瑶岛。',116,'宋词/ci.song.18000.json','["冰片熔肌，水沈换骨，蜿蜒梦断瑶岛。", "翦碎腥云，杵匀枯沫，妙手制成翻巧。", "金篝候火，无似有、微薰初好。", "帘影垂风不动，屏深护春宜小。", "残梅舞红褪了。", "佩珠寒、满怀清峭。", "几度酒馀重省，旧愁多少。", "荀令风流未减，怎奈向飘零赋情老。", "待寄相思，仙山路杳。"]'),
('song-ci-433','水龙吟','吕同老','宋','宋词','song-ci','水龙吟','[]','素肌不污天真，晓来玉立瑶池里。',126,'宋词/ci.song.18000.json','["素肌不污天真，晓来玉立瑶池里。", "亭亭翠盖，盈盈素靥，时妆净洗。", "太液波翻，霓裳舞罢，断魂流水。", "甚依然、旧日浓香淡粉，花不似，人憔悴。", "欲唤凌波仙子。", "泛扁舟、浩波千里。", "只愁回首，冰帘半掩，明珰乱坠。", "月影凄迷，露华零落，小阑谁倚。", "共芳盟，犹有双栖雪鹭，夜寒惊起。"]'),
('song-ci-434','齐天乐','吕同老','宋','宋词','song-ci','齐天乐','[]','绿荫初蔽林塘路，凄凄乍流清韵。',122,'宋词/ci.song.18000.json','["绿荫初蔽林塘路，凄凄乍流清韵。", "倦咽高槐，惊嘶别柳，还忆当曾听。", "西窗梦醒。", "叹弦绝重调，珥空难整。", "绰约冰绡，夜深谁念露华冷。", "不知身世易老，一声声断续，频报秋信。", "坠叶山明，疏枝月小，惆怅齐姬薄幸。", "馀音未尽。", "早枯翼飞仙，暗嗟残景。", "见洗冰奁，怕翻双翠鬓。"]'),
('song-ci-435','桂枝香','吕同老','宋','宋词','song-ci','桂枝香','[]','松江岸侧。',124,'宋词/ci.song.18000.json','["松江岸侧。", "正乱叶坠红，残浪收碧。", "犹记灯寒暗聚，簖疏轻入。", "休嫌郭索尊前笑，且开颜、共倾芳液。", "翠橙丝雾，玉葱浣雪，嫩黄初擘。", "自那日、新诗换得。", "又几度相逢，落潮秋色。", "常是篱边早菊，慰渠岑寂。", "如今谩有江山兴，更谁怜、草泥踪迹。", "但将身世，浮沈醉乡，旧游休忆。"]'),
('song-ci-436','天香','李居仁','宋','宋词','song-ci','天香','[]','瀛峤浮烟，沧波挂月，潜虬睡起清晓。',116,'宋词/ci.song.18000.json','["瀛峤浮烟，沧波挂月，潜虬睡起清晓。", "万里槎程，一番花信，付与露薇冰脑。", "纤云渐暖，凝翠席、氤氲不了。", "银叶重调火活。", "珠帘日垂风悄。", "螺屏酒醒梦好。", "绣罗帱、依旧痕少。", "几度试拈心字，暗惊芳抱。", "隐约仙舟路杳。", "谩佩影玲珑护娇小。", "素手金篝，春情未老。"]'),
('song-ci-437','水龙吟','李居仁','宋','宋词','song-ci','水龙吟','[]','蕊仙群拥宸游，素肌似怯波心冷。',127,'宋词/ci.song.18000.json','["蕊仙群拥宸游，素肌似怯波心冷。", "霜裳缟夜，冰壶凝露，红尘洗尽。", "弄玉轻盈，飞琼绰约，淡妆临镜。", "更多情、一片碧云不掩，笼娇面、回清影。", "菱唱数声乍听。", "载名娃、藕丝萦艇。", "雪鸥沙鹭，夜来同梦，晓风吹醒。", "酒量全消，粉痕微渍，色明香莹。", "问此花，盖贮瑶池，应未许、繁红并。"]'),
('song-ci-438','水龙吟','唐珏','宋','宋词','song-ci','水龙吟','[]','淡妆人更婵娟，晚奁净洗铅华腻。',124,'宋词/ci.song.18000.json','["淡妆人更婵娟，晚奁净洗铅华腻。", "泠泠月色，萧萧风度，娇红敛避。", "太液池空，霓裳舞倦，不堪重记。", "叹冰魂犹在，翠舆难驻，玉簪为谁轻坠。", "别有凌空一叶，泛青寒、素波千里。", "珠房泪湿，明珰恨远，旧游梦里。", "羽扇生秋，琼楼不夜，尚遗仙意。", "奈香易散，绡衣半脱，露凉如水。"]'),
('song-ci-439','摸鱼儿','唐珏','宋','宋词','song-ci','摸鱼儿','[]','渐沧浪、冻痕消尽。',140,'宋词/ci.song.18000.json','["渐沧浪、冻痕消尽。", "琼丝初漾明镜。", "鲛人夜翦龙髯滑，织就水晶帘冷。", "凫叶净。", "最好似、嫩荷半卷浮倩影。", "玉流翠凝。", "早枯豉融香，红盐和雪，醉齿嚼清莹。", "功名梦，曾被秋风唤醒。", "故人应动高兴。", "悠然世味浑如水，千里旧怀谁省。", "空对景。", "奈回首、姑苏台畔愁波暝。", "烟寒夜静。", "但只有芳洲，苹花共老，何日泛归艇。"]'),
('song-ci-440','齐天乐','唐珏','宋','宋词','song-ci','齐天乐','[]','蜡痕初染仙茎露，新声又移凉影。',123,'宋词/ci.song.18000.json','["蜡痕初染仙茎露，新声又移凉影。", "佩玉流空，绡衣翦雾，几度槐昏柳暝。", "幽窗睡醒。", "奈欲断还连，不堪重听。", "怨结齐姬，故宫烟树翠阴冷。", "当时旧情在否，晚妆清镜里，犹记娇鬓。", "乱咽频惊，馀悲渐杳，摇曳风枝未定。", "秋期话尽。", "又抱叶凄凄，暮寒山静。", "付与孤蛩，苦吟清夜永。"]'),
('song-ci-441','桂枝香','唐珏','宋','宋词','song-ci','桂枝香','[]','松江舍北。',123,'宋词/ci.song.18000.json','["松江舍北。", "正水落晚汀，霜老枯荻。", "还见青匡似绣，绀螯如戟。", "西风有恨无肠断，恨东流、几番潮沙。", "夜灯争聚微光，挂影误投帘隙。", "更喜荐、新篘玉液。", "正半壳含黄，一醉秋色。", "纤手香橙风味，有人相忆。", "江湖岁晚听飞雪，但沙痕、空记行迹。", "至今茶鼎，时时犹认，眼波愁碧。"]'),
('song-ci-442','水龙吟','赵汝钠','宋','宋词','song-ci','水龙吟','[]','露华洗尽凡妆，玉妃来侍瑶池宴。',127,'宋词/ci.song.18000.json','["露华洗尽凡妆，玉妃来侍瑶池宴。", "风裳水佩，冰肌雪艳，清凉不汗。", "解语情多，凌波步稳，酒容易散。", "想温泉浴罢，天然真态，浑疑是、宫妆浅。", "暗想凄愁别岸。", "粉痕消、香腮凝汗。", "雪空冰冷，此情唯许，鹭知鸥见。", "羽扇微摇，翠帷低拥，清凉庭院。", "待夜深，月上阑干，更邀取、姮娥伴。"]'),
('song-ci-443','贺新郎','曹稆孙','宋','宋词','song-ci','贺新郎','[]','极目天如画。',142,'宋词/ci.song.18000.json','["极目天如画。", "水花中、涌出莲宫，翠楹碧瓦。", "胜景中川金焦似，勒石□□□□。", "尚隔浦、风烟不跨。", "妖蜃自降真歇手，涨平沙、妙补乾坤罅。", "双寺合，万僧夏。", "东西塔影龙分挂。", "夜无云、点点一天，星斗相射。", "七十二滩声到海，括橹瓯帆上下。", "泣不为、琵琶声哑。", "故寝荒凉成一梦，问来鸥、去鹭无知者。", "烟树湿，怒涛打。"]'),
('song-ci-444','大江词・念奴娇','林横舟','宋','宋词','song-ci','大江词・念奴娇','[]','一蓂呈秀，近迎长佳节，拟书云物。',120,'宋词/ci.song.18000.json','["一蓂呈秀，近迎长佳节，拟书云物。", "隐隐虹桥天际下，光照梅仙丹壁。", "鹏路横飞，蟾宫直上，早脱麻衣雪。", "一时篇翰，并游俱是魁杰。", "长记怀燕良辰，华堂称庆，皓齿清歌发。", "自暖杯中须缓举，莫放金炉香灭。", "事业伊周，功名韩白，未到星星发。", "九天有诏，蓝田□□风月。"]'),
('song-ci-445','浣溪沙','杨舜举','宋','宋词','song-ci','浣溪沙','[]','残照西风一片愁。',48,'宋词/ci.song.18000.json','["残照西风一片愁。", "疏杨画出六桥秋。", "游人不上十三楼。", "有泪金仙还泣汉，无心玉马已朝周。", "平湖寂寂水空流。"]'),
('song-ci-446','永遇乐','危复之','宋','宋词','song-ci','永遇乐','[]','早叶初莺，晚风孤蝶，幽思何限。',128,'宋词/ci.song.18000.json','["早叶初莺，晚风孤蝶，幽思何限。", "檐角萦云，阶痕积雨，一夜苔生遍。", "玉窗闲掩，瑶琴慵理，寂寞水沈烟断。", "悄无言，春归无觅处，卷帘见双飞燕。", "风亭泉石，烟林薇蕨，梦绕旧时曾见。", "江上闲鸥，心盟犹在，分得眠沙半。", "引觞浮月，飞谈卷雾，莫管愁深欢浅。", "起来倚阑干，拾得残红一片。"]'),
('song-ci-447','金人捧露盘','罗志仁','宋','宋词','song-ci','金人捧露盘','[]','湿苔青，妖血碧，坏垣红。',99,'宋词/ci.song.18000.json','["湿苔青，妖血碧，坏垣红。", "怕精灵、来往相逢。", "荒烟瓦砾，宝钗零乱隐鸾龙。", "吴峰越巘，翠颦锁、苦为谁容。", "浮屠换、昭阳殿，僧磬改、景阳钟。", "兴亡事、泪老金铜。", "骊山废尽，更无宫女说元宗。", "角声起，海涛落，满眼秋风。"]'),
('song-ci-448','霓裳中序第一','罗志仁','宋','宋词','song-ci','霓裳中序第一','[]','来鸿又去燕。',127,'宋词/ci.song.18000.json','["来鸿又去燕。", "看罢江潮收画扇。", "湖曲雕阑倚倦。", "正船过西陵，快篙如箭。", "凌波不见。", "但陌花、遗曲凄怨。", "孤山路，晚蒲病柳，淡绿锁深院。", "谁恨。", "五云深处宫殿。", "记旧日、曾游翠辇。", "青红如写便面。", "下鹄池荒，放鹤人远。", "粉墙随岸转。", "漏碧瓦、残阳一线。", "蓬莱梦，人间那信，坐看海涛浅。"]'),
('song-ci-449','风流子','罗志仁','宋','宋词','song-ci','风流子','[]','歌咽翠眉低。',134,'宋词/ci.song.18000.json','["歌咽翠眉低。", "湖船客、尊酒谩重携。", "正断续斋钟，高峰南北，飘零野褐，太乙东西。", "凄凉处，翠连松九里，僧马溅障泥。", "葛岭楼台，梦随烟散，吴山宫阙，恨与云霁。", "灵峰飞来久，飞不去，有落日断猿啼。", "无限风荷废港，露柳荒畦。", "岳公英骨，麒麟旧冢，坡仙吟魄，莺燕长堤。", "欲吊梅花无句，素壁慵题。"]'),
('song-ci-450','扬州慢','罗志仁','宋','宋词','song-ci','扬州慢','[]','危榭摧红，断砖埋玉，定王台下园林。',120,'宋词/ci.song.18000.json','["危榭摧红，断砖埋玉，定王台下园林。", "听樯干燕子，诉别后惊心。", "尽江上、青峰好在，可怜曾是，野烧痕深。", "付潇湘渔笛，吹残今古销沈。", "妙奴不见，纵秦郎、谁更知音。", "正雁妾悲歌，雕奚醉舞，楚户停砧。", "化碧旧愁何处，魂归些、晚日阴阴。", "渺云平铁坝，凄凉天也沾襟。"]'),
('song-ci-451','虞美人','罗志仁','宋','宋词','song-ci','虞美人','[]','君王曾惜如花面。',66,'宋词/ci.song.18000.json','["君王曾惜如花面。", "往事多恩怨。", "霓裳和泪换袈裟。", "又送鸾舆北去、听琵琶。", "当年未削青螺髻。", "知是归期未。", "天花丈室万缘空。", "结绮临春何处、泪痕中。"]'),
('song-ci-452','木兰花慢','罗志仁','宋','宋词','song-ci','木兰花慢','[]','汉家糜粟诏，将不醉、饱生灵。',121,'宋词/ci.song.18000.json','["汉家糜粟诏，将不醉、饱生灵。", "便收拾银瓶，当垆人去，春歇旗亭。", "渊明权停种秫，遍人间，暂学屈原醒。", "天子宜呼李白，妇人却笑刘伶。", "提葫芦更有谁听。", "爱酒已无星。", "想难变春江，蒲桃酿绿，空想芳馨。", "温存鸬鹚鹦鹉，且茶瓯淡对晚山青。", "但结秋风鱼梦，赐酺依旧沈冥。"]'),
('song-ci-453','菩萨蛮','罗志仁','宋','宋词','song-ci','菩萨蛮','[]','晓莺催起。',134,'宋词/ci.song.18000.json','["晓莺催起。", "问当年秀色，为谁料理。", "怅别后、屏掩吴山，便楼燕月寒，鬓蝉云委。", "锦字无恁，付银烛、尽烧千纸。", "对寒泓静碧，又把去鸿，往恨都洗。", "桃花自贪结子。", "道东风有意，吹送流水。", "谩记得当日、心嫁卿卿，是日暮天寒，翠袖堪倚。", "扇月乘鸾，尽梦隔、婵娟千里。", "到嗔人、从今不信，画檐鹊喜。"]'),
('song-ci-454','减字木兰花','曾寅孙','宋','宋词','song-ci','减字木兰花','[]','生绡蜀茧。',52,'宋词/ci.song.18000.json','["生绡蜀茧。", "笔底墨云飞一片。", "点点秋腴。", "收得骊龙颌下珠。", "兴来一扫。", "惜处有时悭似宝。", "露叶烟条。", "几度西风吹不凋。"]'),
('song-ci-455','甘州・八声甘州','沈钦','宋','宋词','song-ci','甘州・八声甘州','[]','有吴僧、醉倒墨池边，西风暗吹芳。',119,'宋词/ci.song.18000.json','["有吴僧、醉倒墨池边，西风暗吹芳。", "对苍髯冷挂，龙珠万颗，晴映经窗。", "却似仙人黄鹤，笛里换时光。", "静处观生意，竹老梅荒。", "犹说当年分种，是枯槎远驾，万里途长。", "信留真何许，烨烨楮毫香。", "□前度、离宫别馆，正金铺、深掩绿苔床。", "都休问，一番展卷，清昼生凉。"]'),
('song-ci-456','甘州・八声甘州','刘沆','宋','宋词','song-ci','甘州・八声甘州','[]','爱累累、万颗贯骊珠，特地写幽芳。',119,'宋词/ci.song.18000.json','["爱累累、万颗贯骊珠，特地写幽芳。", "想黄昏云淡，夜深人静，清影横窗。", "冷澹一枝两叶，笔下老秋光。", "参透圆明相，日观开荒。", "最是柔髭修梗，映风姿雾质，雅趣悠长。", "更淋漓草圣，把玩墨犹香。", "珍重好、卷藏归去，枕屏间、偏称道人床。", "江南路，后回重见、同话凄凉。"]'),
('song-ci-457','卜算子','止禅师','宋','宋词','song-ci','卜算子','[]','书是玉关来，泪向松江堕。',52,'宋词/ci.song.18000.json','["书是玉关来，泪向松江堕。", "梅自飘香柳自青，嘹唳征鸿过。", "沙漠暗尘飞，嵩狱愁云锁。", "淮上千营夜枕戈，此恨凭谁破。"]'),
('song-ci-458','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','渺渺啼鸦了。',142,'宋词/ci.song.18000.json','["渺渺啼鸦了。", "亘鱼天、寒生峭屿，五湖秋晓。", "竹几一灯人做梦，嘶马谁行古道。", "起搔首、窥星多少。", "月有微黄篱无影，挂牵牛、数朵青花小。", "秋太淡，添红枣。", "愁痕倚赖西风扫。", "被西风、翻催鬓鬒，与秋俱老。", "旧院隔霜帘不卷，金粉屏边醉倒。", "计无此、中年怀抱。", "万里江南吹箫恨，恨参差、白雁横天杪。", "烟未敛，楚山杳。"]'),
('song-ci-459','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','雁屿晴岚薄。',142,'宋词/ci.song.18000.json','["雁屿晴岚薄。", "倚层屏、千树高低，粉纤红弱。", "云隘东风藏不尽，吹艳生香万壑。", "又散入、汀蘅洲药。", "扰扰匆匆尘土面，看歌莺、舞燕逢春乐。", "人共物，知谁错。", "宝钗楼上围帘幕。", "小婵娟、双调弹筝，半霄鸾鹤。", "我辈中人无此分，琴思诗情当却。", "也胜似、愁横眉角。", "芳景三分才过二，便绿阴、门巷杨花落。", "沽斗酒，且同酌。"]'),
('song-ci-460','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','浪涌孤亭起。',142,'宋词/ci.song.18000.json','["浪涌孤亭起。", "是当年、蓬莱顶上，海风飘坠。", "帝遣江神长守护，八柱蛟龙缠尾。", "斗吐出、寒烟寒雨。", "昨夜鲸翻坤轴动，卷雕翬、掷向虚空里。", "但留得，绛虹住。", "五湖有客扁舟舣。", "怕群仙、重游到此，翠旌难驻。", "手拍阑干呼白鹭，为我殷勤寄语。", "奈鹭也、惊飞沙渚。", "星月一天云万壑，览茫茫、宇宙知何处。", "鼓双楫，浩歌去。"]'),
('song-ci-461','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','梦冷黄金屋。',142,'宋词/ci.song.18000.json','["梦冷黄金屋。", "叹秦筝、斜鸿阵里，素弦尘扑。", "化作娇莺飞归去，犹认纱窗旧绿。", "正过雨、荆桃如菽。", "此恨难平君知否，似琼台、涌起弹棋局。", "消瘦影，嫌明烛。", "鸳楼碎泻东西玉。", "问芳悰、何时再展，翠钗难卜。", "待把宫眉横云样，描上生绡画幅。", "怕不是、新来妆束。", "彩扇红牙今都在，恨无人、解听开元曲。", "空掩袖，倚寒竹。"]'),
('song-ci-462','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','深阁帘垂绣。',142,'宋词/ci.song.18000.json','["深阁帘垂绣。", "记家人、软语灯边，笑涡红透。", "万叠城头哀怨角，吹落霜花满袖。", "影厮伴、东奔西走。", "望断乡关知何处，羡寒鸦、到著黄昏后。", "一点点，归杨柳。", "相看只有山如旧。", "叹浮云、本是无心，也成苍狗。", "明日枯荷包冷饭，又过前头小阜。", "趁未发、且尝村酒。", "醉探枵囊毛锥在，问邻翁、要写牛经否。", "翁不应，但摇手。"]'),
('song-ci-463','沁园春','蒋捷','宋','宋词','song-ci','沁园春','[]','老子平生，辛勤几年，始有此庐。',139,'宋词/ci.song.18000.json','["老子平生，辛勤几年，始有此庐。", "也学那陶潜，篱栽些菊，依他杜甫，园种些蔬。", "除了雕梁，肯容紫燕，谁管门前长者车。", "怪近日，把一庭明月，却借伊渠。", "鬓边白发纷如。", "又何苦招宾约客欤。", "但夏榻宵眠，面风敧枕，冬檐昼短，背日观书。", "若有人寻，只教僮道，这屋主人今自居。", "休羡彼，有摇金宝辔，织翠华裾。"]'),
('song-ci-464','沁园春','蒋捷','宋','宋词','song-ci','沁园春','[]','结算平生，风流债负，请一笔句。',140,'宋词/ci.song.18000.json','["结算平生，风流债负，请一笔句。", "盖攻性之兵，花围锦阵，毒身之鸩，笑齿歌喉。", "岂识吾儒，道中乐地，绝胜珠帘十里楼。", "迷因底，叹晴乾不去，待雨淋头。", "休休。", "著甚来由。", "硬铁汉从来气食牛。", "但只有千篇，好诗好曲，都无半点，闲闷闲愁。", "自古娇波，溺人多矣，试问还能溺我不。", "高抬眼，看牵丝傀儡，谁弄谁收。"]'),
('song-ci-465','女冠子','蒋捷','宋','宋词','song-ci','女冠子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','蕙花香也。',136,'宋词/ci.song.18000.json','["蕙花香也。", "雪晴池馆如画。", "春风飞到，宝钗楼上，一片笙箫，琉璃光射。", "而今灯漫挂。", "不是暗尘明月，那时元夜。", "况年来、心懒意怯，羞与蛾儿争要。", "江城人悄初更打。", "问繁华谁解，再向天公借。", "剔残红灺。", "但梦里隐隐，钿车罗帕。", "吴笺银粉砑。", "待把旧家风景，写成闲话。", "笑绿鬟邻女，倚窗犹唱，夕阳西下。"]'),
('song-ci-466','女冠子','蒋捷','宋','宋词','song-ci','女冠子','[]','电旗飞舞。',136,'宋词/ci.song.18000.json','["电旗飞舞。", "双双还又争渡。", "湘漓云外，独醒何在，翠药红蘅，芳菲如故。", "深衷全未语。", "不似素车白马，卷潮起怒。", "但悄然、千载旧迹，时有闲人吊古。", "生平惯受椒兰苦。", "甚魄沈寒浪，更被馋蛟妒。", "结琼纫璐。", "料贝阙隐隐，骑鲸烟雾。", "楚妃花倚暮。", "□□琼箫吹了，溯波同步。", "待月明洲渚，小留旌节，朗吟骚赋。"]'),
('song-ci-467','大圣乐','蒋捷','宋','宋词','song-ci','大圣乐','[]','笙月凉边，翠翘双舞，寿仙曲破。',133,'宋词/ci.song.18000.json','["笙月凉边，翠翘双舞，寿仙曲破。", "更听得艳拍流星，慢唱寿词初了，群唱莲歌。", "主翁楼上披鹤氅，展一笑、微微红透涡。", "襟怀好，纵炎官驻伞，长是春和。", "千年鼻祖事业，记曾趁雷声飞快梭。", "但也曾三径，抚松采菊，随分吟哦。", "富贵云浮，荣华风过，淡处还他滋味多。", "休辞饮，有碧荷贮酒，深似金荷。"]'),
('song-ci-468','解连环','蒋捷','宋','宋词','song-ci','解连环','[]','妒花风恶。',132,'宋词/ci.song.18000.json','["妒花风恶。", "吹青阴涨却，乱红池阁。", "驻媚景、别有仙葩，遍琼甃小台，翠油疏箔。", "旧日天香，记曾绕、玉奴弦索。", "自长安路远，腻紫肥黄，但谱东洛。", "天津霁红如昨。", "听鹃声度月，春又寥寞。", "散艳魄、飞入江南，转湖渺山茫，梦境难托。", "万叠花愁，正困倚、钓阑斜角。", "待携尊、醉歌醉舞，劝花自乐。"]'),
('song-ci-469','永遇乐','蒋捷','宋','宋词','song-ci','永遇乐','[]','清逼池亭，润侵山阁，雪气凝聚。',128,'宋词/ci.song.18000.json','["清逼池亭，润侵山阁，雪气凝聚。", "未有蝉前，已无蝶后，花事随逝水。", "西园支径，今朝重到，半碍醉筇吟袂。", "除非是、莺身瘦小，暗中引雏穿去。", "梅檐溜滴，风来吹断，放得斜阳一缕。", "玉子敲枰，香绡落翦，声度深几许。", "层层离恨，凄迷如此，点破谩烦轻絮。", "应难认、争春旧馆，倚红杏处。"]'),
('song-ci-470','花心动','蒋捷','宋','宋词','song-ci','花心动','["\u897f\u6e56"]','春入南塘，粉梅花、盈盈倚风微笑。',127,'宋词/ci.song.18000.json','["春入南塘，粉梅花、盈盈倚风微笑。", "虹晕贯帘，星球攒巷，遍地宝光交照。", "涌金门外楼台影，参差浸、西湖波渺。", "暮天远，芙蓉万朵，是谁移到。", "鬒鬓双仙未老。", "陪玳席佳宾，暖香云绕。", "翠簨叩冰，银管嘘霜，瑞露满锺频釂。", "醉归深院重歌舞，雕盘转、珍珠红小。", "凤洲柳，丝丝淡烟弄晓。"]'),
('song-ci-471','金盏子','蒋捷','宋','宋词','song-ci','金盏子','[]','练月萦窗，梦乍醒、黄花翠竹庭馆。',126,'宋词/ci.song.18000.json','["练月萦窗，梦乍醒、黄花翠竹庭馆。", "心字夜香消，人孤另、双鹣被池羞看。", "拟待告诉天公，减秋声一半。", "无情雁。", "正用恁时飞来，叫云寻伴。", "犹记杏栊暖。", "银烛下、纤影卸佩款。", "春涡晕，红豆小，莺衣嫩，珠痕淡印芳汗。", "自从信误青骊，想笼莺停唤。", "风刀快，翦尽画檐梧桐，怎翦愁断。"]'),
('song-ci-472','喜迁莺','蒋捷','宋','宋词','song-ci','喜迁莺','[]','游丝纤弱。',126,'宋词/ci.song.18000.json','["游丝纤弱。", "谩著意绊春，春难凭托。", "水暖成纹，云晴生影，双燕又窥帘幕。", "露添牡丹新艳，风摆秋千闲索。", "对此景，动高歌一曲，何妨行乐。", "行乐。", "春正好，无奈绿窗，孤负敲棋约。", "锦屋调笙，银瓶索酒，争奈也曾迷著。", "自从发凋心倦，常倚钩阑斜角。", "翠深处，看悠悠几点，杨花飞落。"]'),
('song-ci-473','昼锦堂','蒋捷','宋','宋词','song-ci','昼锦堂','[]','染柳烟消，敲菰雨断，历历犹寄斜阳。',122,'宋词/ci.song.18000.json','["染柳烟消，敲菰雨断，历历犹寄斜阳。", "掩冉玉妃芳袂，拥出灵场。", "倩他鸳鸯来寄语，驻君舴艋亦何妨。", "渔榔静，独奏棹歌，邀妃试酌清觞。", "湖上云渐暝，秋浩荡，鲜风支尽蝉粮。", "赠我非环非佩，万斛生香。", "半蜗茅屋归吹影，数螺苔石压波光。", "鸳鸯笑，何似且留双楫，翠隐红藏。"]'),
('song-ci-474','水龙吟','蒋捷','宋','宋词','song-ci','水龙吟','[]','醉兮琼瀣浮觞些。',126,'宋词/ci.song.18000.json','["醉兮琼瀣浮觞些。", "招兮遣巫阳些。", "君毋去此，飓风将起，天微黄些。", "野马尘埃，污君楚楚，白霓裳些。", "驾空兮云浪，茫洋东下，流君往、他方些。", "月满兮西厢些。", "叫云矣、笛凄凉些。", "归来为我，重倚蛟背，寒鳞苍些。", "俯视春红，浩然一笑，吐山香些。", "翠禽兮弄晓，招君未至，我心伤些。"]'),
('song-ci-475','瑞鹤仙','蒋捷','宋','宋词','song-ci','瑞鹤仙','[]','缟霜霏霁雪。',127,'宋词/ci.song.18000.json','["缟霜霏霁雪。", "渐翠没凉痕，猩浮寒血。", "山窗梦凄切。", "短吟筇犹倚，莺边新樾。", "花魂未歇。", "似追惜、芳消艳灭。", "挽西风、再入柔柯，误染绀云成缬。", "休说。", "深题锦翰，浅泛琼漪，暗春曾泄。", "情条万结。", "依然是，未愁绝。", "最怜他，南苑空阶堆遍，人隔仙蓬怨别。", "锁芙蓉、小殿秋深，碎虫诉月。"]'),
('song-ci-476','瑞鹤仙','蒋捷','宋','宋词','song-ci','瑞鹤仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绀烟迷雁迹。',127,'宋词/ci.song.18000.json','["绀烟迷雁迹。", "渐断鼓零钟，街喧初息。", "风檠背寒壁。", "放冰蜍飞到，丝丝窗隙。", "琼瑰暗泣。", "念乡关、霜芜似织。", "漫将身、化鹤归来，忘却旧游端的。", "欢极。", "蓬壶蕖浸，花院梨溶，醉连春夕。", "柯云罢弈。", "樱桃在，梦难觅。", "劝清光，乍可幽窗相伴，休照红楼夜笛。", "怕人间、换谱伊凉，素娥未识。"]'),
('song-ci-477','瑞鹤仙','蒋捷','宋','宋词','song-ci','瑞鹤仙','[]','玉霜生穗也。',127,'宋词/ci.song.18000.json','["玉霜生穗也。", "渺洲云翠痕，雁绳低也。", "层帘四垂也。", "锦堂寒早近，开炉时也。", "香风递也。", "是东篱、花深处也。", "料此花、伴我仙翁，未肯放秋归也。", "嬉也。", "缯波稳舫，镜月危楼，釂琼ⅲ也。", "笼莺睡也。", "红妆旋、舞衣也。", "待纱灯客散，纱窗日上，便是严凝序也。", "换青毡、小帐围春，又还醉也。"]'),
('song-ci-478','瑞鹤仙','蒋捷','宋','宋词','song-ci','瑞鹤仙','[]','素肌元是雪。',127,'宋词/ci.song.18000.json','["素肌元是雪。", "向雪里带香，更添奇绝。", "梅花太孤洁。", "问梨花何似，风标难识。", "长洲漾楫。", "料鸳边、娇容乍折。", "对珠栊、自翦凉衣，爱把淡罗轻叠。", "清彻。", "螺心翠靥，龙吻琼涎，总成虚设。", "微微醉缬。", "窗灯晕，弄明灭。", "算银台高处，芳菲仙佩，步遍纤云万叶。", "觉来时、人在红帱，半廊界月。"]'),
('song-ci-479','木兰花慢','蒋捷','宋','宋词','song-ci','木兰花慢','[]','傍池阑倚遍，问山影、是谁偷。',125,'宋词/ci.song.18000.json','["傍池阑倚遍，问山影、是谁偷。", "但鹭敛琼丝，鸳藏绣羽，碍浴妨浮。", "寒流。", "暗冲片响，似犀椎、带月静敲秋。", "因念凉荷院宇，纷丸曾泛金瓯。", "妆楼。", "晓涩翠罂油。", "倦鬓理还休。", "更有何意绪，怜他半夜，瓶破梅愁。", "红裯。", "泪乾万点。", "待穿来、寄与薄情收。", "只恐东风未转，误人日望归舟。"]'),
('song-ci-480','木兰花慢','蒋捷','宋','宋词','song-ci','木兰花慢','[]','渺琉璃万顷，冷光射、夕阳洲。',125,'宋词/ci.song.18000.json','["渺琉璃万顷，冷光射、夕阳洲。", "见败柳漂枝，残芦泛叶，欲去仍留。", "罗帱。", "少年梦里，正窥帘、月浸素肌柔。", "谁念衰翁自老，断髭冻得成虬。", "凝眸。", "一望绝飞鸥。", "宇宙正清幽。", "漫细敲紫砚，轻呵翠管，吟思难抽。", "飕飕。", "晚风又起，但时听、碎玉落檐头。", "多少梅花片脑，醉来误整香篝。"]'),
('song-ci-481','珍珠帘・真珠帘','蒋捷','宋','宋词','song-ci','珍珠帘・真珠帘','[]','书楼四面筠帘卷。',123,'宋词/ci.song.18000.json','["书楼四面筠帘卷。", "微薰起，翠弄悬签丝软。", "楼上读书仙，对宝狻霏转。", "绣馆钗行云度影，滟寿觥、盈盈争劝。", "争劝。", "奈芸边事切，花中情浅。", "金奏未响昏蜩，早传言放却，舞衫歌扇。", "柳雨一窝凉，再展开湘卷。", "万颗蕖心琼珠辊，细滴与、银朱小砚。", "深院。", "待月满廊腰，玉笙又远。"]'),
('song-ci-482','高阳台','蒋捷','宋','宋词','song-ci','高阳台','[]','霞铄帘珠，云蒸篆玉，环楼婉婉飞铃。',122,'宋词/ci.song.18000.json','["霞铄帘珠，云蒸篆玉，环楼婉婉飞铃。", "天上王郎，飚轮此地曾停。", "秋香不断台隍远，溢万丛、锦艳鲜明。", "事成尘，鸾凤箫中，空度歌声。", "臞翁一点清寒髓，惯餐英菊屿，饮露兰汀。", "透屋高红，新营小样花城。", "霜浓月淡三更梦，梦曼仙、来倚吟屏。", "共襟期，不是琼姬，不是芳卿。"]'),
('song-ci-483','高阳台','蒋捷','宋','宋词','song-ci','高阳台','[]','燕卷情丝，蜂黏落絮，天教绾住闲愁。',121,'宋词/ci.song.18000.json','["燕卷情丝，蜂黏落絮，天教绾住闲愁。", "闲里清明，匆匆粉涩红羞。", "灯摇缥晕茸窗冷，语未阑、蛾影分收。", "好伤情，春也难留，人也难留。", "芳尘满目悠悠。", "问萦云佩响，还绕谁楼。", "别酒才斟，从前心事都休。", "飞莺纵有风吹转，奈旧家、苑已成秋。", "莫思量，杨柳湾西，且棹吟舟。"]'),
('song-ci-484','高阳台','蒋捷','宋','宋词','song-ci','高阳台','[]','桥尾星沈，街心尘敛，天公还把春饶。',122,'宋词/ci.song.18000.json','["桥尾星沈，街心尘敛，天公还把春饶。", "桂月黄昏，金丝柳换星摇。", "相逢小曲方嫌冷，便暖薰、珠络香飘。", "却怜他、隔岁芳期，枉费囊绡。", "人情终似蛾儿舞，到嚬翻宿粉，怎比初描。", "认得游踪，花骢不住嘶骄。", "梅梢一寸残红炬，喜尚堪、移照樱桃。", "醉醺醺，不记元宵，只道花朝。"]'),
('song-ci-485','春夏两相期','蒋捷','宋','宋词','song-ci','春夏两相期','["\u897f\u6e56"]','听深深、谢家庭馆。',120,'宋词/ci.song.18000.json','["听深深、谢家庭馆。", "东风对语双燕。", "似说朝来，天上婺星光现。", "金裁花诰紫泥香，绣裹藤舆红茵软。", "散蜡宫辉，行鳞厨品，至今人羡。", "西湖万柳如线。", "料月仙当此，小停飚辇。", "付与长年，教见海心波浅。", "萦云玉佩五侯门，洗雪华桐三春苑。", "慢拍调莺，急鼓吹鸾，翠阴生院。"]'),
('song-ci-486','念奴娇','蒋捷','宋','宋词','song-ci','念奴娇','[]','稼翁居士，有几多抱负，几多声价。',120,'宋词/ci.song.18000.json','["稼翁居士，有几多抱负，几多声价。", "玉立绣衣霄汉表，曾览八州风化。", "进退行藏，此时正要，一著高天下。", "黄埃扑面，不成也控羸马。", "人道云出无心，才离山后，岂是无心者。", "自古达官酣富贵，住住遭人描画。", "只有青门，种瓜闲客，千载传佳话。", "稼翁一笑，吾今亦爱吾稼。"]'),
('song-ci-487','绛都春','蒋捷','宋','宋词','song-ci','绛都春','[]','春愁怎画。',122,'宋词/ci.song.18000.json','["春愁怎画。", "正莺背带雪，酴醿花谢。", "细雨院深，淡月廊斜重帘挂。", "归时记约烧灯夜。", "早拆尽、秋千红架。", "纵然归近，风光又是，翠阴初夏。", "娅姹。", "嚬青泫白，恨玉佩罢舞，芳尘凝榭。", "几拟情人，付与兰香秋罗帕。", "知他堕策斜拢马。", "在底处、垂杨楼下。", "无言暗拥娇鬟，凤钗溜也。"]'),
('song-ci-488','声声慢','蒋捷','宋','宋词','song-ci','声声慢','[]','黄花深巷，红叶低窗，凄凉一片秋声。',119,'宋词/ci.song.18000.json','["黄花深巷，红叶低窗，凄凉一片秋声。", "豆雨声来，中间夹带风声。", "疏疏二十五点，丽谯门、不锁更声。", "故人远，问谁摇玉佩，檐底铃声。", "彩角声吹月堕，渐连营马动，四起笳声。", "闪烁邻灯，灯前尚有砧声。", "知他诉愁到晓，碎哝哝、多少蛩声。", "诉未了，把一半、分与雁声。"]'),
('song-ci-489','尾犯','蒋捷','宋','宋词','song-ci','尾犯','[]','夜倚读书床，敲碎唾壶，灯晕明灭。',119,'宋词/ci.song.18000.json','["夜倚读书床，敲碎唾壶，灯晕明灭。", "多事西风，把斋铃频掣。", "人共语、温温芋火，雁孤飞、萧萧桧雪。", "遍阑干外，万顷鱼天，未了予愁绝。", "鸡边长剑舞，念不到、此样豪杰。", "瘦骨棱棱，但凄其衾铁。", "是非梦、无痕堪记，似双瞳、缤纷翠缬。", "浩然心在，我逢著、梅花便说。"]'),
('song-ci-490','满江红','蒋捷','宋','宋词','song-ci','满江红','[]','一掬乡心，付杳杳、露莎烟苇。',115,'宋词/ci.song.18000.json','["一掬乡心，付杳杳、露莎烟苇。", "来相伴、凄然客影，谢他穷鬼。", "新绿旧红春又老，少玄老白人生几。", "况无情、世故荡摩中，凋英伟。", "词场笔，行群蚁。", "战场胄，藏群虮。", "问何如清昼，倚藤凭棐。", "流水青山屋上下，束书壶酒船头尾。", "任垂涎、斗大印黄金，狂周顗。"]'),
('song-ci-491','满江红','蒋捷','宋','宋词','song-ci','满江红','[]','秋本无愁，奈客里、秋偏岑寂。',115,'宋词/ci.song.18000.json','["秋本无愁，奈客里、秋偏岑寂。", "身老大、忺敲秦缶，懒移陶甓。", "万误曾因疏处起，一闲且向贫中觅。", "笑新来、多事是征鸿，声嘹呖。", "双户掩，孤灯剔。", "书束架，琴悬壁。", "笑人间无此，小窗幽阒。", "浪远微听葭叶响，雨残细数梧梢滴。", "正依稀、梦到故人家，谁横笛。"]'),
('song-ci-492','探芳信','蒋捷','宋','宋词','song-ci','探芳信','[]','翠吟悄。',110,'宋词/ci.song.18000.json','["翠吟悄。", "似有人黄裳，孤伫埃表。", "渐老侵芳岁，识君恨不早。", "料应陶令吟魂在，凝此秋香妙。", "傲霜姿，尚想前身，倚窗馀傲。", "回首醉年少。", "控骏马蓉边，红亸茸帽。", "淡泊东篱，有谁肯、梦飞到。", "正襟三诵悠然句，聊遣花微笑。", "酒休赊，醒眼看花正好。"]'),
('song-ci-493','梅花引','蒋捷','宋','宋词','song-ci','梅花引','[]','白鸥问我泊孤舟。',108,'宋词/ci.song.18000.json','["白鸥问我泊孤舟。", "是身留。", "是心留。", "心若留时、何事锁眉头。", "风拍小帘灯晕舞，对闲影，冷清清，忆旧游。", "旧游旧游今在不。", "花外楼。", "柳下舟。", "梦也梦也，梦不到、寒水空流。", "漠漠黄云、湿透木绵裘。", "都道无人愁似我，今夜雪，有梅花，似我愁。"]'),
('song-ci-494','洞仙歌','蒋捷','宋','宋词','song-ci','洞仙歌','[]','世间何处，最难忘杯酒。',101,'宋词/ci.song.18000.json','["世间何处，最难忘杯酒。", "惟是停云想亲友。", "此时无一盏，千种离愁，西风外，长伴枯荷衰柳。", "去年深夜语，倾倒书□，窗烛心悬小红豆。", "记得到门时，雨正萧萧，嗟今雨、此情非旧。", "待与子、相期采黄花，又未卜重阳，果能晴否。"]'),
('song-ci-495','洞仙歌','蒋捷','宋','宋词','song-ci','洞仙歌','[]','枝枝叶叶，受东风调弄。',102,'宋词/ci.song.18000.json','["枝枝叶叶，受东风调弄。", "便是鸾穿也微动。", "自鹅黄千缕，数到飞绵，闲无事，谁管将春迎送。", "轻柔心性在，教得游人，酒舞花吟姿狂纵。", "更谁家鸾镜里，贪学纤蛾，移来傍、妆楼新种。", "总不道、江头锁清愁，正雨渺烟茫，翠阴如梦。"]'),
('song-ci-496','最高楼','蒋捷','宋','宋词','song-ci','最高楼','[]','新春景，明媚在何时。',100,'宋词/ci.song.18000.json','["新春景，明媚在何时。", "宜早不宜迟。", "软尘巷陌青油幰，重帘深院画罗衣。", "要些儿，晴日照，暖风吹。", "一片片、雪儿休要下。", "一点点、雨儿休要洒。", "才恁地，越愆期。", "悠悠不趁梅花到，匆匆枉带柳花飞。", "倩黄莺，将我语，报春归。"]'),
('song-ci-497','祝英台・祝英台近','蒋捷','宋','宋词','song-ci','祝英台・祝英台近','[]','柳边楼，花下馆。',95,'宋词/ci.song.18000.json','["柳边楼，花下馆。", "低卷绣帘半。", "帘外天丝，扰扰似情乱。", "知他蛾绿纤眉，鹅黄小袖。", "在何处、闲游闲玩。", "最堪叹。", "筝面一寸尘深，玉柱网斜雁。", "谱字红蔫，翦烛记同看。", "几回传语东风，将愁吹去，怎奈向、东风不管。"]'),
('song-ci-498','风入松','蒋捷','宋','宋词','song-ci','风入松','[]','东风方到旧桃枝。',90,'宋词/ci.song.18000.json','["东风方到旧桃枝。", "仙梦已云迷。", "画阑红子摴蒱处，依然是、春昼帘垂。", "恨杀河东狮子，惊回海底鸥儿。", "寻芳小步莫嫌迟。", "此去却慵移。", "断肠不在分襟后，元来在、襟未分时。", "柳岸犹携素手，兰房早掩朱扉。"]'),
('song-ci-499','解佩令','蒋捷','宋','宋词','song-ci','解佩令','[]','春晴也好。',81,'宋词/ci.song.18000.json','["春晴也好。", "春阴也好。", "著些儿、春雨越好。", "春雨如丝，绣出花枝红袅。", "怎禁他、孟婆合皂。", "梅花风小。", "杏花风小。", "海棠风、蓦地寒峭。", "岁岁春光，被二十四风吹老。", "楝花风、尔且慢到。"]'),
('song-ci-500','一翦梅','蒋捷','宋','宋词','song-ci','一翦梅','[]','小巧楼台眼界宽。',72,'宋词/ci.song.18000.json','["小巧楼台眼界宽。", "朝卷帘看。", "暮卷帘看。", "故乡一望一心酸。", "云又迷漫。", "水又迷漫。", "天不教人客梦安。", "昨夜春寒。", "今夜春寒。", "梨花月底两眉攒。", "敲遍阑干。", "拍遍阑干。"]'),
('song-ci-501','一翦梅','蒋捷','宋','宋词','song-ci','一翦梅','[]','一片春愁待酒浇。',72,'宋词/ci.song.18000.json','["一片春愁待酒浇。", "江上舟摇。", "楼上帘招。", "秋娘度与泰娘娇。", "风又飘飘。", "雨又萧萧。", "何日归家洗客袍。", "银字笙调。", "心字香烧。", "流光容易把人抛。", "红了樱桃。", "绿了芭蕉。"]'),
('song-ci-502','糖多令・唐多令','蒋捷','宋','宋词','song-ci','糖多令・唐多令','[]','秋碧泻晴湾。',74,'宋词/ci.song.18000.json','["秋碧泻晴湾。", "楼台云影闲。", "记仙家、元在蓬山。", "飞到雁峰尘更少，三万顷、玉无边。", "金盏倒垂莲。", "歌摇香雾鬟。", "任芙蓉、玉月朱阑。", "天气已凉犹未冷，重九后、小春前。"]'),
('song-ci-503','柳梢青','蒋捷','宋','宋词','song-ci','柳梢青','[]','小饮微吟，残灯断雨，静户幽窗。',61,'宋词/ci.song.18000.json','["小饮微吟，残灯断雨，静户幽窗。", "几度花开，几番花谢，又到黄昏。", "潘娘不是潘郎。", "料应也、霜黏鬓旁。", "鹦鹉阑空，鸳鸯壶破，烟渺云茫。"]'),
('song-ci-504','阮郎归','蒋捷','宋','宋词','song-ci','阮郎归','[]','雪飞灯背雁声低。',56,'宋词/ci.song.18000.json','["雪飞灯背雁声低。", "寒生红被池。", "小屏风畔立多时。", "闲看番马儿。", "新搵泪，旧题诗。", "一般罗带垂。", "琼箫夜夜挟愁吹。", "梅花知不知。"]'),
('song-ci-505','金蕉叶','蒋捷','宋','宋词','song-ci','金蕉叶','[]','云褰翠幕。',55,'宋词/ci.song.18000.json','["云褰翠幕。", "满天星碎珠迸索。", "孤蟾阑外，照我看看过转角。", "酒醒寒砧正作。", "待眠来、梦魂怕恶。", "枕屏那更，画了平洲断雁落。"]'),
('song-ci-506','忆秦娥','蒋捷','宋','宋词','song-ci','忆秦娥','[]','山无限。',51,'宋词/ci.song.18000.json','["山无限。", "登山试望吴宫殿。", "吴宫殿。", "是藏深坞，是临清浅。", "（缺词文）（缺词文）（缺词文）（缺词文）（缺词文）"]'),
('song-ci-507','谒金门','蒋捷','宋','宋词','song-ci','谒金门','[]','（缺词文）（缺词文）（缺词文）（缺词文）（缺词文）',25,'宋词/ci.song.18000.json','["（缺词文）（缺词文）（缺词文）（缺词文）（缺词文）"]'),
('song-ci-508','菩萨蛮','蒋捷','宋','宋词','song-ci','菩萨蛮','[]','（缺词文）（缺词文）（缺词文）（缺词文）',20,'宋词/ci.song.18000.json','["（缺词文）（缺词文）（缺词文）（缺词文）"]'),
('song-ci-509','卜算子','蒋捷','宋','宋词','song-ci','卜算子','[]','（缺词文）（缺词文）（缺词文）',15,'宋词/ci.song.18000.json','["（缺词文）（缺词文）（缺词文）"]'),
('song-ci-510','霜天晓角','蒋捷','宋','宋词','song-ci','霜天晓角','[]','（缺词文）（缺词文）',10,'宋词/ci.song.18000.json','["（缺词文）（缺词文）"]'),
('song-ci-511','点绛唇','蒋捷','宋','宋词','song-ci','点绛唇','[]','（缺词文）',5,'宋词/ci.song.18000.json','["（缺词文）"]'),
('song-ci-512','昭君怨','蒋捷','宋','宋词','song-ci','昭君怨','[]','担子挑春虽小。',48,'宋词/ci.song.18000.json','["担子挑春虽小。", "白白红红都好。", "卖过巷东家。", "巷西家。", "帘外一声声叫。", "帘里鸦鬟入报。", "问道买梅花。", "买梅花。"]'),
('song-ci-513','如梦令','蒋捷','宋','宋词','song-ci','如梦令','[]','夜月溪篁鸾影。',40,'宋词/ci.song.18000.json','["夜月溪篁鸾影。", "晓露岩花鹤顶。", "半世踏红尘，到底输他村景。", "村景。", "村景。", "樵斧耕蓑渔艇。"]'),
('song-ci-514','小重山','蒋捷','宋','宋词','song-ci','小重山','[]','晴浦溶溶明断霞。',70,'宋词/ci.song.18000.json','["晴浦溶溶明断霞。", "楼台摇影处，是谁家。", "银红裙裥皱宫纱。", "风前坐，闲斗郁金芽。", "人散树啼鸦。", "粉团黏不住，旧繁华。", "双龙尾上月痕斜。", "而今照，冷淡白菱花。"]'),
('song-ci-515','小重山','蒋捷','宋','宋词','song-ci','小重山','[]','曾伴芳卿锵佩环。',70,'宋词/ci.song.18000.json','["曾伴芳卿锵佩环。", "西风吹梦断，堕人寰。", "假饶无分入雕阑。", "窥妆镜，也合小溪湾。", "此地有谁怜。", "斜阳牛卧处，牧童攀。", "劝花休苦恨天天。", "从来道，薄命是朱颜。"]'),
('song-ci-516','白苎','蒋捷','宋','宋词','song-ci','白苎','[]','正春晴，又春冷，云低欲落。',155,'宋词/ci.song.18000.json','["正春晴，又春冷，云低欲落。", "琼苞未剖，早是东风作恶。", "旋安排、一双银蒜镇罗幕。", "幽壑。", "水生漪，皱嫩绿、潜鳞初跃。", "愔愔门巷，桃树红才约略。", "知甚时，霁华烘破青青萼。", "忆昨。", "□□□□，引蝶花边，近来重见，身学垂杨瘦削。", "问小翠眉山，为谁攒却。", "斜阳院宇，任蛛丝罥遍，玉筝弦索。", "户外惟闻，放翦刀声，深在妆阁。", "料想裁缝，白苎春衫薄。"]'),
('song-ci-517','蝶恋花','蒋捷','宋','宋词','song-ci','蝶恋花','[]','我爱荷花花最软。',70,'宋词/ci.song.18000.json','["我爱荷花花最软。", "锦拶云挨，朵朵娇如颤。", "一阵微风来自远。", "红低欲蘸凉波浅。", "莫是羊家张静婉。", "抱月飘烟，舞得腰肢倦。", "偷把翠罗香被展。", "无眠却又频翻转。"]'),
('song-ci-518','虞美人','蒋捷','宋','宋词','song-ci','虞美人','[]','丝丝杨柳丝丝雨。',66,'宋词/ci.song.18000.json','["丝丝杨柳丝丝雨。", "春在溟濛处。", "楼儿忒小不藏愁。", "几度和云飞去、觅归舟。", "天怜客子乡关远。", "借与花消遣。", "海棠红近绿阑干。", "才卷朱帘却又、晚风寒。"]'),
('song-ci-519','虞美人','蒋捷','宋','宋词','song-ci','虞美人','[]','少年听雨歌楼上。',66,'宋词/ci.song.18000.json','["少年听雨歌楼上。", "红烛昏罗帐。", "壮年听雨客舟中。", "江阔云低、断雁叫西风。", "而今听雨僧庐下。", "鬓已星星也。", "悲欢离合总无情。", "一任阶前、点滴到天明。"]'),
('song-ci-520','南乡子','蒋捷','宋','宋词','song-ci','南乡子','[]','泊雁小汀洲。',66,'宋词/ci.song.18000.json','["泊雁小汀洲。", "冷淡湔裙水漫秋。", "裙上唾花无觅处，重游。", "隔柳惟存月半钩。", "准拟架层楼。", "望得伊家见始休。", "还怕粉云天末起，悠悠。", "化作相思一片愁。"]'),
('song-ci-521','南乡子','蒋捷','宋','宋词','song-ci','南乡子','[]','翠幰夜游车。',66,'宋词/ci.song.18000.json','["翠幰夜游车。", "不到山边与水涯。", "随分纸灯三四盏，邻家。", "便做元宵好景夸。", "谁解倚梅花。", "思想灯球坠绛纱。", "旧说梦华犹未了，堪嗟。", "才百馀年又梦华。"]'),
('song-ci-522','步蟾宫','蒋捷','宋','宋词','song-ci','步蟾宫','[]','绿华翦碎娇云瘦。',67,'宋词/ci.song.18000.json','["绿华翦碎娇云瘦。", "剩妆点、菊前蓉后。", "娟娟月也染成香，何况、纤罗襟袖。", "秋窗一夜西风骤。", "翠奁锁、琼珠花镂。", "人间富贵总腥膻，且和露、攀花三嗅。"]'),
('song-ci-523','步蟾宫','蒋捷','宋','宋词','song-ci','步蟾宫','[]','玉窗掣锁香云涨。',68,'宋词/ci.song.18000.json','["玉窗掣锁香云涨。", "唤绿袖、低敲方响。", "流苏拂处字微讹，但斜倚、红梅一饷。", "濛濛月在帘衣上。", "做池馆、春阴模样。", "春阴模样不如晴，这催雪、曲儿休唱。"]'),
('song-ci-524','玉楼春','蒋捷','宋','宋词','song-ci','玉楼春','[]','秦人占得桃源地。',64,'宋词/ci.song.18000.json','["秦人占得桃源地。", "说道花深堪避世。", "桃花湾内岂无花，吕政马来拦不住。", "明朝与子穿花去。", "去看霜蹄剜石处。", "茫茫秦事是耶非，万一问花花解语。"]'),
('song-ci-525','恋绣衾','蒋捷','宋','宋词','song-ci','恋绣衾','[]','茜金小袖花下行。',68,'宋词/ci.song.18000.json','["茜金小袖花下行。", "过桥亭、倚树听莺。", "被柳线、低萦鬓，绀云垂、钗凤半横。", "红薇影转晴窗昼，漾兰心、未到绣絣。", "奈一点、春来恨，在青蛾、弯处又生。"]'),
('song-ci-526','浪淘沙','蒋捷','宋','宋词','song-ci','浪淘沙','[]','人爱晓妆鲜。',64,'宋词/ci.song.18000.json','["人爱晓妆鲜。", "我爱妆残。", "翠钗扶住欲敧鬟。", "印了夜香无事也，月上凉天。", "新谱学筝难。", "愁涌蛾弯。", "一床衾浪未红翻。", "听得人催佯不睬，去洗珠钿。"]'),
('song-ci-527','浪淘沙','蒋捷','宋','宋词','song-ci','浪淘沙','[]','明露浴疏桐。',64,'宋词/ci.song.18000.json','["明露浴疏桐。", "秋满帘栊。", "掩琴无语意忡忡。", "掐破东窗窥皓月，早上芙蓉。", "前事渺茫中。", "烟水孤鸿。", "一尊重九又成空。", "不解吹愁吹帽落，恨杀西风。"]'),
('song-ci-528','燕归梁','蒋捷','宋','宋词','song-ci','燕归梁','[]','我梦唐宫春昼迟。',64,'宋词/ci.song.18000.json','["我梦唐宫春昼迟。", "正舞到、曳裾时。", "翠云队仗绛霞衣。", "慢腾腾、手双垂。", "忽然急鼓催将起，似彩凤、乱惊飞。", "梦回不见万琼妃。", "见荷花、被风吹。"]'),
('song-ci-529','步蟾宫','蒋捷','宋','宋词','song-ci','步蟾宫','[]','去年云掩冰轮皎。',68,'宋词/ci.song.18000.json','["去年云掩冰轮皎。", "喜今岁、微阴俱扫。", "乾坤一片玉琉璃，怎算得、清光多少。", "无歌无酒痴顽老。", "对愁影、翻嫌分晓。", "天公元不负中秋，我自把、中秋误了。"]'),
('song-ci-530','南乡子','蒋捷','宋','宋词','song-ci','南乡子','[]','冷淡是秋花。',66,'宋词/ci.song.18000.json','["冷淡是秋花。", "更比秋花冷淡些。", "到处芙蓉供醉赏，从他。", "自有幽人处士夸。", "寂寞两三葩。", "昼日无风也带斜。", "一片西窗残照里，谁家。", "卷却湘裙薄薄纱。"]'),
('song-ci-531','行香子','蒋捷','宋','宋词','song-ci','行香子','[]','红了樱桃。',84,'宋词/ci.song.18000.json','["红了樱桃。", "绿了芭蕉。", "送春归、客尚蓬飘。", "昨宵谷水，今夜兰皋。", "奈云溶溶，风淡淡，雨潇潇。", "银字笙调。", "心字香烧。", "料芳悰、乍整还凋。", "待将春恨，都付春潮。", "过窈娘堤，秋娘渡，泰娘桥。"]'),
('song-ci-532','粉蝶儿','蒋捷','宋','宋词','song-ci','粉蝶儿','[]','啼鴂声中，春光化成春梦。',90,'宋词/ci.song.18000.json','["啼鴂声中，春光化成春梦。", "问东君、仗谁诗送。", "燕怜晴，莺爱暖，一窗芳哄。", "奈匆匆、催他柳绵狂纵。", "轻罗扇小，桐花又飞么凤。", "记寒吟、沁梅霜冻。", "古今□，人易老，莫闲双鞚。", "尚堪游、荼䕷粉云香洞。"]'),
('song-ci-533','翠羽吟','蒋捷','宋','宋词','song-ci','翠羽吟','[]','绀露浓。',151,'宋词/ci.song.18000.json','["绀露浓。", "映素空。", "楼观峭玲珑。", "粉冻霁英，冷光摇荡古青松。", "半规黄昏淡月，梅气山影溟濛。", "有丽人、步依修竹，萧然态若游龙。", "绡袂微皱水溶溶。", "仙茎清瀣，净洗斜红。", "劝我浮香桂酒，环佩暗解，声飞芳霭中。", "弄春弱柳垂丝，慢按翠舞娇童。", "醉不知何处，惊翦翦、凄紧霜风。", "梦醒寻痕访踪。", "但留残星挂穹。", "梅花未老，翠羽双吟，一片晓峰。"]'),
('song-ci-534','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','甚矣君狂矣。',142,'宋词/ci.song.18000.json','["甚矣君狂矣。", "想胸中、些儿磊磈，酒浇不去。", "据我看来何所似，一似韩家五鬼。", "又一似、杨家风子。", "怪鸟啾啾鸣未了，被天公、捉住樊笼里。", "这一错，铁难铸。", "濯溪雨涨荆溪水。", "送君归、斩蛟桥外，水光清处。", "世上恨无楼百尺，装着许多俊气。", "做弄得、栖栖如此。", "临别赠言朋友事，有殷勤、六字君听取。", "节饮食，慎言语。"]'),
('song-ci-535','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','妾有琵琶谱。',142,'宋词/ci.song.18000.json','["妾有琵琶谱。", "抱金槽、慢拈轻抛，柳梢莺妒。", "羽调六么弹遍了，花底灵犀暗度。", "奈敲断、玉钗纤股。", "低画屏深朱户掩，卷西风、满地吹尘土。", "芳事往，蝶空诉。", "天天把妾芳心误。", "小楼东、隐约谁家，凤箫鼍鼓。", "泪点染衫双袖翠，修竹凄其又暮。", "背灯影、萧条情互。", "捐佩洲前裙步步，渺无边、一片相思苦。", "春去也，乱红舞。"]'),
('song-ci-536','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','绿堕云垂领。',141,'宋词/ci.song.18000.json','["绿堕云垂领。", "背琵琶、盈盈袖手，粉闲红靓。", "依约春游归来倦，又似春眠未醒。", "滟寒泚、低迷蓉影。", "莺带松声飞过也，柳窗深、尚记停针听。", "魂浩荡，孤芳景。", "金钗断股瓶沈井。", "问苏城、香销卷子，倩谁题咏。", "灯晕青红残醉在，小院屏昏帐暝。", "误瞋怪、眉心慵整。", "人道真真招得下，任千呼万唤无言应。", "空对此，泪花冷。"]'),
('song-ci-537','摸鱼子','蒋捷','宋','宋词','song-ci','摸鱼子','[]','亸吟鞭、雁峰高处。',140,'宋词/ci.song.18000.json','["亸吟鞭、雁峰高处。", "曾游长寿仙府。", "年年长见瑶簪会，霞杪盖芝轻度。", "开绣户。", "笑万朵香红，剩染秋光素。", "清箫丽鼓。", "任滟玉杯深，鸾酣凤醉，犹未洞天暮。", "尘缘误。", "迷却桃园旧步。", "飞琼芳梦同赋。", "朝来闻道仙童宴，翘首翠房玄圃。", "云又雾。", "身恍到微茫，认得胎禽舞。", "遥汀近浦。", "便一苇渔航，撑烟载雨，归去伴寒鹭。"]'),
('song-ci-538','沁园春','蒋捷','宋','宋词','song-ci','沁园春','[]','昔裴晋公，生甲辰岁，秉唐相钧。',139,'宋词/ci.song.18000.json','["昔裴晋公，生甲辰岁，秉唐相钧。", "向东都治第，才娱老眼，北门建节，又绊闲身。", "燠馆花浓，凉台月淡，不记弓刀千骑尘。", "谁堪羡，羡南塘居士，做散仙人。", "南塘水向晴云。", "三百树凤洲杨柳春。", "有绿衣奏曲，金斜小雁，彩衣劝酒，玉跪双麟。", "前后同年，逸劳异趣，中立翻成雌甲辰。", "斯言也，是梅花说与，竹里山民。"]'),
('song-ci-539','喜迁莺','蒋捷','宋','宋词','song-ci','喜迁莺','[]','风涛如此，被闲鸥诮我，君行良苦。',126,'宋词/ci.song.18000.json','["风涛如此，被闲鸥诮我，君行良苦。", "槲叶深湾，芦窠窄港，小憩倦篙慵橹。", "壮年夜吹笛去，惊得鱼龙嗥舞。", "怅今老，但蓬窗紧掩，荒凉愁愫。", "别浦。", "云断处。", "低雁一绳，拦断家山路。", "佩玉无诗，飞霞乏序，满席快飚谁付。", "醉中几番重九，今度芳尊孤负。", "便晴否。", "怕明朝蝶冷，黄花秋圃。"]'),
('song-ci-540','喜迁莺','蒋捷','宋','宋词','song-ci','喜迁莺','[]','晴天廖廓。',126,'宋词/ci.song.18000.json','["晴天廖廓。", "被孤云画出，离愁消索。", "玉局弹棋，金钗翦烛，芳思可胜摇落。", "镜妆为慵迟晚，笙曲缘愁差错。", "倒纤指，□从头细数，年时同乐。", "寂寞。", "花院悄，昨夜醉眠，梦也难凭托。", "车角生时，马蹄方后，才始断伊漂泊。", "闷无半分消遣，春又一番担阁。", "倚阑久，奈东风忒冷，红绡单薄。"]'),
('song-ci-541','齐天乐','蒋捷','宋','宋词','song-ci','齐天乐','[]','银蟾飞到觚棱外。',123,'宋词/ci.song.18000.json','["银蟾飞到觚棱外。", "娟娟下窥龙尾。", "电紫鞘轻，云红筤曲，雕玉舆穿灯底。", "峰缯岫绮。", "沸一簇人声，道随竿媚。", "侍女迎銮，燕娇莺姹炫珠翠。", "华胥仙梦未了，被天公澒洞，吹换尘世。", "淡柳湖山，浓花巷陌，惟说钱塘而已。", "回头汴水。", "望当日宸游，万□□□。", "但有寒芜，夜深青磷起。"]'),
('song-ci-542','念奴娇','蒋捷','宋','宋词','song-ci','念奴娇','[]','夜深清梦，到丛花深处，满襟冰雪。',120,'宋词/ci.song.18000.json','["夜深清梦，到丛花深处，满襟冰雪。", "人在琼云方响乐，杳杳冲牙清绝。", "翠簨翔龙，金枞跃凤，不是蕤宾铁。", "凄锵仙调，风敲珠树新折。", "中有五色光开，参差帔影，对舞山香彻。", "雾阁云窗归去也，笑拥灵君旌节。", "六曲阑干，一声鹦鹉，霍地空花灭。", "梦回孤馆，秋笳霜外呜咽。"]'),
('song-ci-543','应天长','蒋捷','宋','宋词','song-ci','应天长','[]','柳湖载酒，梅墅赊棋，东风袖里寒色。',122,'宋词/ci.song.18000.json','["柳湖载酒，梅墅赊棋，东风袖里寒色。", "转眼翠笼池阁，含樱荐莺食。", "匆匆过、春是客。", "弄细雨、昼阴生寂。", "似琼花、谪下红裳，再返仙籍。", "无限倚阑愁，梦断云箫，鹊叫度青壁。", "漫有戏龙盘□，盈盈住花宅。", "骄骢马、嘶巷陌。", "户半掩、堕鞭无迹。", "但追想，白苎裁缝，灯下初识。"]'),
('song-ci-544','贺新郎','蒋捷','宋','宋词','song-ci','贺新郎','[]','绝代幽人独。',142,'宋词/ci.song.18000.json','["绝代幽人独。", "掩芳姿、深居何处，乱云深谷。", "自说关中良家子，零落聊依草木。", "世丧败、谁收骨肉。", "轻薄儿郎为夫婿，爱新人、窕窈颜如玉。", "千万事，风前烛。", "鸳鸯一旦成孤宿。", "最堪怜、新人欢笑，旧人哀哭。", "侍婢卖珠回来后，相与牵萝补屋。", "漫采得、柏枝盈掬。", "日暮山中天寒也，翠绡衣、薄甚肌生粟。", "空敛袖，倚修竹。"]'),
('song-ci-545','玉漏迟','蒋捷','宋','宋词','song-ci','玉漏迟','[]','客窗空翠杪。',116,'宋词/ci.song.18000.json','["客窗空翠杪。", "前生饮惯，长生琼醥。", "回首红尘，换了□花幰草。", "隔水神仙洞府，但只有、飞霞能到。", "谁信道。", "西风送我，还陪清啸。", "缥渺。", "柳侧双楼，正绣幕围春，露深烟悄。", "鱼尾停时，雪上鬒云犹少。", "醉傍芙蓉自语，愿来此、年年簪帽。", "青屿小。", "鹤立淡烟秋晓。"]'),
('song-ci-546','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','十年前事翻疑梦，重逢可怜俱老。',123,'宋词/ci.song.18000.json','["十年前事翻疑梦，重逢可怜俱老。", "水国春空，山城岁晚，无语相看一笑。", "荷衣换了。", "任京洛尘沙，冷凝风帽。", "见说吟情，近来不到谢池草。", "欢游曾步翠窈。", "乱红迷紫曲，芳意今少。", "舞扇招香，歌桡唤玉，犹忆钱塘苏小。", "无端暗恼。", "又几度留连，燕昏莺晓。", "回首妆楼，甚时重去好。"]'),
('song-ci-547','三姝媚','张炎','宋','宋词','song-ci','三姝媚','[]','芙蓉城伴侣。',122,'宋词/ci.song.18000.json','["芙蓉城伴侣。", "乍卸却单衣，茜罗重护。", "傍水开时，细看来、浑似阮郎前度。", "记得小楼，听一夜，江南春雨。", "梦醒箫声，流水青苹，旧游何许。", "谁翦层芳深贮。", "便洗尽长安，半面尘土。", "绝似桃根，带笑痕来伴，柳枝娇舞。", "莫是孤村，试与问、酒家何处。", "曾醉梢头双果，园林未暑。"]'),
('song-ci-548','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','记玉关、踏雪事清游。',118,'宋词/ci.song.18000.json','["记玉关、踏雪事清游。", "寒气脆貂裘。", "傍枯林古道，长河饮马，此意悠悠。", "短梦依然江表，老泪洒西州。", "一字无题处，落叶都愁。", "载取白云归去，问谁留楚佩，弄影中洲。", "折芦花赠远，零落一身秋。", "向寻常野桥流水，待招来、不是旧沙鸥。", "空怀感，有斜阳处，却怕登楼。"]'),
('song-ci-549','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','寒花清事，老圃闲人，相看秋色霏霏。',119,'宋词/ci.song.18000.json','["寒花清事，老圃闲人，相看秋色霏霏。", "带叶分根，空翠半湿荷衣。", "沅湘旧愁未减，有黄金、难铸相思。", "但醉里，把苔笺重谱，不许春知。", "聊慰幽怀古意，且频簪短帽，休怨斜晖。", "采摘无多，一笑竟日忘归。", "从教护香径小，似东山、还似东篱。", "待去隐，怕如今、不是晋时。"]'),
('song-ci-550','扫花游・扫地游','张炎','宋','宋词','song-ci','扫花游・扫地游','[]','烟霞万壑，记曲径幽寻，霁痕初晓。',117,'宋词/ci.song.18000.json','["烟霞万壑，记曲径幽寻，霁痕初晓。", "绿窗窈窕。", "看随花甃石，就泉通沼。", "几日不来，一片苍云未扫。", "自长啸。", "怅乔木荒凉，都是残照。", "碧天秋浩渺。", "听虚籁泠泠，飞下孤峭。", "山空翠老。", "步仙风，怕有采芝人到。", "野色闲门，芳草不除更好。", "境深悄。", "比斜川、又清多少。"]'),
('song-ci-551','琐窗寒','张炎','宋','宋词','song-ci','琐窗寒','[]','断碧分山，空帘剩月，故人天外。',124,'宋词/ci.song.18000.json','["断碧分山，空帘剩月，故人天外。", "香留酒殢。", "蝴蝶一生花里。", "想如今、醉魂未醒，夜台梦语秋声碎。", "自中仙去后，词笺赋笔，便无清致。", "都是。", "凄凉意。", "怅玉笥埋云，锦袍归水。", "形容憔悴。", "料应也、孤吟山鬼。", "那知人、弹折素弦，黄金铸出相思泪。", "但柳枝、门掩枯阴，候蛩愁暗苇。"]'),
('song-ci-552','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','龟峰深处隐，岩壑静、万尘空。',123,'宋词/ci.song.18000.json','["龟峰深处隐，岩壑静、万尘空。", "任一路白云，山童休扫，却似崆峒。", "只恐烂柯人到，怕光阴、不与世间同。", "旋采生枝带叶，微煎石鼎团龙。", "从容。", "吟啸百年翁。", "行乐少扶筇。", "向镜水传心，柴桑袖手，门掩清风。", "如何晋人去后，好林泉、都在夕阳中。", "禅外更无今古，醉归明月千松。"]'),
('song-ci-553','三姝媚','张炎','宋','宋词','song-ci','三姝媚','[]','苍潭枯海树。',122,'宋词/ci.song.18000.json','["苍潭枯海树。", "正雪窦高寒，水声东去。", "古意萧闲，问结庐人远，白云谁侣。", "贺监犹狂，还散迹、千岩风露。", "抱瑟空游，都是凄凉，此愁难语。", "莫趁江湖鸥鹭。", "怕太乙炉荒，暗消铅虎。", "投老心情，未归来何事，共成羁旅。", "布袜青鞋，休误入、桃源深处。", "待得重逢却说，巴山夜雨。"]'),
('song-ci-554','扫花游・扫地游','张炎','宋','宋词','song-ci','扫花游・扫地游','[]','嫩寒禁暖，正草色侵衣，野光如洗。',117,'宋词/ci.song.18000.json','["嫩寒禁暖，正草色侵衣，野光如洗。", "去城数里。", "绕长堤是柳，钓船深舣。", "小立斜阳，试数花风第几。", "问春意。", "待留取断红，心事难寄。", "芳讯成拈指。", "甚远客他乡，老怀如此。", "醉馀梦里。", "尚分明认得，旧时罗绮。", "可惜空帘，误却归来燕子。", "胜游地。", "想依然、断桥流水。"]'),
('song-ci-555','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','春风不暖垂杨树，吹却絮云多少。',123,'宋词/ci.song.18000.json','["春风不暖垂杨树，吹却絮云多少。", "燕子人家，夕阳巷陌，行入野畦深窈。", "筹花斗草。", "记小舫寻芳，断桥初晓。", "那日心情，几人同向近来老。", "消忧何处最好。", "夜深频秉烛，犹是迟了。", "南浦歌阑，东林社冷，赢得如今怀抱。", "吟悰暗恼。", "待醉也慵听，劝归啼鸟。", "怕扰离愁，乱红休去扫。"]'),
('song-ci-556','疏影','张炎','宋','宋词','song-ci','疏影','[]','柳黄未结。',134,'宋词/ci.song.18000.json','["柳黄未结。", "放嫩晴消尽，断桥残雪。", "隔水人家，浑是花阴，曾醉好春时节。", "轻车几度新堤晓，想如今、燕莺犹说。", "纵艳游、得似当年，早是旧情都别。", "重到翻疑梦醒，弄泉试照影，惊见华发。", "却笑归来，石老云荒，身世飘然一叶。", "闭门约住青山色，自容与、吟窗清绝。", "怕夜寒、吹到梅花，休卷半帘明月。"]'),
('song-ci-557','渡江云','张炎','宋','宋词','song-ci','渡江云','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','山空天入海，倚楼望极，风急暮潮初。',123,'宋词/ci.song.18000.json','["山空天入海，倚楼望极，风急暮潮初。", "一帘鸠外雨，几处闲田，隔水动春锄。", "新烟禁柳，想如今、绿到西湖。", "犹记得、当年深隐，门掩两三株。", "愁余。", "荒洲古溆，断梗疏萍，更漂流何处。", "空自觉、围羞带减，影怯灯孤。", "常疑即见桃花面，甚近来、翻笑无书。", "书纵远，如何也都无。"]'),
('song-ci-558','琐窗寒','张炎','宋','宋词','song-ci','琐窗寒','[]','乱雨敲春，深烟带晚，水窗慵凭。',122,'宋词/ci.song.18000.json','["乱雨敲春，深烟带晚，水窗慵凭。", "空帘谩卷，数日更无花影。", "怕依然、旧时燕归，定应未识江南冷。", "最怜他、树底蔫红，不语背人吹尽。", "清润。", "通幽径。", "待移灯翦韭，试香温鼎。", "分明醉里，过了几番风信。", "想竹间、高阁半开，小车未来犹自等。", "傍新晴、隔柳呼船，待教潮信稳。"]'),
('song-ci-559','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','记开帘过酒，隔水悬灯，款语梅边。',124,'宋词/ci.song.18000.json','["记开帘过酒，隔水悬灯，款语梅边。", "未了清游兴，又飘然独去，何处山川。", "淡风暗收榆荚，吹下沈郎钱。", "叹客里光阴，消磨艳冶，都在尊前。", "留连。", "殢人处，是镜曲窥莺，兰阜围泉。", "醉拂珊瑚树，写百年幽恨，分付吟笺。", "故乡几回飞梦，江雨夜凉船。", "纵忘却归期，千山未必无杜鹃。"]'),
('song-ci-560','水龙吟','张炎','宋','宋词','song-ci','水龙吟','[]','仙人掌上芙蓉，涓涓犹湿金盘露。',126,'宋词/ci.song.18000.json','["仙人掌上芙蓉，涓涓犹湿金盘露。", "轻妆照水，纤裳玉立，飘摇似舞。", "几度消凝，满湖烟月，一汀鸥鹭。", "记小舟夜悄，波明香远，浑不见、花开处。", "应是浣纱人妒。", "褪红衣、被谁轻误。", "闲情淡雅，冶容清润，凭娇待语。", "隔浦相逢，偶然倾盖，似传心素。", "怕湘皋佩解，绿云十里，卷风西去。"]'),
('song-ci-561','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','叹江潭树老，杜曲门荒，同赋飘零。',124,'宋词/ci.song.18000.json','["叹江潭树老，杜曲门荒，同赋飘零。", "乍见翻疑梦，对萧萧乱发，都是愁根。", "秉烛故人归后，花月锁春深。", "纵草带堪题，争如片叶，能寄殷勤。", "重寻。", "已无处，尚记得依稀，柳下芳邻。", "伫立香风外，抱孤愁凄惋，羞燕惭莺。", "俯仰十年前事，醉后醒还惊。", "又晓日千峰，涓涓露湿花气生。"]'),
('song-ci-562','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','倚危楼、一笛翠屏空，万里见天心。',119,'宋词/ci.song.18000.json','["倚危楼、一笛翠屏空，万里见天心。", "度野光清峭，晴峰涌日，冷石生云。", "帘卷小亭虚院，无地不花阴。", "径曲知何处，春水泠泠。", "啸傲柴桑影里，且怡颜莫问，谁古谁今。", "任燕留鸥住，聊复慰幽情。", "爱吾庐、点尘难到，好林泉、都付与闲人。", "还知否，元来卜隐，不在山深。"]'),
('song-ci-563','摸鱼子','张炎','宋','宋词','song-ci','摸鱼子','[]','爱吾庐、傍湖千顷，苍茫一片清润。',140,'宋词/ci.song.18000.json','["爱吾庐、傍湖千顷，苍茫一片清润。", "晴岚暖翠融融处，花影倒窥天镜。", "沙浦迥。", "看野水涵波，隔柳横孤艇。", "眠鸥未醒。", "甚占得莼乡，都无人见，斜照起春暝。", "还重省。", "岂料山中秦晋。", "桃源今度难认。", "林间即是长生路，一笑元非捷径。", "深更静。", "待散以吹箫，跨鹤天风冷。", "凭高露饮。", "正碧落尘空，光摇半壁，月在万松顶。"]'),
('song-ci-564','风入松','张炎','宋','宋词','song-ci','风入松','[]','老来学圃乐年华。',90,'宋词/ci.song.18000.json','["老来学圃乐年华。", "茅屋短篱遮。", "儿孙戏逐田翁去，小桥横、路转三叉。", "细雨一犁春意，西风万宝生涯。", "携筇犹记度晴沙。", "流水带寒鸦。", "门前少得宽闲地，绕平畴、尽是桑麻。", "却笑牧童遥指，杏花深处人家。"]'),
('song-ci-565','凤凰台上忆吹箫','张炎','宋','宋词','song-ci','凤凰台上忆吹箫','[]','水国浮家，渔村古隐，浪游惯占花深。',120,'宋词/ci.song.18000.json','["水国浮家，渔村古隐，浪游惯占花深。", "犹记得、琵琶半面，曾湿衫青。", "不道江空岁晚，桃叶渡、还叹飘零。", "因乘兴，醉梦醒时，却是山阴。", "投闲倦呼俦侣，竟棹入芦花，俗客难寻。", "风渺渺、云拖暮雪，独钓寒清。", "远溯流光万里，浑错认、叶竹寰瀛。", "元来是、天上太乙真人。"]'),
('song-ci-566','解连环','张炎','宋','宋词','song-ci','解连环','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','楚江空晚。',132,'宋词/ci.song.18000.json','["楚江空晚。", "怅离群万里，恍然惊散。", "自顾影、欲下寒塘，正沙净草枯，水平天远。", "写不成书，只寄得、相思一点。", "料因循误了，残毡拥雪，故人心眼。", "谁怜旅愁荏苒。", "谩长门夜悄，锦筝弹怨。", "想伴侣、犹宿芦花，也曾念春前，去程应转。", "暮雨相呼，怕蓦地、玉关重见。", "未羞他、双燕归来，画帘半卷。"]'),
('song-ci-567','满庭芳','张炎','宋','宋词','song-ci','满庭芳','[]','晴皎霜花，晓熔冰羽，开帘觉道寒轻。',118,'宋词/ci.song.18000.json','["晴皎霜花，晓熔冰羽，开帘觉道寒轻。", "误闻啼鸟，生意又园林。", "闲了凄凉赋笔，便而今、不听秋声。", "消凝处，一枝借暖，终是未多情。", "阳和能几许，寻红探粉，也恁忺人。", "笑邻娃痴小，料理护花铃。", "却怕惊回睡蝶，恐和他、草梦都醒。", "还知否，能消几日，风雪灞桥深。"]'),
('song-ci-568','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','问蓬莱何处，风月依然，万里江清。',123,'宋词/ci.song.18000.json','["问蓬莱何处，风月依然，万里江清。", "休说神仙事，便神仙纵有，即是闲人。", "笑我几番醒醉，石磴扫松阴。", "任狂客难招，采芳难赠，且自微吟。", "俯仰成陈迹，叹百年谁在，阑槛孤凭。", "海日生残夜，看卧龙和梦，飞入秋冥。", "还听水声东去，山冷不生云。", "正目极空寒，萧萧汉柏愁茂陵。"]'),
('song-ci-569','解连环','张炎','宋','宋词','song-ci','解连环','[]','句章城郭。',132,'宋词/ci.song.18000.json','["句章城郭。", "问千年往事，几回归鹤。", "叹贞元、朝士无多，又日冷湖阴，柳边门钥。", "向北来时，无处认、江南花落。", "纵荷衣未改，病损茂陵，总是离索。", "山中故人去却。", "但碑寒岘首，旧景如昨。", "怅二乔、空老春深，正歌断帘空，草暗铜雀。", "楚魄难招，被万叠、闲云迷著。", "料犹是、听风听雨，朗吟夜壑。"]'),
('song-ci-570','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','薛涛笺上相思字，重开又还重折。',123,'宋词/ci.song.18000.json','["薛涛笺上相思字，重开又还重折。", "载酒船空，眠波柳老，一缕离痕难折。", "虚沙动月。", "叹千里悲歌，唾壶敲缺。", "却说巴山，此时怀抱那时节。", "寒香深处话别。", "病来浑瘦损，懒赋情切。", "太白闲云，新丰旧雨，多少英游消歇。", "回潮似咽。", "送一点秋心，故人天末。", "江影沈沈，露凉鸥梦阔。"]'),
('song-ci-571','声声慢','张炎','宋','宋词','song-ci','声声慢','["\u897f\u6e56"]','荷衣消翠，蕙带馀香，灯前共语生平。',119,'宋词/ci.song.18000.json','["荷衣消翠，蕙带馀香，灯前共语生平。", "苦竹黄芦，都是梦里游情。", "西湖几番夜雨，怕如今、冷却鸥盟。", "倩寄远，见故人说道，杜老飘零。", "难挽清风飞佩，有相思都在，断柳长汀。", "此别何如，一笑写入瑶琴。", "天空水云变色，任愔愔、山鬼愁听。", "兴未已，更何妨、弹到广陵。"]');
